module ClientMain {
  method Main(_noArgsParameter: seq<seq<char>>)
  {
    var rootPass, rootTotal := AhpSkeleton.RunCorpus();
    print ""ROOT CORPUS:          "", rootPass, ""/"", rootTotal, "" green against extracted code\n"";
    var rwPass, rwTotal := ResourceWatch.RunCorpus();
    print ""RESOURCEWATCH CORPUS: "", rwPass, ""/"", rwTotal, "" green against extracted code\n"";
    var cvPass, cvTotal := Canvas.RunCorpus();
    print ""CANVAS CORPUS:        "", cvPass, ""/"", cvTotal, "" green against extracted code\n"";
    var csPass, csTotal := Changeset.RunCorpus();
    print ""CHANGESET CORPUS:     "", csPass, ""/"", csTotal, "" green against extracted code\n"";
    var anPass, anTotal := Annotations.RunCorpus();
    print ""ANNOTATIONS CORPUS:   "", anPass, ""/"", anTotal, "" green against extracted code\n"";
    var tPass, tTotal := Terminal.RunCorpus();
    print ""TERMINAL CORPUS:      "", tPass, ""/"", tTotal, "" green against extracted code\n"";
    var sPass, sModeled := Session.RunCorpus();
    print ""SESSION CORPUS:       "", sPass, ""/"", sModeled, "" modeled green (of 61 total; all ~25 action TYPES now modeled)\n"";
    var chPass, chModeled := Chat.RunCorpus();
    print ""CHAT CORPUS:          "", chPass, ""/"", chModeled, "" modeled green (of 97 total; full tool-call state machine + turn lifecycle modeled)\n"";
    var pass := rootPass + rwPass + cvPass + csPass + anPass + tPass + sPass + chPass;
    var total := rootTotal + rwTotal + cvTotal + csTotal + anTotal + tTotal + sModeled + chModeled;
    print ""TOTAL: "", pass, ""/"", total, "" corpus fixtures green (5 full AHP channels + session/chat partial)\n"";
    expect pass == total, ""expectation violation"";
    print ""MULTI-CHANNEL CLIENT OK — extract(cs,js) + corpus all green\n"";
  }

  import AhpSkeleton

  import ResourceWatch

  import Canvas

  import Changeset

  import Annotations

  import Terminal

  import Session

  import Chat
}

module ConfluxContract {
  function Fold<S, A>(r: Reducer<S, A>, s: S, actions: seq<A>): S
    decreases |actions|
  {
    if |actions| == 0 then
      s
    else
      Fold(r, r(s, actions[0]), actions[1..])
  }

  lemma /*{:_inductionTrigger Fold(r, Fold(r, s, xs), ys)}*/ /*{:_inductionTrigger xs + ys}*/ /*{:_induction xs, ys}*/ FoldConcat<S, A>(r: Reducer<S, A>, s: S, xs: seq<A>, ys: seq<A>)
    ensures Fold(r, s, xs + ys) == Fold(r, Fold(r, s, xs), ys)
    decreases |xs|
  {
    if |xs| == 0 {
      assert xs + ys == ys;
    } else {
      assert (xs + ys)[0] == xs[0];
      assert (xs + ys)[1..] == xs[1..] + ys;
      FoldConcat(r, r(s, xs[0]), xs[1..], ys);
    }
  }

  lemma /*{:_inductionTrigger actions[k..]}*/ /*{:_inductionTrigger actions[..k]}*/ /*{:_inductionTrigger |actions|}*/ /*{:_induction actions}*/ SnapshotReplay<S, A>(r: Reducer<S, A>, s: S, actions: seq<A>, k: nat)
    requires k <= |actions|
    ensures Fold(r, s, actions) == Fold(r, Fold(r, s, actions[..k]), actions[k..])
    decreases actions, k
  {
    assert actions == actions[..k] + actions[k..];
    FoldConcat(r, s, actions[..k], actions[k..]);
  }

  lemma PeersConverge<S, A>(r: Reducer<S, A>, s: S, actions: seq<A>, j: nat, k: nat)
    requires j <= |actions| && k <= |actions|
    ensures Fold(r, Fold(r, s, actions[..j]), actions[j..]) == Fold(r, Fold(r, s, actions[..k]), actions[k..])
    decreases actions, j, k
  {
    SnapshotReplay(r, s, actions, j);
    SnapshotReplay(r, s, actions, k);
  }

  lemma NonVacuousWitness()
    ensures exists r: Reducer<int, int>, s: int, a: int {:trigger Fold(r, s, [a])} :: Fold(r, s, [a]) != s
  {
    ghost var add := (s: int, a: int) => s + a;
    assert Fold(add, 0, [1, 2, 3]) == 6;
    assert Fold(add, Fold(add, 0, [1]), [2, 3]) == 6;
    assert Fold(add, 0, [1]) == 1;
    assert Fold(add, 0, [1]) != 0;
  }

  function Iterate<T>(f: T -> T, x: T, n: nat): T
    decreases n
  {
    if n == 0 then
      x
    else
      Iterate(f, f(x), n - 1)
  }

  lemma /*{:_inductionTrigger Iterate(f, Iterate(f, x, n), m)}*/ /*{:_induction n, m}*/ IterateAdd<T>(f: T -> T, x: T, n: nat, m: nat)
    ensures Iterate(f, x, n + m) == Iterate(f, Iterate(f, x, n), m)
    decreases n
  {
    if n == 0 {
    } else {
      assert n + m - 1 == n - 1 + m;
      IterateAdd(f, f(x), n - 1, m);
    }
  }

  lemma /*{:_inductionTrigger Iterate(g, x, n)}*/ /*{:_inductionTrigger Iterate(f, x, n)}*/ /*{:_induction n}*/ IterateCongruence<T(!new)>(f: T -> T, g: T -> T, x: T, n: nat)
    requires forall y: T {:trigger g(y)} {:trigger f(y)} :: f(y) == g(y)
    ensures Iterate(f, x, n) == Iterate(g, x, n)
    decreases n
  {
    if n == 0 {
    } else {
      assert f(x) == g(x);
      IterateCongruence(f, g, f(x), n - 1);
    }
  }

  lemma /*{:_inductionTrigger Iterate(f, x, n)}*/ /*{:_induction n}*/ IterateIsFold<T>(f: T -> T, x: T, n: nat)
    ensures Iterate(f, x, n) == Fold((s: T, ignored: int) => f(s), x, seq(n, (i: int) => 0))
    decreases n
  {
    if n == 0 {
    } else {
      assert seq(n, (i: int) => 0)[1..] == seq(n - 1, (i: int) => 0);
      IterateIsFold(f, f(x), n - 1);
    }
  }

  datatype Option<T> = None | Some(value: T)

  type Reducer<!S, !A> = (S, A) -> S
}

module ConfluxSemanticGraphIdentity {
  function StableId(canonicalEncode: StableIdentityInput -> string, sha256: string -> Digest, input: StableIdentityInput): Digest
    decreases input
  {
    sha256(""archai:stable-id:1.0.0\n"" + canonicalEncode(input))
  }

  function ContentRevision<T>(kind: string, schemaVersion: string, canonicalSemanticContent: T -> string, sha256: string -> Digest, content: T): Digest
    decreases kind, schemaVersion
  {
    sha256(""archai:"" + kind + "":"" + schemaVersion + ""\n"" + canonicalSemanticContent(content))
  }

  function GraphRevision(canonicalEncode: GraphIdentityInput -> string, sha256: string -> Digest, input: GraphIdentityInput): Digest
    decreases input
  {
    sha256(""archai:semantic-graph:1.0.0\n"" + canonicalEncode(input))
  }

  function GraphId(sha256: string -> Digest, authorityId: string, selectorKind: string, selectorId: string, schemaEpoch: string): Digest
    decreases authorityId, selectorKind, selectorId, schemaEpoch
  {
    sha256(""archai:graph-id:1.0.0\n"" + authorityId + ""\n"" + selectorKind + ""\n"" + selectorId + ""\n"" + schemaEpoch)
  }

  lemma StableIdIgnoresLocator(canonicalEncode: StableIdentityInput -> string, sha256: string -> Digest, input: StableIdentityInput, first: NonSemanticMetadata, second: NonSemanticMetadata)
    ensures forall a: StableIdentityInput, b: StableIdentityInput {:trigger StableId(canonicalEncode, sha256, b), StableId(canonicalEncode, sha256, a)} {:trigger StableId(canonicalEncode, sha256, b), canonicalEncode(a)} {:trigger StableId(canonicalEncode, sha256, a), canonicalEncode(b)} {:trigger canonicalEncode(b), canonicalEncode(a)} :: canonicalEncode(a) == canonicalEncode(b) ==> StableId(canonicalEncode, sha256, a) == StableId(canonicalEncode, sha256, b)
    decreases input, first, second
  {
  }

  lemma GraphRevisionIgnoresTransportMetadata(canonicalEncode: GraphIdentityInput -> string, sha256: string -> Digest, input: GraphIdentityInput, first: NonSemanticMetadata, second: NonSemanticMetadata)
    ensures forall a: GraphIdentityInput, b: GraphIdentityInput {:trigger GraphRevision(canonicalEncode, sha256, b), GraphRevision(canonicalEncode, sha256, a)} {:trigger GraphRevision(canonicalEncode, sha256, b), canonicalEncode(a)} {:trigger GraphRevision(canonicalEncode, sha256, a), canonicalEncode(b)} {:trigger canonicalEncode(b), canonicalEncode(a)} :: canonicalEncode(a) == canonicalEncode(b) ==> GraphRevision(canonicalEncode, sha256, a) == GraphRevision(canonicalEncode, sha256, b)
    decreases input, first, second
  {
  }

  type Digest = string

  datatype StableIdentityInput = StableIdentityInput(kind: string, authorityId: string, naturalKey: string)

  datatype GraphIdentityInput = GraphIdentityInput(graphId: Digest, authorityArtifactIdentity: Digest, capabilityRevisions: seq<Digest>, lensRevisions: seq<Digest>, recordRevisions: seq<Digest>)

  datatype NonSemanticMetadata = NonSemanticMetadata(absoluteLocator: string, gitHead: string, listenerPid: string, wallClock: string, receiptLocator: string)
}

module ConfluxSemanticGraphContract {
  predicate CompleteWitness(c: Completeness)
    decreases c
  {
    c.complete ==>
      |c.reasons| == 0
  }

  predicate TypedRecordWellFormed(value: TypedValue)
    decreases value
  {
    match value
    case TVList(items) =>
      forall i: int {:trigger items[i]} | 0 <= i < |items| :: 
        TypedRecordWellFormed(items[i])
    case TVRecord(names, values) =>
      |names| == |values| &&
      (forall i: int, j: int {:trigger names[j], names[i]} | 0 <= i < j < |names| :: 
        names[i] != names[j]) &&
      forall i: int {:trigger values[i]} | 0 <= i < |values| :: 
        TypedRecordWellFormed(values[i])
    case _ /* _v0 */ =>
      true
  }

  predicate GraphReferencesClose(graph: SemanticGraphSnapshotV1)
    decreases graph
  {
    var nodeIds: set<StableId> := graph.nodes.Keys;
    var edgeIds: set<StableId> := graph.edges.Keys;
    var factIds: set<StableId> := graph.facts.Keys;
    var findingIds: set<StableId> := graph.findings.Keys;
    var evidenceIds: set<StableId> := graph.evidence.Keys;
    (forall id: seq<char> {:trigger graph.nodes[id]} {:trigger id in nodeIds} | id in nodeIds :: 
      var node: SemanticNode := graph.nodes[id]; node.id == id && node.factIds <= factIds && node.evidenceIds <= evidenceIds) &&
    (forall id: seq<char> {:trigger graph.edges[id]} {:trigger id in edgeIds} | id in edgeIds :: 
      var edge: SemanticEdge := graph.edges[id]; edge.id == id && edge.fromId in graph.nodes && edge.toId in graph.nodes && edge.factIds <= factIds && edge.evidenceIds <= evidenceIds) &&
    (forall id: seq<char> {:trigger graph.facts[id]} {:trigger id in factIds} | id in factIds :: 
      var fact: SemanticFact := graph.facts[id]; fact.id == id && fact.subjectId in graph.nodes && fact.supportingFactIds <= factIds && fact.evidenceIds <= evidenceIds && TypedRecordWellFormed(fact.value)) &&
    (forall id: seq<char> {:trigger graph.findings[id]} {:trigger id in findingIds} | id in findingIds :: 
      var finding: SemanticFinding := graph.findings[id]; finding.id == id && (finding.subjectId == """" || finding.subjectId in graph.nodes) && finding.supportingFactIds <= factIds && finding.evidenceIds <= evidenceIds) &&
    forall id: seq<char> {:trigger graph.evidence[id]} {:trigger id in evidenceIds} | id in evidenceIds :: 
      var item: EvidenceRecord := graph.evidence[id]; item.id == id && item.parentEvidenceIds <= evidenceIds
  }

  predicate GraphWellFormed(graph: SemanticGraphSnapshotV1)
    decreases graph
  {
    graph.schemaVersion == ""semantic-graph/1.0.0"" &&
    graph.graphId != """" &&
    graph.revision != """" &&
    graph.snapshotId != """" &&
    graph.receiptId != """" &&
    CompleteWitness(graph.completeness) &&
    GraphReferencesClose(graph)
  }

  predicate NonResetDeltaWellFormed(delta: SemanticGraphDeltaV1)
    decreases delta
  {
    !delta.reset &&
    delta.resetReason.None? &&
    delta.replacement.None? &&
    delta.nodes.added.Keys !! delta.nodes.changed.Keys &&
    delta.edges.added.Keys !! delta.edges.changed.Keys &&
    delta.facts.added.Keys !! delta.facts.changed.Keys &&
    delta.findings.added.Keys !! delta.findings.changed.Keys &&
    delta.evidence.added.Keys !! delta.evidence.changed.Keys
  }

  predicate ResetDeltaWellFormed(delta: SemanticGraphDeltaV1)
    decreases delta
  {
    delta.reset &&
    delta.resetReason.Some? &&
    delta.replacement.Some? &&
    |delta.nodes.added| + |delta.nodes.changed| + |delta.nodes.removed| == 0 &&
    |delta.edges.added| + |delta.edges.changed| + |delta.edges.removed| == 0 &&
    |delta.facts.added| + |delta.facts.changed| + |delta.facts.removed| == 0 &&
    |delta.findings.added| + |delta.findings.changed| + |delta.findings.removed| == 0 &&
    |delta.evidence.added| + |delta.evidence.changed| + |delta.evidence.removed| == 0
  }

  predicate DeltaWellFormed(delta: SemanticGraphDeltaV1)
    decreases delta
  {
    delta.schemaVersion == ""semantic-graph-delta/1.0.0"" &&
    delta.graphId != """" &&
    delta.fromRevision != """" &&
    delta.toRevision != """" &&
    delta.receiptId != """" &&
    if delta.reset then ResetDeltaWellFormed(delta) else NonResetDeltaWellFormed(delta)
  }

  predicate DeltaApplies(before: SemanticGraphSnapshotV1, delta: SemanticGraphDeltaV1, after: SemanticGraphSnapshotV1)
    decreases before, delta, after
  {
    GraphWellFormed(before) &&
    GraphWellFormed(after) &&
    DeltaWellFormed(delta) &&
    !delta.reset &&
    before.graphId == delta.graphId &&
    after.graphId == delta.graphId &&
    before.revision == delta.fromRevision &&
    after.revision == delta.toRevision &&
    after.previousRevision == before.revision
  }

  lemma DeltaApplicationTargetsExactRevision(before: SemanticGraphSnapshotV1, delta: SemanticGraphDeltaV1, after: SemanticGraphSnapshotV1)
    requires DeltaApplies(before, delta, after)
    ensures before.revision == delta.fromRevision
    ensures after.revision == delta.toRevision
    ensures after.previousRevision == before.revision
    decreases before, delta, after
  {
  }

  lemma LocatorIndependentGraphIdentity(canonicalEncode: Id.GraphIdentityInput -> string, sha256: string -> Digest, input: Id.GraphIdentityInput, first: Id.NonSemanticMetadata, second: Id.NonSemanticMetadata)
    ensures forall a: Id.GraphIdentityInput, b: Id.GraphIdentityInput {:trigger Id.GraphRevision(canonicalEncode, sha256, b), Id.GraphRevision(canonicalEncode, sha256, a)} {:trigger Id.GraphRevision(canonicalEncode, sha256, b), canonicalEncode(a)} {:trigger Id.GraphRevision(canonicalEncode, sha256, a), canonicalEncode(b)} {:trigger canonicalEncode(b), canonicalEncode(a)} :: canonicalEncode(a) == canonicalEncode(b) ==> Id.GraphRevision(canonicalEncode, sha256, a) == Id.GraphRevision(canonicalEncode, sha256, b)
    decreases input, first, second
  {
    Id.GraphRevisionIgnoresTransportMetadata(canonicalEncode, sha256, input, first, second);
  }

  import Id = ConfluxSemanticGraphIdentity

  import CA = ConfluxContentAddress

  import C = ConfluxContract

  type Digest = string

  type StableId = string

  datatype SelectorKind = Workspace | RepositorySet | Repository | Project | File | Subject

  datatype SemanticStatus = Complete | Failed | Unavailable | Cancelled | Stale

  datatype Availability = Available | Partial | CapabilityUnavailable

  datatype CapabilityKind = Transport | Snapshot | View | Analysis | Projection | Cache | Lens

  datatype FactLayer = Declared | Discovered | Observed | Derived | Policy

  datatype FindingSeverity = Error | Warning | Information | Hint

  datatype FindingStatus = Open | Resolved | FindingUnavailable

  datatype EvidenceKind = Source | Overlay | Directory | Config | Std | Doo | Syntax | Symbol | CallEdge | LexicalMatch | Plugin | Rule | Derivation | PolicyEvidence | Receipt | CacheDecision

  datatype LensArchetype = Graph | Matrix | Layered | List | Table | MasterDetail

  datatype TypedValue = TVNull | TVBool(boolValue: bool) | TVInteger(decimalString: string) | TVDecimal(canonicalDecimalString: string) | TVString(stringValue: string) | TVRef(targetId: StableId) | TVList(items: seq<TypedValue>) | TVRecord(fieldNames: seq<string>, fieldValues: seq<TypedValue>)

  datatype TypedField = TypedField(name: string, value: TypedValue)

  datatype Completeness = Completeness(complete: bool, reasons: seq<string>)

  datatype SourcePosition = SourcePosition(line: nat, column: nat)

  datatype SourceRange = SourceRange(start: SourcePosition, end: SourcePosition)

  datatype CapabilityRequirement = CapabilityRequirement(id: string, versionRange: string)

  datatype CapabilityDescriptor = CapabilityDescriptor(id: string, version: string, schemaDigest: Digest, implementationDigest: Digest, kind: CapabilityKind, scopes: set<SelectorKind>, requirements: seq<CapabilityRequirement>, availability: Availability, unavailableReasons: seq<string>, contentRevision: Digest)

  datatype AuthorityDescriptor = AuthorityDescriptor(authorityId: string, producerId: string, producerVersion: string, implementationDigest: Digest, sourceArtifactDigest: Digest, registryDigest: Digest)

  datatype EvidenceRecord = EvidenceRecord(id: StableId, snapshotId: Digest, kind: EvidenceKind, logicalRootId: string, logicalUri: string, locator: string, range: C.Option<SourceRange>, symbolId: string, artifactDigest: Digest, producerDigest: Digest, statement: string, parentEvidenceIds: set<StableId>, contentRevision: Digest)

  datatype SemanticNode = SemanticNode(id: StableId, kind: string, displayLabel: string, attributes: seq<TypedField>, factIds: set<StableId>, evidenceIds: set<StableId>, contentRevision: Digest)

  datatype SemanticEdge = SemanticEdge(id: StableId, kind: string, fromId: StableId, toId: StableId, directed: bool, attributes: seq<TypedField>, factIds: set<StableId>, evidenceIds: set<StableId>, contentRevision: Digest)

  datatype SemanticFact = SemanticFact(id: StableId, analysisId: string, subjectId: StableId, key: string, value: TypedValue, valueSchema: Digest, layer: FactLayer, ruleId: string, supportingFactIds: set<StableId>, evidenceIds: set<StableId>, contentRevision: Digest)

  datatype SemanticFinding = SemanticFinding(id: StableId, analysisId: string, ruleId: string, subjectId: StableId, severity: FindingSeverity, status: FindingStatus, code: string, message: string, expected: TypedValue, actual: TypedValue, supportingFactIds: set<StableId>, evidenceIds: set<StableId>, blocking: bool, contentRevision: Digest)

  datatype GraphLensDescriptor = GraphLensDescriptor(id: StableId, version: string, archetype: LensArchetype, title: string, nodeSelector: string, edgeSelector: string, factSelector: string, labelField: string, detailFields: seq<string>, columns: seq<string>, requiredCapabilities: seq<CapabilityRequirement>, contentRevision: Digest)

  datatype SemanticGraphSnapshotV1 = SemanticGraphSnapshotV1(schemaVersion: string, graphId: Digest, revision: Digest, previousRevision: string, snapshotId: Digest, authority: AuthorityDescriptor, capabilities: map<StableId, CapabilityDescriptor>, lenses: map<StableId, GraphLensDescriptor>, nodes: map<StableId, SemanticNode>, edges: map<StableId, SemanticEdge>, facts: map<StableId, SemanticFact>, findings: map<StableId, SemanticFinding>, evidence: map<StableId, EvidenceRecord>, completeness: Completeness, receiptId: Digest)

