module ConfluxResourceCeilings {
  predicate ValidMeasurement(measurement: ResourceMeasurement)
    decreases measurement
  {
    (measurement.status.MeasurementComplete? ==>
      measurement.value.Some?) &&
    (measurement.status.MeasurementPartial? ==>
      measurement.value.Some? &&
      |measurement.status.reason| > 0) &&
    (measurement.status.MeasurementUnavailable? ==>
      |measurement.status.reason| > 0) &&
    (measurement.status.MeasurementNotRequested? || measurement.status.MeasurementUnavailable? ==>
      measurement.value.None?)
  }

  function CompleteMeasurement(value: nat): ResourceMeasurement
    ensures ValidMeasurement(CompleteMeasurement(value))
    decreases value
  {
    ResourceMeasurement(Some(value), MeasurementComplete)
  }

  function NotRequestedMeasurement(): ResourceMeasurement
    ensures ValidMeasurement(NotRequestedMeasurement())
  {
    ResourceMeasurement(None, MeasurementNotRequested)
  }

  function UnavailableMeasurement(reason: string): ResourceMeasurement
    ensures ValidMeasurement(UnavailableMeasurement(reason))
    decreases reason
  {
    ResourceMeasurement(None, MeasurementUnavailable(if |reason| > 0 then reason else ""measurement unavailable""))
  }

  function RequestedPhaseFor(state: CacheHostPhaseState): ExecutionPhase
    decreases state
  {
    match state
    case HostPhaseUnavailable() =>
      Unknown
    case HostPhaseKnown(hostGeneration, cachedGeneration) =>
      if cachedGeneration.Some? && cachedGeneration.value == hostGeneration then
        Warm
      else
        Cold
  }

  const DefaultResourceCeilings: ResourceCeilings := ResourceCeilings(PhaseTimeCeilings(5000, 30000), PhaseMemoryCeilings(1024, 2048), 128)

  function EffectivePhase(phase: ExecutionPhase): ExecutionPhase
    decreases phase
  {
    if phase == Warm then
      Warm
    else
      Cold
  }

  function TimeCeilingForPhase(budget: PhaseTimeCeilings, phase: ExecutionPhase): nat
    decreases budget, phase
  {
    if EffectivePhase(phase) == Warm then
      budget.warmMs
    else
      budget.coldMs
  }

  function MemoryCeilingForPhase(budget: PhaseMemoryCeilings, phase: ExecutionPhase): nat
    decreases budget, phase
  {
    if EffectivePhase(phase) == Warm then
      budget.warmMb
    else
      budget.coldMb
  }

  predicate MemoryMeasurementRequired(budget: ResourceCeilings, phase: ExecutionPhase)
    decreases budget, phase
  {
    MemoryCeilingForPhase(budget.memory, phase) > 0
  }

  predicate OutputMeasurementRequired(budget: ResourceCeilings)
    decreases budget
  {
    budget.maxOutputMb > 0
  }

  function BytesToMegabytes(bytes: nat): nat
    decreases bytes
  {
    if bytes == 0 then
      0
    else
      (bytes + 1024 * 1024 - 1) / (1024 * 1024)
  }

  predicate IsMeasurementComplete(measurement: ResourceMeasurement)
    decreases measurement
  {
    ValidMeasurement(measurement) &&
    measurement.status.MeasurementComplete?
  }

  predicate MeasurementHasValue(measurement: ResourceMeasurement)
    decreases measurement
  {
    ValidMeasurement(measurement) &&
    measurement.value.Some?
  }

  predicate RequiredMemoryMeasurementFailed(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    decreases budget, phase, obs
  {
    MemoryMeasurementRequired(budget, phase) &&
    !IsMeasurementComplete(obs.peakRssMb)
  }

  predicate RequiredOutputMeasurementFailed(budget: ResourceCeilings, obs: ResourceObservation)
    decreases budget, obs
  {
    OutputMeasurementRequired(budget) &&
    !IsMeasurementComplete(obs.combinedOutputBytes)
  }

  predicate TimeBreached(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    decreases budget, phase, obs
  {
    TimeCeilingForPhase(budget.time, phase) > 0 &&
    obs.wallMs > TimeCeilingForPhase(budget.time, phase)
  }

  predicate MemoryBreached(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    decreases budget, phase, obs
  {
    MeasurementHasValue(obs.peakRssMb) &&
    MemoryCeilingForPhase(budget.memory, phase) > 0 &&
    obs.peakRssMb.value.value > MemoryCeilingForPhase(budget.memory, phase)
  }

  predicate OutputBreached(budget: ResourceCeilings, obs: ResourceObservation)
    decreases budget, obs
  {
    MeasurementHasValue(obs.combinedOutputBytes) &&
    budget.maxOutputMb > 0 &&
    BytesToMegabytes(obs.combinedOutputBytes.value.value) > budget.maxOutputMb
  }

  predicate DimensionViolated(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation, dimension: ResourceDimension)
    decreases budget, phase, obs, dimension
  {
    if dimension == TimeDimension then
      TimeBreached(budget, phase, obs)
    else if dimension == MemoryDimension then
      MemoryBreached(budget, phase, obs) || RequiredMemoryMeasurementFailed(budget, phase, obs)
    else
      OutputBreached(budget, obs) || RequiredOutputMeasurementFailed(budget, obs)
  }

  function ViolatedDimensions(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation): seq<ResourceDimension>
    decreases budget, phase, obs
  {
    (if TimeBreached(budget, phase, obs) then [TimeDimension] else []) + (if MemoryBreached(budget, phase, obs) || RequiredMemoryMeasurementFailed(budget, phase, obs) then [MemoryDimension] else []) + if OutputBreached(budget, obs) || RequiredOutputMeasurementFailed(budget, obs) then [OutputDimension] else []
  }

  function BreachedDimensions(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation): seq<ResourceDimension>
    decreases budget, phase, obs
  {
    ViolatedDimensions(budget, phase, obs)
  }

  function LimitForDimension(budget: ResourceCeilings, phase: ExecutionPhase, dimension: ResourceDimension): nat
    decreases budget, phase, dimension
  {
    if dimension == TimeDimension then
      TimeCeilingForPhase(budget.time, phase)
    else if dimension == MemoryDimension then
      MemoryCeilingForPhase(budget.memory, phase)
    else
      budget.maxOutputMb
  }

  function ObservedForDimension(obs: ResourceObservation, dimension: ResourceDimension): Option<nat>
    decreases obs, dimension
  {
    if dimension == TimeDimension then
      Some(obs.wallMs)
    else if dimension == MemoryDimension then
      obs.peakRssMb.value
    else
      match obs.combinedOutputBytes.value case None() => None case Some(bytes) => Some(BytesToMegabytes(bytes))
  }

  function Ok(phase: ExecutionPhase): ResourceVerdict
    decreases phase
  {
    ResourceVerdict(EnforcementOk, None, EffectivePhase(phase), None, None, ""within resource budget"")
  }

  function ViolationReason(outcome: EnforcementOutcome, budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation, dimension: ResourceDimension): string
    requires outcome != EnforcementOk
    requires DimensionViolated(budget, phase, obs, dimension)
    decreases outcome, budget, phase, obs, dimension
  {
    var prefix: seq<char> := if outcome == EnforcementKill then ""kill: "" else """";
    if dimension == MemoryDimension && RequiredMemoryMeasurementFailed(budget, phase, obs) then
      prefix + ""required process-tree RSS measurement unavailable""
    else if dimension == OutputDimension && RequiredOutputMeasurementFailed(budget, obs) then
      prefix + ""required combined-output measurement unavailable""
    else if dimension == TimeDimension then
      prefix + ""time budget exceeded""
    else if dimension == MemoryDimension then
      prefix + ""memory budget exceeded""
    else
      prefix + ""output budget exceeded""
  }

  function Violation(outcome: EnforcementOutcome, budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation, dimension: ResourceDimension): ResourceVerdict
    requires outcome != EnforcementOk
    requires DimensionViolated(budget, phase, obs, dimension)
    decreases outcome, budget, phase, obs, dimension
  {
    var measurementFailure: bool := (dimension == MemoryDimension && RequiredMemoryMeasurementFailed(budget, phase, obs)) || (dimension == OutputDimension && RequiredOutputMeasurementFailed(budget, obs));
    ResourceVerdict(outcome, Some(dimension), EffectivePhase(phase), Some(LimitForDimension(budget, phase, dimension)), if measurementFailure then None else ObservedForDimension(obs, dimension), ViolationReason(outcome, budget, phase, obs, dimension))
  }

  function DecideAs(outcome: EnforcementOutcome, budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation): ResourceVerdict
    requires outcome != EnforcementOk
    decreases outcome, budget, phase, obs
  {
    var dimensions: seq<ResourceDimension> := ViolatedDimensions(budget, phase, obs);
    if |dimensions| == 0 then
      Ok(phase)
    else
      Violation(outcome, budget, phase, obs, dimensions[0])
  }

  function DecideRecorded(outcome: EnforcementOutcome, budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation, dimension: ResourceDimension): ResourceVerdict
    requires outcome != EnforcementOk
    requires DimensionViolated(budget, phase, obs, dimension)
    decreases outcome, budget, phase, obs, dimension
  {
    Violation(outcome, budget, phase, obs, dimension)
  }

  function RecordedViolationReason(outcome: EnforcementOutcome, dimension: ResourceDimension, measurementFailure: bool): string
    requires outcome != EnforcementOk
    requires measurementFailure ==> dimension == MemoryDimension || dimension == OutputDimension
    decreases outcome, dimension, measurementFailure
  {
    var prefix: seq<char> := if outcome == EnforcementKill then ""kill: "" else """";
    if measurementFailure then
      if dimension == MemoryDimension then
        prefix + ""required process-tree RSS measurement unavailable""
      else
        prefix + ""required combined-output measurement unavailable""
    else if dimension == TimeDimension then
      prefix + ""time budget exceeded""
    else if dimension == MemoryDimension then
      prefix + ""memory budget exceeded""
    else
      prefix + ""output budget exceeded""
  }

  function RecordedViolation(outcome: EnforcementOutcome, budget: ResourceCeilings, phase: ExecutionPhase, dimension: ResourceDimension, observed: Option<nat>, measurementFailure: bool): ResourceVerdict
    requires outcome != EnforcementOk
    requires measurementFailure ==> observed.None?
    requires measurementFailure ==> dimension == MemoryDimension || dimension == OutputDimension
    decreases outcome, budget, phase, dimension, observed, measurementFailure
  {
    ResourceVerdict(outcome, Some(dimension), EffectivePhase(phase), Some(LimitForDimension(budget, phase, dimension)), observed, RecordedViolationReason(outcome, dimension, measurementFailure))
  }

  function DecidePostHoc(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation): ResourceVerdict
    decreases budget, phase, obs
  {
    DecideAs(EnforcementFail, budget, phase, obs)
  }

  function DecideInFlight(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation): ResourceVerdict
    decreases budget, phase, obs
  {
    DecideAs(EnforcementKill, budget, phase, obs)
  }

  lemma DecisionMatchesBudgetAndObservation(outcome: EnforcementOutcome, budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    requires outcome != EnforcementOk
    requires ValidMeasurement(obs.peakRssMb)
    requires ValidMeasurement(obs.combinedOutputBytes)
    ensures ghost var verdict: ResourceVerdict := DecideAs(outcome, budget, phase, obs); if verdict.outcome == EnforcementOk then (TimeCeilingForPhase(budget.time, phase) == 0 || obs.wallMs <= TimeCeilingForPhase(budget.time, phase)) && (MemoryCeilingForPhase(budget.memory, phase) == 0 || (obs.peakRssMb.status.MeasurementComplete? && obs.peakRssMb.value.Some? && obs.peakRssMb.value.value <= MemoryCeilingForPhase(budget.memory, phase))) && (budget.maxOutputMb == 0 || (obs.combinedOutputBytes.status.MeasurementComplete? && obs.combinedOutputBytes.value.Some? && BytesToMegabytes(obs.combinedOutputBytes.value.value) <= budget.maxOutputMb)) else verdict.dimension.Some? && verdict.ceiling.Some? && verdict.ceiling.value == LimitForDimension(budget, phase, verdict.dimension.value) && verdict.ceiling.value > 0 && if verdict.observed.None? then (verdict.dimension.value == MemoryDimension && !obs.peakRssMb.status.MeasurementComplete?) || (verdict.dimension.value == OutputDimension && !obs.combinedOutputBytes.status.MeasurementComplete?) else verdict.observed.value > verdict.ceiling.value && verdict.observed == ObservedForDimension(obs, verdict.dimension.value)
    decreases outcome, budget, phase, obs
  {
    ghost var dimensions := ViolatedDimensions(budget, phase, obs);
    if |dimensions| == 0 {
    } else {
      assert DimensionViolated(budget, phase, obs, dimensions[0]);
      if dimensions[0] == MemoryDimension {
        if RequiredMemoryMeasurementFailed(budget, phase, obs) {
          assert !obs.peakRssMb.status.MeasurementComplete?;
        } else {
          assert MemoryBreached(budget, phase, obs);
        }
      } else if dimensions[0] == OutputDimension {
        if RequiredOutputMeasurementFailed(budget, obs) {
          assert !obs.combinedOutputBytes.status.MeasurementComplete?;
        } else {
          assert OutputBreached(budget, obs);
        }
      }
    }
  }

  function MaxValue(left: Option<nat>, right: Option<nat>): Option<nat>
    decreases left, right
  {
    if left.None? then
      right
    else if right.None? then
      left
    else
      Some(if left.value >= right.value then left.value else right.value)
  }

  function AddValue(left: Option<nat>, right: Option<nat>): Option<nat>
    decreases left, right
  {
    if left.None? then
      right
    else if right.None? then
      left
    else
      Some(left.value + right.value)
  }

  function AggregateStatus(left: MeasurementStatus, right: MeasurementStatus, value: Option<nat>): MeasurementStatus
    decreases left, right, value
  {
    if left.MeasurementComplete? && right.MeasurementComplete? then
      MeasurementComplete
    else if left.MeasurementNotRequested? && right.MeasurementNotRequested? then
      MeasurementNotRequested
    else if value.Some? then
      MeasurementPartial(""provider aggregate contains incomplete measurements"")
    else
      MeasurementUnavailable(""provider aggregate measurements unavailable"")
  }

  function MergeMaxMeasurement(left: ResourceMeasurement, right: ResourceMeasurement): ResourceMeasurement
    requires ValidMeasurement(left) && ValidMeasurement(right)
    ensures ValidMeasurement(MergeMaxMeasurement(left, right))
    decreases left, right
  {
    var value: Option<nat> := MaxValue(left.value, right.value);
    ResourceMeasurement(value, AggregateStatus(left.status, right.status, value))
  }

  function MergeSumMeasurement(left: ResourceMeasurement, right: ResourceMeasurement): ResourceMeasurement
    requires ValidMeasurement(left) && ValidMeasurement(right)
    ensures ValidMeasurement(MergeSumMeasurement(left, right))
    decreases left, right
  {
    var value: Option<nat> := AddValue(left.value, right.value);
    ResourceMeasurement(value, AggregateStatus(left.status, right.status, value))
  }

  function MergeObservations(left: ResourceObservation, right: ResourceObservation): ResourceObservation
    requires ValidMeasurement(left.peakRssMb) && ValidMeasurement(right.peakRssMb)
    requires ValidMeasurement(left.combinedOutputBytes) && ValidMeasurement(right.combinedOutputBytes)
    decreases left, right
  {
    ResourceObservation(if left.wallMs >= right.wallMs then left.wallMs else right.wallMs, MergeMaxMeasurement(left.peakRssMb, right.peakRssMb), MergeSumMeasurement(left.combinedOutputBytes, right.combinedOutputBytes))
  }

  function OutcomeRank(outcome: EnforcementOutcome): nat
    decreases outcome
  {
    if outcome == EnforcementOk then
      0
    else if outcome == EnforcementFail then
      1
    else
      2
  }

  function DominantOutcome(prior: EnforcementOutcome, candidate: EnforcementOutcome): EnforcementOutcome
    decreases prior, candidate
  {
    if OutcomeRank(prior) >= OutcomeRank(candidate) then
      prior
    else
      candidate
  }

  lemma UnknownUsesCold(budget: ResourceCeilings)
    ensures TimeCeilingForPhase(budget.time, Unknown) == budget.time.coldMs
    ensures MemoryCeilingForPhase(budget.memory, Unknown) == budget.memory.coldMb
    decreases budget
  {
  }

  lemma PhaseSelectionIsTotal(state: CacheHostPhaseState)
    ensures RequestedPhaseFor(state) == Warm || RequestedPhaseFor(state) == Cold || RequestedPhaseFor(state) == Unknown
    decreases state
  {
  }

  lemma EveryViolationIsPostHocFailure(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    requires |ViolatedDimensions(budget, phase, obs)| > 0
    ensures DecidePostHoc(budget, phase, obs).outcome == EnforcementFail
    decreases budget, phase, obs
  {
  }

  lemma EveryViolationIsInFlightKill(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    requires |ViolatedDimensions(budget, phase, obs)| > 0
    ensures DecideInFlight(budget, phase, obs).outcome == EnforcementKill
    decreases budget, phase, obs
  {
  }

  lemma PostHocNeverKills(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    ensures DecidePostHoc(budget, phase, obs).outcome != EnforcementKill
    decreases budget, phase, obs
  {
  }

  lemma InFlightNeverFails(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    ensures DecideInFlight(budget, phase, obs).outcome != EnforcementFail
    decreases budget, phase, obs
  {
  }

  lemma DecisionsUseEffectivePhase(budget: ResourceCeilings, phase: ExecutionPhase, obs: ResourceObservation)
    ensures DecidePostHoc(budget, phase, obs).phase == EffectivePhase(phase)
    ensures DecideInFlight(budget, phase, obs).phase == EffectivePhase(phase)
    decreases budget, phase, obs
  {
  }

  lemma RequiredUnavailableMemoryFailsClosed(budget: ResourceCeilings, phase: ExecutionPhase, wallMs: nat, outputBytes: nat)
    requires MemoryMeasurementRequired(budget, phase)
    requires !TimeBreached(budget, phase, ResourceObservation(wallMs, UnavailableMeasurement(""rss unavailable""), CompleteMeasurement(outputBytes)))
    ensures DecidePostHoc(budget, phase, ResourceObservation(wallMs, UnavailableMeasurement(""rss unavailable""), CompleteMeasurement(outputBytes))).outcome == EnforcementFail
    ensures DecideInFlight(budget, phase, ResourceObservation(wallMs, UnavailableMeasurement(""rss unavailable""), CompleteMeasurement(outputBytes))).outcome == EnforcementKill
    decreases budget, phase, wallMs, outputBytes
  {
  }

  lemma OptionalUnavailableMemoryMaySucceed(budget: ResourceCeilings, phase: ExecutionPhase, wallMs: nat, outputBytes: nat)
    requires !MemoryMeasurementRequired(budget, phase)
    requires !TimeBreached(budget, phase, ResourceObservation(wallMs, NotRequestedMeasurement(), CompleteMeasurement(outputBytes)))
    requires !OutputBreached(budget, ResourceObservation(wallMs, NotRequestedMeasurement(), CompleteMeasurement(outputBytes)))
    ensures DecidePostHoc(budget, phase, ResourceObservation(wallMs, NotRequestedMeasurement(), CompleteMeasurement(outputBytes))).outcome == EnforcementOk
    decreases budget, phase, wallMs, outputBytes
  {
  }

  lemma FailureCannotNarrowToSuccess(prior: EnforcementOutcome, candidate: EnforcementOutcome)
    requires prior != EnforcementOk
    ensures DominantOutcome(prior, candidate) != EnforcementOk
    decreases prior, candidate
  {
  }

  lemma TypedAggregationRetainsObservedValues()
    ensures forall v: nat, s: string {:trigger Some(v), UnavailableMeasurement(s)} {:trigger UnavailableMeasurement(s), CompleteMeasurement(v)} :: MergeMaxMeasurement(CompleteMeasurement(v), UnavailableMeasurement(s)).value == Some(v) && MergeMaxMeasurement(CompleteMeasurement(v), UnavailableMeasurement(s)).status.MeasurementPartial? && MergeSumMeasurement(CompleteMeasurement(v), UnavailableMeasurement(s)).value == Some(v) && MergeSumMeasurement(CompleteMeasurement(v), UnavailableMeasurement(s)).status.MeasurementPartial?
  {
    ghost var partialRss := MergeMaxMeasurement(CompleteMeasurement(10), UnavailableMeasurement(""provider missing""));
    assert partialRss.value == Some(10);
    assert partialRss.status.MeasurementPartial?;
    ghost var partialOutput := MergeSumMeasurement(CompleteMeasurement(7), UnavailableMeasurement(""provider missing""));
    assert partialOutput.value == Some(7);
    assert partialOutput.status.MeasurementPartial?;
  }

  lemma AllViolationVectorsForPhase(phase: ExecutionPhase)
    ensures exists budget: ResourceCeilings, obs: ResourceObservation {:trigger ViolatedDimensions(budget, phase, obs)} :: ViolatedDimensions(budget, phase, obs) == [TimeDimension]
    ensures exists budget: ResourceCeilings, obs: ResourceObservation {:trigger ViolatedDimensions(budget, phase, obs)} :: ViolatedDimensions(budget, phase, obs) == [MemoryDimension]
    ensures exists budget: ResourceCeilings, obs: ResourceObservation {:trigger ViolatedDimensions(budget, phase, obs)} :: ViolatedDimensions(budget, phase, obs) == [OutputDimension]
    ensures exists budget: ResourceCeilings, obs: ResourceObservation {:trigger ViolatedDimensions(budget, phase, obs)} :: ViolatedDimensions(budget, phase, obs) == [TimeDimension, MemoryDimension, OutputDimension]
    decreases phase
  {
    ghost var budget := ResourceCeilings(PhaseTimeCeilings(10, 10), PhaseMemoryCeilings(20, 20), 30);
    ghost var timeOnly := ResourceObservation(11, CompleteMeasurement(20), CompleteMeasurement(30 * 1024 * 1024));
    ghost var memoryOnly := ResourceObservation(10, CompleteMeasurement(21), CompleteMeasurement(30 * 1024 * 1024));
    ghost var outputOnly := ResourceObservation(10, CompleteMeasurement(20), CompleteMeasurement(30 * 1024 * 1024 + 1));
    ghost var simultaneous := ResourceObservation(11, CompleteMeasurement(21), CompleteMeasurement(30 * 1024 * 1024 + 1));
    ghost var missingMemory := ResourceObservation(10, UnavailableMeasurement(""rss unavailable""), CompleteMeasurement(30 * 1024 * 1024));
    assert ViolatedDimensions(budget, phase, timeOnly) == [TimeDimension];
    assert ViolatedDimensions(budget, phase, memoryOnly) == [MemoryDimension];
    assert ViolatedDimensions(budget, phase, outputOnly) == [OutputDimension];
    assert ViolatedDimensions(budget, phase, simultaneous) == [TimeDimension, MemoryDimension, OutputDimension];
    assert ViolatedDimensions(budget, phase, missingMemory) == [MemoryDimension];
    assert DecidePostHoc(budget, phase, simultaneous).outcome == EnforcementFail;
    assert DecideInFlight(budget, phase, simultaneous).outcome == EnforcementKill;
    assert DecidePostHoc(budget, phase, missingMemory).outcome == EnforcementFail;
    assert DecideInFlight(budget, phase, missingMemory).outcome == EnforcementKill;
  }

  lemma NonVacuousBudgetWitness()
    ensures exists obs: ResourceObservation {:trigger DecideInFlight(DefaultResourceCeilings, Warm, obs)} :: DecideInFlight(DefaultResourceCeilings, Warm, obs).outcome == EnforcementKill
    ensures exists obs: ResourceObservation {:trigger DecidePostHoc(DefaultResourceCeilings, Cold, obs)} :: DecidePostHoc(DefaultResourceCeilings, Cold, obs).outcome == EnforcementFail
    ensures exists st: CacheHostPhaseState {:trigger RequestedPhaseFor(st)} :: RequestedPhaseFor(st) == Warm
    ensures exists st: CacheHostPhaseState {:trigger RequestedPhaseFor(st)} :: RequestedPhaseFor(st) == Cold
    ensures exists st: CacheHostPhaseState {:trigger RequestedPhaseFor(st)} :: RequestedPhaseFor(st) == Unknown
  {
    ghost var b := DefaultResourceCeilings;
    assert DecideInFlight(b, Warm, ResourceObservation(5001, CompleteMeasurement(1), CompleteMeasurement(0))).outcome == EnforcementKill;
    assert DecidePostHoc(b, Cold, ResourceObservation(30001, CompleteMeasurement(1), CompleteMeasurement(0))).outcome == EnforcementFail;
    assert RequestedPhaseFor(HostPhaseUnavailable) == Unknown;
    assert RequestedPhaseFor(HostPhaseKnown(7, None)) == Cold;
    assert RequestedPhaseFor(HostPhaseKnown(7, Some(7))) == Warm;
  }

  import opened ConfluxContract

  datatype ExecutionPhase = Warm | Cold | Unknown

  datatype PhaseTimeCeilings = PhaseTimeCeilings(warmMs: nat, coldMs: nat)

  datatype PhaseMemoryCeilings = PhaseMemoryCeilings(warmMb: nat, coldMb: nat)

  datatype ResourceCeilings = ResourceCeilings(time: PhaseTimeCeilings, memory: PhaseMemoryCeilings, maxOutputMb: nat)

  datatype MeasurementStatus = MeasurementComplete | MeasurementNotRequested | MeasurementPartial(reason: string) | MeasurementUnavailable(reason: string)

  datatype ResourceMeasurement = ResourceMeasurement(value: Option<nat>, status: MeasurementStatus)

  datatype ResourceObservation = ResourceObservation(wallMs: nat, peakRssMb: ResourceMeasurement, combinedOutputBytes: ResourceMeasurement)

  datatype ResourceDimension = TimeDimension | MemoryDimension | OutputDimension

  datatype EnforcementOutcome = EnforcementOk | EnforcementFail | EnforcementKill

  datatype ResourceVerdict = ResourceVerdict(outcome: EnforcementOutcome, dimension: Option<ResourceDimension>, phase: ExecutionPhase, ceiling: Option<nat>, observed: Option<nat>, reason: string)

  datatype CacheHostPhaseState = HostPhaseUnavailable | HostPhaseKnown(hostGeneration: nat, cachedGeneration: Option<nat>)
}

module ConfluxSupervisedOperationResult {
  const SupervisedOperationResultSchemaVersion: nat := 1
  const V1MaxSafeInteger: nat := 9007199254740991
  const V1MinSafeInteger: int := -9007199254740991

  predicate V1WireNat(value: nat)
    decreases value
  {
    value <= V1MaxSafeInteger
  }

  predicate V1WireInt(value: int)
    decreases value
  {
    V1MinSafeInteger <= value <= V1MaxSafeInteger
  }

  predicate V1WireOptionalNat(value: CC.Option<nat>)
    decreases value
  {
    value.None? || V1WireNat(value.value)
  }

  predicate V1BudgetSafeForPhase(budget: RB.ResourceCeilings, phase: RB.ExecutionPhase)
    decreases budget, phase
  {
    V1WireNat(RB.TimeCeilingForPhase(budget.time, phase)) &&
    V1WireNat(RB.MemoryCeilingForPhase(budget.memory, phase)) &&
    V1WireNat(budget.maxOutputMb)
  }

  function InclusiveWallMs(timing: TimingCoverage): nat
    decreases timing
  {
    if timing.completedMs >= timing.startedMs then
      timing.completedMs - timing.startedMs
    else
      0
  }

  function ClampCoverage(inclusiveMs: nat, unionMs: nat): nat
    decreases inclusiveMs, unionMs
  {
    if unionMs <= inclusiveMs then
      unionMs
    else
      inclusiveMs
  }

  function ExclusiveWallMs(timing: TimingCoverage): nat
    decreases timing
  {
    InclusiveWallMs(timing) - ClampCoverage(InclusiveWallMs(timing), timing.childUnionMs)
  }

  function GapWallMs(timing: TimingCoverage): nat
    decreases timing
  {
    InclusiveWallMs(timing) - ClampCoverage(InclusiveWallMs(timing), timing.observedUnionMs)
  }

  function ExpandBudget(budget: RB.ResourceCeilings, requestedPhase: RB.ExecutionPhase): ExpandedResourceBudgetV1
    decreases budget, requestedPhase
  {
    ExpandedResourceBudgetV1(RB.TimeCeilingForPhase(budget.time, requestedPhase), RB.MemoryCeilingForPhase(budget.memory, requestedPhase), budget.maxOutputMb)
  }

  function StatusKind(status: RB.MeasurementStatus): nat
    decreases status
  {
    if status.MeasurementComplete? then
      0
    else if status.MeasurementPartial? then
      1
    else if status.MeasurementUnavailable? then
      2
    else
      3
  }

  function DerivedObservationStatus(observation: SupervisionObservationV1): nat
    decreases observation
  {
    if observation.peakDescendantRssMb.status.MeasurementComplete? && observation.combinedOutputBytes.status.MeasurementComplete? && observation.processTree.ProcessTreeObserved? then
      0
    else
      1
  }

  predicate VerdictShapeValid(verdict: RB.ResourceVerdict)
    decreases verdict
  {
    (verdict.outcome == RB.EnforcementOk ==>
      verdict.dimension.None? &&
      verdict.ceiling.None? &&
      verdict.observed.None?) &&
    (verdict.outcome != RB.EnforcementOk ==>
      verdict.dimension.Some? &&
      verdict.ceiling.Some? &&
      |verdict.reason| > 0)
  }

  predicate FirstBreachCoherent(result: SupervisedOperationResultV1)
    decreases result
  {
    (result.verdict.outcome == RB.EnforcementOk) == result.supervisionState.SupervisionRunning? &&
    (result.supervisionState.SupervisionTripped? ==>
      result.supervisionState.record.verdict == result.verdict &&
      result.supervisionState.record.verdict.outcome != RB.EnforcementOk &&
      (result.supervisionState.record.measurementFailure ==>
        result.verdict.dimension.Some? &&
        (result.verdict.dimension.value == RB.MemoryDimension || result.verdict.dimension.value == RB.OutputDimension) &&
        result.verdict.observed.None?) &&
      (!result.supervisionState.record.measurementFailure ==>
        result.verdict.observed.Some?))
  }

  predicate RequiredMeasurementsFailClosed(result: SupervisedOperationResultV1)
    decreases result
  {
    (result.expandedCeilings.peakRssMb > 0 &&
    !result.observation.peakDescendantRssMb.status.MeasurementComplete? ==>
      result.verdict.outcome != RB.EnforcementOk &&
      result.wrapperExitCode != 0) &&
    (result.expandedCeilings.combinedOutputMb > 0 &&
    !result.observation.combinedOutputBytes.status.MeasurementComplete? ==>
      result.verdict.outcome != RB.EnforcementOk &&
      result.wrapperExitCode != 0)
  }

  predicate CleanupValid(cleanup: CleanupStatus)
    decreases cleanup
  {
    cleanup.CleanupNotRequired? || (cleanup.CleanupComplete? && cleanup.deadlineMs > 0 && cleanup.elapsedMs <= cleanup.deadlineMs) || (cleanup.CleanupFailed? && cleanup.deadlineMs > 0 && cleanup.elapsedMs <= cleanup.deadlineMs && |cleanup.reason| > 0)
  }

  predicate MeasurementStatusValid(status: RB.MeasurementStatus)
    decreases status
  {
    (!status.MeasurementPartial? && !status.MeasurementUnavailable?) || |status.reason| > 0
  }

  predicate CleanupCoherent(result: SupervisedOperationResultV1)
    decreases result
  {
    if result.cleanup.CleanupNotRequired? then
      result.termination == NoTermination
    else
      result.termination == ProcessTreeTermination && result.cleanup.deadlineMs > 0 && result.cleanup.elapsedMs <= result.cleanup.deadlineMs && (result.cleanup.CleanupComplete? || (result.cleanup.CleanupFailed? && |result.cleanup.reason| > 0))
  }

  function ExpandedLimit(result: SupervisedOperationResultV1, dimension: RB.ResourceDimension): nat
    decreases result, dimension
  {
    if dimension == RB.TimeDimension then
      result.expandedCeilings.timeMs
    else if dimension == RB.MemoryDimension then
      result.expandedCeilings.peakRssMb
    else
      result.expandedCeilings.combinedOutputMb
  }

  predicate NumericBreachReflected(result: SupervisedOperationResultV1, dimension: RB.ResourceDimension, observed: nat)
    decreases result, dimension, observed
  {
    if dimension == RB.TimeDimension then
      observed <= InclusiveWallMs(result.observation.timing)
    else if dimension == RB.MemoryDimension then
      result.observation.peakDescendantRssMb.value.Some? &&
      observed <= result.observation.peakDescendantRssMb.value.value
    else
      result.observation.combinedOutputBytes.value.Some? && observed <= RB.BytesToMegabytes(result.observation.combinedOutputBytes.value.value)
  }

  predicate VerdictBudgetCoherent(result: SupervisedOperationResultV1)
    decreases result
  {
    if result.verdict.outcome == RB.EnforcementOk then
      (result.expandedCeilings.timeMs == 0 || InclusiveWallMs(result.observation.timing) <= result.expandedCeilings.timeMs) &&
      (result.expandedCeilings.peakRssMb == 0 || (result.observation.peakDescendantRssMb.status.MeasurementComplete? && result.observation.peakDescendantRssMb.value.Some? && result.observation.peakDescendantRssMb.value.value <= result.expandedCeilings.peakRssMb)) &&
      (result.expandedCeilings.combinedOutputMb == 0 || (result.observation.combinedOutputBytes.status.MeasurementComplete? && result.observation.combinedOutputBytes.value.Some? && RB.BytesToMegabytes(result.observation.combinedOutputBytes.value.value) <= result.expandedCeilings.combinedOutputMb))
    else
      result.supervisionState.SupervisionTripped? && result.verdict.dimension.Some? && result.verdict.ceiling.Some? && result.verdict.ceiling.value == ExpandedLimit(result, result.verdict.dimension.value) && result.verdict.ceiling.value > 0 && if result.supervisionState.record.measurementFailure then result.verdict.observed.None? && if result.verdict.dimension.value == RB.MemoryDimension then !result.observation.peakDescendantRssMb.status.MeasurementComplete? else result.verdict.dimension.value == RB.OutputDimension && !result.observation.combinedOutputBytes.status.MeasurementComplete? else result.verdict.observed.Some? && result.verdict.observed.value > result.verdict.ceiling.value && NumericBreachReflected(result, result.verdict.dimension.value, result.verdict.observed.value)
  }

  predicate V1WireSafe(result: SupervisedOperationResultV1)
    decreases result
  {
    V1WireNat(result.schemaVersion) &&
    V1WireNat(result.expandedCeilings.timeMs) &&
    V1WireNat(result.expandedCeilings.peakRssMb) &&
    V1WireNat(result.expandedCeilings.combinedOutputMb) &&
    V1WireNat(result.observation.timing.startedMs) &&
    V1WireNat(result.observation.timing.completedMs) &&
    V1WireNat(result.observation.timing.childUnionMs) &&
    V1WireNat(result.observation.timing.observedUnionMs) &&
    V1WireOptionalNat(result.observation.peakDescendantRssMb.value) &&
    V1WireOptionalNat(result.observation.combinedOutputBytes.value) &&
    V1WireOptionalNat(result.verdict.ceiling) &&
    V1WireOptionalNat(result.verdict.observed) &&
    (if result.supervisionState.SupervisionRunning? then V1WireNat(result.supervisionState.samplesSeen) else result.supervisionState.record.sampleIndex < V1MaxSafeInteger) &&
    (if result.cleanup.CleanupNotRequired? then true else V1WireNat(result.cleanup.elapsedMs) && V1WireNat(result.cleanup.deadlineMs)) &&
    (result.exit.ExitNotObserved? || V1WireInt(result.exit.code)) &&
    V1WireInt(result.wrapperExitCode)
  }

  predicate ValidV1(result: SupervisedOperationResultV1)
    decreases result
  {
    result.schemaVersion == SupervisedOperationResultSchemaVersion &&
    V1WireSafe(result) &&
    |result.policyId| > 0 &&
    result.effectivePhase == RB.EffectivePhase(result.requestedPhase) &&
    result.observation.timing.completedMs >= result.observation.timing.startedMs &&
    RB.ValidMeasurement(result.observation.peakDescendantRssMb) &&
    RB.ValidMeasurement(result.observation.combinedOutputBytes) &&
    MeasurementStatusValid(result.observationStatus) &&
    StatusKind(result.observationStatus) == DerivedObservationStatus(result.observation) &&
    (result.observation.processTree.ProcessTreeObserved? ==>
      result.observation.peakDescendantRssMb.status.MeasurementComplete?) &&
    (result.observation.processTree.ProcessTreeUnavailable? ==>
      !result.observation.peakDescendantRssMb.status.MeasurementComplete? &&
      |result.observation.processTree.reason| > 0) &&
    result.verdict.phase == result.effectivePhase &&
    VerdictShapeValid(result.verdict) &&
    result.reason == result.verdict.reason &&
    FirstBreachCoherent(result) &&
    RequiredMeasurementsFailClosed(result) &&
    VerdictBudgetCoherent(result) &&
    CleanupValid(result.cleanup) &&
    (result.verdict.outcome == RB.EnforcementOk ==>
      result.enforcement == NoEnforcement &&
      result.termination == NoTermination &&
      (result.exit.ExitObserved? ==>
        result.wrapperExitCode == result.exit.code)) &&
    (result.verdict.outcome == RB.EnforcementFail ==>
      result.enforcement == PostHocFailure &&
      result.termination == NoTermination &&
      result.wrapperExitCode != 0) &&
    (result.verdict.outcome == RB.EnforcementKill ==>
      result.enforcement == InFlightProcessTreeTermination &&
      result.termination == ProcessTreeTermination &&
      result.wrapperExitCode != 0) &&
    CleanupCoherent(result)
  }

  predicate V1ReaderAccepts(schemaVersion: nat, requiredV1FieldsPresent: bool, requiredV1MeaningsUnchanged: bool)
    decreases schemaVersion, requiredV1FieldsPresent, requiredV1MeaningsUnchanged
  {
    schemaVersion == SupervisedOperationResultSchemaVersion &&
    requiredV1FieldsPresent &&
    requiredV1MeaningsUnchanged
  }

  function PreserveProviderOutcome(provider: RB.EnforcementOutcome, consumerCandidate: RB.EnforcementOutcome): RB.EnforcementOutcome
    decreases provider, consumerCandidate
  {
    RB.DominantOutcome(provider, consumerCandidate)
  }

  lemma TimingPartitionsAreBounded(timing: TimingCoverage)
    ensures ExclusiveWallMs(timing) <= InclusiveWallMs(timing)
    ensures GapWallMs(timing) <= InclusiveWallMs(timing)
    decreases timing
  {
  }

  lemma RequiredUnavailableRssCannotBeSuccess(result: SupervisedOperationResultV1)
    requires ValidV1(result)
    requires result.expandedCeilings.peakRssMb > 0
    requires !result.observation.peakDescendantRssMb.status.MeasurementComplete?
    ensures result.verdict.outcome != RB.EnforcementOk
    ensures result.wrapperExitCode != 0
    decreases result
  {
  }

  lemma FirstBreachIsResultAuthority(result: SupervisedOperationResultV1)
    requires ValidV1(result)
    requires result.supervisionState.SupervisionTripped?
    ensures result.supervisionState.record.verdict == result.verdict
    ensures result.verdict.outcome != RB.EnforcementOk
    decreases result
  {
  }

  lemma ConsumerCannotNarrowFailure(result: SupervisedOperationResultV1, candidate: RB.EnforcementOutcome)
    requires result.verdict.outcome != RB.EnforcementOk
    ensures PreserveProviderOutcome(result.verdict.outcome, candidate) != RB.EnforcementOk
    decreases result, candidate
  {
    RB.FailureCannotNarrowToSuccess(result.verdict.outcome, candidate);
  }

  import CC = ConfluxContract

  import RB = ConfluxResourceCeilings

  datatype TimingCoverage = TimingCoverage(startedMs: nat, completedMs: nat, childUnionMs: nat, observedUnionMs: nat)

  datatype ExpandedResourceBudgetV1 = ExpandedResourceBudgetV1(timeMs: nat, peakRssMb: nat, combinedOutputMb: nat)

  datatype ProcessTreeStatus = ProcessTreeObserved | ProcessTreeUnavailable(reason: string)

  datatype CleanupStatus = CleanupNotRequired | CleanupComplete(elapsedMs: nat, deadlineMs: nat) | CleanupFailed(elapsedMs: nat, deadlineMs: nat, reason: string)

  datatype ExitStatus = ExitNotObserved | ExitObserved(code: int)

  datatype EnforcementStatus = NoEnforcement | PostHocFailure | InFlightProcessTreeTermination

  datatype TerminationScope = NoTermination | ProcessTreeTermination

  datatype SupervisionObservationV1 = SupervisionObservationV1(timing: TimingCoverage, peakDescendantRssMb: RB.ResourceMeasurement, combinedOutputBytes: RB.ResourceMeasurement, processTree: ProcessTreeStatus)

  datatype FirstBreachV1 = FirstBreachV1(sampleIndex: nat, verdict: RB.ResourceVerdict, measurementFailure: bool)

  datatype SupervisionState = SupervisionRunning(samplesSeen: nat) | SupervisionTripped(record: FirstBreachV1)

  datatype SupervisedOperationResultV1 = SupervisedOperationResultV1(schemaVersion: nat, policyId: string, requestedPhase: RB.ExecutionPhase, effectivePhase: RB.ExecutionPhase, expandedCeilings: ExpandedResourceBudgetV1, observationStatus: RB.MeasurementStatus, observation: SupervisionObservationV1, supervisionState: SupervisionState, cleanup: CleanupStatus, exit: ExitStatus, enforcement: EnforcementStatus, termination: TerminationScope, wrapperExitCode: int, reason: string, verdict: RB.ResourceVerdict)
}

module ConfluxOperators {
  function Map<A, B>(f: A -> B, xs: seq<A>): seq<B>
    decreases xs
  {
    seq(|xs|, (i: int) requires 0 <= i < |xs| => f(xs[i]))
  }

  function Filter<A>(p: A -> bool, xs: seq<A>): seq<A>
    decreases |xs|
  {
    if |xs| == 0 then
      []
    else
      (if p(xs[0]) then [xs[0]] else []) + Filter(p, xs[1..])
  }

  function MapFold<A, B, S>(f: A -> B, r: Reducer<S, B>, init: S, xs: seq<A>): S
    decreases xs
  {
    Fold(r, init, Map(f, xs))
  }

  lemma MapPreservesLength<A, B>(f: A -> B, xs: seq<A>)
    ensures |Map(f, xs)| == |xs|
    decreases xs
  {
  }

  import opened ConfluxContract
}

module ConfluxTree {
  function RoseMap<A, B>(f: A -> B, t: Rose<A>): Rose<B>
    decreases t, 1
  {
    Rose(f(t.value), MapChildren(f, t.children))
  }

  function MapChildren<A, B>(f: A -> B, ts: seq<Rose<A>>): seq<Rose<B>>
    decreases ts, 0
  {
    if |ts| == 0 then
      []
    else
      [RoseMap(f, ts[0])] + MapChildren(f, ts[1..])
  }

  lemma /*{:_inductionTrigger MapChildren(f, ts)}*/ /*{:_induction ts}*/ MapChildrenLen<A, B>(f: A -> B, ts: seq<Rose<A>>)
    ensures |MapChildren(f, ts)| == |ts|
    decreases ts
  {
    if |ts| == 0 {
    } else {
      MapChildrenLen(f, ts[1..]);
    }
  }

  lemma RoseMapIdentity<T>(t: Rose<T>)
    ensures RoseMap((x: T) => x, t) == t
    decreases t
  {
    IdChildren(t.children);
  }

  lemma IdChildren<T>(ts: seq<Rose<T>>)
    ensures MapChildren((x: T) => x, ts) == ts
    decreases ts
  {
    if |ts| == 0 {
    } else {
      RoseMapIdentity(ts[0]);
      IdChildren(ts[1..]);
    }
  }

  lemma /*{:_inductionTrigger RoseMap(f, t)}*/ /*{:_induction t}*/ RoseMapCompose<A, B, C>(f: A -> B, g: B -> C, t: Rose<A>)
    ensures RoseMap(g, RoseMap(f, t)) == RoseMap((x: A) => g(f(x)), t)
    decreases t
  {
    ComposeChildren(f, g, t.children);
  }

  lemma /*{:_inductionTrigger MapChildren(f, ts)}*/ /*{:_induction ts}*/ ComposeChildren<A, B, C>(f: A -> B, g: B -> C, ts: seq<Rose<A>>)
    ensures MapChildren(g, MapChildren(f, ts)) == MapChildren((x: A) => g(f(x)), ts)
    decreases ts
  {
    if |ts| == 0 {
    } else {
      RoseMapCompose(f, g, ts[0]);
      ComposeChildren(f, g, ts[1..]);
    }
  }

  function Dbl(x: int): int
    decreases x
  {
    x * 2
  }

  lemma RoseMapWitness()
    ensures exists t: Rose<int> {:trigger RoseMap(Dbl, t)} :: RoseMap(Dbl, t) == Rose(2, [Rose(4, [])])
  {
    ghost var t := Rose(1, [Rose(2, [])]);
    assert RoseMap(Dbl, t) == Rose(2, [Rose(4, [])]);
  }

  datatype Rose<T> = Rose(value: T, children: seq<Rose<T>>)
}

module ConfluxMerge {
  function Merge<SA, SB, A, B>(rA: Reducer<SA, A>, rB: Reducer<SB, B>): Reducer<(SA, SB), Either<A, B>>
  {
    (s: (SA, SB), e: Either<A, B>) => match e case Left(a) => (rA(s.0, a), s.1) case Right(b) => (s.0, rB(s.1, b))
  }

  lemma MergeLeftDrivesA<SA, SB, A, B>(rA: Reducer<SA, A>, rB: Reducer<SB, B>, s: (SA, SB), a: A)
    ensures Merge(rA, rB)(s, Left(a)) == (rA(s.0, a), s.1)
    decreases s
  {
  }

  lemma MergeRightDrivesB<SA, SB, A, B>(rA: Reducer<SA, A>, rB: Reducer<SB, B>, s: (SA, SB), b: B)
    ensures Merge(rA, rB)(s, Right(b)) == (s.0, rB(s.1, b))
    decreases s
  {
  }

  lemma MergeWitness()
    ensures exists rA: Reducer<int, int>, rB: Reducer<int, int>, xs: seq<Either<int, int>> {:trigger Fold(Merge(rA, rB), (0, 1), xs)} :: Fold(Merge(rA, rB), (0, 1), xs) == (8, 4)
  {
    ghost var rA := (s: int, a: int) => s + a;
    ghost var rB := (s: int, b: int) => s * b;
    assert Merge(rA, rB)((0, 1), Left(3)) == (3, 1);
    assert Merge(rA, rB)((0, 1), Right(4)) == (0, 4);
    assert Fold(Merge(rA, rB), (0, 1), [Left(3), Right(4), Left(5)]) == (8, 4);
  }

  import opened ConfluxContract

  datatype Either<A, B> = Left(l: A) | Right(r: B)
}

module ConfluxRoute {
  function Route<K, S, A>(keyOf: A -> K, r: Reducer<S, A>, empty: S): Reducer<map<K, S>, A>
  {
    (m: map<K, S>, a: A) => var k: K := keyOf(a); m[k := r(if k in m then m[k] else empty, a)]
  }

  lemma RouteAddsKey<K, S, A>(keyOf: A -> K, r: Reducer<S, A>, empty: S, m: map<K, S>, a: A)
    ensures keyOf(a) in Route(keyOf, r, empty)(m, a)
    decreases m
  {
  }

  lemma RouteIsolates<K, S, A>(keyOf: A -> K, r: Reducer<S, A>, empty: S, m: map<K, S>, a: A, k2: K)
    requires k2 != keyOf(a) && k2 in m
    ensures Route(keyOf, r, empty)(m, a)[k2] == m[k2]
    decreases m
  {
  }

  lemma RouteWitness()
    ensures exists keyOf: int -> int, r: Reducer<int, int> {:trigger Route(keyOf, r, 0)} :: Route(keyOf, r, 0)(Route(keyOf, r, 0)(Route(keyOf, r, 0)(map[], 3), 5), 4) == map[1 := 8, 0 := 4]
  {
    ghost var keyOf := (a: int) => a % 2;
    ghost var r := (s: int, a: int) => s + a;
    ghost var m1 := Route(keyOf, r, 0)(map[], 3);
    assert m1 == map[1 := 3];
    ghost var m2 := Route(keyOf, r, 0)(m1, 5);
    assert m2 == map[1 := 8];
    ghost var m3 := Route(keyOf, r, 0)(m2, 4);
    assert m3 == map[1 := 8, 0 := 4];
    assert Route(keyOf, r, 0)(Route(keyOf, r, 0)(Route(keyOf, r, 0)(map[], 3), 5), 4) == map[1 := 8, 0 := 4];
  }

  function GuardedRoute<K, S, A>(keyOf: A -> K, guard: (Option<S>, A) -> Option<S>): Reducer<map<K, S>, A>
  {
    (m: map<K, S>, a: A) => var k: K := keyOf(a); var cur: Option<S> := if k in m then Some(m[k]) else None; match guard(cur, a) case None() => m case Some(s2) => m[k := s2]
  }

  lemma GuardedRouteDeclineUnchanged<K, S, A>(keyOf: A -> K, guard: (Option<S>, A) -> Option<S>, m: map<K, S>, a: A)
    requires guard(if keyOf(a) in m then Some(m[keyOf(a)]) else None, a) == None
    ensures GuardedRoute(keyOf, guard)(m, a) == m
    decreases m
  {
  }

  lemma GuardedRouteIsolates<K, S, A>(keyOf: A -> K, guard: (Option<S>, A) -> Option<S>, m: map<K, S>, a: A, k2: K)
    requires k2 != keyOf(a) && k2 in m
    ensures GuardedRoute(keyOf, guard)(m, a)[k2] == m[k2]
    decreases m
  {
  }

  lemma RouteIsAlwaysAcceptGuarded<K, S, A>(keyOf: A -> K, r: Reducer<S, A>, empty: S, m: map<K, S>, a: A)
    ensures Route(keyOf, r, empty)(m, a) == GuardedRoute(keyOf, (cur: Option<S>, a2: A) => Some(r(if cur.Some? then cur.value else empty, a2)))(m, a)
    decreases m
  {
  }

  lemma GuardedRouteWitness()
    ensures exists keyOf: int -> int, guard: (Option<int>, int) -> Option<int> {:trigger GuardedRoute(keyOf, guard)} :: GuardedRoute(keyOf, guard)(map[], 7) == map[7 := 70] && GuardedRoute(keyOf, guard)(map[7 := 70], 7) == map[7 := 70]
  {
    ghost var keyOf := (a: int) => a;
    ghost var guard := (cur: Option<int>, a: int) => if cur.None? then Some(a * 10) else None;
    assert GuardedRoute(keyOf, guard)(map[], 7) == map[7 := 70];
    assert GuardedRoute(keyOf, guard)(map[7 := 70], 7) == map[7 := 70];
  }

  import opened ConfluxContract
}

module ConfluxMapValues {
  function MapValues<K, A, B>(f: (K, A) -> B, m: map<K, A>): map<K, B>
    decreases m
  {
    map k: K {:trigger m[k]} {:trigger k in m} | k in m :: f(k, m[k])
  }

  lemma MapValuesKeys<K, A, B>(f: (K, A) -> B, m: map<K, A>)
    ensures MapValues(f, m).Keys == m.Keys
    decreases m
  {
  }

  lemma MapValuesAt<K, A, B>(f: (K, A) -> B, m: map<K, A>, k: K)
    requires k in m
    ensures k in MapValues(f, m) && MapValues(f, m)[k] == f(k, m[k])
    decreases m
  {
  }

  lemma MapValuesIdentity<K, A>(m: map<K, A>)
    ensures MapValues((k: K, a: A) => a, m) == m
    decreases m
  {
  }

  function Times10(k: int, v: int): int
    decreases k, v
  {
    v * 10
  }

  lemma MapValuesWitness()
    ensures MapValues(Times10, map[1 := 2, 3 := 4]) == map[1 := 20, 3 := 40]
    ensures 1 in MapValues(Times10, map[1 := 2, 3 := 4]) && MapValues(Times10, map[1 := 2, 3 := 4])[1] == 20
  {
    assert MapValues(Times10, map[1 := 2, 3 := 4]) == map[1 := 20, 3 := 40];
  }
}

module ConfluxDelimited {
  function Intercalate<E>(sep: E, xss: seq<seq<E>>): seq<E>
    decreases |xss|
  {
    if |xss| == 0 then
      []
    else if |xss| == 1 then
      xss[0]
    else
      xss[0] + [sep] + Intercalate(sep, xss[1..])
  }

  function Flatten<E>(xss: seq<seq<E>>): seq<E>
    decreases |xss|
  {
    if |xss| == 0 then
      []
    else
      xss[0] + Flatten(xss[1..])
  }

  lemma /*{:_inductionTrigger Flatten(xs) + Flatten(ys)}*/ /*{:_inductionTrigger Flatten(xs + ys)}*/ /*{:_induction xs, ys}*/ FlattenConcat<E>(xs: seq<seq<E>>, ys: seq<seq<E>>)
    ensures Flatten(xs + ys) == Flatten(xs) + Flatten(ys)
    decreases |xs|
  {
    if |xs| == 0 {
      assert xs + ys == ys;
    } else {
      assert (xs + ys)[1..] == xs[1..] + ys;
      FlattenConcat(xs[1..], ys);
    }
  }

  function IndexOf<E(==)>(sep: E, xs: seq<E>): nat
    ensures IndexOf(sep, xs) <= |xs|
    ensures IndexOf(sep, xs) < |xs| ==> xs[IndexOf(sep, xs)] == sep
    ensures forall k: int {:trigger xs[k]} :: 0 <= k < IndexOf(sep, xs) ==> xs[k] != sep
    decreases |xs|
  {
    if |xs| == 0 then
      0
    else if xs[0] == sep then
      0
    else
      1 + IndexOf(sep, xs[1..])
  }

  function Split<E(==)>(sep: E, xs: seq<E>): seq<seq<E>>
    ensures |Split(sep, xs)| >= 1
    decreases |xs|
  {
    var i: nat := IndexOf(sep, xs);
    if i == |xs| then
      [xs]
    else
      [xs[..i]] + Split(sep, xs[i + 1..])
  }

  ghost predicate HasNoSep<E>(sep: E, xs: seq<E>)
    decreases xs
  {
    forall i: int {:trigger xs[i]} :: 
      0 <= i < |xs| ==>
        xs[i] != sep
  }

  ghost predicate NoSep<E>(sep: E, xss: seq<seq<E>>)
    decreases xss
  {
    forall j: int {:trigger xss[j]} :: 
      0 <= j < |xss| ==>
        HasNoSep(sep, xss[j])
  }

  lemma /*{:_inductionTrigger |xs|}*/ /*{:_inductionTrigger IndexOf(sep, xs)}*/ /*{:_inductionTrigger HasNoSep(sep, xs)}*/ /*{:_induction xs}*/ NoSepIndexIsEnd<E>(sep: E, xs: seq<E>)
    requires HasNoSep(sep, xs)
    ensures IndexOf(sep, xs) == |xs|
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      assert xs[0] != sep;
      assert HasNoSep(sep, xs[1..]);
      NoSepIndexIsEnd(sep, xs[1..]);
    }
  }

  lemma /*{:_inductionTrigger prefix + [sep] + tail}*/ /*{:_induction prefix, tail}*/ IndexAfterNoSepPrefix<E>(sep: E, prefix: seq<E>, tail: seq<E>)
    requires HasNoSep(sep, prefix)
    ensures IndexOf(sep, prefix + [sep] + tail) == |prefix|
    decreases |prefix|
  {
    ghost var xs := prefix + [sep] + tail;
    if |prefix| == 0 {
      assert xs[0] == sep;
    } else {
      assert xs[0] == prefix[0] != sep;
      assert xs[1..] == prefix[1..] + [sep] + tail;
      IndexAfterNoSepPrefix(sep, prefix[1..], tail);
    }
  }

  lemma /*{:_inductionTrigger Intercalate(sep, xss)}*/ /*{:_inductionTrigger NoSep(sep, xss)}*/ /*{:_inductionTrigger |xss|}*/ /*{:_induction xss}*/ RoundTrip<E>(sep: E, xss: seq<seq<E>>)
    requires |xss| >= 1
    requires NoSep(sep, xss)
    ensures Split(sep, Intercalate(sep, xss)) == xss
    decreases |xss|
  {
    if |xss| == 1 {
      assert Intercalate(sep, xss) == xss[0];
      assert HasNoSep(sep, xss[0]);
      NoSepIndexIsEnd(sep, xss[0]);
      assert Split(sep, xss[0]) == [xss[0]];
      assert xss == [xss[0]];
    } else {
      ghost var x0 := xss[0];
      ghost var rest := xss[1..];
      ghost var tail := Intercalate(sep, rest);
      assert Intercalate(sep, xss) == x0 + [sep] + tail;
      assert HasNoSep(sep, x0);
      IndexAfterNoSepPrefix(sep, x0, tail);
      ghost var xs := x0 + [sep] + tail;
      assert IndexOf(sep, xs) == |x0|;
      assert xs[..|x0|] == x0;
      assert xs[|x0| + 1..] == tail;
      RoundTrip(sep, rest);
      assert Split(sep, xs) == [x0] + rest;
      assert [x0] + rest == xss;
    }
  }

  lemma /*{:_inductionTrigger Intercalate(sep, xss)}*/ /*{:_inductionTrigger NoSep(sep, xss)}*/ /*{:_induction xss}*/ ChildCountPreserved<E>(sep: E, xss: seq<seq<E>>)
    requires |xss| >= 1
    requires NoSep(sep, xss)
    ensures |Split(sep, Intercalate(sep, xss))| == |xss|
    decreases xss
  {
    RoundTrip(sep, xss);
  }

  lemma SingletonIsIdentity<E>(sep: E, x: seq<E>)
    ensures Intercalate(sep, [x]) == x
    decreases x
  {
  }

  lemma /*{:_inductionTrigger xss[1..]}*/ /*{:_inductionTrigger xss[0]}*/ /*{:_inductionTrigger |xss|}*/ /*{:_induction xss}*/ IntercalateCons<E>(sep: E, xss: seq<seq<E>>)
    requires |xss| >= 2
    ensures Intercalate(sep, xss) == xss[0] + [sep] + Intercalate(sep, xss[1..])
    decreases xss
  {
  }

  lemma Witness()
    ensures Intercalate(';', [""a"", ""b"", ""c""]) == ""a;b;c""
    ensures Split(';', ""a;b;c"") == [""a"", ""b"", ""c""]
    ensures Intercalate(';', [""solo""]) == ""solo""
  {
    RoundTrip(';', [""a"", ""b"", ""c""]);
  }
}

module ConfluxFixpoint {
  ghost predicate {:opaque} BoundedBy<T(!new)>(succ: set<T> -> set<T>, U: set<T>)
    decreases U
  {
    forall A: set<T> {:trigger succ(A)} :: 
      A <= U ==>
        succ(A) <= U
  }

  ghost predicate {:opaque} MonotoneOn<T(!new)>(succ: set<T> -> set<T>, U: set<T>)
    decreases U
  {
    forall B: set<T>, A: set<T> {:trigger succ(B), succ(A)} {:trigger succ(A), B <= U} :: 
      A <= B <= U ==>
        succ(A) <= succ(B)
  }

  ghost predicate {:opaque} AdditiveOn<T(!new)>(succ: set<T> -> set<T>, U: set<T>)
    decreases U
  {
    forall A: set<T>, B: set<T> {:trigger succ(A) + succ(B)} {:trigger succ(A + B)} {:trigger B <= U, A <= U} :: 
      A <= U &&
      B <= U ==>
        succ(A + B) == succ(A) + succ(B)
  }

  lemma UseBounded<T(!new)>(succ: set<T> -> set<T>, U: set<T>, A: set<T>)
    requires BoundedBy(succ, U) && A <= U
    ensures succ(A) <= U
    decreases U, A
  {
    reveal BoundedBy();
  }

  lemma UseMonotone<T(!new)>(succ: set<T> -> set<T>, U: set<T>, A: set<T>, B: set<T>)
    requires MonotoneOn(succ, U) && A <= B <= U
    ensures succ(A) <= succ(B)
    decreases U, A, B
  {
    reveal MonotoneOn();
  }

  lemma UseAdditive<T(!new)>(succ: set<T> -> set<T>, U: set<T>, A: set<T>, B: set<T>)
    requires AdditiveOn(succ, U) && A <= U && B <= U
    ensures succ(A + B) == succ(A) + succ(B)
    decreases U, A, B
  {
    reveal AdditiveOn();
  }

  lemma AdditiveImpliesMonotone<T(!new)>(succ: set<T> -> set<T>, U: set<T>)
    requires AdditiveOn(succ, U)
    ensures MonotoneOn(succ, U)
    decreases U
  {
    reveal AdditiveOn(), MonotoneOn();
    forall A: set<T>, B: set<T> | A <= B <= U
      ensures succ(A) <= succ(B)
    {
      assert B == A + B;
      assert succ(B) == succ(A) + succ(B);
    }
  }

  function Step<T(!new)>(succ: set<T> -> set<T>, S: set<T>): set<T>
    decreases S
  {
    S + succ(S)
  }

  function Closure<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>): set<T>
    requires S <= U
    requires MonotoneOn(succ, U)
    requires BoundedBy(succ, U)
    decreases U - S
  {
    var next: set<T> := Step(succ, S);
    if next == S then
      S
    else
      assert succ(S) <= U by {
    reveal BoundedBy();
  } assert next <= U; assert S < next; Closure(succ, U, next)
  }

  lemma /*{:_inductionTrigger Closure(succ, U, S)}*/ /*{:_induction U, S}*/ ContainsSeed<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>)
    requires S <= U && MonotoneOn(succ, U) && BoundedBy(succ, U)
    ensures S <= Closure(succ, U, S)
    decreases U - S
  {
    ghost var next := Step(succ, S);
    if next != S {
      UseBounded(succ, U, S);
      assert next <= U;
      assert S < next;
      ContainsSeed(succ, U, next);
    }
  }

  lemma /*{:_inductionTrigger Closure(succ, U, S)}*/ /*{:_induction U, S}*/ ClosureSubsetU<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>)
    requires S <= U && MonotoneOn(succ, U) && BoundedBy(succ, U)
    ensures Closure(succ, U, S) <= U
    decreases U - S
  {
    ghost var next := Step(succ, S);
    if next != S {
      UseBounded(succ, U, S);
      assert next <= U;
      assert S < next;
      ClosureSubsetU(succ, U, next);
    }
  }

  lemma /*{:_inductionTrigger Closure(succ, U, S)}*/ /*{:_inductionTrigger S <= U}*/ /*{:_induction U, S}*/ ClosureClosed<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>)
    requires S <= U && MonotoneOn(succ, U) && BoundedBy(succ, U)
    ensures Step(succ, Closure(succ, U, S)) == Closure(succ, U, S)
    decreases U - S
  {
    ghost var next := Step(succ, S);
    if next != S {
      UseBounded(succ, U, S);
      assert next <= U;
      assert S < next;
      ClosureClosed(succ, U, next);
    }
  }

  lemma /*{:_inductionTrigger Closure(succ, U, S)}*/ /*{:_induction U, S}*/ Least<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>, C: set<T>)
    requires S <= U && MonotoneOn(succ, U) && BoundedBy(succ, U)
    requires S <= C <= U
    requires succ(C) <= C
    ensures Closure(succ, U, S) <= C
    decreases U - S
  {
    ghost var next := Step(succ, S);
    if next != S {
      UseBounded(succ, U, S);
      UseMonotone(succ, U, S, C);
      assert next <= C;
      assert next <= U;
      assert S < next;
      Least(succ, U, next, C);
    }
  }

  lemma /*{:_inductionTrigger Closure(succ, U, B), Closure(succ, U, A)}*/ /*{:_induction U, A, B}*/ ClosureMonotone<T(!new)>(succ: set<T> -> set<T>, U: set<T>, A: set<T>, B: set<T>)
    requires A <= B <= U && MonotoneOn(succ, U) && BoundedBy(succ, U)
    ensures Closure(succ, U, A) <= Closure(succ, U, B)
    decreases U, A, B
  {
    ContainsSeed(succ, U, B);
    ClosureClosed(succ, U, B);
    ClosureSubsetU(succ, U, B);
    Least(succ, U, A, Closure(succ, U, B));
  }

  lemma /*{:_inductionTrigger Step(succ, S), BoundedBy(succ, U)}*/ /*{:_inductionTrigger Step(succ, S), MonotoneOn(succ, U)}*/ /*{:_inductionTrigger succ(S), BoundedBy(succ, U)}*/ /*{:_inductionTrigger succ(S), MonotoneOn(succ, U)}*/ /*{:_induction U, S}*/ ClosureUnroll<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>)
    requires S <= U && MonotoneOn(succ, U) && BoundedBy(succ, U)
    requires succ(S) <= U
    ensures Closure(succ, U, S) == Closure(succ, U, Step(succ, S))
    decreases U, S
  {
    ghost var next := Step(succ, S);
    if next != S {
      assert next <= U;
    }
  }

  lemma /*{:_inductionTrigger Closure(succ, U, S), Closure(succ, U, Sp)}*/ /*{:_inductionTrigger Closure(succ, U, Sp), Step(succ, S)}*/ /*{:_inductionTrigger Closure(succ, U, Sp), succ(S)}*/ /*{:_inductionTrigger Sp <= Step(succ, S), BoundedBy(succ, U)}*/ /*{:_inductionTrigger Sp <= Step(succ, S), MonotoneOn(succ, U)}*/ /*{:_induction U, S, Sp}*/ ClosureSandwich<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>, Sp: set<T>)
    requires S <= U && MonotoneOn(succ, U) && BoundedBy(succ, U)
    requires succ(S) <= U
    requires S <= Sp <= Step(succ, S)
    ensures Closure(succ, U, Sp) == Closure(succ, U, S)
    decreases U, S, Sp
  {
    assert Step(succ, S) <= U;
    ClosureMonotone(succ, U, S, Sp);
    ClosureMonotone(succ, U, Sp, Step(succ, S));
    ClosureUnroll(succ, U, S);
  }

  function Worklist<T(!new)>(succ: set<T> -> set<T>, U: set<T>, frontier: set<T>, visited: set<T>): set<T>
    requires frontier <= U && visited <= U
    requires AdditiveOn(succ, U) && BoundedBy(succ, U)
    decreases U - visited
  {
    var f: set<T> := frontier - visited;
    if f == {} then
      visited
    else
      assert f <= U; assert succ(f) <= U by {
    reveal BoundedBy();
  } assert visited + f <= U; assert visited < visited + f; Worklist(succ, U, succ(f), visited + f)
  }

  lemma /*{:_inductionTrigger Worklist(succ, U, frontier, visited)}*/ /*{:_inductionTrigger frontier - visited, BoundedBy(succ, U)}*/ /*{:_inductionTrigger frontier - visited, AdditiveOn(succ, U)}*/ /*{:_inductionTrigger frontier - visited, MonotoneOn(succ, U)}*/ /*{:_inductionTrigger visited + frontier, BoundedBy(succ, U)}*/ /*{:_inductionTrigger visited + frontier, AdditiveOn(succ, U)}*/ /*{:_inductionTrigger visited + frontier, MonotoneOn(succ, U)}*/ /*{:_induction U, frontier, visited}*/ WlBaseCase<T(!new)>(succ: set<T> -> set<T>, U: set<T>, frontier: set<T>, visited: set<T>)
    requires frontier <= U && visited <= U && MonotoneOn(succ, U) && AdditiveOn(succ, U) && BoundedBy(succ, U)
    requires succ(visited) <= visited + frontier
    requires frontier - visited == {}
    ensures Worklist(succ, U, frontier, visited) == Closure(succ, U, visited + frontier)
    decreases U, frontier, visited
  {
    assert visited + frontier == visited + (frontier - visited);
    assert visited + frontier == visited;
    assert succ(visited) <= visited;
    assert Step(succ, visited) == visited;
  }

  lemma WlChildInvariant<T(!new)>(succ: set<T> -> set<T>, U: set<T>, frontier: set<T>, visited: set<T>, f: set<T>)
    requires frontier <= U && visited <= U && AdditiveOn(succ, U) && BoundedBy(succ, U)
    requires succ(visited) <= visited + frontier
    requires f == frontier - visited && f != {}
    ensures succ(f) <= U && visited + f <= U && visited < visited + f
    ensures succ(visited + f) <= visited + f + succ(f)
    decreases U, frontier, visited, f
  {
    assert f <= U;
    UseBounded(succ, U, f);
    assert visited + f <= U;
    UseAdditive(succ, U, visited, f);
    assert frontier <= visited + f;
    assert succ(visited) <= visited + f;
  }

  lemma /*{:_inductionTrigger succ(f), frontier - visited, BoundedBy(succ, U)}*/ /*{:_inductionTrigger succ(f), frontier - visited, AdditiveOn(succ, U)}*/ /*{:_inductionTrigger succ(f), frontier - visited, MonotoneOn(succ, U)}*/ /*{:_induction U, frontier, visited, f}*/ WlStepEq<T(!new)>(succ: set<T> -> set<T>, U: set<T>, frontier: set<T>, visited: set<T>, f: set<T>)
    requires frontier <= U && visited <= U && MonotoneOn(succ, U) && AdditiveOn(succ, U) && BoundedBy(succ, U)
    requires f == frontier - visited && f != {} && succ(f) <= U && visited + f <= U
    ensures Closure(succ, U, visited + f + succ(f)) == Closure(succ, U, visited + frontier)
    decreases U, frontier, visited, f
  {
    ghost var S := visited + frontier;
    assert visited + f == S;
    assert visited + f + succ(f) == S + succ(f);
    assert f <= S;
    UseBounded(succ, U, S);
    UseMonotone(succ, U, f, S);
    assert S <= S + succ(f) <= Step(succ, S);
    ClosureSandwich(succ, U, S, S + succ(f));
  }

  lemma /*{:_inductionTrigger Worklist(succ, U, frontier, visited)}*/ /*{:_inductionTrigger visited + frontier, BoundedBy(succ, U)}*/ /*{:_inductionTrigger visited + frontier, AdditiveOn(succ, U)}*/ /*{:_inductionTrigger visited + frontier, MonotoneOn(succ, U)}*/ /*{:_induction U, frontier, visited}*/ WorklistIsClosure<T(!new)>(succ: set<T> -> set<T>, U: set<T>, frontier: set<T>, visited: set<T>)
    requires frontier <= U && visited <= U
    requires MonotoneOn(succ, U) && AdditiveOn(succ, U) && BoundedBy(succ, U)
    requires succ(visited) <= visited + frontier
    ensures Worklist(succ, U, frontier, visited) == Closure(succ, U, visited + frontier)
    decreases U - visited
  {
    ghost var f := frontier - visited;
    if f == {} {
      WlBaseCase(succ, U, frontier, visited);
    } else {
      WlChildInvariant(succ, U, frontier, visited, f);
      WorklistIsClosure(succ, U, succ(f), visited + f);
      WlStepEq(succ, U, frontier, visited, f);
    }
  }

  lemma /*{:_inductionTrigger Closure(succ, U, frontier)}*/ /*{:_inductionTrigger Worklist(succ, U, frontier, {})}*/ /*{:_inductionTrigger succ({}) <= frontier, BoundedBy(succ, U)}*/ /*{:_inductionTrigger succ({}) <= frontier, AdditiveOn(succ, U)}*/ /*{:_inductionTrigger succ({}) <= frontier, MonotoneOn(succ, U)}*/ /*{:_inductionTrigger frontier <= U}*/ /*{:_induction U, frontier}*/ WorklistFromEmpty<T(!new)>(succ: set<T> -> set<T>, U: set<T>, frontier: set<T>)
    requires frontier <= U && MonotoneOn(succ, U) && AdditiveOn(succ, U) && BoundedBy(succ, U)
    requires succ({}) <= frontier
    ensures Worklist(succ, U, frontier, {}) == Closure(succ, U, frontier)
    decreases U, frontier
  {
    WorklistIsClosure(succ, U, frontier, {});
    assert {} + frontier == frontier;
  }

  function StepOne(A: set<int>): set<int>
    decreases A
  {
    if 0 in A then
      {1}
    else
      {}
  }

  lemma StepOneAdditive()
    ensures AdditiveOn(StepOne, {0, 1})
  {
    reveal AdditiveOn();
    forall A: set<int>, B: set<int> | A <= {0, 1} && B <= {0, 1}
      ensures StepOne(A + B) == StepOne(A) + StepOne(B)
    {
    }
  }

  lemma StepOneBounded()
    ensures BoundedBy(StepOne, {0, 1})
  {
    reveal BoundedBy();
  }

  lemma Witness()
    ensures exists succ: set<int> -> set<int>, U: set<int>, S: set<int> {:trigger Closure(succ, U, S)} :: S <= U && MonotoneOn(succ, U) && BoundedBy(succ, U) && S < Closure(succ, U, S) && Closure(succ, U, S) == U
  {
    StepOneAdditive();
    StepOneBounded();
    AdditiveImpliesMonotone(StepOne, {0, 1});
    assert Step(StepOne, {0}) == {0, 1};
    assert Step(StepOne, {0, 1}) == {0, 1};
    assert Closure(StepOne, {0, 1}, {0, 1}) == {0, 1};
    assert Closure(StepOne, {0, 1}, {0}) == {0, 1};
    assert {0} <= {0, 1} && MonotoneOn(StepOne, {0, 1}) && BoundedBy(StepOne, {0, 1}) && {0} < Closure(StepOne, {0, 1}, {0}) && Closure(StepOne, {0, 1}, {0}) == {0, 1};
  }

  function ClosureClamp<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>, fuel: nat): set<T>
    decreases fuel
  {
    var next: set<T> := (S + succ(S)) * U;
    if next == S || fuel == 0 then
      S
    else
      ClosureClamp(succ, U, next, fuel - 1)
  }

  function ClosureTotal<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>): set<T>
    decreases U, S
  {
    ClosureClamp(succ, U, S * U, |U|)
  }

  lemma /*{:_inductionTrigger ClosureClamp(succ, U, S, fuel)}*/ /*{:_induction U, S, fuel}*/ ClosureClampSubsetU<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>, fuel: nat)
    requires S <= U
    ensures ClosureClamp(succ, U, S, fuel) <= U
    decreases fuel
  {
    ghost var next := (S + succ(S)) * U;
    if !(next == S || fuel == 0) {
      ClosureClampSubsetU(succ, U, next, fuel - 1);
    }
  }

  lemma ClosureTotalSubsetU<T(!new)>(succ: set<T> -> set<T>, U: set<T>, S: set<T>)
    ensures ClosureTotal(succ, U, S) <= U
    decreases U, S
  {
    ClosureClampSubsetU(succ, U, S * U, |U|);
  }

  function TwoHop(s: set<int>): set<int>
    decreases s
  {
    (if 0 in s then {1} else {}) + if 1 in s then {2} else {}
  }

  lemma ClosureTotalWitness()
    ensures exists succ: set<int> -> set<int>, U: set<int>, S: set<int> {:trigger ClosureTotal(succ, U, S)} :: S < U && ClosureTotal(succ, U, S) == U
  {
    ghost var U := {0, 1, 2};
    assert ClosureClamp(TwoHop, U, {0, 1, 2}, 1) == {0, 1, 2};
    assert ClosureClamp(TwoHop, U, {0, 1}, 2) == {0, 1, 2};
    assert ClosureClamp(TwoHop, U, {0}, 3) == {0, 1, 2};
    assert ClosureTotal(TwoHop, U, {0}) == {0, 1, 2};
    assert {0} < U && ClosureTotal(TwoHop, U, {0}) == U;
  }
}

module ConfluxGenericCodec {
  ghost predicate RoundTrips<J, T(!new)>(c: Codec<J, T>)
    decreases c
  {
    forall t: T {:trigger Some(t)} {:trigger c.encode(t)} :: 
      c.decode(c.encode(t)) == Some(t)
  }

  ghost predicate RoundTripsWhere<J, T(!new)>(c: Codec<J, T>, wf: T -> bool)
    decreases c
  {
    forall t: T {:trigger Some(t)} {:trigger c.encode(t)} {:trigger wf(t)} :: 
      wf(t) ==>
        c.decode(c.encode(t)) == Some(t)
  }

  lemma RoundTripsIsWhereTrue<J, T(!new)>(c: Codec<J, T>)
    requires RoundTrips(c)
    ensures RoundTripsWhere(c, (t: T) => true)
    decreases c
  {
  }

  function IdCodec<J(!new)>(): Codec<J, J>
  {
    Codec((j: J) => j, (j: J) => Some(j))
  }

  lemma IdCodecRoundTrips<J(!new)>()
    ensures RoundTrips(IdCodec<J>())
  {
  }

  function DoubleCodec(): Codec<int, int>
  {
    Codec((n: int) => n + n, (j: int) => if j % 2 == 0 then Some(j / 2) else None)
  }

  lemma DoubleCodecRoundTrips()
    ensures RoundTrips(DoubleCodec())
  {
    forall t: int | true
      ensures DoubleCodec().decode(DoubleCodec().encode(t)) == Some(t)
    {
      assert (t + t) % 2 == 0 && (t + t) / 2 == t;
    }
  }

  datatype Option<T> = None | Some(value: T)

  datatype Codec<!J, !T> = Codec(encode: T -> J, decode: J -> Option<T>)
}

module ConfluxResolve {
  function ResolveLookup<K(==), T>(rk: Option<K>, snapshot: map<K, T>): ResolveVerdict<T>
    decreases rk, snapshot
  {
    match rk
    case None() =>
      NoKeyResolved
    case Some(k) =>
      if k in snapshot then
        Matched(snapshot[k])
      else
        KeyResolvedButAbsent
  }

  lemma NoKeyIffNone<K, T>(rk: Option<K>, snapshot: map<K, T>)
    ensures ResolveLookup(rk, snapshot).NoKeyResolved? <==> rk.None?
    decreases rk, snapshot
  {
  }

  lemma MatchedIffPresent<K, T>(rk: Option<K>, snapshot: map<K, T>)
    ensures ResolveLookup(rk, snapshot).Matched? <==> rk.Some? && rk.value in snapshot
    ensures rk.Some? && rk.value in snapshot ==> ResolveLookup(rk, snapshot).value == snapshot[rk.value]
    decreases rk, snapshot
  {
  }

  lemma AbsentIffResolvedMissing<K, T>(rk: Option<K>, snapshot: map<K, T>)
    ensures ResolveLookup(rk, snapshot).KeyResolvedButAbsent? <==> rk.Some? && rk.value !in snapshot
    decreases rk, snapshot
  {
  }

  lemma ResolveIsolates<K, T>(rk: Option<K>, s1: map<K, T>, s2: map<K, T>)
    requires rk.Some? ==> (rk.value in s1 <==> rk.value in s2) && (rk.value in s1 ==> s1[rk.value] == s2[rk.value])
    ensures ResolveLookup(rk, s1) == ResolveLookup(rk, s2)
    decreases rk, s1, s2
  {
  }

  lemma ResolveWitness()
    ensures exists rk: Option<string>, snap: map<string, int> {:trigger ResolveLookup(rk, snap)} :: ResolveLookup(rk, snap) == NoKeyResolved
    ensures exists rk: Option<string>, snap: map<string, int> {:trigger ResolveLookup(rk, snap)} :: ResolveLookup(rk, snap) == KeyResolvedButAbsent
    ensures exists rk: Option<string>, snap: map<string, int>, v: int {:trigger Matched(v), ResolveLookup(rk, snap)} :: ResolveLookup(rk, snap) == Matched(v)
  {
    ghost var snap := map[""a"" := 10];
    assert ResolveLookup(None, snap) == NoKeyResolved;
    assert ResolveLookup(Some(""b""), snap) == KeyResolvedButAbsent;
    assert ResolveLookup(Some(""a""), snap) == Matched(10);
  }

  datatype Option<K> = None | Some(value: K)

  datatype ResolveVerdict<T> = NoKeyResolved | KeyResolvedButAbsent | Matched(value: T)
}

module ConfluxWatermark {
  ghost predicate Wf(c: Cap)
    decreases c
  {
    c.pos <= c.cap
  }

  function Slack(c: Cap): nat
    requires Wf(c)
    decreases c
  {
    c.cap - c.pos
  }

  function TryAdvance(c: Cap): (Cap, AdvOutcome)
    requires Wf(c)
    decreases c
  {
    if c.pos < c.cap then
      (Cap(c.pos + 1, c.cap), Advanced)
    else
      (c, Declined)
  }

  function AdvanceN(c: Cap, n: nat): Cap
    requires Wf(c) && c.pos + n <= c.cap
    decreases n
  {
    if n == 0 then
      c
    else
      AdvanceN(TryAdvance(c).0, n - 1)
  }

  function Raise(c: Cap, incoming: nat): Cap
    decreases c, incoming
  {
    Cap(c.pos, if incoming >= c.cap then incoming else c.cap)
  }

  lemma WfPreserved(c: Cap)
    requires Wf(c)
    ensures Wf(TryAdvance(c).0)
    decreases c
  {
  }

  lemma NoRegress(c: Cap)
    requires Wf(c)
    ensures TryAdvance(c).0.pos >= c.pos
    decreases c
  {
  }

  lemma SlackShrinks(c: Cap)
    requires Wf(c)
    ensures TryAdvance(c).1.Advanced? ==> Slack(TryAdvance(c).0) < Slack(c)
    decreases c
  {
  }

  lemma DeclineFreezesLoud(c: Cap)
    requires Wf(c)
    ensures c.pos == c.cap ==> TryAdvance(c) == (c, Declined)
    decreases c
  {
  }

  lemma /*{:_inductionTrigger AdvanceN(c, n)}*/ /*{:_induction c, n}*/ AdvanceNExact(c: Cap, n: nat)
    requires Wf(c) && c.pos + n <= c.cap
    ensures AdvanceN(c, n).pos == c.pos + n
    ensures AdvanceN(c, n).cap == c.cap
    decreases n
  {
    if n == 0 {
    } else {
      WfPreserved(c);
      AdvanceNExact(TryAdvance(c).0, n - 1);
    }
  }

  lemma RaiseMonotone(c: Cap, x: nat)
    ensures Raise(c, x).cap >= c.cap && Raise(c, x).pos == c.pos
    decreases c, x
  {
  }

  lemma RaiseStaleNoOp(c: Cap, x: nat)
    requires x <= c.cap
    ensures Raise(c, x) == c
    decreases c, x
  {
  }

  lemma Witness()
    ensures TryAdvance(Cap(0, 2)) == (Cap(1, 2), Advanced)
    ensures TryAdvance(Cap(2, 2)) == (Cap(2, 2), Declined)
    ensures AdvanceN(Cap(0, 3), 3) == Cap(3, 3)
  {
  }

  datatype Cap = Cap(pos: nat, cap: nat)

  datatype AdvOutcome = Advanced | Declined
}

module ConfluxStateMachine {
  function TransitionState<S, A, Out>(step: StateTransition<S, A, Out>): Reducer<S, A>
  {
    (s: S, a: A) => step(s, a).0
  }

  function FinalState<S, Out>(run: TransitionRun<S, Out>): S
    decreases run
  {
    run.state
  }

  function Outputs<S, Out>(run: TransitionRun<S, Out>): seq<Out>
    decreases run
  {
    run.outputs
  }

  function RunTransitions<S, A, Out>(step: StateTransition<S, A, Out>, s: S, xs: seq<A>): TransitionRun<S, Out>
    decreases |xs|
  {
    if |xs| == 0 then
      TransitionRun(s, [])
    else
      var so: (S, Out) := step(s, xs[0]); var rest: TransitionRun<S, Out> := RunTransitions(step, so.0, xs[1..]); TransitionRun(rest.state, [so.1] + rest.outputs)
  }

  lemma /*{:_inductionTrigger Fold(TransitionState(step), s, xs)}*/ /*{:_inductionTrigger RunTransitions(step, s, xs)}*/ /*{:_induction xs}*/ RunStateIsFold<S, A, Out>(step: StateTransition<S, A, Out>, s: S, xs: seq<A>)
    ensures FinalState(RunTransitions(step, s, xs)) == Fold(TransitionState(step), s, xs)
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      RunStateIsFold(step, step(s, xs[0]).0, xs[1..]);
    }
  }

  lemma /*{:_inductionTrigger RunTransitions(step, s, xs)}*/ /*{:_induction xs}*/ OneOutputPerInput<S, A, Out>(step: StateTransition<S, A, Out>, s: S, xs: seq<A>)
    ensures |RunTransitions(step, s, xs).outputs| == |xs|
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      OneOutputPerInput(step, step(s, xs[0]).0, xs[1..]);
    }
  }

  lemma /*{:_inductionTrigger xs[k..]}*/ /*{:_inductionTrigger xs[..k]}*/ /*{:_inductionTrigger RunTransitions(step, s, xs)}*/ /*{:_inductionTrigger |xs|}*/ /*{:_induction xs}*/ StateMachineSnapshotReplay<S, A, Out>(step: StateTransition<S, A, Out>, s: S, xs: seq<A>, k: nat)
    requires k <= |xs|
    ensures FinalState(RunTransitions(step, s, xs)) == Fold(TransitionState(step), Fold(TransitionState(step), s, xs[..k]), xs[k..])
    decreases xs, k
  {
    RunStateIsFold(step, s, xs);
    SnapshotReplay(TransitionState(step), s, xs, k);
  }

  function GuardedTransition<S, A, Out>(base: StateTransition<S, A, Out>, breached: (S, A) -> bool, onBreach: (S, A) -> Out): StateTransition<S, A, Out>
  {
    (s: S, a: A) => if breached(s, a) then (s, onBreach(s, a)) else base(s, a)
  }

  lemma HoldOnBreach<S, A, Out>(base: StateTransition<S, A, Out>, breached: (S, A) -> bool, onBreach: (S, A) -> Out, s: S, a: A)
    requires breached(s, a)
    ensures GuardedTransition(base, breached, onBreach)(s, a).0 == s
    ensures GuardedTransition(base, breached, onBreach)(s, a).1 == onBreach(s, a)
  {
  }

  lemma AdvanceWhenAllowed<S, A, Out>(base: StateTransition<S, A, Out>, breached: (S, A) -> bool, onBreach: (S, A) -> Out, s: S, a: A)
    requires !breached(s, a)
    ensures GuardedTransition(base, breached, onBreach)(s, a) == base(s, a)
  {
  }

  lemma Witness()
    ensures exists step: StateTransition<int, bool, bool>, xs: seq<bool> {:trigger RunTransitions(step, 0, xs)} :: FinalState(RunTransitions(step, 0, xs)) == 2 && RunTransitions(step, 0, xs).outputs == [true, true]
  {
    ghost var base := (n: int, u: bool) => (n + 1, true);
    ghost var breach := (n: int, u: bool) => n >= 2;
    ghost var loud := (n: int, u: bool) => false;
    ghost var gstep := GuardedTransition(base, breach, loud);
    AdvanceWhenAllowed(base, breach, loud, 0, true);
    assert gstep(0, true) == (1, true);
    HoldOnBreach(base, breach, loud, 2, true);
    assert gstep(2, true) == (2, false);
    RunStateIsFold(gstep, 0, [true, true]);
    OneOutputPerInput(gstep, 0, [true, true]);
    assert FinalState(RunTransitions(gstep, 0, [true, true])) == 2;
    assert RunTransitions(gstep, 0, [true, true]).outputs == [true, true];
  }

  import opened ConfluxContract

  type StateTransition<!S, !A, !Out> = (S, A) -> (S, Out)

  datatype TransitionRun<S, Out> = TransitionRun(state: S, outputs: seq<Out>)
}

module ConfluxProduct {
  function Product<S1(!new), S2(!new), A(!new)>(r1: Reducer<S1, A>, r2: Reducer<S2, A>): Reducer<(S1, S2), A>
  {
    (s: (S1, S2), a: A) => (r1(s.0, a), r2(s.1, a))
  }

  lemma ProjLeft<S1(!new), S2(!new), A(!new)>(r1: Reducer<S1, A>, r2: Reducer<S2, A>, s: (S1, S2), a: A)
    ensures Product(r1, r2)(s, a).0 == r1(s.0, a)
    decreases s
  {
  }

  lemma ProjRight<S1(!new), S2(!new), A(!new)>(r1: Reducer<S1, A>, r2: Reducer<S2, A>, s: (S1, S2), a: A)
    ensures Product(r1, r2)(s, a).1 == r2(s.1, a)
    decreases s
  {
  }

  lemma Independence<S1(!new), S2(!new), A(!new)>(r1: Reducer<S1, A>, r2: Reducer<S2, A>, s1: S1, s2a: S2, s2b: S2, a: A)
    ensures Product(r1, r2)((s1, s2a), a).0 == Product(r1, r2)((s1, s2b), a).0
  {
  }

  lemma /*{:_inductionTrigger Fold(r2, s.1, xs)}*/ /*{:_inductionTrigger Fold(r1, s.0, xs)}*/ /*{:_inductionTrigger Fold(Product(r1, r2), s, xs)}*/ /*{:_induction s, xs}*/ ProductFold<S1(!new), S2(!new), A(!new)>(r1: Reducer<S1, A>, r2: Reducer<S2, A>, s: (S1, S2), xs: seq<A>)
    ensures Fold(Product(r1, r2), s, xs) == (Fold(r1, s.0, xs), Fold(r2, s.1, xs))
    decreases xs
  {
    if |xs| == 0 {
    } else {
      ProductFold(r1, r2, Product(r1, r2)(s, xs[0]), xs[1..]);
    }
  }

  lemma Witness()
    ensures exists r1: Reducer<nat, nat>, r2: Reducer<nat, nat>, xs: seq<nat> {:trigger Fold(Product(r1, r2), (0, 0), xs)} :: Fold(Product(r1, r2), (0, 0), xs) == (6, 3)
  {
    ghost var inc: Reducer<nat, nat> := (s: nat, a: nat) => s + a;
    ghost var last: Reducer<nat, nat> := (s: nat, a: nat) => a;
    assert Product(inc, last)((10, 0), 5) == (15, 5);
    ProductFold(inc, last, (0, 0), [1, 2, 3]);
    assert Fold(Product(inc, last), (0, 0), [1, 2, 3]) == (6, 3);
  }

  import opened ConfluxContract
}

module ConfluxJoin {
  function JoinCheckpoint<K, P, S, O>(combine: (K, P, Option<S>) -> O, primary: map<K, P>, side: map<K, S>): map<K, O>
    decreases primary, side
  {
    map k: K {:trigger side[k]} {:trigger k in side} {:trigger primary[k]} {:trigger k in primary} | k in primary :: combine(k, primary[k], if k in side then Some(side[k]) else None)
  }

  lemma JoinCardinality<K, P, S, O>(combine: (K, P, Option<S>) -> O, primary: map<K, P>, side: map<K, S>)
    ensures JoinCheckpoint(combine, primary, side).Keys == primary.Keys
    decreases primary, side
  {
  }

  lemma JoinAt<K, P, S, O>(combine: (K, P, Option<S>) -> O, primary: map<K, P>, side: map<K, S>, k: K)
    requires k in primary
    ensures k in JoinCheckpoint(combine, primary, side) && JoinCheckpoint(combine, primary, side)[k] == combine(k, primary[k], if k in side then Some(side[k]) else None)
    decreases primary, side
  {
  }

  lemma JoinWitness()
    ensures exists combine: (string, int, Option<int>) -> int, prim: map<string, int>, side: map<string, int> {:trigger JoinCheckpoint(combine, prim, side)} :: JoinCheckpoint(combine, prim, side) == map[""a"" := 200, ""b"" := 0]
  {
    ghost var combine := (k: string, tok: int, rate: Option<int>) => tok * match rate case Some(r) => r case None() => 0;
    ghost var prim := map[""a"" := 100, ""b"" := 200];
    ghost var side := map[""a"" := 2];
    assert JoinCheckpoint(combine, prim, side) == map[""a"" := 200, ""b"" := 0];
  }

  import opened ConfluxContract
}

module ConfluxPrune {
  function PrunableRoute<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>): Reducer<map<K, S>, A>
  {
    (m: map<K, S>, a: A) => var k: K := keyOf(a); var cur: Option<S> := if k in m then Some(m[k]) else None; match op(cur, a) case NoOp() => m case Install(s) => m[k := s] case Remove() => m - {k}
  }

  lemma PruneRemovesKey<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>, m: map<K, S>, a: A)
    requires op(if keyOf(a) in m then Some(m[keyOf(a)]) else None, a).Remove?
    ensures PrunableRoute(keyOf, op)(m, a) == m - {keyOf(a)}
    ensures keyOf(a) !in PrunableRoute(keyOf, op)(m, a)
    decreases m
  {
  }

  lemma PruneIsolates<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>, m: map<K, S>, a: A, k2: K)
    requires k2 != keyOf(a) && k2 in m
    ensures k2 in PrunableRoute(keyOf, op)(m, a) && PrunableRoute(keyOf, op)(m, a)[k2] == m[k2]
    decreases m
  {
  }

  lemma PruneWitness()
    ensures exists keyOf: int -> int, op: (Option<int>, int) -> RouteOp<int> {:trigger PrunableRoute(keyOf, op)} :: PrunableRoute(keyOf, op)(map[], 7) == map[7 := 70] && PrunableRoute(keyOf, op)(map[7 := 70], 7) == map[]
  {
    ghost var keyOf := (a: int) => a;
    ghost var op := (cur: Option<int>, a: int) => if cur.None? then Install(a * 10) else Remove;
    assert PrunableRoute(keyOf, op)(map[], 7) == map[7 := 70];
    assert PrunableRoute(keyOf, op)(map[7 := 70], 7) == map[];
  }

  import opened ConfluxContract

  datatype RouteOp<S> = NoOp | Install(next: S) | Remove
}

module ConfluxDedupe {
  function DedupeAppend<T(==)>(xs: seq<T>, x: T): seq<T>
    decreases xs
  {
    if x in xs then
      xs
    else
      xs + [x]
  }

  lemma DedupeIdempotent<T>(xs: seq<T>, x: T)
    requires x in xs
    ensures DedupeAppend(xs, x) == xs
    decreases xs
  {
  }

  lemma DedupeAddsAbsent<T>(xs: seq<T>, x: T)
    requires x !in xs
    ensures DedupeAppend(xs, x) == xs + [x] && x in DedupeAppend(xs, x)
    decreases xs
  {
  }

  lemma DedupeNoDup<T>(xs: seq<T>, x: T)
    requires x in xs
    ensures |DedupeAppend(xs, x)| == |xs|
    decreases xs
  {
  }

  lemma DedupeWitness()
    ensures exists xs: seq<int>, x: int {:trigger DedupeAppend(xs, x)} {:trigger x in xs} :: x in xs && DedupeAppend(xs, x) == xs
    ensures exists xs: seq<int>, x: int {:trigger xs + [x]} {:trigger DedupeAppend(xs, x)} {:trigger x in xs} :: x !in xs && DedupeAppend(xs, x) == xs + [x]
  {
    assert DedupeAppend([1, 2], 2) == [1, 2];
    assert DedupeAppend([1, 2], 3) == [1, 2, 3];
  }
}

module ConfluxBatchRoute {
  function BatchRoute<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>, m: map<K, S>, batch: seq<A>): map<K, S>
    decreases m, batch
  {
    Fold(PrunableRoute(keyOf, op), m, batch)
  }

  function Reset<K, S, A>(seed: map<K, S>): Reducer<map<K, S>, A>
    decreases seed
  {
    (m: map<K, S>, a: A) => seed
  }

  lemma BatchRouteEmpty<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>, m: map<K, S>)
    ensures BatchRoute(keyOf, op, m, []) == m
    decreases m
  {
  }

  lemma BatchRouteSingletonIsStep<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>, m: map<K, S>, a: A)
    ensures BatchRoute(keyOf, op, m, [a]) == PrunableRoute(keyOf, op)(m, a)
    decreases m
  {
    ghost var r := PrunableRoute(keyOf, op);
    assert [a][0] == a && [a][1..] == [];
    assert BatchRoute(keyOf, op, m, [a]) == Fold(r, m, [a]) == Fold(r, r(m, a), []) == r(m, a);
  }

  lemma BatchRouteStep<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>, m: map<K, S>, a: A, rest: seq<A>)
    ensures BatchRoute(keyOf, op, m, [a] + rest) == BatchRoute(keyOf, op, PrunableRoute(keyOf, op)(m, a), rest)
    decreases m, rest
  {
    assert ([a] + rest)[0] == a;
    assert ([a] + rest)[1..] == rest;
  }

  lemma BatchRouteConcat<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>, m: map<K, S>, xs: seq<A>, ys: seq<A>)
    ensures BatchRoute(keyOf, op, m, xs + ys) == BatchRoute(keyOf, op, BatchRoute(keyOf, op, m, xs), ys)
    decreases m, xs, ys
  {
    FoldConcat(PrunableRoute(keyOf, op), m, xs, ys);
  }

  lemma BatchRouteGrowsManyKeys<K, S, A>(keyOf: A -> K, op: (Option<S>, A) -> RouteOp<S>, a1: A, a2: A, s1: S, s2: S)
    requires keyOf(a1) != keyOf(a2)
    requires op(None, a1) == Install(s1)
    requires op(if keyOf(a2) in map[keyOf(a1) := s1] then Some(map[keyOf(a1) := s1][keyOf(a2)]) else None, a2) == Install(s2)
    ensures BatchRoute(keyOf, op, map[], [a1, a2]) == map[keyOf(a1) := s1, keyOf(a2) := s2]
    ensures |BatchRoute(keyOf, op, map[], [a1, a2]).Keys| == 2
  {
    BatchRouteStep(keyOf, op, map[], a1, [a2]);
    BatchRouteSingletonIsStep(keyOf, op, map[keyOf(a1) := s1], a2);
  }

  lemma ResetIgnoresPrior<K, S, A>(seed: map<K, S>, m1: map<K, S>, m2: map<K, S>, a: A)
    ensures Reset<K, S, A>(seed)(m1, a) == Reset<K, S, A>(seed)(m2, a)
    decreases seed, m1, m2
  {
  }

  lemma ResetIsSeed<K, S, A>(seed: map<K, S>, m: map<K, S>, a: A)
    ensures Reset<K, S, A>(seed)(m, a) == seed
    decreases seed, m
  {
  }

  lemma ResetEmptiesMap<K, S, A>(m: map<K, S>, a: A)
    ensures Reset<K, S, A>(map[])(m, a) == map[]
    ensures Reset<K, S, A>(map[])(m, a).Keys == {}
    decreases m
  {
  }

  lemma Witness()
    ensures exists keyOf: ((string, int)) -> string, op: (Option<int>, (string, int)) -> RouteOp<int>, batch: seq<(string, int)> {:trigger BatchRoute(keyOf, op, map[], batch)} :: BatchRoute(keyOf, op, map[], batch) == map[""a"" := 1, ""b"" := 2] && |BatchRoute(keyOf, op, map[], batch).Keys| == 2
    ensures exists m: map<string, int>, a: int {:trigger Reset<string, int, int>(map[])(m, a)} :: m != map[] && Reset<string, int, int>(map[])(m, a) == map[]
  {
    ghost var keyOf := (a: (string, int)) => a.0;
    ghost var op := (cur: Option<int>, a: (string, int)) => Install(a.1);
    ghost var batch := [(""a"", 1), (""b"", 2)];
    BatchRouteStep(keyOf, op, map[], (""a"", 1), [(""b"", 2)]);
    BatchRouteSingletonIsStep(keyOf, op, map[""a"" := 1], (""b"", 2));
    ghost var routed := BatchRoute(keyOf, op, map[], batch);
    assert routed == map[""a"" := 1, ""b"" := 2];
    assert |routed.Keys| == 2;
    ghost var cleared := Reset<string, int, int>(map[])(map[""x"" := 9, ""y"" := 8], 0);
    assert cleared == map[] && |cleared| == 0;
    ghost var seeded := Reset<string, int, int>(map[""z"" := 5])(map[""x"" := 9], 0);
    assert seeded == map[""z"" := 5];
  }

  import opened ConfluxContract

  import opened ConfluxPrune
}

module ConfluxSeqRoute {
  function SeqUpsertById<K(==), V>(keyOf: V -> K, xs: seq<V>, v: V): seq<V>
    decreases |xs|
  {
    if |xs| == 0 then
      [v]
    else if keyOf(xs[0]) == keyOf(v) then
      [v] + xs[1..]
    else
      [xs[0]] + SeqUpsertById(keyOf, xs[1..], v)
  }

  function SeqRemoveById<K(==), V>(keyOf: V -> K, xs: seq<V>, k: K): seq<V>
    decreases |xs|
  {
    if |xs| == 0 then
      []
    else if keyOf(xs[0]) == k then
      SeqRemoveById(keyOf, xs[1..], k)
    else
      [xs[0]] + SeqRemoveById(keyOf, xs[1..], k)
  }

  function ToMap<K(==), V>(keyOf: V -> K, xs: seq<V>): map<K, V>
    decreases |xs|
  {
    if |xs| == 0 then
      map[]
    else
      ToMap(keyOf, xs[1..])[keyOf(xs[0]) := xs[0]]
  }

  lemma /*{:_inductionTrigger SeqUpsertById(keyOf, xs, v)}*/ /*{:_induction xs}*/ UpsertMapView<K, V>(keyOf: V -> K, xs: seq<V>, v: V)
    ensures ToMap(keyOf, SeqUpsertById(keyOf, xs, v)) == ToMap(keyOf, xs)[keyOf(v) := v]
    decreases xs
  {
    if |xs| == 0 {
    } else if keyOf(xs[0]) == keyOf(v) {
      assert SeqUpsertById(keyOf, xs, v) == [v] + xs[1..];
    } else {
      UpsertMapView(keyOf, xs[1..], v);
      assert keyOf(xs[0]) != keyOf(v);
    }
  }

  predicate UniqueKeys<K(==), V>(keyOf: V -> K, xs: seq<V>)
    decreases xs
  {
    forall i: int, j: int {:trigger xs[j], xs[i]} :: 
      0 <= i < |xs| &&
      0 <= j < |xs| &&
      keyOf(xs[i]) == keyOf(xs[j]) ==>
        i == j
  }

  lemma UniqueTail<K, V>(keyOf: V -> K, xs: seq<V>)
    requires |xs| > 0 && UniqueKeys(keyOf, xs)
    ensures UniqueKeys(keyOf, xs[1..])
    ensures keyOf(xs[0]) !in set x: V {:trigger keyOf(x)} {:trigger x in xs[1..]} | x in xs[1..] :: keyOf(x)
    decreases xs
  {
    forall i: int, j: int | 0 <= i < |xs[1..]| && 0 <= j < |xs[1..]| && keyOf(xs[1..][i]) == keyOf(xs[1..][j])
      ensures i == j
    {
      assert xs[1..][i] == xs[i + 1] && xs[1..][j] == xs[j + 1];
    }
    if keyOf(xs[0]) in set x: V {:trigger keyOf(x)} {:trigger x in xs[1..]} | x in xs[1..] :: keyOf(x) {
      ghost var x :| x in xs[1..] && keyOf(x) == keyOf(xs[0]);
      ghost var t :| 0 <= t < |xs[1..]| && xs[1..][t] == x;
      assert xs[t + 1] == x && keyOf(xs[t + 1]) == keyOf(xs[0]);
    }
  }

  lemma KeyNotInTailMapView<K, V>(keyOf: V -> K, xs: seq<V>, k: K)
    requires |xs| > 0 && keyOf(xs[0]) == k && UniqueKeys(keyOf, xs)
    ensures k !in ToMap(keyOf, xs[1..])
    decreases xs
  {
    UniqueTail(keyOf, xs);
    KeyInMapViewIffInSeq(keyOf, xs[1..], k);
  }

  lemma /*{:_inductionTrigger |xs|}*/ /*{:_inductionTrigger ToMap(keyOf, xs)}*/ /*{:_induction xs}*/ KeyInMapViewIffInSeq<K, V>(keyOf: V -> K, xs: seq<V>, k: K)
    ensures (k in ToMap(keyOf, xs)) == exists i: int {:trigger xs[i]} :: 0 <= i < |xs| && keyOf(xs[i]) == k
    decreases xs
  {
    if |xs| == 0 {
    } else {
      KeyInMapViewIffInSeq(keyOf, xs[1..], k);
      if keyOf(xs[0]) == k {
      } else {
        assert (exists i: int {:trigger xs[i]} :: 0 <= i < |xs| && keyOf(xs[i]) == k) == exists i: int {:trigger xs[1..][i]} :: 0 <= i < |xs[1..]| && keyOf(xs[1..][i]) == k by {
          if exists i: int {:trigger xs[i]} :: 0 <= i < |xs| && keyOf(xs[i]) == k {
            ghost var i :| 0 <= i < |xs| && keyOf(xs[i]) == k;
            assert i > 0 && xs[1..][i - 1] == xs[i];
          }
          if exists i: int {:trigger xs[1..][i]} :: 0 <= i < |xs[1..]| && keyOf(xs[1..][i]) == k {
            ghost var i :| 0 <= i < |xs[1..]| && keyOf(xs[1..][i]) == k;
            assert xs[i + 1] == xs[1..][i];
          }
        }
      }
    }
  }

  lemma /*{:_inductionTrigger ToMap(keyOf, xs) - {k}}*/ /*{:_inductionTrigger SeqRemoveById(keyOf, xs, k)}*/ /*{:_inductionTrigger UniqueKeys(keyOf, xs)}*/ /*{:_induction xs}*/ RemoveMapView<K, V>(keyOf: V -> K, xs: seq<V>, k: K)
    requires UniqueKeys(keyOf, xs)
    ensures ToMap(keyOf, SeqRemoveById(keyOf, xs, k)) == ToMap(keyOf, xs) - {k}
    decreases xs
  {
    if |xs| == 0 {
      assert ToMap(keyOf, xs) == map[];
    } else if keyOf(xs[0]) == k {
      UniqueTail(keyOf, xs);
      RemoveMapView(keyOf, xs[1..], k);
      KeyNotInTailMapView(keyOf, xs, k);
    } else {
      UniqueTail(keyOf, xs);
      RemoveMapView(keyOf, xs[1..], k);
      assert keyOf(xs[0]) != k;
    }
  }

  lemma PruneApplied<K, V>(keyOf: V -> K, op: (Option<V>, V) -> RouteOp<V>, m: map<K, V>, v: V)
    ensures PrunableRoute<K, V, V>((a: V) => keyOf(a), op)(m, v) == ghost var cur: Option<V> := if keyOf(v) in m then Some(m[keyOf(v)]) else None; match op(cur, v) case NoOp() => m case Install(s) => m[keyOf(v) := s] case Remove() => m - {keyOf(v)}
    decreases m
  {
  }

  function InstallOp<V>(cur: Option<V>, v: V): RouteOp<V>
    decreases cur
  {
    Install(v)
  }

  function RemoveOp<V>(cur: Option<V>, v: V): RouteOp<V>
    decreases cur
  {
    Remove
  }

  lemma /*{:_inductionTrigger SeqUpsertById(keyOf, xs, v)}*/ /*{:_induction xs}*/ UpsertIsPruneInstall<K, V>(keyOf: V -> K, xs: seq<V>, v: V)
    ensures ToMap(keyOf, SeqUpsertById(keyOf, xs, v)) == PrunableRoute<K, V, V>((a: V) => keyOf(a), InstallOp)(ToMap(keyOf, xs), v)
    decreases xs
  {
    UpsertMapView(keyOf, xs, v);
    PruneApplied(keyOf, InstallOp, ToMap(keyOf, xs), v);
  }

  lemma /*{:_inductionTrigger SeqRemoveById(keyOf, xs, k)}*/ /*{:_inductionTrigger UniqueKeys(keyOf, xs)}*/ /*{:_induction xs}*/ RemoveIsPruneRemove<K, V>(keyOf: V -> K, xs: seq<V>, k: K, wit: V)
    requires UniqueKeys(keyOf, xs) && keyOf(wit) == k
