      ensures i == j
    {
      if i == 0 && j == 0 {
      } else if i >= 1 && j >= 1 {
        assert ys[i] == rest[i - 1] && ys[j] == rest[j - 1];
      } else {
        ghost var p := if i == 0 then j else i;
        assert ys[p] == rest[p - 1] && keyOf(a) == keyOf(rest[p - 1]);
        SeqKeysMembership(keyOf, rest, keyOf(a));
        assert false;
      }
    }
