      SeqKeysConcat(keyOf, [us[0]], us[1..]);
      assert forall k: K {:trigger k in SeqKeys(keyOf, vs)} {:trigger k in SeqKeys(keyOf, us[1..])} :: k in SeqKeys(keyOf, us[1..]) ==> k !in SeqKeys(keyOf, vs);
      ConcatUnique(keyOf, us[1..], vs);
      SeqKeysConcat(keyOf, us[1..], vs);
      assert keyOf(us[0]) !in SeqKeys(keyOf, us[1..] + vs);
      assert us + vs == [us[0]] + (us[1..] + vs);
      ConsUnique(keyOf, us[0], us[1..] + vs);
    }
  }

  lemma /*{:_inductionTrigger SeqKeys(keyOf, xs) + {keyOf(v)}}*/ /*{:_inductionTrigger SeqUpsertById(keyOf, xs, v)}*/ /*{:_induction xs}*/ UpsertSeqKeys<K, V>(keyOf: V -> K, xs: seq<V>, v: V)
