    ensures SeqUpdateAllWhere(keyOf, pred, xs, k, f) == SeqUpdateByIdWhere(keyOf, pred, xs, k, f)
    decreases |xs|
  {
    if |xs| == 0 {
    } else if keyOf(xs[0]) == k {
      UniqueTail(keyOf, xs);
      UpdateAllWhereNoMatch(keyOf, pred, xs[1..], k, f);
      UpdateWhereNoMatch(keyOf, pred, xs[1..], k, f);
    } else {
      UniqueTail(keyOf, xs);
      SeqUpdateAllWhereEqualsWhere(keyOf, pred, xs[1..], k, f);
    }
  }

  lemma /*{:_inductionTrigger SeqUpdateAllWhere(keyOf, pred, xs, k, f)}*/ /*{:_inductionTrigger UniqueKeys(keyOf, xs)}*/ /*{:_induction xs}*/ UpdateAllWhereIsPruneGuarded<K, V(!new)>(keyOf: V -> K, pred: V -> bool, xs: seq<V>, k: K, f: V -> V, wit: V)
