  lemma SeqRouteWitness()
    ensures exists keyOf: ((int, string)) -> int, xs: seq<(int, string)> {:trigger SeqRemoveById(keyOf, xs, 1)} {:trigger SeqUpsertById(keyOf, xs, (3, ""c""))} {:trigger SeqUpsertById(keyOf, xs, (2, ""B""))} {:trigger UniqueKeys(keyOf, xs)} :: UniqueKeys(keyOf, xs) && SeqUpsertById(keyOf, xs, (2, ""B"")) == [(1, ""a""), (2, ""B"")] && SeqUpsertById(keyOf, xs, (3, ""c"")) == [(1, ""a""), (2, ""b""), (3, ""c"")] && SeqRemoveById(keyOf, xs, 1) == [(2, ""b"")]
