    ghost var keyOf := (p: (int, string)) => p.0;
    ghost var xs := [(1, ""a""), (2, ""b"")];
    assert UniqueKeys(keyOf, xs) by {
      assert keyOf(xs[0]) == 1 && keyOf(xs[1]) == 2;
    }
    ghost var up := SeqUpsertById(keyOf, xs, (2, ""B""));
    assert up == [(1, ""a""), (2, ""B"")];
    ghost var app := SeqUpsertById(keyOf, xs, (3, ""c""));
    assert app == [(1, ""a""), (2, ""b""), (3, ""c"")];
    ghost var rm := SeqRemoveById(keyOf, xs, 1);
    assert rm == [(2, ""b"")];
    ghost var upd := SeqUpdateById(keyOf, xs, 1, (p: (int, string)) => (p.0, ""Z""));
    assert upd == [(1, ""Z""), (2, ""b"")];
    ghost var noop := SeqUpdateById(keyOf, xs, 9, (p: (int, string)) => (p.0, ""Z""));
    assert noop == xs;
    ghost var wOk := SeqUpdateByIdWhere(keyOf, (p: (int, string)) => p.1 == ""a"", xs, 1, (p: (int, string)) => (p.0, ""Z""));
    assert wOk == [(1, ""Z""), (2, ""b"")];
    ghost var wNo := SeqUpdateByIdWhere(keyOf, (p: (int, string)) => p.1 == ""a"", xs, 2, (p: (int, string)) => (p.0, ""Z""));
    assert wNo == xs;
    UpsertMapView(keyOf, xs, (2, ""B""));
    assert ToMap(keyOf, up) == ToMap(keyOf, xs)[2 := (2, ""B"")];
  }

  import opened ConfluxContract

  import opened ConfluxPrune
}

module ConfluxSeqRouteMerge {
  function SeqUpsertByIdWith<K(==), V>(keyOf: V -> K, combine: (Option<V>, V) -> V, xs: seq<V>, v: V): seq<V>
    decreases |xs|
  {
    if |xs| == 0 then
      [combine(None, v)]
    else if keyOf(xs[0]) == keyOf(v) then
      [combine(Some(xs[0]), v)] + xs[1..]
    else
      [xs[0]] + SeqUpsertByIdWith(keyOf, combine, xs[1..], v)
  }

  function MergeUpsertById<K(==), V>(keyOf: V -> K, combine: (Option<V>, V) -> V, xs: seq<V>, v: V): seq<V>
    decreases xs
  {
    SeqUpsertByIdWith(keyOf, combine, xs, v)
  }

  lemma /*{:_inductionTrigger SeqUpsertById(keyOf, xs, v)}*/ /*{:_induction xs}*/ UpsertWithConstIsUpsert<K, V>(keyOf: V -> K, xs: seq<V>, v: V)
    ensures SeqUpsertByIdWith(keyOf, (cur: Option<V>, a: V) => a, xs, v) == SeqUpsertById(keyOf, xs, v)
    decreases |xs|
  {
    if |xs| == 0 {
    } else if keyOf(xs[0]) == keyOf(v) {
    } else {
      UpsertWithConstIsUpsert(keyOf, xs[1..], v);
    }
  }

  ghost predicate CombineKeyPreserving<K, V(!new)>(keyOf: V -> K, combine: (Option<V>, V) -> V)
  {
    forall cur: Option<V>, a: V {:trigger combine(cur, a)} :: 
      keyOf(combine(cur, a)) == keyOf(a)
  }

  lemma /*{:_inductionTrigger SeqKeys(keyOf, xs) + {keyOf(v)}}*/ /*{:_inductionTrigger SeqUpsertByIdWith(keyOf, combine, xs, v)}*/ /*{:_induction xs}*/ UpsertWithSeqKeys<K, V(!new)>(keyOf: V -> K, combine: (Option<V>, V) -> V, xs: seq<V>, v: V)
    requires CombineKeyPreserving(keyOf, combine)
    ensures SeqKeys(keyOf, SeqUpsertByIdWith(keyOf, combine, xs, v)) == SeqKeys(keyOf, xs) + {keyOf(v)}
    decreases |xs|
  {
    ghost var ys := SeqUpsertByIdWith(keyOf, combine, xs, v);
    if |xs| == 0 {
      assert ys == [combine(None, v)];
      assert keyOf(combine(None, v)) == keyOf(v);
    } else if keyOf(xs[0]) == keyOf(v) {
      assert ys == [combine(Some(xs[0]), v)] + xs[1..];
      assert keyOf(combine(Some(xs[0]), v)) == keyOf(v);
      assert SeqKeys(keyOf, ys) == {keyOf(v)} + SeqKeys(keyOf, xs[1..]);
      assert SeqKeys(keyOf, xs) == {keyOf(xs[0])} + SeqKeys(keyOf, xs[1..]);
    } else {
      UpsertWithSeqKeys(keyOf, combine, xs[1..], v);
      assert ys == [xs[0]] + SeqUpsertByIdWith(keyOf, combine, xs[1..], v);
      assert SeqKeys(keyOf, ys) == {keyOf(xs[0])} + SeqKeys(keyOf, SeqUpsertByIdWith(keyOf, combine, xs[1..], v));
      assert SeqKeys(keyOf, xs) == {keyOf(xs[0])} + SeqKeys(keyOf, xs[1..]);
    }
  }

  lemma /*{:_inductionTrigger SeqUpsertByIdWith(keyOf, combine, xs, v)}*/ /*{:_induction xs}*/ UpsertWithPreservesUnique<K, V(!new)>(keyOf: V -> K, combine: (Option<V>, V) -> V, xs: seq<V>, v: V)
    requires UniqueKeys(keyOf, xs) && CombineKeyPreserving(keyOf, combine)
    ensures UniqueKeys(keyOf, SeqUpsertByIdWith(keyOf, combine, xs, v))
    decreases |xs|
  {
    ghost var ys := SeqUpsertByIdWith(keyOf, combine, xs, v);
    if |xs| == 0 {
    } else if keyOf(xs[0]) == keyOf(v) {
      assert ys == [combine(Some(xs[0]), v)] + xs[1..];
      UniqueTail(keyOf, xs);
      assert keyOf(combine(Some(xs[0]), v)) == keyOf(v);
      assert keyOf(combine(Some(xs[0]), v)) !in SeqKeys(keyOf, xs[1..]);
      ConsUnique(keyOf, combine(Some(xs[0]), v), xs[1..]);
    } else {
      ghost var zs := SeqUpsertByIdWith(keyOf, combine, xs[1..], v);
      assert ys == [xs[0]] + zs;
      UniqueTail(keyOf, xs);
      UpsertWithPreservesUnique(keyOf, combine, xs[1..], v);
      UpsertWithSeqKeys(keyOf, combine, xs[1..], v);
      assert keyOf(xs[0]) !in SeqKeys(keyOf, zs);
      ConsUnique(keyOf, xs[0], zs);
    }
  }

  lemma /*{:_inductionTrigger ToMap(keyOf, xs)[keyOf(v)]}*/ /*{:_inductionTrigger keyOf(v) in ToMap(keyOf, xs)}*/ /*{:_inductionTrigger SeqUpsertByIdWith(keyOf, combine, xs, v)}*/ /*{:_inductionTrigger UniqueKeys(keyOf, xs)}*/ /*{:_induction xs}*/ UpsertWithMapView<K, V(!new)>(keyOf: V -> K, combine: (Option<V>, V) -> V, xs: seq<V>, v: V)
