    ensures ToMap(keyOf, SeqUpsertByIdWith(keyOf, combine, xs, v)) == ToMap(keyOf, xs)[keyOf(v) := combine(if keyOf(v) in ToMap(keyOf, xs) then Some(ToMap(keyOf, xs)[keyOf(v)]) else None, v)]
    decreases |xs|
