    if |xs| == 0 {
      assert ToMap(keyOf, xs) == map[];
      assert keyOf(combine(None, v)) == keyOf(v);
    } else if keyOf(xs[0]) == keyOf(v) {
      UniqueTail(keyOf, xs);
      KeyNotInTailMapView(keyOf, xs, keyOf(v));
      assert keyOf(combine(Some(xs[0]), v)) == keyOf(v);
    } else {
      UniqueTail(keyOf, xs);
      UpsertWithMapView(keyOf, combine, xs[1..], v);
      assert keyOf(xs[0]) != keyOf(v);
    }
  }

  function UpsertWithOp<V>(combine: (Option<V>, V) -> V): (Option<V>, V) -> RouteOp<V>
  {
    (cur: Option<V>, a: V) => Install(combine(cur, a))
  }

  lemma /*{:_inductionTrigger SeqUpsertByIdWith(keyOf, combine, xs, v)}*/ /*{:_inductionTrigger UniqueKeys(keyOf, xs)}*/ /*{:_induction xs}*/ UpsertWithIsPruneInstall<K, V(!new)>(keyOf: V -> K, combine: (Option<V>, V) -> V, xs: seq<V>, v: V)
    requires UniqueKeys(keyOf, xs) && CombineKeyPreserving(keyOf, combine)
    ensures ToMap(keyOf, SeqUpsertByIdWith(keyOf, combine, xs, v)) == PrunableRoute<K, V, V>((a: V) => keyOf(a), UpsertWithOp(combine))(ToMap(keyOf, xs), v)
    decreases xs
  {
    UpsertWithMapView(keyOf, combine, xs, v);
    PruneApplied(keyOf, UpsertWithOp(combine), ToMap(keyOf, xs), v);
  }

  lemma SeqUpsertWithWitness()
    ensures exists keyOf: ((int, string)) -> int, combine: (Option<(int, string)>, (int, string)) -> (int, string), xs: seq<(int, string)> {:trigger SeqUpsertByIdWith(keyOf, combine, xs, (2, ""B""))} {:trigger SeqUpsertByIdWith(keyOf, combine, xs, (2, """"))} :: SeqUpsertByIdWith(keyOf, combine, xs, (2, """")) == [(1, ""a""), (2, ""b"")] && SeqUpsertByIdWith(keyOf, combine, xs, (2, ""B"")) == [(1, ""a""), (2, ""B"")]
  {
    ghost var keyOf := (p: (int, string)) => p.0;
    ghost var combine := (cur: Option<(int, string)>, a: (int, string)) => if cur.None? then a else (a.0, if a.1 != """" then a.1 else cur.value.1);
    ghost var xs := [(1, ""a""), (2, ""b"")];
    assert SeqUpsertByIdWith(keyOf, combine, xs, (2, """")) == [(1, ""a""), (2, ""b"")];
    assert SeqUpsertByIdWith(keyOf, combine, xs, (2, ""B"")) == [(1, ""a""), (2, ""B"")];
    assert SeqUpsertByIdWith(keyOf, combine, xs, (3, ""c"")) == [(1, ""a""), (2, ""b""), (3, ""c"")];
    UpsertWithConstIsUpsert(keyOf, xs, (2, ""B""));
  }

  import opened ConfluxContract

  import opened ConfluxPrune

  import opened ConfluxSeqRoute
}

module ConfluxOrderedLog {
  lemma /*{:_inductionTrigger ToMap(keyOf, xs)}*/ /*{:_induction xs}*/ ToMapValueInSeq<K, V>(keyOf: V -> K, xs: seq<V>, k: K)
    requires k in ToMap(keyOf, xs)
    ensures ToMap(keyOf, xs)[k] in xs && keyOf(ToMap(keyOf, xs)[k]) == k
    decreases |xs|
  {
    if keyOf(xs[0]) == k {
    } else {
      ToMapValueInSeq(keyOf, xs[1..], k);
    }
  }

  lemma UniqueElem<K, V>(keyOf: V -> K, xs: seq<V>, v: V, w: V)
    requires UniqueKeys(keyOf, xs) && v in xs && w in xs && keyOf(v) == keyOf(w)
    ensures v == w
    decreases xs
  {
    ghost var i :| 0 <= i < |xs| && xs[i] == v;
    ghost var j :| 0 <= j < |xs| && xs[j] == w;
  }

  function ContainsK<K(==), V>(keyOf: V -> K, xs: seq<V>, k: K): bool
    decreases |xs|
  {
    if |xs| == 0 then
      false
    else if keyOf(xs[0]) == k then
      true
    else
      ContainsK(keyOf, xs[1..], k)
  }

  function FindK<K(==), V>(keyOf: V -> K, xs: seq<V>, k: K): seq<V>
    decreases |xs|
  {
    if |xs| == 0 then
      []
    else if keyOf(xs[0]) == k then
      [xs[0]]
    else
      FindK(keyOf, xs[1..], k)
  }

  function TakeListedK<K(==), V>(keyOf: V -> K, xs: seq<V>, order: seq<K>, taken: set<K>): seq<V>
    decreases |order|
  {
    if |order| == 0 then
      []
    else if order[0] !in taken && ContainsK(keyOf, xs, order[0]) then
      FindK(keyOf, xs, order[0]) + TakeListedK(keyOf, xs, order[1..], taken + {order[0]})
    else
      TakeListedK(keyOf, xs, order[1..], taken)
  }

  function RestK<K(==), V>(keyOf: V -> K, xs: seq<V>, order: seq<K>): seq<V>
    decreases |xs|
  {
    if |xs| == 0 then
      []
    else
      (if keyOf(xs[0]) in order then [] else [xs[0]]) + RestK(keyOf, xs[1..], order)
  }

  function SeqReorderByKeys<K(==), V>(keyOf: V -> K, order: seq<K>, xs: seq<V>): seq<V>
    decreases order, xs
  {
    TakeListedK(keyOf, xs, order, {}) + RestK(keyOf, xs, order)
  }

  lemma /*{:_inductionTrigger |xs|}*/ /*{:_inductionTrigger ContainsK(keyOf, xs, k)}*/ /*{:_induction xs}*/ ContainsKIff<K, V>(keyOf: V -> K, xs: seq<V>, k: K)
    ensures ContainsK(keyOf, xs, k) == exists i: int {:trigger xs[i]} :: 0 <= i < |xs| && keyOf(xs[i]) == k
    decreases |xs|
  {
    if |xs| == 0 {
    } else if keyOf(xs[0]) == k {
    } else {
      ContainsKIff(keyOf, xs[1..], k);
      if ContainsK(keyOf, xs[1..], k) {
        ghost var i :| 0 <= i < |xs[1..]| && keyOf(xs[1..][i]) == k;
        assert xs[i + 1] == xs[1..][i];
      }
      if exists i: int {:trigger xs[i]} :: 0 <= i < |xs| && keyOf(xs[i]) == k {
        ghost var i :| 0 <= i < |xs| && keyOf(xs[i]) == k;
        assert i > 0 && xs[1..][i - 1] == xs[i];
      }
    }
  }

  lemma /*{:_inductionTrigger FindK(keyOf, xs, k)}*/ /*{:_inductionTrigger ContainsK(keyOf, xs, k)}*/ /*{:_induction xs}*/ FindKFirst<K, V>(keyOf: V -> K, xs: seq<V>, k: K)
    requires ContainsK(keyOf, xs, k)
    ensures |FindK(keyOf, xs, k)| == 1 && keyOf(FindK(keyOf, xs, k)[0]) == k && FindK(keyOf, xs, k)[0] in xs
    decreases |xs|
  {
    if keyOf(xs[0]) == k {
    } else {
      FindKFirst(keyOf, xs[1..], k);
      assert FindK(keyOf, xs, k)[0] in xs[1..];
    }
  }

  lemma /*{:_inductionTrigger RestK(keyOf, xs, order)}*/ /*{:_induction xs, order}*/ RestKMembership<K, V>(keyOf: V -> K, xs: seq<V>, order: seq<K>, v: V)
    ensures (v in RestK(keyOf, xs, order)) == (v in xs && keyOf(v) !in order)
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      RestKMembership(keyOf, xs[1..], order, v);
      assert (v in xs) == (v == xs[0] || v in xs[1..]);
    }
  }

  lemma /*{:_inductionTrigger TakeListedK(keyOf, xs, order, taken)}*/ /*{:_induction xs, order, taken}*/ TakeListedSubsetXs<K, V>(keyOf: V -> K, xs: seq<V>, order: seq<K>, taken: set<K>, v: V)
    requires v in TakeListedK(keyOf, xs, order, taken)
    ensures v in xs
    decreases |order|
  {
    if order[0] !in taken && ContainsK(keyOf, xs, order[0]) {
      if v in FindK(keyOf, xs, order[0]) {
        FindKFirst(keyOf, xs, order[0]);
      } else {
        TakeListedSubsetXs(keyOf, xs, order[1..], taken + {order[0]}, v);
      }
    } else {
      TakeListedSubsetXs(keyOf, xs, order[1..], taken, v);
    }
  }

  lemma ReorderSubsetXs<K, V>(keyOf: V -> K, order: seq<K>, xs: seq<V>, v: V)
    requires v in SeqReorderByKeys(keyOf, order, xs)
    ensures v in xs
    decreases order, xs
  {
    if v in TakeListedK(keyOf, xs, order, {}) {
      TakeListedSubsetXs(keyOf, xs, order, {}, v);
    } else {
      RestKMembership(keyOf, xs, order, v);
    }
  }

  lemma /*{:_inductionTrigger TakeListedK(keyOf, xs, order, taken)}*/ /*{:_inductionTrigger FindK(keyOf, xs, k), k in taken, k in order}*/ /*{:_inductionTrigger ContainsK(keyOf, xs, k), k in taken, k in order}*/ /*{:_induction xs, order, taken}*/ TakeListedContainsFirst<K, V>(keyOf: V -> K, xs: seq<V>, order: seq<K>, taken: set<K>, k: K)
    requires k in order && k !in taken && ContainsK(keyOf, xs, k)
    ensures forall w: V {:trigger w in TakeListedK(keyOf, xs, order, taken)} {:trigger w in FindK(keyOf, xs, k)} :: w in FindK(keyOf, xs, k) ==> w in TakeListedK(keyOf, xs, order, taken)
    decreases |order|
  {
    if order[0] == k {
    } else if order[0] !in taken && ContainsK(keyOf, xs, order[0]) {
      TakeListedContainsFirst(keyOf, xs, order[1..], taken + {order[0]}, k);
    } else {
      TakeListedContainsFirst(keyOf, xs, order[1..], taken, k);
    }
  }

  lemma ReorderElemMembership<K, V>(keyOf: V -> K, order: seq<K>, xs: seq<V>, v: V)
    requires UniqueKeys(keyOf, xs)
    ensures (v in SeqReorderByKeys(keyOf, order, xs)) == (v in xs)
    decreases order, xs
  {
    if v in SeqReorderByKeys(keyOf, order, xs) {
      ReorderSubsetXs(keyOf, order, xs, v);
    }
    if v in xs {
      ghost var k := keyOf(v);
      if k in order {
        ContainsKIff(keyOf, xs, k);
        assert ContainsK(keyOf, xs, k);
        FindKFirst(keyOf, xs, k);
        ghost var w := FindK(keyOf, xs, k)[0];
        UniqueElem(keyOf, xs, v, w);
        TakeListedContainsFirst(keyOf, xs, order, {}, k);
        assert w in FindK(keyOf, xs, k);
        assert v in TakeListedK(keyOf, xs, order, {});
      } else {
        RestKMembership(keyOf, xs, order, v);
      }
    }
  }

  lemma /*{:_inductionTrigger SeqReorderByKeys(keyOf, order, xs)}*/ /*{:_inductionTrigger UniqueKeys(keyOf, xs)}*/ /*{:_induction xs}*/ ReorderPreservesToMap<K, V>(keyOf: V -> K, order: seq<K>, xs: seq<V>)
    requires UniqueKeys(keyOf, xs)
    ensures ToMap(keyOf, SeqReorderByKeys(keyOf, order, xs)) == ToMap(keyOf, xs)
    decreases order, xs
  {
    ghost var ys := SeqReorderByKeys(keyOf, order, xs);
    forall k: K | k in ToMap(keyOf, ys)
      ensures k in ToMap(keyOf, xs)
    {
      KeyInMapViewIffInSeq(keyOf, ys, k);
      ghost var i :| 0 <= i < |ys| && keyOf(ys[i]) == k;
      ReorderElemMembership(keyOf, order, xs, ys[i]);
      ghost var j :| 0 <= j < |xs| && xs[j] == ys[i];
      KeyInMapViewIffInSeq(keyOf, xs, k);
    }
    forall k: K | k in ToMap(keyOf, xs)
      ensures k in ToMap(keyOf, ys)
    {
      KeyInMapViewIffInSeq(keyOf, xs, k);
      ghost var i :| 0 <= i < |xs| && keyOf(xs[i]) == k;
      ReorderElemMembership(keyOf, order, xs, xs[i]);
      ghost var j :| 0 <= j < |ys| && ys[j] == xs[i];
      KeyInMapViewIffInSeq(keyOf, ys, k);
    }
    assert ToMap(keyOf, ys).Keys == ToMap(keyOf, xs).Keys;
    forall k: K | k in ToMap(keyOf, xs)
      ensures k in ToMap(keyOf, ys) && ToMap(keyOf, ys)[k] == ToMap(keyOf, xs)[k]
    {
      assert k in ToMap(keyOf, ys);
      ToMapValueInSeq(keyOf, xs, k);
      ToMapValueInSeq(keyOf, ys, k);
      ghost var vx := ToMap(keyOf, xs)[k];
      ghost var vy := ToMap(keyOf, ys)[k];
      ReorderElemMembership(keyOf, order, xs, vy);
      UniqueElem(keyOf, xs, vx, vy);
    }
    assert ToMap(keyOf, ys) == ToMap(keyOf, xs);
  }

  lemma /*{:_inductionTrigger TakeListedK(keyOf, xs, order, taken)}*/ /*{:_induction xs, order, taken}*/ TakeListedKUnique<K, V>(keyOf: V -> K, xs: seq<V>, order: seq<K>, taken: set<K>)
    ensures UniqueKeys(keyOf, TakeListedK(keyOf, xs, order, taken))
    ensures forall k: K {:trigger k in taken} {:trigger k in order} {:trigger k in SeqKeys(keyOf, TakeListedK(keyOf, xs, order, taken))} :: (k in SeqKeys(keyOf, TakeListedK(keyOf, xs, order, taken)) ==> k in order) && (k in SeqKeys(keyOf, TakeListedK(keyOf, xs, order, taken)) ==> k !in taken)
    decreases |order|
  {
    if |order| == 0 {
    } else if order[0] !in taken && ContainsK(keyOf, xs, order[0]) {
      ghost var w := FindK(keyOf, xs, order[0]);
      FindKFirst(keyOf, xs, order[0]);
      ghost var tail := TakeListedK(keyOf, xs, order[1..], taken + {order[0]});
      TakeListedKUnique(keyOf, xs, order[1..], taken + {order[0]});
      assert w == [w[0]];
      assert SeqKeys(keyOf, w) == {order[0]};
      assert order[0] !in SeqKeys(keyOf, tail);
      ConcatUnique(keyOf, w, tail);
      SeqKeysConcat(keyOf, w, tail);
      assert TakeListedK(keyOf, xs, order, taken) == w + tail;
      forall k: K | k in SeqKeys(keyOf, TakeListedK(keyOf, xs, order, taken))
        ensures k in order && k !in taken
      {
        if k in SeqKeys(keyOf, tail) {
          assert k in order[1..] && k in order;
        }
      }
    } else {
      TakeListedKUnique(keyOf, xs, order[1..], taken);
      forall k: K | k in SeqKeys(keyOf, TakeListedK(keyOf, xs, order, taken))
        ensures k in order && k !in taken
      {
        assert k in order[1..] && k in order;
      }
    }
  }

  lemma /*{:_inductionTrigger RestK(keyOf, xs, order)}*/ /*{:_induction xs, order}*/ RestKUnique<K, V>(keyOf: V -> K, xs: seq<V>, order: seq<K>)
    requires UniqueKeys(keyOf, xs)
    ensures UniqueKeys(keyOf, RestK(keyOf, xs, order))
    ensures forall k: K {:trigger k in order} {:trigger k in SeqKeys(keyOf, RestK(keyOf, xs, order))} :: k in SeqKeys(keyOf, RestK(keyOf, xs, order)) ==> k !in order
    ensures forall k: K {:trigger k in SeqKeys(keyOf, xs)} {:trigger k in SeqKeys(keyOf, RestK(keyOf, xs, order))} :: k in SeqKeys(keyOf, RestK(keyOf, xs, order)) ==> k in SeqKeys(keyOf, xs)
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      UniqueTail(keyOf, xs);
      ghost var rest := RestK(keyOf, xs[1..], order);
      RestKUnique(keyOf, xs[1..], order);
      SeqKeysConcat(keyOf, [xs[0]], xs[1..]);
      assert xs == [xs[0]] + xs[1..];
      if keyOf(xs[0]) in order {
        assert RestK(keyOf, xs, order) == rest;
      } else {
        assert RestK(keyOf, xs, order) == [xs[0]] + rest;
        assert keyOf(xs[0]) !in SeqKeys(keyOf, rest);
        ConsUnique(keyOf, xs[0], rest);
        SeqKeysConcat(keyOf, [xs[0]], rest);
      }
    }
  }

  lemma ReorderPreservesUnique<K, V>(keyOf: V -> K, order: seq<K>, xs: seq<V>)
    requires UniqueKeys(keyOf, xs)
    ensures UniqueKeys(keyOf, SeqReorderByKeys(keyOf, order, xs))
    decreases order, xs
  {
    ghost var t := TakeListedK(keyOf, xs, order, {});
    ghost var r := RestK(keyOf, xs, order);
    TakeListedKUnique(keyOf, xs, order, {});
    RestKUnique(keyOf, xs, order);
    assert forall k: K {:trigger k in SeqKeys(keyOf, r)} {:trigger k in SeqKeys(keyOf, t)} :: k in SeqKeys(keyOf, t) ==> k !in SeqKeys(keyOf, r);
    ConcatUnique(keyOf, t, r);
    assert SeqReorderByKeys(keyOf, order, xs) == t + r;
  }

  function SeqKeepThrough<K(==), V>(keyOf: V -> K, k: K, xs: seq<V>): seq<V>
    decreases |xs|
  {
    if |xs| == 0 then
      []
    else if keyOf(xs[0]) == k then
      [xs[0]]
    else
      [xs[0]] + SeqKeepThrough(keyOf, k, xs[1..])
  }

  lemma /*{:_inductionTrigger SeqKeepThrough(keyOf, k, xs)}*/ /*{:_induction xs}*/ KeepThroughIsPrefix<K, V>(keyOf: V -> K, k: K, xs: seq<V>)
    ensures |SeqKeepThrough(keyOf, k, xs)| <= |xs|
    ensures SeqKeepThrough(keyOf, k, xs) == xs[..|SeqKeepThrough(keyOf, k, xs)|]
    decreases |xs|
  {
    if |xs| == 0 {
    } else if keyOf(xs[0]) == k {
      assert SeqKeepThrough(keyOf, k, xs) == [xs[0]] == xs[..1];
    } else {
      KeepThroughIsPrefix(keyOf, k, xs[1..]);
      ghost var r := SeqKeepThrough(keyOf, k, xs[1..]);
      assert SeqKeepThrough(keyOf, k, xs) == [xs[0]] + r;
      assert xs[..1 + |r|] == [xs[0]] + xs[1..][..|r|];
    }
  }

  lemma /*{:_inductionTrigger xs[..n]}*/ /*{:_inductionTrigger |xs|}*/ /*{:_induction xs}*/ PrefixToMapSubmap<K, V>(keyOf: V -> K, xs: seq<V>, n: nat)
    requires 0 <= n <= |xs|
    ensures forall k: K {:trigger ToMap(keyOf, xs)[k]} {:trigger ToMap(keyOf, xs[..n])[k]} {:trigger k in ToMap(keyOf, xs)} {:trigger k in ToMap(keyOf, xs[..n])} :: (k in ToMap(keyOf, xs[..n]) ==> k in ToMap(keyOf, xs)) && (k in ToMap(keyOf, xs[..n]) ==> ToMap(keyOf, xs[..n])[k] == ToMap(keyOf, xs)[k])
    decreases |xs|
  {
    if |xs| == 0 {
      assert xs[..n] == [];
    } else if n == 0 {
      assert xs[..0] == [];
    } else {
      assert xs[..n][0] == xs[0];
      assert xs[..n][1..] == xs[1..][..n - 1];
      PrefixToMapSubmap(keyOf, xs[1..], n - 1);
      forall k: K | k in ToMap(keyOf, xs[..n])
        ensures k in ToMap(keyOf, xs) && ToMap(keyOf, xs[..n])[k] == ToMap(keyOf, xs)[k]
      {
        if k == keyOf(xs[0]) {
        } else {
        }
      }
    }
  }

  lemma /*{:_inductionTrigger SeqKeepThrough(keyOf, k, xs)}*/ /*{:_induction xs}*/ KeepThroughIsSubmap<K, V>(keyOf: V -> K, k: K, xs: seq<V>)
    ensures forall j: K {:trigger ToMap(keyOf, xs)[j]} {:trigger ToMap(keyOf, SeqKeepThrough(keyOf, k, xs))[j]} {:trigger j in ToMap(keyOf, xs)} {:trigger j in ToMap(keyOf, SeqKeepThrough(keyOf, k, xs))} :: (j in ToMap(keyOf, SeqKeepThrough(keyOf, k, xs)) ==> j in ToMap(keyOf, xs)) && (j in ToMap(keyOf, SeqKeepThrough(keyOf, k, xs)) ==> ToMap(keyOf, SeqKeepThrough(keyOf, k, xs))[j] == ToMap(keyOf, xs)[j])
    decreases xs
  {
    KeepThroughIsPrefix(keyOf, k, xs);
    ghost var n := |SeqKeepThrough(keyOf, k, xs)|;
    assert SeqKeepThrough(keyOf, k, xs) == xs[..n];
    PrefixToMapSubmap(keyOf, xs, n);
  }

  lemma /*{:_inductionTrigger SeqKeepThrough(keyOf, k, xs)}*/ /*{:_inductionTrigger ContainsK(keyOf, xs, k)}*/ /*{:_induction xs}*/ KeepThroughIncludesKey<K, V>(keyOf: V -> K, k: K, xs: seq<V>)
    requires ContainsK(keyOf, xs, k)
    ensures |SeqKeepThrough(keyOf, k, xs)| >= 1
    ensures keyOf(SeqKeepThrough(keyOf, k, xs)[|SeqKeepThrough(keyOf, k, xs)| - 1]) == k
    decreases |xs|
  {
    if keyOf(xs[0]) == k {
    } else {
      ContainsKIff(keyOf, xs, k);
      ghost var i :| 0 <= i < |xs| && keyOf(xs[i]) == k;
      assert i > 0 && xs[1..][i - 1] == xs[i];
      ContainsKIff(keyOf, xs[1..], k);
      KeepThroughIncludesKey(keyOf, k, xs[1..]);
    }
  }

  lemma /*{:_inductionTrigger SeqKeepThrough(keyOf, k, xs)}*/ /*{:_inductionTrigger ContainsK(keyOf, xs, k)}*/ /*{:_induction xs}*/ KeepThroughAbsentIsAll<K, V>(keyOf: V -> K, k: K, xs: seq<V>)
    requires !ContainsK(keyOf, xs, k)
    ensures SeqKeepThrough(keyOf, k, xs) == xs
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      assert keyOf(xs[0]) != k;
      KeepThroughAbsentIsAll(keyOf, k, xs[1..]);
    }
  }

  lemma OrderedLogWitness()
    ensures exists keyOf: ((int, string)) -> int, order: seq<int>, xs: seq<(int, string)> {:trigger SeqReorderByKeys(keyOf, order, xs)} :: UniqueKeys(keyOf, xs) && SeqReorderByKeys(keyOf, order, xs) != xs && ToMap(keyOf, SeqReorderByKeys(keyOf, order, xs)) == ToMap(keyOf, xs)
    ensures exists keyOf: ((int, string)) -> int, cut: int, xs: seq<(int, string)> {:trigger SeqKeepThrough(keyOf, cut, xs)} :: |xs| >= 2 && SeqKeepThrough(keyOf, cut, xs) == xs[..2] && SeqKeepThrough(keyOf, cut, xs) != xs
  {
    ghost var keyOf := (p: (int, string)) => p.0;
    ghost var xs := [(1, ""a""), (2, ""b""), (3, ""c"")];
    assert UniqueKeys(keyOf, xs) by {
      assert keyOf(xs[0]) == 1 && keyOf(xs[1]) == 2 && keyOf(xs[2]) == 3;
    }
    ghost var re := SeqReorderByKeys(keyOf, [3, 1], xs);
    assert re == [(3, ""c""), (1, ""a""), (2, ""b"")];
    ReorderPreservesToMap(keyOf, [3, 1], xs);
    assert ToMap(keyOf, re) == ToMap(keyOf, xs);
    assert SeqReorderByKeys(keyOf, [3, 3, 9, 1], xs) == [(3, ""c""), (1, ""a""), (2, ""b"")];
    ghost var kt := SeqKeepThrough(keyOf, 2, xs);
    assert kt == [(1, ""a""), (2, ""b"")];
    KeepThroughIsPrefix(keyOf, 2, xs);
    assert kt == xs[..2];
    KeepThroughIsSubmap(keyOf, 2, xs);
    assert 1 in ToMap(keyOf, kt) && ToMap(keyOf, kt)[1] == ToMap(keyOf, xs)[1];
    assert 3 !in ToMap(keyOf, kt) && 3 in ToMap(keyOf, xs);
    assert SeqKeepThrough(keyOf, 9, xs) == xs;
    assert SeqReorderByKeys(keyOf, [3, 1], xs) != xs;
    assert SeqKeepThrough(keyOf, 2, xs) == xs[..2] && SeqKeepThrough(keyOf, 2, xs) != xs;
  }

  import opened ConfluxSeqRoute
}

module ConfluxKeyedOps {
  lemma /*{:_inductionTrigger Filter(p, xs)}*/ /*{:_induction xs}*/ FilterMembership<V>(p: V -> bool, xs: seq<V>)
    ensures forall x: V {:trigger x in xs} {:trigger x in Filter(p, xs)} :: x in Filter(p, xs) ==> x in xs
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      FilterMembership(p, xs[1..]);
    }
  }

  lemma /*{:_inductionTrigger Filter(p, xs)}*/ /*{:_induction xs}*/ FilterPreservesUnique<K, V>(keyOf: V -> K, p: V -> bool, xs: seq<V>)
    requires UniqueKeys(keyOf, xs)
    ensures UniqueKeys(keyOf, Filter(p, xs))
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      UniqueTail(keyOf, xs);
      FilterPreservesUnique(keyOf, p, xs[1..]);
      if p(xs[0]) {
        assert Filter(p, xs) == [xs[0]] + Filter(p, xs[1..]);
        if keyOf(xs[0]) in SeqKeys(keyOf, Filter(p, xs[1..])) {
          SeqKeysMembership(keyOf, Filter(p, xs[1..]), keyOf(xs[0]));
          ghost var i :| 0 <= i < |Filter(p, xs[1..])| && keyOf(Filter(p, xs[1..])[i]) == keyOf(xs[0]);
          FilterMembership(p, xs[1..]);
          assert Filter(p, xs[1..])[i] in xs[1..];
          assert false;
        }
        ConsUnique(keyOf, xs[0], Filter(p, xs[1..]));
      } else {
        assert Filter(p, xs) == Filter(p, xs[1..]);
      }
    }
  }

  lemma MapPreservesUnique<K, V(!new)>(keyOf: V -> K, f: V -> V, xs: seq<V>)
    requires UniqueKeys(keyOf, xs) && KeyPreserving(keyOf, f)
    ensures UniqueKeys(keyOf, Map(f, xs))
    decreases xs
  {
    MapPreservesLength(f, xs);
    ghost var ys := Map(f, xs);
    forall i: int, j: int | 0 <= i < |ys| && 0 <= j < |ys| && keyOf(ys[i]) == keyOf(ys[j])
      ensures i == j
    {
      assert keyOf(xs[i]) == keyOf(xs[j]);
    }
  }

  import opened ConfluxSeqRoute

  import opened ConfluxOperators
}

module ConfluxFilterKeys {
  function FilterKeys<K, V>(p: (K, V) -> bool, m: map<K, V>): map<K, V>
    decreases m
  {
    map k: K {:trigger m[k]} {:trigger k in m} | k in m && p(k, m[k]) :: k := m[k]
  }

  lemma FilterKeysSubset<K, V>(p: (K, V) -> bool, m: map<K, V>)
    ensures FilterKeys(p, m).Keys <= m.Keys
    decreases m
  {
  }

  lemma FilterKeysMember<K, V>(p: (K, V) -> bool, m: map<K, V>, k: K)
    ensures k in FilterKeys(p, m) <==> k in m && p(k, m[k])
    decreases m
  {
  }

  lemma FilterKeysAt<K, V>(p: (K, V) -> bool, m: map<K, V>, k: K)
    requires k in FilterKeys(p, m)
    ensures FilterKeys(p, m)[k] == m[k]
    decreases m
  {
  }

  lemma FilterKeysKeySet<K, V>(p: (K, V) -> bool, m: map<K, V>)
    ensures FilterKeys(p, m).Keys == set k: K {:trigger m[k]} {:trigger k in m} | k in m && p(k, m[k])
    decreases m
  {
  }

  lemma FilterKeysIdentity<K, V>(m: map<K, V>)
    ensures FilterKeys((k: K, v: V) => true, m) == m
    decreases m
  {
  }

  lemma FilterKeysWitness()
    ensures exists p: (int, int) -> bool, m: map<int, int> {:trigger FilterKeys(p, m)} :: 1 in m && 1 !in FilterKeys(p, m) && FilterKeys(p, m) == map[2 := 20, 3 := 30]
  {
    ghost var p := (k: int, v: int) => v >= 20;
    ghost var m := map[1 := 10, 2 := 20, 3 := 30];
    assert FilterKeys(p, m) == map[2 := 20, 3 := 30];
    assert 1 in m && 1 !in FilterKeys(p, m) && FilterKeys(p, m) == map[2 := 20, 3 := 30];
  }

  function FilterSet<T>(p: T -> bool, s: set<T>): set<T>
    decreases s
  {
    set x: T {:trigger p(x)} {:trigger x in s} | x in s && p(x)
  }

  lemma FilterSetSubset<T>(p: T -> bool, s: set<T>)
    ensures FilterSet(p, s) <= s
    decreases s
  {
  }

  lemma FilterSetMember<T>(p: T -> bool, s: set<T>, x: T)
    ensures x in FilterSet(p, s) <==> x in s && p(x)
    decreases s
  {
  }

  lemma FilterSetIdentity<T>(s: set<T>)
    ensures FilterSet((x: T) => true, s) == s
    decreases s
  {
  }

  lemma FilterSetWitness()
    ensures exists p: int -> bool, s: set<int> {:trigger FilterSet(p, s)} :: 1 in s && 1 !in FilterSet(p, s) && FilterSet(p, s) == {2, 4}
  {
    ghost var p := (x: int) => x % 2 == 0;
    ghost var s := {1, 2, 3, 4};
    assert 1 in s && 1 !in FilterSet(p, s) && FilterSet(p, s) == {2, 4};
  }
}

module ConfluxChannel {
  function Accept<S, A>(r: Reducer<S, A>, h: HostState<S>, a: A): HostState<S>
    decreases h
  {
    HostState(r(h.canonical, a), h.nextSeq + 1)
  }

  function Receive<S, A>(r: Reducer<S, A>, c: ClientState<S>, a: A): ClientState<S>
    decreases c
  {
    ClientState(r(c.mirror, a), c.lastSeq + 1)
  }

  lemma AcceptAdvancesSeq<S, A>(r: Reducer<S, A>, h: HostState<S>, a: A)
    ensures Accept(r, h, a).nextSeq == h.nextSeq + 1
    decreases h
  {
  }

  function AcceptFold<S, A>(r: Reducer<S, A>, h: HostState<S>, actions: seq<A>): HostState<S>
    decreases |actions|
  {
    if |actions| == 0 then
      h
    else
      AcceptFold(r, Accept(r, h, actions[0]), actions[1..])
  }

  function ReceiveFold<S, A>(r: Reducer<S, A>, c: ClientState<S>, actions: seq<A>): ClientState<S>
    decreases |actions|
  {
    if |actions| == 0 then
      c
    else
      ReceiveFold(r, Receive(r, c, actions[0]), actions[1..])
  }

  lemma /*{:_inductionTrigger AcceptFold(r, h, actions)}*/ /*{:_induction h, actions}*/ HostSeqAdvances<S, A>(r: Reducer<S, A>, h: HostState<S>, actions: seq<A>)
    ensures AcceptFold(r, h, actions).nextSeq == h.nextSeq + |actions|
    decreases |actions|
  {
    if |actions| == 0 {
    } else {
      HostSeqAdvances(r, Accept(r, h, actions[0]), actions[1..]);
    }
  }

  lemma /*{:_inductionTrigger Fold(r, h.canonical, actions)}*/ /*{:_inductionTrigger AcceptFold(r, h, actions)}*/ /*{:_induction h, actions}*/ HostCanonicalIsFold<S, A>(r: Reducer<S, A>, h: HostState<S>, actions: seq<A>)
    ensures AcceptFold(r, h, actions).canonical == Fold(r, h.canonical, actions)
    decreases |actions|
  {
    if |actions| == 0 {
    } else {
      HostCanonicalIsFold(r, Accept(r, h, actions[0]), actions[1..]);
    }
  }

  lemma /*{:_inductionTrigger Fold(r, c.mirror, actions)}*/ /*{:_inductionTrigger ReceiveFold(r, c, actions)}*/ /*{:_induction c, actions}*/ ClientMirrorIsFold<S, A>(r: Reducer<S, A>, c: ClientState<S>, actions: seq<A>)
    ensures ReceiveFold(r, c, actions).mirror == Fold(r, c.mirror, actions)
    decreases |actions|
  {
    if |actions| == 0 {
    } else {
      ClientMirrorIsFold(r, Receive(r, c, actions[0]), actions[1..]);
    }
  }

  lemma /*{:_inductionTrigger ReceiveFold(r, c, actions), AcceptFold(r, h, actions).canonical}*/ /*{:_induction h, c, actions}*/ PeersConverge<S, A>(r: Reducer<S, A>, h: HostState<S>, c: ClientState<S>, actions: seq<A>)
    requires h.canonical == c.mirror
    ensures AcceptFold(r, h, actions).canonical == ReceiveFold(r, c, actions).mirror
    decreases h, c, actions
  {
    HostCanonicalIsFold(r, h, actions);
    ClientMirrorIsFold(r, c, actions);
  }

  lemma ChannelWitness()
    ensures exists r: Reducer<int, int>, h: HostState<int>, c: ClientState<int>, actions: seq<int> {:trigger AcceptFold(r, h, actions).nextSeq, ReceiveFold(r, c, actions).mirror} {:trigger ReceiveFold(r, c, actions), AcceptFold(r, h, actions).canonical} :: h.canonical == c.mirror && |actions| > 0 && AcceptFold(r, h, actions).canonical == ReceiveFold(r, c, actions).mirror && AcceptFold(r, h, actions).nextSeq == h.nextSeq + |actions|
  {
    ghost var add := (s: int, a: int) => s + a;
    ghost var h0 := HostState(0, 0);
    ghost var c0 := ClientState(0, 0);
    PeersConverge(add, h0, c0, [1, 2, 3]);
    assert AcceptFold(add, h0, [1, 2, 3]).canonical == ReceiveFold(add, c0, [1, 2, 3]).mirror;
    HostSeqAdvances(add, h0, [1, 2, 3]);
    assert AcceptFold(add, h0, [1, 2, 3]).nextSeq == 3;
  }

  import opened ConfluxContract

  datatype HostState<S> = HostState(canonical: S, nextSeq: nat)

  datatype ClientState<S> = ClientState(mirror: S, lastSeq: nat)
}

module ConfluxCommand {
  function CanonicalCommandCodecVersion(): string
  {
    ""oa-canonical-json-v1""
  }

  function IsLowerHexChar(c: char): bool
    decreases c
  {
    '0' <= c <= '9' || 'a' <= c <= 'f'
  }

  function IsLowerHex(s: string): bool
    decreases |s|
  {
    |s| == 0 || (IsLowerHexChar(s[0]) && IsLowerHex(s[1..]))
  }

  function RepeatChar(c: char, count: nat): string
    decreases count
  {
    if count == 0 then
      """"
    else
      [c] + RepeatChar(c, count - 1)
  }

  lemma /*{:_inductionTrigger RepeatChar(c, count)}*/ /*{:_induction c, count}*/ RepeatedLowerHex(c: char, count: nat)
    requires IsLowerHexChar(c)
    ensures |RepeatChar(c, count)| == count
    ensures IsLowerHex(RepeatChar(c, count))
    decreases count
  {
    if count > 0 {
      RepeatedLowerHex(c, count - 1);
    }
  }

  function ValidSha256Digest(digest: string): bool
    decreases digest
  {
    |digest| == 71 &&
    digest[..7] == ""sha256:"" &&
    IsLowerHex(digest[7..])
  }

  function CanonicalCommandBytes<C(==)>(codec: CommandIdentityCodec<C>, proposal: Proposal<C>): seq<bv8>
    decreases codec, proposal
  {
    codec.encode(proposal.command)
  }

  function ValidProposalIdentity<C(==)>(codec: CommandIdentityCodec<C>, proposal: Proposal<C>): bool
    decreases codec, proposal
  {
    codec.codecVersion == CanonicalCommandCodecVersion() &&
    proposal.codecVersion == codec.codecVersion &&
    codec.decode(CanonicalCommandBytes(codec, proposal)) == Some(proposal.command) &&
    ValidSha256Digest(proposal.commandDigest) &&
    proposal.commandDigest == codec.digest(CanonicalCommandBytes(codec, proposal))
  }

  function IdentityOf<C(==)>(codec: CommandIdentityCodec<C>, proposal: Proposal<C>): ProposalIdentity
    decreases codec, proposal
  {
    var bytes: seq<bv8> := CanonicalCommandBytes(codec, proposal);
    ProposalIdentity(""conflux-command-v1"", codec.codecVersion, proposal.channel, proposal.expectedServerSeq, codec.digest(bytes), bytes)
  }

  ghost predicate AuthorityCodecRoundTrips<S(!new), A(!new)>(codec: AuthorityCodec<S, A>)
    decreases codec
  {
    forall state: AuthorityState<S, A> {:trigger Some(state)} {:trigger codec.encode(state)} :: 
      codec.decode(codec.encode(state)) == Some(state)
  }

  ghost predicate AuthorityResultCodecRoundTrips<A(!new)>(codec: AuthorityResultCodec<A>)
    decreases codec
  {
    forall decision: AuthorityResult<A> {:trigger Some(decision)} {:trigger codec.encode(decision)} :: 
      codec.decode(codec.encode(decision)) == Some(decision)
  }

  function FindRecord<A>(history: DecisionHistory<A>, origin: CommandOrigin): Option<DecisionRecord<A>>
    decreases |history.records|
  {
    if |history.records| == 0 then
      None
    else if history.records[0].origin == origin then
      Some(history.records[0])
    else
      FindRecord(DecisionHistory(history.records[1..]), origin)
  }

  function FindDecision<A>(history: DecisionHistory<A>, origin: CommandOrigin): Option<AuthorityResult<A>>
    decreases history, origin
  {
    match FindRecord(history, origin)
    case None() =>
      None
    case Some(record) =>
      Some(record.result)
  }

  function RecordDecision<A>(history: DecisionHistory<A>, channel: string, origin: CommandOrigin, proposalIdentity: ProposalIdentity, result: AuthorityResult<A>): DecisionHistory<A>
    decreases history, channel, origin, proposalIdentity, result
  {
    var appended: History<DecisionRecord<A>> := DH.Append(DH.History(history.records), DecisionRecord(channel, origin, proposalIdentity, result));
    DecisionHistory(appended.entries)
  }

  lemma RecordDecisionUsesDurableAppend<A>(history: DecisionHistory<A>, channel: string, origin: CommandOrigin, proposalIdentity: ProposalIdentity, result: AuthorityResult<A>)
    ensures RecordDecision(history, channel, origin, proposalIdentity, result).records == history.records + [DecisionRecord(channel, origin, proposalIdentity, result)]
    ensures |RecordDecision(history, channel, origin, proposalIdentity, result).records| == |history.records| + 1
    decreases history, channel, origin, proposalIdentity, result
  {
    DH.AppendExtendsHistory(DH.History(history.records), DecisionRecord(channel, origin, proposalIdentity, result));
  }

  function StampActions<A>(channel: string, origin: CommandOrigin, nextSeq: nat, actions: seq<A>): seq<SequencedActionEnvelope<A>>
    decreases |actions|
  {
    if |actions| == 0 then
      []
    else
      [SequencedActionEnvelope(channel, nextSeq, origin, actions[0])] + StampActions(channel, origin, nextSeq + 1, actions[1..])
  }

  function EnvelopeActions<A>(envelopes: seq<SequencedActionEnvelope<A>>): seq<A>
    decreases |envelopes|
  {
    if |envelopes| == 0 then
      []
    else
      [envelopes[0].action] + EnvelopeActions(envelopes[1..])
  }

  function DecisionActions<A>(decision: AuthorityResult<A>): seq<SequencedActionEnvelope<A>>
    decreases decision
  {
    match decision
    case Rejected(_ /* _v1 */, _ /* _v2 */) =>
      []
    case Accepted(_ /* _v3 */, envelopes) =>
      envelopes
  }

  function RecordAcceptedActions<A>(record: DecisionRecord<A>): seq<SequencedActionEnvelope<A>>
    decreases record
  {
    DecisionActions(record.result)
  }

  function AcceptedHistory<A>(history: DecisionHistory<A>): seq<SequencedActionEnvelope<A>>
    decreases |history.records|
  {
    if |history.records| == 0 then
      []
    else
      RecordAcceptedActions(history.records[0]) + AcceptedHistory(DecisionHistory(history.records[1..]))
  }

  function ExpectedSequenceMatches<C(==), S, A>(state: AuthorityState<S, A>, proposal: Proposal<C>): bool
    decreases state, proposal
  {
    match proposal.expectedServerSeq
    case None() =>
      true
    case Some(expected) =>
      expected == state.host.nextSeq
  }

  function StaleExpectedServerSeq(): RejectionReason
  {
    RejectionReason(""staleExpectedServerSeq"", ""expected sequence does not match"", None)
  }

  function IdempotencyOriginConflict(recorded: ProposalIdentity, attempted: ProposalIdentity): RejectionReason
    decreases recorded, attempted
  {
    RejectionReason(""idempotencyOriginConflict"", ""command origin is already bound to a different proposal"", Some(recorded.commandDigest + "":"" + attempted.commandDigest))
  }

  function InvalidProposalIdentity(codecVersion: string): RejectionReason
    decreases codecVersion
  {
    RejectionReason(""invalidProposalIdentity"", ""command codec version, canonical encoding round-trip, or digest is invalid"", Some(codecVersion))
  }

  function EmptyAuthorizedActions(): RejectionReason
  {
    RejectionReason(""emptyAuthorizedActions"", ""mutating command authority requires at least one action"", None)
  }

  function RecordRejection<C(==), S, A>(state: AuthorityState<S, A>, proposal: Proposal<C>, identity: ProposalIdentity, reason: RejectionReason): ReconcileResult<S, A>
    decreases state, proposal, identity, reason
  {
    var decision: AuthorityResult<A> := Rejected(proposal.origin, reason);
    ReconcileResult(AuthorityState(state.host, RecordDecision(state.history, proposal.channel, proposal.origin, identity, decision)), decision, true)
  }

  function Reconcile<C(==), S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>): ReconcileResult<S, A>
    decreases state, proposal, commandCodec
  {
    if !ValidProposalIdentity(commandCodec, proposal) then
      ReconcileResult(state, Rejected(proposal.origin, InvalidProposalIdentity(proposal.codecVersion)), false)
    else
      match FindRecord(state.history, proposal.origin) case Some(recorded) => (if recorded.proposalIdentity == IdentityOf(commandCodec, proposal) then ReconcileResult(state, recorded.result, false) else ReconcileResult(state, Rejected(proposal.origin, IdempotencyOriginConflict(recorded.proposalIdentity, IdentityOf(commandCodec, proposal))), false)) case None() => if !ExpectedSequenceMatches(state, proposal) then RecordRejection(state, proposal, IdentityOf(commandCodec, proposal), StaleExpectedServerSeq()) else match authorizeAndLower(state.host, proposal.command) case Denied(reason) => RecordRejection(state, proposal, IdentityOf(commandCodec, proposal), reason) case Allowed(actions) => if |actions| == 0 then RecordRejection(state, proposal, IdentityOf(commandCodec, proposal), EmptyAuthorizedActions()) else var envelopes: seq<SequencedActionEnvelope<A>> := StampActions(proposal.channel, proposal.origin, state.host.nextSeq, actions); var decision: AuthorityResult<A> := Accepted(proposal.origin, envelopes); ReconcileResult(AuthorityState(AcceptFold(reducer, state.host, actions), RecordDecision(state.history, proposal.channel, proposal.origin, IdentityOf(commandCodec, proposal), decision)), decision, true)
  }

  function MakeCheckpoint<S, A>(historyId: string, reducerSchemaVersion: string, hashBytes: seq<bv8> -> string, codec: AuthorityCodec<S, A>, state: AuthorityState<S, A>): CommandCheckpoint<S, A>
    decreases historyId, reducerSchemaVersion, codec, state
  {
    CommandCheckpoint(DH.MakeCheckpoint(historyId, reducerSchemaVersion, (authority: AuthorityState<S, A>) => authority.host.nextSeq, hashBytes, DH.StateCodec(codec.encode, codec.decode), state))
  }

  function RestoreCheckpoint<S, A>(expectedHistoryId: string, expectedReducerSchemaVersion: string, hashBytes: seq<bv8> -> string, codec: AuthorityCodec<S, A>, checkpoint: CommandCheckpoint<S, A>): Option<AuthorityState<S, A>>
    decreases expectedHistoryId, expectedReducerSchemaVersion, codec, checkpoint
  {
    DH.RestoreCheckpoint(expectedHistoryId, expectedReducerSchemaVersion, (authority: AuthorityState<S, A>) => authority.host.nextSeq, hashBytes, DH.StateCodec(codec.encode, codec.decode), checkpoint.durable)
  }

  predicate EnvelopesPreserveOrigin<A>(origin: CommandOrigin, envelopes: seq<SequencedActionEnvelope<A>>)
    decreases |envelopes|
  {
    |envelopes| == 0 || (envelopes[0].origin == origin && EnvelopesPreserveOrigin(origin, envelopes[1..]))
  }

  predicate ChannelsPreserved<A>(channel: string, envelopes: seq<SequencedActionEnvelope<A>>)
    decreases |envelopes|
  {
    |envelopes| == 0 || (envelopes[0].channel == channel && ChannelsPreserved(channel, envelopes[1..]))
  }

  predicate SequencesContiguous<A>(start: nat, envelopes: seq<SequencedActionEnvelope<A>>)
    decreases |envelopes|
  {
    |envelopes| == 0 || (envelopes[0].serverSeq == start && SequencesContiguous(start + 1, envelopes[1..]))
  }

  lemma /*{:_inductionTrigger StampActions(channel, origin, start, actions)}*/ /*{:_induction channel, origin, start, actions}*/ StampActionsPreservesOrigin<A>(channel: string, origin: CommandOrigin, start: nat, actions: seq<A>)
    ensures EnvelopesPreserveOrigin(origin, StampActions(channel, origin, start, actions))
    decreases |actions|
  {
    if |actions| > 0 {
      StampActionsPreservesOrigin(channel, origin, start + 1, actions[1..]);
    }
  }

  lemma /*{:_inductionTrigger StampActions(channel, origin, start, actions)}*/ /*{:_induction channel, origin, start, actions}*/ StampActionsPreservesChannel<A>(channel: string, origin: CommandOrigin, start: nat, actions: seq<A>)
    ensures ChannelsPreserved(channel, StampActions(channel, origin, start, actions))
    decreases |actions|
  {
    if |actions| > 0 {
      StampActionsPreservesChannel(channel, origin, start + 1, actions[1..]);
    }
  }

  lemma /*{:_inductionTrigger StampActions(channel, origin, start, actions)}*/ /*{:_induction channel, origin, start, actions}*/ AcceptedSequencesContiguous<A>(channel: string, origin: CommandOrigin, start: nat, actions: seq<A>)
    ensures SequencesContiguous(start, StampActions(channel, origin, start, actions))
    decreases |actions|
  {
    if |actions| > 0 {
      AcceptedSequencesContiguous(channel, origin, start + 1, actions[1..]);
    }
  }

  lemma /*{:_inductionTrigger StampActions(channel, origin, start, actions)}*/ /*{:_induction channel, origin, start, actions}*/ StampActionsRoundTrip<A>(channel: string, origin: CommandOrigin, start: nat, actions: seq<A>)
    ensures EnvelopeActions(StampActions(channel, origin, start, actions)) == actions
    decreases |actions|
  {
    if |actions| > 0 {
      StampActionsRoundTrip(channel, origin, start + 1, actions[1..]);
    }
  }

  lemma RejectUnchanged<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>)
    requires Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision.Rejected?
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority.host == state.host
    decreases state, proposal, commandCodec
  {
  }

  lemma RejectAssignsNoSequence<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>)
    requires Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision.Rejected?
    ensures DecisionActions(Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision) == []
    decreases state, proposal, commandCodec
  {
  }

  lemma FreshDecisionRecordedOnce<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>)
    requires FindRecord(state.history, proposal.origin) == None
    requires ValidProposalIdentity(commandCodec, proposal)
    ensures |Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority.history.records| == |state.history.records| + 1
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).isFresh
    decreases state, proposal, commandCodec
  {
    if !ExpectedSequenceMatches(state, proposal) {
      RecordDecisionUsesDurableAppend(state.history, proposal.channel, proposal.origin, IdentityOf(commandCodec, proposal), Rejected(proposal.origin, StaleExpectedServerSeq()));
    } else {
      match authorizeAndLower(state.host, proposal.command)
      case {:split false} Denied(reason) =>
        RecordDecisionUsesDurableAppend(state.history, proposal.channel, proposal.origin, IdentityOf(commandCodec, proposal), Rejected(proposal.origin, reason));
      case {:split false} Allowed(actions) =>
        if |actions| == 0 {
          RecordDecisionUsesDurableAppend(state.history, proposal.channel, proposal.origin, IdentityOf(commandCodec, proposal), Rejected(proposal.origin, EmptyAuthorizedActions()));
        } else {
          RecordDecisionUsesDurableAppend(state.history, proposal.channel, proposal.origin, IdentityOf(commandCodec, proposal), Accepted(proposal.origin, StampActions(proposal.channel, proposal.origin, state.host.nextSeq, actions)));
        }
    }
  }

  lemma /*{:_inductionTrigger StampActions(proposal.channel, proposal.origin, state.host.nextSeq, actions)}*/ /*{:_inductionTrigger AcceptFold(reducer, state.host, actions)}*/ /*{:_inductionTrigger |actions|}*/ /*{:_inductionTrigger Authorization<A>.Allowed(actions)}*/ /*{:_induction actions}*/ AcceptIsAcceptFold<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>, actions: seq<A>)
    requires FindRecord(state.history, proposal.origin) == None
    requires ValidProposalIdentity(commandCodec, proposal)
    requires ExpectedSequenceMatches(state, proposal)
    requires authorizeAndLower(state.host, proposal.command) == Allowed(actions)
    requires |actions| > 0
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority.host == AcceptFold(reducer, state.host, actions)
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision == Accepted(proposal.origin, StampActions(proposal.channel, proposal.origin, state.host.nextSeq, actions))
    decreases state, proposal, commandCodec, actions
  {
  }

  lemma OriginPreserved<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>, actions: seq<A>)
    requires FindRecord(state.history, proposal.origin) == None
    requires ValidProposalIdentity(commandCodec, proposal)
    requires ExpectedSequenceMatches(state, proposal)
    requires authorizeAndLower(state.host, proposal.command) == Allowed(actions)
    requires |actions| > 0
    ensures EnvelopesPreserveOrigin(proposal.origin, DecisionActions(Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision))
    decreases state, proposal, commandCodec, actions
  {
    StampActionsPreservesOrigin(proposal.channel, proposal.origin, state.host.nextSeq, actions);
  }

  lemma AcceptedDecisionSequencesContiguous<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>, actions: seq<A>)
    requires FindRecord(state.history, proposal.origin) == None
    requires ValidProposalIdentity(commandCodec, proposal)
    requires ExpectedSequenceMatches(state, proposal)
    requires authorizeAndLower(state.host, proposal.command) == Allowed(actions)
    requires |actions| > 0
    ensures SequencesContiguous(state.host.nextSeq, DecisionActions(Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision))
    ensures ChannelsPreserved(proposal.channel, DecisionActions(Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision))
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority.host.nextSeq == state.host.nextSeq + |actions|
    decreases state, proposal, commandCodec, actions
  {
    AcceptedSequencesContiguous(proposal.channel, proposal.origin, state.host.nextSeq, actions);
    StampActionsPreservesChannel(proposal.channel, proposal.origin, state.host.nextSeq, actions);
    HostSeqAdvances(reducer, state.host, actions);
  }

  lemma DuplicateIsIdempotent<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>, recorded: DecisionRecord<A>)
    requires FindRecord(state.history, proposal.origin) == Some(recorded)
    requires ValidProposalIdentity(commandCodec, proposal)
    requires recorded.proposalIdentity == IdentityOf(commandCodec, proposal)
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority == state
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision == recorded.result
    ensures !Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).isFresh
    decreases state, proposal, commandCodec, recorded
  {
  }

  lemma DuplicateReturnsIdenticalDecisionBytes<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, recorded: DecisionRecord<A>, commandCodec: CommandIdentityCodec<C>, codec: AuthorityResultCodec<A>)
    requires FindRecord(state.history, proposal.origin) == Some(recorded)
    requires ValidProposalIdentity(commandCodec, proposal)
    requires recorded.proposalIdentity == IdentityOf(commandCodec, proposal)
    ensures codec.encode(Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision) == codec.encode(recorded.result)
    decreases state, proposal, recorded, commandCodec, codec
  {
    DuplicateIsIdempotent(reducer, state, proposal, authorizeAndLower, commandCodec, recorded);
  }

  lemma ReusedOriginWithDifferentProposalConflicts<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>, recorded: DecisionRecord<A>)
    requires FindRecord(state.history, proposal.origin) == Some(recorded)
    requires ValidProposalIdentity(commandCodec, proposal)
    requires recorded.proposalIdentity != IdentityOf(commandCodec, proposal)
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority == state
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision == Rejected(proposal.origin, IdempotencyOriginConflict(recorded.proposalIdentity, IdentityOf(commandCodec, proposal)))
    ensures !Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).isFresh
    decreases state, proposal, commandCodec, recorded
  {
  }

  lemma SameDigestDifferentCanonicalCommandConflicts<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>, recorded: DecisionRecord<A>)
    requires FindRecord(state.history, proposal.origin) == Some(recorded)
    requires ValidProposalIdentity(commandCodec, proposal)
    requires recorded.proposalIdentity.commandDigest == proposal.commandDigest
    requires recorded.proposalIdentity.canonicalCommandBytes != CanonicalCommandBytes(commandCodec, proposal)
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority == state
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision == Rejected(proposal.origin, IdempotencyOriginConflict(recorded.proposalIdentity, IdentityOf(commandCodec, proposal)))
    ensures !Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).isFresh
    decreases state, proposal, commandCodec, recorded
  {
  }

  lemma InvalidProposalIdentityRejectsBeforeDedupe<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>)
    requires !ValidProposalIdentity(commandCodec, proposal)
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority == state
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision == Rejected(proposal.origin, InvalidProposalIdentity(proposal.codecVersion))
    ensures !Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).isFresh
    decreases state, proposal, commandCodec
  {
  }

  lemma EmptyAuthorizationRejects<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>)
    requires FindRecord(state.history, proposal.origin) == None
    requires ValidProposalIdentity(commandCodec, proposal)
    requires ExpectedSequenceMatches(state, proposal)
    requires authorizeAndLower(state.host, proposal.command) == Allowed([])
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision == Rejected(proposal.origin, EmptyAuthorizedActions())
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority.host == state.host
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).isFresh
    decreases state, proposal, commandCodec
  {
  }

  lemma DecisionTotal<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>)
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision.Rejected? || Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision.Accepted?
    decreases state, proposal, commandCodec
  {
  }

  lemma StaleExpectedSequenceRejects<C, S, A>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>)
    requires FindRecord(state.history, proposal.origin) == None
    requires ValidProposalIdentity(commandCodec, proposal)
    requires !ExpectedSequenceMatches(state, proposal)
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision == Rejected(proposal.origin, StaleExpectedServerSeq())
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority.host == state.host
    decreases state, proposal, commandCodec
  {
  }

  lemma RestoreRoundTrips<S(!new), A(!new)>(historyId: string, reducerSchemaVersion: string, hashBytes: seq<bv8> -> string, codec: AuthorityCodec<S, A>, state: AuthorityState<S, A>)
    requires AuthorityCodecRoundTrips(codec)
    ensures RestoreCheckpoint(historyId, reducerSchemaVersion, hashBytes, codec, MakeCheckpoint(historyId, reducerSchemaVersion, hashBytes, codec, state)) == Some(state)
    decreases historyId, reducerSchemaVersion, codec, state
  {
  }

  lemma RetryAfterRestartIsIdempotent<C, S(!new), A(!new)>(reducer: Reducer<S, A>, state: AuthorityState<S, A>, proposal: Proposal<C>, authorizeAndLower: (HostState<S>, C) -> Authorization<A>, commandCodec: CommandIdentityCodec<C>, recorded: DecisionRecord<A>, historyId: string, reducerSchemaVersion: string, hashBytes: seq<bv8> -> string, codec: AuthorityCodec<S, A>)
    requires AuthorityCodecRoundTrips(codec)
    requires FindRecord(state.history, proposal.origin) == Some(recorded)
    requires ValidProposalIdentity(commandCodec, proposal)
    requires recorded.proposalIdentity == IdentityOf(commandCodec, proposal)
    ensures RestoreCheckpoint(historyId, reducerSchemaVersion, hashBytes, codec, MakeCheckpoint(historyId, reducerSchemaVersion, hashBytes, codec, state)) == Some(state)
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).authority == state
    ensures Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).decision == recorded.result
    ensures !Reconcile(reducer, state, proposal, authorizeAndLower, commandCodec).isFresh
    decreases state, proposal, commandCodec, recorded, historyId, reducerSchemaVersion, codec
  {
    RestoreRoundTrips(historyId, reducerSchemaVersion, hashBytes, codec, state);
    DuplicateIsIdempotent(reducer, state, proposal, authorizeAndLower, commandCodec, recorded);
  }

  lemma CommandWitness()
    ensures exists reducer: Reducer<int, int>, state0: AuthorityState<int, int>, proposal: Proposal<int>, lower: (HostState<int>, int) -> Authorization<int>, commandCodec: CommandIdentityCodec<int> {:trigger Reconcile(reducer, state0, proposal, lower, commandCodec).authority} {:trigger Reconcile(reducer, state0, proposal, lower, commandCodec).decision.Accepted?} :: Reconcile(reducer, state0, proposal, lower, commandCodec).decision.Accepted? && Reconcile(reducer, state0, proposal, lower, commandCodec).isFresh && Reconcile(reducer, Reconcile(reducer, state0, proposal, lower, commandCodec).authority, proposal, lower, commandCodec).decision == Reconcile(reducer, state0, proposal, lower, commandCodec).decision && !Reconcile(reducer, Reconcile(reducer, state0, proposal, lower, commandCodec).authority, proposal, lower, commandCodec).isFresh
  {
    ghost var reducer := (state: int, action: int) => state + action;
    ghost var lower := (host: HostState<int>, command: int) => if command >= 0 then Allowed([command]) else Denied(RejectionReason(""invalid"", ""command must be nonnegative"", None));
    ghost var origin := CommandOrigin(""fixture-client"", 1);
    ghost var state0 := AuthorityState(HostState(0, 7), DecisionHistory([]));
    ghost var digest4 := ""sha256:"" + RepeatChar('4', 64);
    ghost var commandCodec := CommandIdentityCodec(CanonicalCommandCodecVersion(), (command: int) => if command == 4 then [4] else [0], (bytes: seq<bv8>) => if bytes == [4] then Some(4) else None, (bytes: seq<bv8>) => if bytes == [4] then digest4 else ""sha256:"" + RepeatChar('0', 64));
    ghost var proposal := Proposal(""fixture:/counter"", origin, Some(7), CanonicalCommandCodecVersion(), digest4, 4);
    ghost var accepted := Reconcile(reducer, state0, proposal, lower, commandCodec);
    assert FindDecision(state0.history, proposal.origin) == None;
    assert ExpectedSequenceMatches(state0, proposal);
    assert lower(state0.host, proposal.command) == Allowed([4]);
    RepeatedLowerHex('4', 64);
    assert ValidProposalIdentity(commandCodec, proposal);
    AcceptIsAcceptFold(reducer, state0, proposal, lower, commandCodec, [4]);
    assert accepted.decision.Accepted?;
    assert accepted.isFresh;
    assert accepted.authority.host == HostState(4, 8);
    assert |accepted.authority.history.records| == 1;
    ghost var duplicate := Reconcile(reducer, accepted.authority, proposal, lower, commandCodec);
    assert duplicate.authority == accepted.authority;
    assert duplicate.decision == accepted.decision;
    assert !duplicate.isFresh;
  }

  import opened ConfluxContract

  import opened ConfluxChannel

  import DH = ConfluxDurableHistory

  datatype CommandOrigin = CommandOrigin(clientId: string, clientSeq: nat)

  datatype Proposal<!C(==)> = Proposal(channel: string, origin: CommandOrigin, expectedServerSeq: Option<nat>, codecVersion: string, commandDigest: string, command: C)

  datatype ProposalIdentity = ProposalIdentity(protocol: string, codecVersion: string, channel: string, expectedServerSeq: Option<nat>, commandDigest: string, canonicalCommandBytes: seq<bv8>)

  datatype CommandIdentityCodec<!C(==)> = CommandIdentityCodec(codecVersion: string, encode: C -> seq<bv8>, decode: seq<bv8> -> Option<C>, digest: seq<bv8> -> string)

  datatype RejectionReason = RejectionReason(code: string, message: string, detailsDigest: Option<string>)

  datatype SequencedActionEnvelope<!A> = SequencedActionEnvelope(channel: string, serverSeq: nat, origin: CommandOrigin, action: A)

  datatype AuthorityResult<!A> = Rejected(origin: CommandOrigin, reason: RejectionReason) | Accepted(origin: CommandOrigin, sequencedActions: seq<SequencedActionEnvelope<A>>)

  datatype Authorization<!A> = Denied(reason: RejectionReason) | Allowed(actions: seq<A>)

  datatype DecisionRecord<!A> = DecisionRecord(channel: string, origin: CommandOrigin, proposalIdentity: ProposalIdentity, result: AuthorityResult<A>)

  datatype DecisionHistory<!A> = DecisionHistory(records: seq<DecisionRecord<A>>)

  datatype AuthorityState<!S, !A> = AuthorityState(host: HostState<S>, history: DecisionHistory<A>)

  datatype ReconcileResult<!S, !A> = ReconcileResult(authority: AuthorityState<S, A>, decision: AuthorityResult<A>, isFresh: bool)

  datatype AuthorityCodec<!S, !A> = AuthorityCodec(encode: AuthorityState<S, A> -> seq<bv8>, decode: seq<bv8> -> Option<AuthorityState<S, A>>)

  datatype AuthorityResultCodec<!A> = AuthorityResultCodec(encode: AuthorityResult<A> -> seq<bv8>, decode: seq<bv8> -> Option<AuthorityResult<A>>)

  datatype CommandCheckpoint<!S, !A> = CommandCheckpoint(durable: DH.ReplayCheckpoint<AuthorityState<S, A>>)
}

module ConfluxChannelManifest {
  function Canonical<S, A, W>(m: ChannelManifest<S, A, W>, actions: seq<A>): S
    decreases m, actions
  {
    Fold(m.apply, m.initial, actions)
  }

  function View<S, A, W>(m: ChannelManifest<S, A, W>, actions: seq<A>): W
    decreases m, actions
  {
    m.readModel(Canonical(m, actions))
  }

  lemma /*{:_inductionTrigger Fold(m.apply, Canonical(m, xs), ys)}*/ /*{:_inductionTrigger xs + ys}*/ /*{:_induction ys}*/ ViewResumesFromCheckpoint<S, A, W>(m: ChannelManifest<S, A, W>, xs: seq<A>, ys: seq<A>)
    ensures View(m, xs + ys) == m.readModel(Fold(m.apply, Canonical(m, xs), ys))
    decreases m, xs, ys
  {
    FoldConcat(m.apply, m.initial, xs, ys);
  }

  lemma ManifestWitness()
    ensures exists m: ChannelManifest<int, int, int>, xs: seq<int>, ys: seq<int>, w: int {:trigger Some(w), m.decode, xs + ys} {:trigger Some(w), m.apply, xs + ys} {:trigger Some(w), m.readModel, xs + ys} {:trigger m.decode(w), Fold(m.apply, Canonical(m, xs), ys)} :: |xs + ys| > 0 && View(m, xs + ys) == m.readModel(Fold(m.apply, Canonical(m, xs), ys)) && m.decode(w) == Some(w)
  {
    ghost var m: ChannelManifest<int, int, int> := ChannelManifest(0, (s: int, a: int) => s + a, (w: int) => Some(w), (s: int) => s);
    ViewResumesFromCheckpoint(m, [1, 2], [3]);
    assert View(m, [1, 2, 3]) == 6;
    assert m.decode(7) == Some(7);
  }

  import opened ConfluxContract

  datatype ChannelManifest<!S, !A, !W> = ChannelManifest(initial: S, apply: Reducer<S, A>, decode: W -> Option<A>, readModel: S -> W)
}

module ConfluxConvergence {
  function FoldHost<S, A>(r: Reducer<S, A>, h: HostState<S>, xs: seq<A>): HostState<S>
    decreases h, xs
  {
    Fold((hs: HostState<S>, a: A) => Accept(r, hs, a), h, xs)
  }

  function FoldClient<S, A>(r: Reducer<S, A>, c: ClientState<S>, xs: seq<A>): ClientState<S>
    decreases c, xs
  {
    Fold((cs: ClientState<S>, a: A) => Receive(r, cs, a), c, xs)
  }

  lemma /*{:_inductionTrigger Fold(r, s0, xs)}*/ /*{:_inductionTrigger FoldHost(r, HostState<S>.HostState(s0, k), xs)}*/ /*{:_induction xs}*/ HostCanonicalIsFold<S, A>(r: Reducer<S, A>, s0: S, k: nat, xs: seq<A>)
    ensures FoldHost(r, HostState(s0, k), xs).canonical == Fold(r, s0, xs)
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      HostCanonicalIsFold(r, r(s0, xs[0]), k + 1, xs[1..]);
    }
  }

  lemma /*{:_inductionTrigger Fold(r, s0, xs)}*/ /*{:_inductionTrigger FoldClient(r, ClientState<S>.ClientState(s0, k), xs)}*/ /*{:_induction xs}*/ ClientMirrorIsFold<S, A>(r: Reducer<S, A>, s0: S, k: nat, xs: seq<A>)
    ensures FoldClient(r, ClientState(s0, k), xs).mirror == Fold(r, s0, xs)
    decreases |xs|
  {
    if |xs| == 0 {
    } else {
      ClientMirrorIsFold(r, r(s0, xs[0]), k + 1, xs[1..]);
    }
  }

  lemma MirrorConverges<S, A>(r: Reducer<S, A>, s0: S, xs: seq<A>)
    ensures FoldHost(r, HostState(s0, 0), xs).canonical == FoldClient(r, ClientState(s0, 0), xs).mirror
    decreases xs
  {
    HostCanonicalIsFold(r, s0, 0, xs);
    ClientMirrorIsFold(r, s0, 0, xs);
  }

  function InitClients<S>(s0: S, n: nat): seq<ClientState<S>>
    decreases n
  {
    seq(n, (_ /* _v4 */: int) => ClientState(s0, 0))
  }

  function FanoutFold<S, A>(r: Reducer<S, A>, clients: seq<ClientState<S>>, xs: seq<A>): seq<ClientState<S>>
    decreases clients, xs
  {
    seq(|clients|, (i: int) requires 0 <= i < |clients| => FoldClient(r, clients[i], xs))
  }

  lemma MultiplexConverges<S, A>(r: Reducer<S, A>, s0: S, xs: seq<A>, n: nat)
    ensures forall i: int {:trigger FanoutFold(r, InitClients(s0, n), xs)[i]} :: 0 <= i < n ==> FanoutFold(r, InitClients(s0, n), xs)[i].mirror == FoldHost(r, HostState(s0, 0), xs).canonical
    decreases xs, n
  {
    HostCanonicalIsFold(r, s0, 0, xs);
    ghost var clients := InitClients(s0, n);
    forall i: int | 0 <= i < n
      ensures FanoutFold(r, clients, xs)[i].mirror == FoldHost(r, HostState(s0, 0), xs).canonical
    {
      assert FanoutFold(r, clients, xs)[i] == FoldClient(r, clients[i], xs);
      assert clients[i] == ClientState(s0, 0);
      ClientMirrorIsFold(r, s0, 0, xs);
    }
  }

  function IntAdd(): Reducer<int, int>
  {
    (s: int, a: int) => s + a
  }

  lemma MultiplexWitness()
    ensures FoldHost(IntAdd(), HostState(0, 0), [1, 2, 3]).canonical == 6
    ensures forall i: int {:trigger FanoutFold(IntAdd(), InitClients(0, 3), [1, 2, 3])[i]} :: 0 <= i < 3 ==> FanoutFold(IntAdd(), InitClients(0, 3), [1, 2, 3])[i].mirror == FoldHost(IntAdd(), HostState(0, 0), [1, 2, 3]).canonical
  {
    MultiplexConverges(IntAdd(), 0, [1, 2, 3], 3);
    ghost var mirrors := FanoutFold(IntAdd(), InitClients(0, 3), [1, 2, 3]);
    assert FoldHost(IntAdd(), HostState(0, 0), [1, 2, 3]).canonical == 6;
    assert forall i: int {:trigger mirrors[i]} :: 0 <= i < 3 ==> mirrors[i].mirror == 6;
  }

  import opened ConfluxContract

  import opened ConfluxChannel
}

module ConfluxBudgetConvergence {
  function ApplyObservation(budget: RB.ResourceCeilings, phase: RB.ExecutionPhase, state: SR.SupervisionState, observation: RB.ResourceObservation): SR.SupervisionState
    decreases budget, phase, state, observation
  {
    match state
    case SupervisionTripped(record) =>
      state
    case SupervisionRunning(samplesSeen) =>
      var verdict: ResourceVerdict := RB.DecideInFlight(budget, phase, observation);
      if verdict.outcome == RB.EnforcementKill then
        SR.SupervisionTripped(SR.FirstBreachV1(samplesSeen, verdict, verdict.observed.None?))
      else
        SR.SupervisionRunning(samplesSeen + 1)
  }

  function Drive(budget: RB.ResourceCeilings, phase: RB.ExecutionPhase, observations: seq<RB.ResourceObservation>): SR.SupervisionState
    decreases budget, phase, observations
  {
    CC.Fold(SupervisionReducer(budget, phase), SR.SupervisionRunning(0), observations)
  }

  function SupervisionReducer(budget: RB.ResourceCeilings, phase: RB.ExecutionPhase): CC.Reducer<SR.SupervisionState, RB.ResourceObservation>
    decreases budget, phase
  {
    (state: SR.SupervisionState, observation: RB.ResourceObservation) => ApplyObservation(budget, phase, state, observation)
  }

  lemma /*{:_inductionTrigger _default.Fold(SupervisionReducer(budget, phase), SupervisionState.SupervisionRunning(seen), observations)}*/ /*{:_inductionTrigger |observations|}*/ /*{:_induction observations}*/ NoTripPrefixAdvances(budget: RB.ResourceCeilings, phase: RB.ExecutionPhase, observations: seq<RB.ResourceObservation>, seen: nat)
    requires forall i: int {:trigger observations[i]} :: 0 <= i < |observations| ==> RB.DecideInFlight(budget, phase, observations[i]).outcome != RB.EnforcementKill
    ensures CC.Fold(SupervisionReducer(budget, phase), SR.SupervisionRunning(seen), observations) == SR.SupervisionRunning(seen + |observations|)
    decreases |observations|
  {
    if |observations| > 0 {
      assert RB.DecideInFlight(budget, phase, observations[0]).outcome != RB.EnforcementKill;
      assert forall i: int {:trigger observations[1..][i]} :: 0 <= i < |observations[1..]| ==> RB.DecideInFlight(budget, phase, observations[1..][i]).outcome != RB.EnforcementKill by {
        forall i: int | 0 <= i < |observations[1..]|
          ensures RB.DecideInFlight(budget, phase, observations[1..][i]).outcome != RB.EnforcementKill
        {
          assert observations[1..][i] == observations[i + 1];
        }
      }
      NoTripPrefixAdvances(budget, phase, observations[1..], seen + 1);
    }
  }

  lemma /*{:_inductionTrigger _default.Fold(SupervisionReducer(budget, phase), SupervisionState.SupervisionTripped(firstBreach), observations)}*/ /*{:_induction observations, firstBreach}*/ KillIsAbsorbing(budget: RB.ResourceCeilings, phase: RB.ExecutionPhase, observations: seq<RB.ResourceObservation>, firstBreach: SR.FirstBreachV1)
    ensures CC.Fold(SupervisionReducer(budget, phase), SR.SupervisionTripped(firstBreach), observations) == SR.SupervisionTripped(firstBreach)
    decreases |observations|
  {
    if |observations| > 0 {
      KillIsAbsorbing(budget, phase, observations[1..], firstBreach);
    }
  }

  lemma EarliestTripWholeStream(budget: RB.ResourceCeilings, phase: RB.ExecutionPhase, prefix: seq<RB.ResourceObservation>, firstBreach: RB.ResourceObservation, suffix: seq<RB.ResourceObservation>)
    requires forall i: int {:trigger prefix[i]} :: 0 <= i < |prefix| ==> RB.DecideInFlight(budget, phase, prefix[i]).outcome != RB.EnforcementKill
    requires RB.DecideInFlight(budget, phase, firstBreach).outcome == RB.EnforcementKill
    ensures Drive(budget, phase, prefix + [firstBreach] + suffix) == SR.SupervisionTripped(SR.FirstBreachV1(|prefix|, RB.DecideInFlight(budget, phase, firstBreach), RB.DecideInFlight(budget, phase, firstBreach).observed.None?))
    decreases budget, phase, prefix, firstBreach, suffix
  {
    ghost var step := SupervisionReducer(budget, phase);
    assert prefix + [firstBreach] + suffix == prefix + ([firstBreach] + suffix);
    CC.FoldConcat(step, SR.SupervisionRunning(0), prefix, [firstBreach] + suffix);
    assert Drive(budget, phase, prefix + [firstBreach] + suffix) == CC.Fold(step, CC.Fold(step, SR.SupervisionRunning(0), prefix), [firstBreach] + suffix);
    NoTripPrefixAdvances(budget, phase, prefix, 0);
    ghost var record := SR.FirstBreachV1(|prefix|, RB.DecideInFlight(budget, phase, firstBreach), RB.DecideInFlight(budget, phase, firstBreach).observed.None?);
    assert CC.Fold(step, SR.SupervisionRunning(|prefix|), [firstBreach]) == SR.SupervisionTripped(record);
    CC.FoldConcat(step, SR.SupervisionRunning(|prefix|), [firstBreach], suffix);
    assert CC.Fold(step, SR.SupervisionRunning(|prefix|), [firstBreach] + suffix) == CC.Fold(step, SR.SupervisionTripped(record), suffix);
    KillIsAbsorbing(budget, phase, suffix, record);
  }

  lemma /*{:_inductionTrigger _default.Fold(SupervisionReducer(budget, phase), SupervisionState.SupervisionTripped(firstBreach), suffix)}*/ /*{:_induction suffix, firstBreach}*/ NoLaterObservationRevives(budget: RB.ResourceCeilings, phase: RB.ExecutionPhase, suffix: seq<RB.ResourceObservation>, firstBreach: SR.FirstBreachV1)
    ensures CC.Fold(SupervisionReducer(budget, phase), SR.SupervisionTripped(firstBreach), suffix) == SR.SupervisionTripped(firstBreach)
    decreases budget, phase, suffix, firstBreach
  {
    KillIsAbsorbing(budget, phase, suffix, firstBreach);
  }

  lemma EarliestTripWitness()
    ensures exists budget: RB.ResourceCeilings, phase: RB.ExecutionPhase, obs: seq<RB.ResourceObservation>, at: nat {:trigger obs[at], Drive(budget, phase, obs)} :: 0 < at < |obs| && Drive(budget, phase, obs) == SR.SupervisionTripped(SR.FirstBreachV1(at, RB.DecideInFlight(budget, phase, obs[at]), RB.DecideInFlight(budget, phase, obs[at]).observed.None?))
  {
    ghost var budget := RB.ResourceCeilings(RB.PhaseTimeCeilings(10, 20), RB.PhaseMemoryCeilings(100, 200), 1);
    ghost var safe := RB.ResourceObservation(1, RB.CompleteMeasurement(50), RB.CompleteMeasurement(1));
    ghost var first := RB.ResourceObservation(11, RB.CompleteMeasurement(50), RB.CompleteMeasurement(1));
    ghost var later := RB.ResourceObservation(1, RB.CompleteMeasurement(101), RB.CompleteMeasurement(2 * 1024 * 1024));
    EarliestTripWholeStream(budget, RB.Warm, [safe], first, [later]);
    assert [safe, first, later] == [safe] + [first] + [later];
    assert Drive(budget, RB.Warm, [safe, first, later]) == SR.SupervisionTripped(SR.FirstBreachV1(1, RB.DecideInFlight(budget, RB.Warm, first), false));
    assert [safe, first, later][1] == first;
  }

  import CC = ConfluxContract

  import RB = ConfluxResourceCeilings

  import SR = ConfluxSupervisedOperationResult
}

module ConfluxExtern {
  function PullToOption<A>(p: Pull<A>): Option<A>
    decreases p
  {
    match p
    case Yield(a) =>
      Some(a)
    case Eof() =>
      None
  }

  lemma YieldNotEof<A>(a: A)
    ensures Yield(a) != Eof
  {
  }

  function PushToOption<E>(p: Push<E>): Option<E>
    decreases p
  {
    match p
    case Emit(e) =>
      Some(e)
    case Closed() =>
      None
  }

  function RunSink<A, E>(sink: A -> Push<E>, xs: seq<A>): seq<E>
    decreases |xs|
  {
    if |xs| == 0 then
      []
    else
      match sink(xs[0]) case Emit(e) => [e] + RunSink(sink, xs[1..]) case Closed() => []
  }

  lemma EmitNotClosed<E>(e: E)
    ensures Emit(e) != Closed
  {
  }

  lemma /*{:_inductionTrigger RunSink(sink, xs)}*/ /*{:_induction xs}*/ RunSinkBounded<A, E>(sink: A -> Push<E>, xs: seq<A>)
    ensures |RunSink(sink, xs)| <= |xs|
    decreases |xs|
  {
    if |xs| != 0 {
      RunSinkBounded(sink, xs[1..]);
    }
  }

  lemma RunSinkWitness()
    ensures exists sink: int -> Push<int>, xs: seq<int> {:trigger RunSink(sink, xs)} :: |xs| > 0 && |RunSink(sink, xs)| == |xs|
  {
    ghost var dbl := (a: int) => Emit(a * 2);
    ghost var xs := [1, 2, 3];
    assert RunSink(dbl, xs) == [2, 4, 6];
    assert |xs| > 0 && |RunSink(dbl, xs)| == |xs|;
  }

  import opened ConfluxContract

  datatype Pull<A> = Yield(action: A) | Eof

  datatype Push<E> = Emit(effect: E) | Closed
}

