  function CanonicalJsonBytes(value: Json): seq<bv8>
    decreases value

  function DecodeCanonicalJson(bytes: seq<bv8>): Option<Json>
    decreases bytes

  function Sha256Digest(bytes: seq<bv8>): string
    decreases bytes

  import opened ConfluxCodec
}

module {:extern} ConfluxCommandIdentityExtern replaces ConfluxCommandIdentityCapability {
  function {:extern} CanonicalJsonBytes(value: Json): seq<bv8>
    decreases value

  function {:extern} DecodeCanonicalJson(bytes: seq<bv8>): Option<Json>
    decreases bytes

  function {:extern} Sha256Digest(bytes: seq<bv8>): string
    decreases bytes

  import opened ConfluxCodec
}

module ConfluxCommandIdentity {
  function DecodeCanonicalCommand<A(==)>(encodeCommand: A -> Codec.Json, decodeCommand: Codec.Json -> Codec.Option<A>, bytes: seq<bv8>): Contract.Option<A>
    decreases bytes
  {
    var parsed: Option<Json> := Native.DecodeCanonicalJson(bytes);
    if parsed.None? then
      Contract.None
    else
      var decoded: Codec.Option<A> := decodeCommand(parsed.value); if decoded.None? || encodeCommand(decoded.value) != parsed.value then Contract.None else Contract.Some(decoded.value)
  }

  function CommandCodecFromJson<A(==)>(encodeCommand: A -> Codec.Json, decodeCommand: Codec.Json -> Codec.Option<A>): Command.CommandIdentityCodec<A>
  {
    Command.CommandIdentityCodec(Command.CanonicalCommandCodecVersion(), (command: A) => Native.CanonicalJsonBytes(encodeCommand(command)), (bytes: seq<bv8>) => DecodeCanonicalCommand(encodeCommand, decodeCommand, bytes), (bytes: seq<bv8>) => Native.Sha256Digest(bytes))
  }

  lemma {:axiom} CanonicalJsonRoundTrips(value: Codec.Json)
    requires JT.CanonicalDomain(value, JT.STRINGIFY_BUDGET)
    ensures Native.DecodeCanonicalJson(Native.CanonicalJsonBytes(value)) == Codec.Some(value)
    decreases value

  lemma {:axiom} Sha256DigestIsValid(bytes: seq<bv8>)
    ensures Command.ValidSha256Digest(Native.Sha256Digest(bytes))
    decreases bytes

  lemma CommandCodecFromJsonIdentity<A>(encodeCommand: A -> Codec.Json, decodeCommand: Codec.Json -> Codec.Option<A>, command: A)
    requires decodeCommand(encodeCommand(command)) == Codec.Some(command)
    requires JT.CanonicalDomain(encodeCommand(command), JT.STRINGIFY_BUDGET)
    ensures ghost var codec: CommandIdentityCodec<A> := CommandCodecFromJson(encodeCommand, decodeCommand); codec.decode(codec.encode(command)) == Contract.Some(command)
    ensures ghost var codec: CommandIdentityCodec<A> := CommandCodecFromJson(encodeCommand, decodeCommand); Command.ValidSha256Digest(codec.digest(codec.encode(command)))
  {
    ghost var codec := CommandCodecFromJson(encodeCommand, decodeCommand);
    ghost var json := encodeCommand(command);
    ghost var bytes := Native.CanonicalJsonBytes(json);
    assert codec.encode(command) == bytes;
    CanonicalJsonRoundTrips(json);
    assert Native.DecodeCanonicalJson(bytes) == Codec.Some(json);
    assert DecodeCanonicalCommand(encodeCommand, decodeCommand, bytes) == Contract.Some(command);
    assert codec.decode(codec.encode(command)) == Contract.Some(command);
    Sha256DigestIsValid(bytes);
    assert codec.digest(codec.encode(command)) == Native.Sha256Digest(bytes);
  }

  import Codec = ConfluxCodec

  import Contract = ConfluxContract

  import Command = ConfluxCommand

  import Native = ConfluxCommandIdentityCapability

  import JT = ConfluxJsonText
}

replaceable module ConfluxIoCapability {
  method ReadFile(path: string) returns (present: bool, content: string)
