    ensures kind == ""missing"" || kind == ""file"" || kind == ""directory"" || kind == ""symlink"" || kind == ""inaccessible""
    ensures 0 <= mode <= 65535
    ensures 0 <= size <= SR.V1MaxSafeInteger
    decreases path

