  method RunProcessBounded(cwd: string, cmd: string, args: seq<string>, timeLimitMs: int, memoryLimitMb: int, outputLimitMb: int)
      returns (code: int, output: string, err: string, timedOut: bool, memoryExceeded: bool, outputExceeded: bool, wallMs: int, memoryPresent: bool, peakRssMb: int, combinedOutputBytes: int, memoryMeasurementFailed: bool, outputMeasurementFailed: bool, treeKillIssued: bool, cleanupComplete: bool, cleanupElapsedMs: int, cleanupDeadlineMs: int, cleanupDiagnostic: string, firstTripPresent: bool, firstTripIndex: int, firstTripDimension: int, firstTripObservedPresent: bool, firstTripObserved: int, firstTripMeasurementFailure: bool, firstTripInFlight: bool, samplesSeen: int)
    requires 0 <= timeLimitMs <= SR.V1MaxSafeInteger
    requires 0 <= memoryLimitMb <= SR.V1MaxSafeInteger
    requires 0 <= outputLimitMb <= SR.V1MaxSafeInteger
    ensures SR.V1WireInt(code)
    ensures 0 <= wallMs <= SR.V1MaxSafeInteger
    ensures !memoryPresent || 0 <= peakRssMb <= SR.V1MaxSafeInteger
    ensures -1 <= combinedOutputBytes <= SR.V1MaxSafeInteger
    ensures 0 <= cleanupElapsedMs <= SR.V1MaxSafeInteger
    ensures 0 <= cleanupDeadlineMs <= SR.V1MaxSafeInteger
    ensures firstTripPresent && firstTripInFlight ==> 0 < cleanupDeadlineMs && cleanupElapsedMs <= cleanupDeadlineMs
    ensures !firstTripPresent || 0 <= firstTripIndex < SR.V1MaxSafeInteger
    ensures !firstTripObservedPresent || 0 <= firstTripObserved <= SR.V1MaxSafeInteger
    ensures 0 <= samplesSeen < SR.V1MaxSafeInteger
    ensures firstTripPresent ==> 0 <= firstTripDimension <= 2
    ensures firstTripPresent ==> if firstTripDimension == 0 then timeLimitMs > 0 else if firstTripDimension == 1 then memoryLimitMb > 0 else outputLimitMb > 0
    ensures firstTripPresent && firstTripMeasurementFailure ==> !firstTripObservedPresent && ((firstTripDimension == 1 && memoryLimitMb > 0 && (!memoryPresent || memoryMeasurementFailed)) || (firstTripDimension == 2 && outputLimitMb > 0 && outputMeasurementFailed))
    ensures firstTripPresent && !firstTripMeasurementFailure ==> firstTripObservedPresent && if firstTripDimension == 0 then firstTripObserved > timeLimitMs && firstTripObserved <= wallMs else if firstTripDimension == 1 then memoryPresent && firstTripObserved > memoryLimitMb && firstTripObserved <= peakRssMb else combinedOutputBytes >= 0 && firstTripObserved > outputLimitMb && firstTripObserved <= RB.BytesToMegabytes(combinedOutputBytes as nat)
    decreases cwd, cmd, args, timeLimitMs, memoryLimitMb, outputLimitMb

  method SpawnProcess(cwd: string, cmd: string, args: seq<string>)
      returns (proc: int)
    decreases cwd, cmd, args

  method WriteStdin(proc: int, payload: seq<bv8>)
    decreases proc, payload

  method ReadStdout(proc: int) returns (chunk: seq<bv8>)
    decreases proc

  method ReadStdoutWithin(proc: int, waitMs: int)
      returns (chunk: seq<bv8>, available: bool, open: bool)
    decreases proc, waitMs

  method ReadProcessOutputWithin(proc: int, waitMs: int)
      returns (chunk: seq<bv8>, available: bool, open: bool, combinedOutputBytesDelta: int)
    decreases proc, waitMs

  method ProcessRssMb(proc: int) returns (present: bool, rssMb: int)
    decreases proc

  method ProcessExitStatus(proc: int)
      returns (handleFound: bool, observed: bool, exitCode: int)
    ensures !handleFound ==> !observed
    ensures !observed || SR.V1WireInt(exitCode)
    decreases proc

  method CurrentProcessRssMb() returns (present: bool, rssMb: int)
    ensures !present || 0 <= rssMb <= SR.V1MaxSafeInteger

  method CurrentProcessId() returns (pid: int)

  method CloseProcess(proc: int)
    decreases proc

  method TerminateProcessTreeWithin(proc: int, deadlineMs: int)
      returns (operationSucceeded: bool, handleFound: bool, treeKillIssued: bool, cleanupComplete: bool, cleanupElapsedMs: int, diagnostic: string, terminalChunk: seq<bv8>, terminalAvailable: bool, combinedOutputBytesDelta: int, exitObserved: bool, exitCode: int)
    requires 0 < deadlineMs <= SR.V1MaxSafeInteger
    ensures !operationSucceeded ==> diagnostic != """"
    ensures operationSucceeded && !handleFound ==> !cleanupComplete && diagnostic == """"
    ensures operationSucceeded && handleFound && cleanupComplete ==> diagnostic == """"
    ensures operationSucceeded && handleFound && !cleanupComplete ==> diagnostic != """"
    ensures 0 <= cleanupElapsedMs <= deadlineMs
    ensures 0 <= combinedOutputBytesDelta <= SR.V1MaxSafeInteger
    ensures !handleFound ==> !treeKillIssued && !terminalAvailable && !exitObserved
    ensures exitObserved ==> SR.V1WireInt(exitCode)
    decreases proc, deadlineMs

  function EncodeUtf8(text: string): seq<bv8>
    decreases text

  function DecodeUtf8(bytes: seq<bv8>): string
    decreases bytes

  method MonotonicTimeMs() returns (nowMs: int)
    ensures 0 <= nowMs <= SR.V1MaxSafeInteger

  method SetExitCode(code: int)
    decreases code

  method WriteStderr(content: string)
    decreases content

  method GetEnv(key: string) returns (present: bool, value: string)
    decreases key

  method StartWatch(roots: seq<string>) returns (watcher: int)
    decreases roots

  method PollWatch(watcher: int, waitMs: int)
      returns (available: bool, path: string)
    decreases watcher, waitMs

  method CloseWatch(watcher: int)
    decreases watcher

  import SR = ConfluxSupervisedOperationResult

  import RB = ConfluxResourceCeilings
}

