      returns (kind: string, mode: int, symlinkText: string, size: int)
    ensures kind == ""missing"" || kind == ""file"" || kind == ""directory"" || kind == ""symlink"" || kind == ""inaccessible""
    ensures 0 <= mode <= 65535
    ensures 0 <= size <= SR.V1MaxSafeInteger
    decreases path

  method {:extern} DeleteFile(path: string)
    decreases path

  method {:extern} AppendFile(path: string, line: string)
    decreases path, line

  method {:extern} ListDir(dir: string) returns (names: seq<string>, isDir: seq<bool>)
    decreases dir

  method {:extern} FileStat(path: string)
      returns (present: bool, mtimeMs: int, size: int)
    decreases path

  method {:extern} ReadByteRange(path: string, offset: int, length: int)
      returns (present: bool, content: string)
    decreases path, offset, length

  method {:extern} RunProcess(cwd: string, cmd: string, args: seq<string>)
      returns (code: int, output: string, err: string)
    decreases cwd, cmd, args

  method {:extern} {:axiom} RunProcessBounded(cwd: string, cmd: string, args: seq<string>, timeLimitMs: int, memoryLimitMb: int, outputLimitMb: int)
      returns (code: int, output: string, err: string, timedOut: bool, memoryExceeded: bool, outputExceeded: bool, wallMs: int, memoryPresent: bool, peakRssMb: int, combinedOutputBytes: int, memoryMeasurementFailed: bool, outputMeasurementFailed: bool, treeKillIssued: bool, cleanupComplete: bool, cleanupElapsedMs: int, cleanupDeadlineMs: int, cleanupDiagnostic: string, firstTripPresent: bool, firstTripIndex: int, firstTripDimension: int, firstTripObservedPresent: bool, firstTripObserved: int, firstTripMeasurementFailure: bool, firstTripInFlight: bool, samplesSeen: int)
    requires 0 <= timeLimitMs <= SR.V1MaxSafeInteger
    requires 0 <= memoryLimitMb <= SR.V1MaxSafeInteger
    requires 0 <= outputLimitMb <= SR.V1MaxSafeInteger
    ensures SR.V1WireInt(code)
    ensures 0 <= wallMs <= SR.V1MaxSafeInteger
    ensures !memoryPresent || 0 <= peakRssMb <= SR.V1MaxSafeInteger
    ensures -1 <= combinedOutputBytes <= SR.V1MaxSafeInteger
    ensures 0 <= cleanupElapsedMs <= SR.V1MaxSafeInteger
    ensures 0 <= cleanupDeadlineMs <= SR.V1MaxSafeInteger
    ensures firstTripPresent && firstTripInFlight ==> 0 < cleanupDeadlineMs && cleanupElapsedMs <= cleanupDeadlineMs
    ensures !firstTripPresent || 0 <= firstTripIndex < SR.V1MaxSafeInteger
    ensures !firstTripObservedPresent || 0 <= firstTripObserved <= SR.V1MaxSafeInteger
    ensures 0 <= samplesSeen < SR.V1MaxSafeInteger
    ensures firstTripPresent ==> 0 <= firstTripDimension <= 2
    ensures firstTripPresent ==> if firstTripDimension == 0 then timeLimitMs > 0 else if firstTripDimension == 1 then memoryLimitMb > 0 else outputLimitMb > 0
    ensures firstTripPresent && firstTripMeasurementFailure ==> !firstTripObservedPresent && ((firstTripDimension == 1 && memoryLimitMb > 0 && (!memoryPresent || memoryMeasurementFailed)) || (firstTripDimension == 2 && outputLimitMb > 0 && outputMeasurementFailed))
    ensures firstTripPresent && !firstTripMeasurementFailure ==> firstTripObservedPresent && if firstTripDimension == 0 then firstTripObserved > timeLimitMs && firstTripObserved <= wallMs else if firstTripDimension == 1 then memoryPresent && firstTripObserved > memoryLimitMb && firstTripObserved <= peakRssMb else combinedOutputBytes >= 0 && firstTripObserved > outputLimitMb && firstTripObserved <= RB.BytesToMegabytes(combinedOutputBytes as nat)
    decreases cwd, cmd, args, timeLimitMs, memoryLimitMb, outputLimitMb

  method {:extern} SpawnProcess(cwd: string, cmd: string, args: seq<string>)
      returns (proc: int)
    decreases cwd, cmd, args

  method {:extern} WriteStdin(proc: int, payload: seq<bv8>)
    decreases proc, payload

  method {:extern} ReadStdout(proc: int) returns (chunk: seq<bv8>)
    decreases proc

  method {:extern} ReadStdoutWithin(proc: int, waitMs: int)
      returns (chunk: seq<bv8>, available: bool, open: bool)
    decreases proc, waitMs

  method {:extern} ReadProcessOutputWithin(proc: int, waitMs: int)
      returns (chunk: seq<bv8>, available: bool, open: bool, combinedOutputBytesDelta: int)
    decreases proc, waitMs

  method {:extern} ProcessRssMb(proc: int) returns (present: bool, rssMb: int)
    decreases proc

  method {:extern} {:axiom} ProcessExitStatus(proc: int)
      returns (handleFound: bool, observed: bool, exitCode: int)
    ensures !handleFound ==> !observed
    ensures !observed || SR.V1WireInt(exitCode)
    decreases proc

  method {:extern} {:axiom} CurrentProcessRssMb() returns (present: bool, rssMb: int)
    ensures !present || 0 <= rssMb <= SR.V1MaxSafeInteger

  method {:extern} CurrentProcessId() returns (pid: int)

  method {:extern} CloseProcess(proc: int)
    decreases proc

  method {:extern} {:axiom} TerminateProcessTreeWithin(proc: int, deadlineMs: int)
      returns (operationSucceeded: bool, handleFound: bool, treeKillIssued: bool, cleanupComplete: bool, cleanupElapsedMs: int, diagnostic: string, terminalChunk: seq<bv8>, terminalAvailable: bool, combinedOutputBytesDelta: int, exitObserved: bool, exitCode: int)
    requires 0 < deadlineMs <= SR.V1MaxSafeInteger
    ensures !operationSucceeded ==> diagnostic != """"
    ensures operationSucceeded && !handleFound ==> !cleanupComplete && diagnostic == """"
    ensures operationSucceeded && handleFound && cleanupComplete ==> diagnostic == """"
    ensures operationSucceeded && handleFound && !cleanupComplete ==> diagnostic != """"
    ensures 0 <= cleanupElapsedMs <= deadlineMs
    ensures 0 <= combinedOutputBytesDelta <= SR.V1MaxSafeInteger
    ensures !handleFound ==> !treeKillIssued && !terminalAvailable && !exitObserved
    ensures exitObserved ==> SR.V1WireInt(exitCode)
    decreases proc, deadlineMs

  function {:extern} EncodeUtf8(text: string): seq<bv8>
    decreases text

  function {:extern} DecodeUtf8(bytes: seq<bv8>): string
    decreases bytes

  method {:extern} {:axiom} MonotonicTimeMs() returns (nowMs: int)
    ensures 0 <= nowMs <= SR.V1MaxSafeInteger

  method {:extern} SetExitCode(code: int)
    decreases code

  method {:extern} WriteStderr(content: string)
    decreases content

  method {:extern} GetEnv(key: string) returns (present: bool, value: string)
    decreases key

  method {:extern} StartWatch(roots: seq<string>) returns (watcher: int)
    decreases roots

  method {:extern} PollWatch(watcher: int, waitMs: int)
      returns (available: bool, path: string)
    decreases watcher, waitMs

  method {:extern} CloseWatch(watcher: int)
    decreases watcher

  import SR = ConfluxSupervisedOperationResult

  import RB = ConfluxResourceCeilings
}

module ConfluxResourceSupervisor {
  const ProcessCleanupDeadlineMs: nat := 2000

  function CleanupDiagnostic(cleanup: SR.CleanupStatus): string
    decreases cleanup
  {
    if cleanup.CleanupFailed? then
      cleanup.reason
    else
      """"
  }

  function TerminationFailureDiagnostic(operationSucceeded: bool, handleFound: bool, cleanupComplete: bool, diagnostic: string): string
    decreases operationSucceeded, handleFound, cleanupComplete, diagnostic
  {
    if diagnostic != """" then
      diagnostic
    else if !operationSucceeded then
      ""checked process-tree termination failed""
    else if handleFound && !cleanupComplete then
      ""checked process-tree termination was not confirmed""
    else
      ""process handle disappeared before checked termination""
  }

  method TerminateProcessWithin(proc: int, deadlineMs: nat) returns (receipt: ProcessTerminationReceipt)
    requires 0 < deadlineMs <= SR.V1MaxSafeInteger
    ensures SR.CleanupValid(receipt.cleanup)
    decreases proc, deadlineMs
  {
    var operationSucceeded, handleFound, treeKillIssued, cleanupComplete, cleanupElapsedMs, diagnostic, terminalChunk, terminalAvailable, combinedOutputBytesDelta, exitObserved, exitCode := IO.TerminateProcessTreeWithin(proc, deadlineMs as int);
    var cleanup := if operationSucceeded && !handleFound then SR.CleanupNotRequired else if operationSucceeded && cleanupComplete then SR.CleanupComplete(NonNegative(cleanupElapsedMs), deadlineMs) else SR.CleanupFailed(NonNegative(cleanupElapsedMs), deadlineMs, TerminationFailureDiagnostic(operationSucceeded, handleFound, cleanupComplete, diagnostic));
    var exit := if exitObserved then SR.ExitObserved(exitCode) else SR.ExitNotObserved;
    receipt := ProcessTerminationReceipt(handleFound, treeKillIssued, cleanup, terminalChunk, terminalAvailable, NonNegative(combinedOutputBytesDelta), exit);
  }

  function NonNegative(value: int): nat
    decreases value
  {
    if value < 0 then
      0
    else
      value as nat
  }

  function FlatByteConcat(left: seq<bv8>, right: seq<bv8>): seq<bv8>
    decreases left, right
  {
    seq(|left| + |right|, (i: int) requires 0 <= i < |left| + |right| => if i < |left| then left[i] else right[i - |left|])
  }

  lemma NonNegativeIsWireSafe(value: int)
    requires SR.V1WireInt(value)
    ensures SR.V1WireNat(NonNegative(value))
    decreases value
  {
  }

  lemma ElapsedIsWireSafe(startedMs: int, completedMs: int)
    requires 0 <= startedMs && SR.V1WireNat(startedMs as nat)
    requires 0 <= completedMs && SR.V1WireNat(completedMs as nat)
    ensures SR.V1WireNat(NonNegative(completedMs - startedMs))
    decreases startedMs, completedMs
  {
  }

  function BytesToMegabytes(bytes: nat): nat
    decreases bytes
  {
    RB.BytesToMegabytes(bytes)
  }

  function DimensionFromNative(value: int): RB.ResourceDimension
    decreases value
  {
    if value == 0 then
      RB.TimeDimension
    else if value == 1 then
      RB.MemoryDimension
    else
      RB.OutputDimension
  }

  function WrapperExitCode(childCode: int, verdict: RB.ResourceVerdict): int
    decreases childCode, verdict
  {
    if verdict.outcome == RB.EnforcementOk then
      childCode
    else if verdict.dimension.None? then
      if childCode == 0 then
        1
      else
        childCode
    else if verdict.dimension.value == RB.TimeDimension then
      124
    else if verdict.dimension.value == RB.MemoryDimension then
      137
    else
      125
  }

  function ObservationStatus(observation: SR.SupervisionObservationV1): RB.MeasurementStatus
    decreases observation
  {
    if observation.peakDescendantRssMb.status.MeasurementComplete? && observation.combinedOutputBytes.status.MeasurementComplete? && observation.processTree.ProcessTreeObserved? then
      RB.MeasurementComplete
    else
      RB.MeasurementPartial(""process observation contains incomplete measurements"")
  }

  method StartObservation() returns (startedMs: int)
  {
    startedMs := IO.MonotonicTimeMs();
  }

  method ObserveCurrentProcess(startedMs: int, outputBytes: CC.Option<nat>, phase: RB.ExecutionPhase, budget: RB.ResourceCeilings)
      returns (observation: RB.ResourceObservation)
    ensures RB.ValidMeasurement(observation.peakRssMb)
    ensures RB.ValidMeasurement(observation.combinedOutputBytes)
    ensures 0 <= startedMs && SR.V1WireNat(startedMs as nat) && SR.V1WireOptionalNat(outputBytes) ==> SR.V1WireNat(observation.wallMs) && SR.V1WireOptionalNat(observation.peakRssMb.value) && SR.V1WireOptionalNat(observation.combinedOutputBytes.value)
    decreases startedMs, outputBytes, phase, budget
  {
    var now := IO.MonotonicTimeMs();
    var memoryPresent, memoryMb := IO.CurrentProcessRssMb();
    if 0 <= startedMs && SR.V1WireNat(startedMs as nat) {
      ElapsedIsWireSafe(startedMs, now);
    }
    if memoryPresent {
      assert SR.V1WireInt(memoryMb);
      NonNegativeIsWireSafe(memoryMb);
    }
    var memory := if memoryPresent then RB.CompleteMeasurement(NonNegative(memoryMb)) else if RB.MemoryMeasurementRequired(budget, phase) then RB.UnavailableMeasurement(""current-process RSS unavailable"") else RB.NotRequestedMeasurement();
    var output := if outputBytes.Some? then RB.CompleteMeasurement(outputBytes.value) else if RB.OutputMeasurementRequired(budget) then RB.UnavailableMeasurement(""combined-output measurement unavailable"") else RB.NotRequestedMeasurement();
    observation := RB.ResourceObservation(NonNegative(now - startedMs), memory, output);
  }

  method ObserveCurrentProcessPostHoc(startedMs: int, outputBytes: CC.Option<nat>, phase: RB.ExecutionPhase, budget: RB.ResourceCeilings)
      returns (observation: RB.ResourceObservation, verdict: RB.ResourceVerdict)
    ensures verdict == RB.DecidePostHoc(budget, phase, observation)
    ensures RB.ValidMeasurement(observation.peakRssMb)
    ensures RB.ValidMeasurement(observation.combinedOutputBytes)
    ensures 0 <= startedMs && SR.V1WireNat(startedMs as nat) && SR.V1WireOptionalNat(outputBytes) ==> SR.V1WireNat(observation.wallMs) && SR.V1WireOptionalNat(observation.peakRssMb.value) && SR.V1WireOptionalNat(observation.combinedOutputBytes.value)
    decreases startedMs, outputBytes, phase, budget
  {
    observation := ObserveCurrentProcess(startedMs, outputBytes, phase, budget);
    verdict := RB.DecidePostHoc(budget, phase, observation);
  }

  method ObserveCurrentProcessPostHocV1(policyId: string, startedMs: int, outputBytes: CC.Option<nat>, phase: RB.ExecutionPhase, budget: RB.ResourceCeilings)
      returns (result: SR.SupervisedOperationResultV1)
    requires 0 <= startedMs && SR.V1WireNat(startedMs as nat)
    requires SR.V1WireOptionalNat(outputBytes)
    requires SR.V1BudgetSafeForPhase(budget, phase)
    ensures SR.ValidV1(result)
    decreases policyId, startedMs, outputBytes, phase, budget
  {
    var resolvedPolicyId := if |policyId| > 0 then policyId else ""policy:conflux/default@1"";
    var observation, verdict := ObserveCurrentProcessPostHoc(startedMs, outputBytes, phase, budget);
    RB.DecisionMatchesBudgetAndObservation(RB.EnforcementFail, budget, phase, observation);
    RB.PostHocNeverKills(budget, phase, observation);
    RB.DecisionsUseEffectivePhase(budget, phase, observation);
    var tree := if observation.peakRssMb.status.MeasurementComplete? then SR.ProcessTreeObserved else SR.ProcessTreeUnavailable(""current-process RSS incomplete"");
    var supervisionObservation := SR.SupervisionObservationV1(SR.TimingCoverage(0, observation.wallMs, 0, observation.wallMs), observation.peakRssMb, observation.combinedOutputBytes, tree);
    var state := if verdict.outcome == RB.EnforcementOk then SR.SupervisionRunning(1) else SR.SupervisionTripped(SR.FirstBreachV1(0, verdict, verdict.observed.None?));
    var wrapperExit := WrapperExitCode(0, verdict);
    result := SR.SupervisedOperationResultV1(SR.SupervisedOperationResultSchemaVersion, resolvedPolicyId, phase, RB.EffectivePhase(phase), SR.ExpandBudget(budget, phase), ObservationStatus(supervisionObservation), supervisionObservation, state, SR.CleanupNotRequired, SR.ExitNotObserved, if verdict.outcome == RB.EnforcementFail then SR.PostHocFailure else SR.NoEnforcement, SR.NoTermination, wrapperExit, verdict.reason, verdict);
  }

  method RunProcess(cwd: string, command: string, arguments: seq<string>, phase: RB.ExecutionPhase, budget: RB.ResourceCeilings)
      returns (result: SupervisedProcessResult)
    requires SR.V1BudgetSafeForPhase(budget, phase)
    decreases cwd, command, arguments, phase, budget
  {
    result := RunProcessV1(""policy:conflux/default@1"", cwd, command, arguments, phase, budget);
  }

  method {:timeLimit 60} {:isolate_assertions} RunProcessV1(policyId: string, cwd: string, command: string, arguments: seq<string>, phase: RB.ExecutionPhase, budget: RB.ResourceCeilings)
      returns (result: SupervisedProcessResult)
    requires SR.V1BudgetSafeForPhase(budget, phase)
    ensures SR.ValidV1(result.supervised)
    ensures result.supervised.verdict == result.verdict
    decreases policyId, cwd, command, arguments, phase, budget
  {
    var resolvedPolicyId := if |policyId| > 0 then policyId else ""policy:conflux/default@1"";
    var timeLimit := RB.TimeCeilingForPhase(budget.time, phase);
    var memoryLimit := RB.MemoryCeilingForPhase(budget.memory, phase);
    var code, output, error, timedOut, memoryExceeded, outputExceeded, wallMs, memoryPresent, peakMemoryMb, combinedOutputBytes, memoryMeasurementFailed, outputMeasurementFailed, treeKillIssued, cleanupComplete, cleanupElapsedMs, cleanupDeadlineMs, cleanupDiagnostic, firstTripPresent, firstTripIndex, firstTripDimension, firstTripObservedPresent, firstTripObserved, firstTripMeasurementFailure, firstTripInFlight, samplesSeen := IO.RunProcessBounded(cwd, command, arguments, timeLimit as int, memoryLimit as int, budget.maxOutputMb as int);
    if memoryPresent {
      assert SR.V1WireInt(peakMemoryMb);
      NonNegativeIsWireSafe(peakMemoryMb);
    }
    NonNegativeIsWireSafe(combinedOutputBytes);
    NonNegativeIsWireSafe(cleanupElapsedMs);
    NonNegativeIsWireSafe(cleanupDeadlineMs);
    if firstTripObservedPresent {
      assert SR.V1WireInt(firstTripObserved);
      NonNegativeIsWireSafe(firstTripObserved);
    }
    var memoryMeasurement := if memoryPresent then if memoryMeasurementFailed then RB.ResourceMeasurement(CC.Some(NonNegative(peakMemoryMb)), RB.MeasurementPartial(""one or more process-tree RSS samples failed"")) else RB.CompleteMeasurement(NonNegative(peakMemoryMb)) else if memoryLimit > 0 then RB.UnavailableMeasurement(""complete process-tree RSS unavailable"") else RB.NotRequestedMeasurement();
    var outputMeasurement := if outputMeasurementFailed then if combinedOutputBytes >= 0 then RB.ResourceMeasurement(CC.Some(NonNegative(combinedOutputBytes)), RB.MeasurementPartial(""combined-output stream observation incomplete"")) else RB.UnavailableMeasurement(""combined-output stream observation unavailable"") else RB.CompleteMeasurement(NonNegative(combinedOutputBytes));
    var observation := RB.ResourceObservation(NonNegative(wallMs), memoryMeasurement, outputMeasurement);
    var nativeDimension := DimensionFromNative(firstTripDimension);
    var nativeObservedCandidate := if firstTripObservedPresent then CC.Some(NonNegative(firstTripObserved)) else RB.ObservedForDimension(observation, nativeDimension);
    var nativeMeasurementFailure := nativeDimension != RB.TimeDimension && (firstTripMeasurementFailure || nativeObservedCandidate.None?);
    var nativeObserved := if nativeMeasurementFailure then CC.None else nativeObservedCandidate;
    var nativeOutcome := if firstTripInFlight then RB.EnforcementKill else RB.EnforcementFail;
    var nativeVerdict := RB.RecordedViolation(nativeOutcome, budget, phase, nativeDimension, nativeObserved, nativeMeasurementFailure);
    var finalVerdict := RB.DecidePostHoc(budget, phase, observation);
    RB.DecisionMatchesBudgetAndObservation(RB.EnforcementFail, budget, phase, observation);
    var verdict := if firstTripPresent then nativeVerdict else finalVerdict;
    RB.DecisionsUseEffectivePhase(budget, phase, observation);
    var state := if firstTripPresent then SR.SupervisionTripped(SR.FirstBreachV1(NonNegative(firstTripIndex), verdict, nativeMeasurementFailure)) else if verdict.outcome != RB.EnforcementOk then SR.SupervisionTripped(SR.FirstBreachV1(NonNegative(samplesSeen), verdict, verdict.observed.None?)) else SR.SupervisionRunning(NonNegative(samplesSeen));
    var processTree := if memoryMeasurement.status.MeasurementComplete? then SR.ProcessTreeObserved else SR.ProcessTreeUnavailable(""complete process-tree RSS observation incomplete"");
    var supervisionObservation := SR.SupervisionObservationV1(SR.TimingCoverage(0, observation.wallMs, 0, observation.wallMs), memoryMeasurement, outputMeasurement, processTree);
    var cleanup := if verdict.outcome == RB.EnforcementKill then if cleanupComplete then SR.CleanupComplete(NonNegative(cleanupElapsedMs), NonNegative(cleanupDeadlineMs)) else SR.CleanupFailed(NonNegative(cleanupElapsedMs), NonNegative(cleanupDeadlineMs), if |cleanupDiagnostic| > 0 then cleanupDiagnostic else ""process-tree cleanup exceeded monotonic deadline"") else SR.CleanupNotRequired;
    var wrapperExit := WrapperExitCode(code, verdict);
    var supervised := SR.SupervisedOperationResultV1(SR.SupervisedOperationResultSchemaVersion, resolvedPolicyId, phase, RB.EffectivePhase(phase), SR.ExpandBudget(budget, phase), ObservationStatus(supervisionObservation), supervisionObservation, state, cleanup, SR.ExitObserved(code), if verdict.outcome == RB.EnforcementKill then SR.InFlightProcessTreeTermination else if verdict.outcome == RB.EnforcementFail then SR.PostHocFailure else SR.NoEnforcement, if verdict.outcome == RB.EnforcementKill then SR.ProcessTreeTermination else SR.NoTermination, wrapperExit, verdict.reason, verdict);
    if firstTripPresent {
      assert 0 <= firstTripDimension <= 2;
      if firstTripMeasurementFailure {
        assert nativeMeasurementFailure;
        assert nativeObserved.None?;
        if nativeDimension == RB.MemoryDimension {
          assert memoryLimit > 0;
          assert !memoryMeasurement.status.MeasurementComplete?;
        } else {
          assert nativeDimension == RB.OutputDimension;
          assert budget.maxOutputMb > 0;
          assert !outputMeasurement.status.MeasurementComplete?;
        }
      } else {
        assert firstTripObservedPresent;
        assert !nativeMeasurementFailure;
        assert nativeObserved.Some?;
        assert nativeObserved.value == NonNegative(firstTripObserved);
        assert nativeObserved.value > RB.LimitForDimension(budget, phase, nativeDimension);
        if nativeDimension == RB.TimeDimension {
          assert nativeObserved.value <= observation.wallMs;
        } else if nativeDimension == RB.MemoryDimension {
          assert memoryMeasurement.value.Some?;
          assert nativeObserved.value <= memoryMeasurement.value.value;
        } else {
          assert outputMeasurement.value.Some?;
          assert nativeObserved.value <= RB.BytesToMegabytes(outputMeasurement.value.value);
        }
      }
    }
    assert SR.VerdictBudgetCoherent(supervised);
    assert SR.CleanupValid(supervised.cleanup);
    result := SupervisedProcessResult(code, output, error, observation, verdict, NonNegative(combinedOutputBytes), treeKillIssued, cleanupComplete, supervised);
  }

  method PollProcess(proc: int, startedMs: int, outputBytesBefore: nat, waitMs: int, phase: RB.ExecutionPhase, budget: RB.ResourceCeilings)
      returns (chunk: seq<bv8>, available: bool, state: ProcessReadState, observation: RB.ResourceObservation, outputBytesAfter: nat)
    decreases proc, startedMs, outputBytesBefore, waitMs, phase, budget
  {
    var open: bool;
    var combinedOutputBytesDelta: int;
    chunk, available, open, combinedOutputBytesDelta := IO.ReadProcessOutputWithin(proc, waitMs);
    var now := IO.MonotonicTimeMs();
    var handleFound, exitObserved, exitCode := IO.ProcessExitStatus(proc);
    if exitObserved {
      var finalChunk, finalAvailable, finalOpen, finalOutputBytesDelta := IO.ReadProcessOutputWithin(proc, 0);
      chunk := FlatByteConcat(chunk, finalChunk);
      available := available || finalAvailable;
      open := finalOpen;
      combinedOutputBytesDelta := combinedOutputBytesDelta + finalOutputBytesDelta;
    }
    outputBytesAfter := outputBytesBefore + NonNegative(combinedOutputBytesDelta);
    var memoryPresent := false;
    var memoryMb := 0;
    if RB.MemoryMeasurementRequired(budget, phase) {
      memoryPresent, memoryMb := IO.ProcessRssMb(proc);
    }
    var memory := if memoryPresent then RB.CompleteMeasurement(NonNegative(memoryMb)) else if RB.MemoryMeasurementRequired(budget, phase) then RB.UnavailableMeasurement(""persistent process-tree RSS unavailable"") else RB.NotRequestedMeasurement();
    observation := RB.ResourceObservation(NonNegative(now - startedMs), memory, RB.CompleteMeasurement(outputBytesAfter));
    var terminal := exitObserved || (!open && !handleFound);
    var verdict := if terminal then RB.DecidePostHoc(budget, phase, observation) else RB.DecideInFlight(budget, phase, observation);
    if terminal && available {
      state := ProcessReadOpen;
    } else if exitObserved {
      state := ProcessReadExited(exitCode, verdict);
    } else if !open && !handleFound {
      state := ProcessReadClosed;
    } else if verdict.outcome == RB.EnforcementKill {
      var termination := TerminateProcessWithin(proc, ProcessCleanupDeadlineMs);
      chunk := FlatByteConcat(chunk, termination.terminalChunk);
      available := available || termination.terminalAvailable;
      outputBytesAfter := outputBytesAfter + termination.combinedOutputBytesDelta;
      var cleanupNow := IO.MonotonicTimeMs();
      observation := RB.ResourceObservation(NonNegative(cleanupNow - startedMs), memory, RB.CompleteMeasurement(outputBytesAfter));
      state := ProcessReadKilled(verdict, termination);
    } else if open || handleFound {
      state := ProcessReadOpen;
    } else {
      state := ProcessReadClosed;
    }
  }

  method CancelProcess(proc: int, startedMs: int, outputBytesBefore: nat, phase: RB.ExecutionPhase, budget: RB.ResourceCeilings)
      returns (receipt: ProcessCancellationResult)
    ensures outputBytesBefore <= receipt.combinedOutputBytes
    ensures receipt.outcome.ProcessTerminationFailed? <==> receipt.termination.cleanup.CleanupFailed?
    decreases proc, startedMs, outputBytesBefore, phase, budget
  {
    var chunk, available, open, combinedOutputBytesDelta := IO.ReadProcessOutputWithin(proc, 0);
    var outputBytesAfter := outputBytesBefore + NonNegative(combinedOutputBytesDelta);
    var now := IO.MonotonicTimeMs();
    var memoryPresent := false;
    var memoryMb := 0;
    if RB.MemoryMeasurementRequired(budget, phase) {
      memoryPresent, memoryMb := IO.ProcessRssMb(proc);
    }
    var memory := if memoryPresent then RB.CompleteMeasurement(NonNegative(memoryMb)) else if RB.MemoryMeasurementRequired(budget, phase) then RB.UnavailableMeasurement(""persistent process-tree RSS unavailable at cancellation"") else RB.NotRequestedMeasurement();
    var beforeObservation := RB.ResourceObservation(NonNegative(now - startedMs), memory, RB.CompleteMeasurement(outputBytesAfter));
    var termination := TerminateProcessWithin(proc, ProcessCleanupDeadlineMs);
    chunk := FlatByteConcat(chunk, termination.terminalChunk);
    available := available || termination.terminalAvailable;
    outputBytesAfter := outputBytesAfter + termination.combinedOutputBytesDelta;
    var cancellationNow := IO.MonotonicTimeMs();
    var finalObservation := RB.ResourceObservation(NonNegative(cancellationNow - startedMs), memory, RB.CompleteMeasurement(outputBytesAfter));
    var outcome := if termination.cleanup.CleanupFailed? then ProcessTerminationFailed else if !termination.handleFound then ProcessAlreadyClosed else ProcessCancelled;
    receipt := ProcessCancellationResult(outcome, chunk, available, beforeObservation, finalObservation, outputBytesAfter, termination);
  }

  lemma ByteConversionWitness()
    ensures BytesToMegabytes(0) == 0
    ensures forall b: nat {:trigger BytesToMegabytes(b)} :: 0 < b ==> BytesToMegabytes(b) >= 1
  {
    assert BytesToMegabytes(0) == 0;
    assert BytesToMegabytes(1) == 1;
    assert BytesToMegabytes(1024 * 1024) == 1;
    assert BytesToMegabytes(1024 * 1024 + 1) == 2;
  }

  import IO = ConfluxIoCapability

  import CC = ConfluxContract

  import RB = ConfluxResourceCeilings

  import SR = ConfluxSupervisedOperationResult

  datatype ProcessReadState = ProcessReadOpen | ProcessReadClosed | ProcessReadExited(exitCode: int, verdict: RB.ResourceVerdict) | ProcessReadKilled(verdict: RB.ResourceVerdict, termination: ProcessTerminationReceipt)

  datatype ProcessTerminationReceipt = ProcessTerminationReceipt(handleFound: bool, treeKillIssued: bool, cleanup: SR.CleanupStatus, terminalChunk: seq<bv8>, terminalAvailable: bool, combinedOutputBytesDelta: nat, exit: SR.ExitStatus)

  datatype ProcessCancellationOutcome = ProcessCancelled | ProcessAlreadyClosed | ProcessTerminationFailed

  datatype ProcessCancellationResult = ProcessCancellationResult(outcome: ProcessCancellationOutcome, chunk: seq<bv8>, available: bool, beforeObservation: RB.ResourceObservation, finalObservation: RB.ResourceObservation, combinedOutputBytes: nat, termination: ProcessTerminationReceipt)

  datatype SupervisedProcessResult = SupervisedProcessResult(code: int, output: string, error: string, observation: RB.ResourceObservation, verdict: RB.ResourceVerdict, combinedOutputBytes: nat, treeKillIssued: bool, cleanupComplete: bool, supervised: SR.SupervisedOperationResultV1)
}

