module ConfluxServiceLifecycle {
  predicate ValidPort(port: nat)
    decreases port
  {
    0 < port <= 65535
  }

  predicate ValidAbsoluteHttpPath(path: string)
    decreases path
  {
    0 < |path| &&
    path[0] == '/'
  }

  predicate AllNonEmpty(values: seq<string>)
    decreases |values|
  {
    |values| == 0 || (0 < |values[0]| && AllNonEmpty(values[1..]))
  }

  predicate ValidServiceSpec(spec: ServiceSpec)
    decreases spec
  {
    spec.schemaVersion == 1 &&
    0 < |spec.serviceId| &&
    0 < |spec.sourceClosure| &&
    AllNonEmpty(spec.sourceClosure) &&
    0 < |spec.buildGeneration| &&
    0 < |spec.runGeneration| &&
    0 < |spec.healthIdentity.owner| &&
    0 < |spec.healthIdentity.protocolVersion| &&
    ValidPort(spec.endpointPolicy.port) &&
    (TailscaleIp in spec.endpointPolicy.allowedBindKinds || LoopbackBind in spec.endpointPolicy.allowedBindKinds) &&
    ValidAbsoluteHttpPath(spec.consolePath) &&
    ValidAbsoluteHttpPath(spec.channelPath) &&
    0 < |spec.stateRoot| &&
    0 < |spec.supervisorAdapter|
  }

  predicate ValidServiceInfo(info: ServiceInfo)
    decreases info
  {
    info.schemaVersion == 1 &&
    0 < |info.serviceId| &&
    0 < |info.healthIdentity.owner| &&
    0 < |info.healthIdentity.protocolVersion| &&
    0 < |info.ownerLeaseId| &&
    0 < info.pid &&
    0 < |info.generation| &&
    0 < |info.bindHost| &&
    0 < |info.publicHost| &&
    ValidPort(info.port) &&
    0 < |info.consoleUrl| &&
    0 < |info.channelBase|
  }

  predicate ExactHealth(info: ServiceInfo, observed: HealthObservation)
    decreases info, observed
  {
    observed.status == ""ok"" &&
    observed.owner == info.healthIdentity.owner &&
    observed.protocolVersion == info.healthIdentity.protocolVersion &&
    observed.pid == info.pid &&
    observed.generation == info.generation &&
    observed.ownerLeaseId == info.ownerLeaseId
  }

  function CanUseTailscale(policy: EndpointPolicy, facts: TailscaleFacts): bool
    decreases policy, facts
  {
    policy.preferTailscaleMagicDns &&
    TailscaleIp in policy.allowedBindKinds &&
    facts.backendRunning &&
    facts.magicDnsEnabled &&
    facts.selfOnline &&
    facts.dnsNameValid &&
    facts.matchingIpValid
  }

  function ChooseEndpoint(policy: EndpointPolicy, facts: TailscaleFacts): EndpointDecision
    decreases policy, facts
  {
    if CanUseTailscale(policy, facts) then
      UseEndpoint(Endpoint(facts.matchingIp, facts.dnsName, TailscaleMagicDns, policy.port))
    else if policy.fallbackLoopback && LoopbackBind in policy.allowedBindKinds then
      UseEndpoint(Endpoint(""127.0.0.1"", ""127.0.0.1"", Loopback, policy.port))
    else
      EndpointUnavailable
  }

  function DecideGeneration(facts: GenerationFacts): GenerationDecision
    decreases facts
  {
    if facts.candidateBuilt && facts.candidateHealthy then
      PromoteCandidate
    else if facts.activeGenerationExists && facts.activeGenerationHealthy then
      RetainActive
    else
      InitialGenerationFailed
  }

  function DecideMachineOwner(facts: MachineOwnerFacts): MachineOwnerDecision
    decreases facts
  {
    if facts.sharedReceiptExactHealth && facts.machineLeasePresent && facts.machineLeaseReadable && facts.machineLeaseMatchesReceipt && facts.leaseOwnerAlive then
      ReuseExternalOwner
    else if facts.sharedReceiptExactHealth || (facts.machineLeasePresent && (!facts.machineLeaseReadable || facts.leaseOwnerAlive)) then
      RefuseSplitBrain
    else if facts.sharedReceiptPresent || facts.machineLeasePresent then
      RecoverStaleOwner
    else
      StartMachineOwner
  }

  function DecideInstallation(facts: InstallationFacts): InstallationDecision
    decreases facts
  {
    if facts.installed && facts.launcherMatches then
      KeepInstalled
    else
      InstallLauncher
  }

  function RequiresBuild(mode: ServiceMode, facts: EnsureFacts): bool
    decreases mode, facts
  {
    !facts.runtimeReady || (mode.Production? && facts.sourcesStale)
  }

  function DecideEnsure(mode: ServiceMode, facts: EnsureFacts): EnsureDecision
    decreases mode, facts
  {
    if facts.bindingMatches && facts.modeMatches && facts.healthy && !RequiresBuild(mode, facts) then
      Reuse
    else if RequiresBuild(mode, facts) then
      ReplaceAndBuild
    else
      Replace
  }

  lemma LifecycleWitness()
    ensures DecideEnsure(Production, EnsureFacts(true, false, true, true, true)) == Reuse
    ensures DecideEnsure(Production, EnsureFacts(true, true, true, true, true)) == ReplaceAndBuild
    ensures DecideEnsure(Development, EnsureFacts(true, false, true, false, true)) == Replace
    ensures DecideInstallation(InstallationFacts(false, false)) == InstallLauncher
    ensures DecideInstallation(InstallationFacts(true, true)) == KeepInstalled
    ensures DecideGeneration(GenerationFacts(true, true, true, true)) == PromoteCandidate
    ensures DecideGeneration(GenerationFacts(true, true, false, false)) == RetainActive
    ensures DecideGeneration(GenerationFacts(false, false, false, false)) == InitialGenerationFailed
    ensures DecideMachineOwner(MachineOwnerFacts(true, true, true, true, true, true)) == ReuseExternalOwner
    ensures DecideMachineOwner(MachineOwnerFacts(false, false, false, false, false, false)) == StartMachineOwner
    ensures DecideMachineOwner(MachineOwnerFacts(true, false, true, true, false, false)) == RecoverStaleOwner
    ensures DecideMachineOwner(MachineOwnerFacts(false, false, true, false, false, false)) == RefuseSplitBrain
  {
    ghost var healthyProduction := EnsureFacts(true, false, true, true, true);
    ghost var staleProduction := EnsureFacts(true, true, true, true, true);
    ghost var staleDevelopment := EnsureFacts(true, true, true, true, true);
    ghost var changedMode := EnsureFacts(true, false, true, false, true);
    assert DecideEnsure(Production, healthyProduction) == Reuse;
    assert DecideEnsure(Production, staleProduction) == ReplaceAndBuild;
    assert DecideEnsure(Development, staleDevelopment) == Reuse;
    assert DecideEnsure(Development, changedMode) == Replace;
    assert DecideInstallation(InstallationFacts(false, false)) == InstallLauncher;
    assert DecideInstallation(InstallationFacts(true, false)) == InstallLauncher;
    assert DecideInstallation(InstallationFacts(true, true)) == KeepInstalled;
    ghost var policy := EndpointPolicy(4072, true, true, [TailscaleIp, LoopbackBind]);
    ghost var tailnet := TailscaleFacts(true, true, true, ""builder.example.ts.net"", true, ""100.64.0.8"", true);
    assert ChooseEndpoint(policy, tailnet) == UseEndpoint(Endpoint(""100.64.0.8"", ""builder.example.ts.net"", TailscaleMagicDns, 4072));
    ghost var malformed := TailscaleFacts(true, true, true, """", false, ""not-an-ip"", false);
    assert ChooseEndpoint(policy, malformed) == UseEndpoint(Endpoint(""127.0.0.1"", ""127.0.0.1"", Loopback, 4072));
    assert DecideGeneration(GenerationFacts(true, true, true, true)) == PromoteCandidate;
    assert DecideGeneration(GenerationFacts(true, true, false, false)) == RetainActive;
    assert DecideGeneration(GenerationFacts(true, true, true, false)) == RetainActive;
    assert DecideGeneration(GenerationFacts(false, false, false, false)) == InitialGenerationFailed;
    assert DecideMachineOwner(MachineOwnerFacts(true, true, true, true, true, true)) == ReuseExternalOwner;
    assert DecideMachineOwner(MachineOwnerFacts(false, false, false, false, false, false)) == StartMachineOwner;
    assert DecideMachineOwner(MachineOwnerFacts(true, false, true, true, false, false)) == RecoverStaleOwner;
    assert DecideMachineOwner(MachineOwnerFacts(false, false, true, false, false, false)) == RefuseSplitBrain;
    assert DecideMachineOwner(MachineOwnerFacts(true, false, true, true, false, true)) == RefuseSplitBrain;
    ghost var spec := ServiceSpec(1, ""fixture"", [""sha256:source""], ""builder/1"", ""runner/1"", HealthIdentity(""fixture-owner"", ""fixture/1""), policy, ""/builds/"", ""/ahp"", ""state/fixture"", ""macos-launchd/1"");
    assert ValidServiceSpec(spec);
    ghost var info := ServiceInfo(1, ""fixture"", HealthIdentity(""fixture-owner"", ""fixture/1""), ""started"", ""running"", ""lease-1"", 42, ""sha256:generation"", ""127.0.0.1"", ""127.0.0.1"", Loopback, 4072, ""http://127.0.0.1:4072/builds/"", ""ws://127.0.0.1:4072"", RefreshStatus(""healthy"", """", """"));
    assert ValidServiceInfo(info);
    assert ExactHealth(info, HealthObservation(""ok"", ""fixture-owner"", ""fixture/1"", 42, ""sha256:generation"", ""lease-1""));
    assert !ExactHealth(info, HealthObservation(""ok"", ""fixture-owner"", ""fixture/1"", 43, ""sha256:generation"", ""lease-1""));
  }

  datatype ServiceMode = Production | Development

  datatype HealthIdentity = HealthIdentity(owner: string, protocolVersion: string)

  datatype BindKind = TailscaleIp | LoopbackBind

  datatype EndpointPolicy = EndpointPolicy(port: nat, preferTailscaleMagicDns: bool, fallbackLoopback: bool, allowedBindKinds: seq<BindKind>)

  datatype ServiceSpec = ServiceSpec(schemaVersion: nat, serviceId: string, sourceClosure: seq<string>, buildGeneration: string, runGeneration: string, healthIdentity: HealthIdentity, endpointPolicy: EndpointPolicy, consolePath: string, channelPath: string, stateRoot: string, supervisorAdapter: string)

  datatype EndpointKind = TailscaleMagicDns | Loopback

  datatype Endpoint = Endpoint(bindHost: string, publicHost: string, endpointKind: EndpointKind, port: nat)

  datatype TailscaleFacts = TailscaleFacts(backendRunning: bool, magicDnsEnabled: bool, selfOnline: bool, dnsName: string, dnsNameValid: bool, matchingIp: string, matchingIpValid: bool)

  datatype EndpointDecision = UseEndpoint(endpoint: Endpoint) | EndpointUnavailable

  datatype RefreshStatus = RefreshStatus(status: string, attemptedGeneration: string, diagnostic: string)

  datatype ServiceInfo = ServiceInfo(schemaVersion: nat, serviceId: string, healthIdentity: HealthIdentity, disposition: string, status: string, ownerLeaseId: string, pid: nat, generation: string, bindHost: string, publicHost: string, endpointKind: EndpointKind, port: nat, consoleUrl: string, channelBase: string, refresh: RefreshStatus)

  datatype HealthObservation = HealthObservation(status: string, owner: string, protocolVersion: string, pid: nat, generation: string, ownerLeaseId: string)

  datatype GenerationFacts = GenerationFacts(activeGenerationExists: bool, activeGenerationHealthy: bool, candidateBuilt: bool, candidateHealthy: bool)

  datatype GenerationDecision = PromoteCandidate | RetainActive | InitialGenerationFailed

  datatype MachineOwnerFacts = MachineOwnerFacts(sharedReceiptPresent: bool, sharedReceiptExactHealth: bool, machineLeasePresent: bool, machineLeaseReadable: bool, machineLeaseMatchesReceipt: bool, leaseOwnerAlive: bool)

  datatype MachineOwnerDecision = ReuseExternalOwner | StartMachineOwner | RecoverStaleOwner | RefuseSplitBrain

  datatype InstallationFacts = InstallationFacts(installed: bool, launcherMatches: bool)

  datatype InstallationDecision = KeepInstalled | InstallLauncher

  datatype EnsureFacts = EnsureFacts(runtimeReady: bool, sourcesStale: bool, bindingMatches: bool, modeMatches: bool, healthy: bool)

  datatype EnsureDecision = Reuse | Replace | ReplaceAndBuild
}

module ConfluxHttpService {
  const CorsHeaders: seq<string> := [""Access-Control-Allow-Origin: *""]
  const EventHeaders: seq<string> := [""Cache-Control: no-cache"", ""Access-Control-Allow-Origin: *""]

  function Contains(text: string, wanted: string): bool
    decreases text, wanted
  {
    SQ.Contains(text, wanted)
  }

  function EndsWith(text: string, suffix: string): bool
    decreases text, suffix
  {
    SQ.EndsWith(text, suffix)
  }

  function PathOnly(path: string): string
    decreases path
  {
    path[..DL.IndexOf('?', path)]
  }

  function MethodMatches(pattern: MethodPattern, httpMethod: string): bool
    decreases pattern, httpMethod
  {
    match pattern
    case ExactMethod(value) =>
      value == httpMethod
    case AnyMethod() =>
      true
  }

  function PathMatches(pattern: PathPattern, path: string): bool
    decreases pattern, path
  {
    match pattern
    case ExactPath(value) =>
      value == path
    case AnyPath() =>
      true
  }

  function HttpRouteStep<H>(state: HttpRouteFold<H>, route: HttpRoute<H>, httpMethod: string, path: string): HttpRouteFold<H>
    decreases state, route, httpMethod, path
  {
    match state
    case RouteSelected(handler) =>
      state
    case RouteSearching() =>
      if !PathMatches(route.pathPattern, path) then
        state
      else if MethodMatches(route.methodPattern, httpMethod) then
        RouteSelected(route.handler)
      else
        RoutePathSeen
    case RoutePathSeen() =>
      if PathMatches(route.pathPattern, path) && MethodMatches(route.methodPattern, httpMethod) then
        RouteSelected(route.handler)
      else
        state
  }

  function FoldHttpRoutes<H>(routes: seq<HttpRoute<H>>, httpMethod: string, path: string, state: HttpRouteFold<H>): HttpRouteFold<H>
    decreases |routes|
  {
    if |routes| == 0 || state.RouteSelected? then
      state
    else
      FoldHttpRoutes(routes[1..], httpMethod, path, HttpRouteStep(state, routes[0], httpMethod, path))
  }

  function ResolveHttpRoute<H>(routes: seq<HttpRoute<H>>, httpMethod: string, rawPath: string): HttpRouteResolution<H>
    decreases routes, httpMethod, rawPath
  {
    var path: string := PathOnly(rawPath);
    match FoldHttpRoutes(routes, httpMethod, path, RouteSearching)
    case RouteSelected(handler) =>
      RouteMatched(handler)
    case RoutePathSeen() =>
      RouteMethodNotAllowed
    case RouteSearching() =>
      RouteNotFound
  }

  function RequestRouteStep<H>(state: RequestRouteFold<H>, route: RequestRoute<H>, name: string): RequestRouteFold<H>
    decreases state, route, name
  {
    match state
    case RequestSelected(handler) =>
      state
    case RequestSearching() =>
      if route.name == name then
        RequestSelected(route.handler)
      else
        state
  }

  function FoldRequestRoutes<H>(routes: seq<RequestRoute<H>>, name: string, state: RequestRouteFold<H>): RequestRouteFold<H>
    decreases |routes|
  {
    if |routes| == 0 || state.RequestSelected? then
      state
    else
      FoldRequestRoutes(routes[1..], name, RequestRouteStep(state, routes[0], name))
  }

  function ResolveRequestRoute<H>(routes: seq<RequestRoute<H>>, name: string): RequestRouteResolution<H>
    decreases routes, name
  {
    match FoldRequestRoutes(routes, name, RequestSearching)
    case RequestSelected(handler) =>
      RequestMatched(handler)
    case RequestSearching() =>
      RequestNotFound
  }

  function StaticName(path: string): string
    decreases path
  {
    var clean: string := PathOnly(path);
    if clean == ""/"" then
      ""index.html""
    else if |clean| > 0 && clean[0] == '/' then
      clean[1..]
    else
      clean
  }

  function SafeStaticName(name: string): bool
    decreases name
  {
    name != """" &&
    !Contains(name, "".."") &&
    !Contains(name, ""\\"")
  }

  function Mime(name: string): string
    decreases name
  {
    if EndsWith(name, "".html"") then
      ""text/html; charset=utf-8""
    else if EndsWith(name, "".js"") then
      ""text/javascript; charset=utf-8""
    else if EndsWith(name, "".css"") then
      ""text/css; charset=utf-8""
    else if EndsWith(name, "".json"") then
      ""application/json; charset=utf-8""
    else if EndsWith(name, "".svg"") then
      ""image/svg+xml""
    else if EndsWith(name, "".png"") then
      ""image/png""
    else
      ""application/octet-stream""
  }

  function EmptyChanges(): Json
  {
    JObj(map[""added"" := JArr([]), ""removed"" := JArr([]), ""changed"" := JArr([])])
  }

  function JsonArray(value: Json): seq<Json>
    decreases value
  {
    if value.JArr? then
      value.elems
    else
      []
  }

  function StringFieldsFrom(items: seq<Json>, fieldName: string): seq<string>
    decreases |items|
  {
    if |items| == 0 then
      []
    else
      var value: string := AsStr(Field(items[0], fieldName)); (if value == """" then [] else [value]) + StringFieldsFrom(items[1..], fieldName)
  }

  function StringFields(value: Json, fieldName: string): seq<string>
    decreases value, fieldName
  {
    StringFieldsFrom(JsonArray(value), fieldName)
  }

  method ParseRpc(body: string) returns (ingress: RpcIngress)
    decreases body
  {
    var parsed := RPC.Parse(body);
    if parsed.None? {
      ingress := RpcParseError;
    } else {
      match parsed.value
      case {:split false} Request(id, rpcMethod, params) =>
        ingress := RpcCall(id, rpcMethod, params);
      case {:split false} Invalid() =>
        ingress := RpcInvalid;
      case {:split false} _ /* _v5 */ =>
        ingress := RpcNonRequest;
    }
  }

  method JsonText(value: Json) returns (text: string)
    decreases value
  {
    text := JT.Stringify(value);
  }

  method RespondJson(request: int, status: int, value: Json)
    decreases request, status, value
  {
    var text := JsonText(value);
    HTTP.Respond(request, status, ""application/json; charset=utf-8"", CorsHeaders, text);
  }

  method RespondRpcError(request: int, status: int, id: Json, code: int, message: string)
    decreases request, status, id, code, message
  {
    RespondJson(request, status, RPC.FailureEnvelope(id, code, message, JNull));
  }

  method RespondRawRpcResult(request: int, id: Json, resultPath: string, unavailableMessage: string)
    decreases request, id, resultPath, unavailableMessage
  {
    var present, content := IO.ReadFile(resultPath);
    if present {
      var idText := JsonText(id);
      HTTP.Respond(request, 200, ""application/json; charset=utf-8"", CorsHeaders, ""{\""jsonrpc\"":\""2.0\"",\""id\"":"" + idText + "",\""result\"":"" + content + ""}"");
    } else {
      RespondRpcError(request, 500, id, -32603, unavailableMessage);
    }
  }

  method RespondFile(request: int, path: string, contentType: string, headers: seq<string>, missingStatus: int, missingBody: Json)
    decreases request, path, contentType, headers, missingStatus, missingBody
  {
    var present, content := IO.ReadFile(path);
    if present {
      HTTP.Respond(request, 200, contentType, headers, content);
    } else {
      RespondJson(request, missingStatus, missingBody);
    }
  }

  method RespondStatic(request: int, root: string, rawPath: string)
    decreases request, root, rawPath
  {
    var name := StaticName(rawPath);
    if !SafeStaticName(name) {
      RespondJson(request, 404, JObj(map[""error"" := JStr(""not found"")]));
    } else {
      RespondFile(request, root + ""/"" + name, Mime(name), [], 404, JObj(map[""error"" := JStr(""not found"")]));
    }
  }

  method RespondCorsPreflight(request: int)
    decreases request
  {
    HTTP.Respond(request, 204, ""text/plain"", [""Access-Control-Allow-Origin: *"", ""Access-Control-Allow-Headers: content-type""], """");
  }

  method BeginEventStream(request: int, eventName: string, value: Json)
    decreases request, eventName, value
  {
    var text := JsonText(value);
    HTTP.BeginStream(request, ""text/event-stream"", EventHeaders, ""event: "" + eventName + ""\ndata: "" + text + ""\n\n"");
  }

  method PublishEvent(server: int, eventName: string, value: Json)
    decreases server, eventName, value
  {
    var text := JsonText(value);
    HTTP.Publish(server, ""event: "" + eventName + ""\ndata: "" + text + ""\n\n"");
  }

  method RefreshJson(cwd: string, command: string, arguments: seq<string>, metadataPath: string, requiredField: string)
      returns (ok: bool, metadata: Json, error: string)
    decreases cwd, command, arguments, metadataPath, requiredField
  {
    var code, output, processError := IO.RunProcess(cwd, command, arguments);
    if code != 0 {
      ok := false;
      metadata := JNull;
      error := processError;
      return;
    }
    var present, text := IO.ReadFile(metadataPath);
    if !present {
      ok := false;
      metadata := JNull;
      error := ""metadata unavailable"";
      return;
    }
    var parsed := JT.ParseJsonChecked(text);
    if parsed.Invalid? || AsStr(Field(parsed.value, requiredField)) == """" {
      ok := false;
      metadata := JNull;
      error := ""metadata invalid"";
      return;
    }
    ok := true;
    metadata := parsed.value;
    error := """";
  }

  method DrainWatch(watcher: int, budget: nat, waitMs: int)
    decreases budget
  {
    if budget > 0 {
      var available, path := IO.PollWatch(watcher, waitMs);
      if available {
        DrainWatch(watcher, budget - 1, waitMs);
      }
    }
  }

  lemma RouteWitness()
    ensures ResolveHttpRoute([HttpRoute(ExactMethod(""GET""), ExactPath(""/health""), ""health""), HttpRoute(ExactMethod(""GET""), AnyPath, ""static"")], ""GET"", ""/health?probe=1"") == RouteMatched(""health"")
    ensures ResolveHttpRoute([HttpRoute(ExactMethod(""GET""), ExactPath(""/health""), ""health""), HttpRoute(ExactMethod(""GET""), AnyPath, ""static"")], ""POST"", ""/health"") == RouteMethodNotAllowed
    ensures ResolveHttpRoute([HttpRoute(ExactMethod(""GET""), ExactPath(""/health""), ""health""), HttpRoute(ExactMethod(""GET""), AnyPath, ""static"")], ""GET"", ""/app.js"") == RouteMatched(""static"")
    ensures ResolveRequestRoute([RequestRoute(""reposet/graph"", ""graph""), RequestRoute(""reposet/graphDelta"", ""delta"")], ""reposet/graphDelta"") == RequestMatched(""delta"")
    ensures ResolveRequestRoute([RequestRoute(""reposet/graph"", ""graph""), RequestRoute(""reposet/graphDelta"", ""delta"")], ""reposet/missing"") == RequestNotFound
    ensures !SafeStaticName(""../secret"")
    ensures StaticName(""/"") == ""index.html""
    ensures Mime(""app.js"") == ""text/javascript; charset=utf-8""
    ensures StringFields(JArr([]), ""path"") == []
  {
    ghost var routes := [HttpRoute(ExactMethod(""GET""), ExactPath(""/health""), ""health""), HttpRoute(ExactMethod(""GET""), AnyPath, ""static"")];
    ghost var requests := [RequestRoute(""reposet/graph"", ""graph""), RequestRoute(""reposet/graphDelta"", ""delta"")];
    assert ResolveHttpRoute(routes, ""GET"", ""/health?probe=1"") == RouteMatched(""health"");
    assert ResolveHttpRoute(routes, ""POST"", ""/health"") == RouteMethodNotAllowed;
    assert ResolveHttpRoute(routes, ""GET"", ""/app.js"") == RouteMatched(""static"");
    assert ResolveRequestRoute(requests, ""reposet/graphDelta"") == RequestMatched(""delta"");
    assert ResolveRequestRoute(requests, ""reposet/missing"") == RequestNotFound;
    assert StaticName(""/"") == ""index.html"";
    assert !SafeStaticName(""../secret"");
    assert Mime(""app.js"") == ""text/javascript; charset=utf-8"";
    assert StringFields(JArr([]), ""path"") == [];
  }

  import opened Wire = ConfluxCodec

  import SQ = ConfluxSequence

  import DL = ConfluxDelimited

  import JT = ConfluxJsonText

  import RPC = ConfluxJsonRpc

  import IO = ConfluxIoCapability

  import HTTP = ConfluxHttpCapability

  datatype RpcIngress = RpcCall(id: Json, rpcMethod: string, params: Json) | RpcParseError | RpcInvalid | RpcNonRequest

  datatype MethodPattern = ExactMethod(value: string) | AnyMethod

  datatype PathPattern = ExactPath(value: string) | AnyPath

  datatype HttpRoute<H> = HttpRoute(methodPattern: MethodPattern, pathPattern: PathPattern, handler: H)

  datatype HttpRouteFold<H> = RouteSearching | RoutePathSeen | RouteSelected(handler: H)

  datatype HttpRouteResolution<H> = RouteMatched(handler: H) | RouteMethodNotAllowed | RouteNotFound

  datatype RequestRoute<H> = RequestRoute(name: string, handler: H)

  datatype RequestRouteFold<H> = RequestSearching | RequestSelected(handler: H)

  datatype RequestRouteResolution<H> = RequestMatched(handler: H) | RequestNotFound
}

module ConfluxContentLength {
  function Token(): seq<bv8>
  {
    [67, 111, 110, 116, 101, 110, 116, 45, 76, 101, 110, 103, 116, 104, 58]
  }

  function Separator(): seq<bv8>
  {
    [13, 10, 13, 10]
  }

  function SkipSpaces(header: seq<bv8>, at: nat): nat
    requires at <= |header|
    ensures at <= SkipSpaces(header, at) <= |header|
    decreases |header| - at
  {
    if at < |header| && (header[at] == 32 || header[at] == 9) then
      SkipSpaces(header, at + 1)
    else
      at
  }

  function IsDigit(value: bv8): bool
    decreases value
  {
    48 <= value <= 57
  }

  function ReadLength(header: seq<bv8>, at: nat, value: nat, seen: bool): Option<nat>
    requires at <= |header|
    decreases |header| - at
  {
    if at < |header| && IsDigit(header[at]) then
      ReadLength(header, at + 1, value * 10 + header[at] as nat - 48, true)
    else if seen then
      Some(value)
    else
      None
  }

  function Parse(header: seq<bv8>): Option<nat>
    decreases header
  {
    var token: seq<bv8> := Token();
    var at: int := SQ.FindSubsequenceFrom(header, token, 0);
    if at < 0 then
      None
    else if at as nat + |token| > |header| then
      None
    else
      ReadLength(header, SkipSpaces(header, at as nat + |token|), 0, false)
  }

  function HeaderText(length: nat): string
    decreases length
  {
    ""Content-Length: "" + DT.NatText(length) + ""\r\n\r\n""
  }

  function Frame(header: seq<bv8>, body: seq<bv8>): seq<bv8>
    decreases header, body
  {
    header + body
  }

  method Extract(data: seq<bv8>) returns (rest: seq<bv8>, bodies: seq<seq<bv8>>)
    decreases |data|
  {
    var separator := Separator();
    var separatorAt := SQ.FindSubsequenceFrom(data, separator, 0);
    if separatorAt < 0 {
      rest, bodies := data, [];
      return;
    }
    var bodyStart := separatorAt as nat + |separator|;
    match Parse(data[..separatorAt as nat])
    case {:split false} None() =>
      rest, bodies := Extract(data[bodyStart..]);
    case {:split false} Some(length) =>
      if |data| < bodyStart + length {
        rest, bodies := data, [];
      } else {
        var tailBodies: seq<seq<bv8>>;
        rest, tailBodies := Extract(data[bodyStart + length..]);
        bodies := [data[bodyStart .. bodyStart + length]] + tailBodies;
      }
  }

  lemma ParseWitness()
    ensures exists header: seq<bv8> {:trigger Parse(header)} :: Parse(header) == Some(3)
  {
    ghost var header: seq<bv8> := [67, 111, 110, 116, 101, 110, 116, 45, 76, 101, 110, 103, 116, 104, 58, 32, 51];
    assert SQ.FindSubsequenceFrom(header, Token(), 0) == 0;
    assert SkipSpaces(header, 15) == 16;
    assert ReadLength(header, 16, 0, false) == Some(3);
    assert Parse(header) == Some(3);
  }

  import opened ConfluxContract

  import SQ = ConfluxSequence

  import DT = ConfluxDecimalText
}

module ConfluxDecimalText {
  function Digit(value: nat): char
    requires value < 10
    decreases value
  {
    ('0' as int + value) as char
  }

  function NatText(value: nat): string
    decreases value
  {
    if value < 10 then
      [Digit(value)]
    else
      NatText(value / 10) + [Digit(value % 10)]
  }

  function ParseDigits(text: string, position: nat, value: nat): nat
    requires position <= |text|
    decreases |text| - position
  {
    if position == |text| || text[position] < '0' || text[position] > '9' then
      value
    else
      ParseDigits(text, position + 1, value * 10 + text[position] as int - '0' as int)
  }

  function ParseNat(text: string): nat
    decreases text
  {
    ParseDigits(text, 0, 0)
  }

  lemma Witness()
    ensures exists v: nat {:trigger NatText(v)} :: NatText(v) == ""42"" && ParseNat(NatText(v)) == v
  {
    assert NatText(0) == ""0"";
    assert NatText(42) == ""42"";
    assert ParseNat(""42"") == 42;
    assert NatText(42) == ""42"" && ParseNat(NatText(42)) == 42;
  }
}

module ConfluxSequence {
  function StartsAt<T(==)>(haystack: seq<T>, needle: seq<T>, at: nat): bool
    requires at <= |haystack|
    decreases haystack, needle, at
  {
    at + |needle| <= |haystack| &&
    haystack[at .. at + |needle|] == needle
  }

  function FindSubsequenceFrom<T(==)>(haystack: seq<T>, needle: seq<T>, at: nat): int
    requires at <= |haystack|
    ensures -1 <= FindSubsequenceFrom(haystack, needle, at)
    ensures FindSubsequenceFrom(haystack, needle, at) >= 0 ==> FindSubsequenceFrom(haystack, needle, at) as nat + |needle| <= |haystack|
    decreases |haystack| - at
  {
    if StartsAt(haystack, needle, at) then
      at
    else if at == |haystack| then
      -1
    else
      FindSubsequenceFrom(haystack, needle, at + 1)
  }

  function Contains<T(==)>(haystack: seq<T>, needle: seq<T>): bool
    decreases haystack, needle
  {
    FindSubsequenceFrom(haystack, needle, 0) >= 0
  }

  function EndsWith<T(==)>(haystack: seq<T>, suffix: seq<T>): bool
    decreases haystack, suffix
  {
    |suffix| <= |haystack| &&
    haystack[|haystack| - |suffix|..] == suffix
  }

  function FindIndexWhere<T>(p: T -> bool, items: seq<T>): int
    ensures -1 <= FindIndexWhere(p, items) < |items|
    decreases |items|
  {
    if |items| == 0 then
      -1
    else if p(items[0]) then
      0
    else
      var tail: int := FindIndexWhere(p, items[1..]); if tail < 0 then -1 else tail + 1
  }

  lemma Witnesses()
    ensures EndsWith([1, 2, 3], [2, 3])
  {
    assert FindIndexWhere((x: int) => x % 2 == 0, [1, 4, 6]) == 1;
  }
}

module ConfluxJsonRpc {
  function Object(fields: map<string, Json>): Json
    decreases fields
  {
    JObj(fields)
  }

  function RequestEnvelope(id: Json, rpcMethod: string, params: Json): Json
    decreases id, rpcMethod, params
  {
    Object(map[""jsonrpc"" := JStr(""2.0""), ""id"" := id, ""method"" := JStr(rpcMethod), ""params"" := params])
  }

  function NotificationEnvelope(rpcMethod: string, params: Json): Json
    decreases rpcMethod, params
  {
    Object(map[""jsonrpc"" := JStr(""2.0""), ""method"" := JStr(rpcMethod), ""params"" := params])
  }

  function SuccessEnvelope(id: Json, result: Json): Json
    decreases id, result
  {
    Object(map[""jsonrpc"" := JStr(""2.0""), ""id"" := id, ""result"" := result])
  }

  function FailureEnvelope(id: Json, code: int, message: string, data: Json): Json
    decreases id, code, message, data
  {
    Object(map[""jsonrpc"" := JStr(""2.0""), ""id"" := id, ""error"" := Object(map[""code"" := JNum(code), ""message"" := JStr(message), ""data"" := data])])
  }

  function NullResult(id: Json): Json
    decreases id
  {
    SuccessEnvelope(id, JNull)
  }

  function Classify(j: Json): Message
    decreases j
  {
    var id: Json := Field(j, ""id"");
    var rpcMethod: string := AsStr(Field(j, ""method""));
    var params: Json := Field(j, ""params"");
    var error: Json := Field(j, ""error"");
    if rpcMethod != """" && !id.JNull? then
      Request(id, rpcMethod, params)
    else if rpcMethod != """" then
      Notification(rpcMethod, params)
    else if !id.JNull? && !error.JNull? then
      Failure(id, error, AsStr(Field(error, ""message"")))
    else if !id.JNull? then
      Success(id, Field(j, ""result""))
    else
      Invalid
  }

  method Parse(text: string) returns (message: Wire.Option<Message>)
    decreases text
  {
    var parsed := JT.ParseJsonChecked(text);
    match parsed
    case {:split false} Parsed(j) =>
      message := Some(Classify(j));
    case {:split false} Invalid() =>
      message := None;
  }

  method Stringify(j: Json) returns (text: string)
    decreases j
  {
    text := JT.Stringify(j);
  }

  lemma EnvelopeWitness()
    ensures exists id: Json, meth: string, params: Json {:trigger Request(id, meth, params)} {:trigger RequestEnvelope(id, meth, params)} :: Classify(RequestEnvelope(id, meth, params)) == Request(id, meth, params)
  {
    ghost var params := Object(map[""uri"" := JStr(""file:///a.dfy"")]);
    assert Classify(RequestEnvelope(JNum(7), ""inspect"", params)) == Request(JNum(7), ""inspect"", params);
    assert Classify(NotificationEnvelope(""changed"", params)) == Notification(""changed"", params);
    assert Classify(SuccessEnvelope(JStr(""request-a""), JBool(true))) == Success(JStr(""request-a""), JBool(true));
    assert Field(NullResult(JNum(8)), ""result"") == JNull;
  }

  import opened Wire = ConfluxCodec

  import JT = ConfluxJsonText

  datatype Message = Success(id: Json, result: Json) | Failure(id: Json, error: Json, errorText: string) | Notification(rpcMethod: string, params: Json) | Request(id: Json, rpcMethod: string, params: Json) | Invalid
}

module ConfluxJsonText {
  predicate IsWs(c: char)
    decreases c
  {
    c == ' ' || c == '\n' || c == '\t' || c == '\r'
  }

  predicate IsDigit(c: char)
    decreases c
  {
    '0' <= c <= '9'
  }

  function SkipWs(s: string, pos: nat): nat
    requires pos <= |s|
    ensures pos <= SkipWs(s, pos) <= |s|
    decreases |s| - pos
  {
    if pos < |s| && IsWs(s[pos]) then
      SkipWs(s, pos + 1)
    else
      pos
  }

  function HexVal(c: char): int
    decreases c
  {
    if '0' <= c <= '9' then
      c as int - '0' as int
    else if 'a' <= c <= 'f' then
      c as int - 'a' as int + 10
    else if 'A' <= c <= 'F' then
      c as int - 'A' as int + 10
    else
      -1
  }

  function HexDigit(n: nat): char
    requires n < 16
    decreases n
  {
    if n < 10 then
      ('0' as int + n) as char
    else
      ('A' as int + n - 10) as char
  }

  lemma HexDigitRoundTrip(n: nat)
    requires n < 16
    ensures HexVal(HexDigit(n)) == n
    decreases n
  {
  }

  lemma HexByteRoundTrip(v: nat)
    requires v < 256
    ensures Hex4(""00"" + [HexDigit(v / 16), HexDigit(v % 16)], 0) == v
    decreases v
  {
    HexDigitRoundTrip(v / 16);
    HexDigitRoundTrip(v % 16);
    assert v == v / 16 * 16 + v % 16;
  }

  function Hex4(s: string, p: nat): int
    requires p + 4 <= |s|
    decreases s, p
  {
    var d0: int := HexVal(s[p]);
    var d1: int := HexVal(s[p + 1]);
    var d2: int := HexVal(s[p + 2]);
    var d3: int := HexVal(s[p + 3]);
    if d0 < 0 || d1 < 0 || d2 < 0 || d3 < 0 then
      -1
    else
      d0 * 4096 + d1 * 256 + d2 * 16 + d3
  }

  predicate IsScalar(v: int)
    decreases v
  {
    0 <= v < 55296 || 57344 <= v <= 1114111
  }

  function ScalarToChar(v: int): char
    decreases v
  {
    if IsScalar(v) then
      v as char
    else
      '\U{FFFD}'
  }

  function ScanDigits(s: string, pos: nat, acc: int, count: nat): DigitCursor
    requires pos <= |s|
    ensures pos <= ScanDigits(s, pos, acc, count).pos <= |s|
    decreases |s| - pos
  {
    if pos < |s| && IsDigit(s[pos]) then
      ScanDigits(s, pos + 1, acc * 10 + s[pos] as int - '0' as int, count + 1)
    else
      DigitCursor(acc, pos, count)
  }

  function ParseStringTail(s: string, pos: nat, acc: string): StringCursor
    requires pos <= |s|
    ensures pos <= ParseStringTail(s, pos, acc).pos <= |s|
    decreases |s| - pos
  {
    if pos >= |s| then
      StringCursor(acc, pos, false)
    else if s[pos] == '""' then
      StringCursor(acc, pos + 1, true)
    else if s[pos] != '\\' then
      if s[pos] as int < 32 then
        StringCursor(acc, pos, false)
      else
        ParseStringTail(s, pos + 1, acc + [s[pos]])
    else if pos + 1 >= |s| then
      StringCursor(acc, pos, false)
    else
      var e: char := s[pos + 1]; if e == '""' || e == '\\' || e == '/' then ParseStringTail(s, pos + 2, acc + [e]) else if e == 'n' then ParseStringTail(s, pos + 2, acc + ['\n']) else if e == 't' then ParseStringTail(s, pos + 2, acc + ['\t']) else if e == 'r' then ParseStringTail(s, pos + 2, acc + ['\r']) else if e == 'b' then ParseStringTail(s, pos + 2, acc + ['\U{8}']) else if e == 'f' then ParseStringTail(s, pos + 2, acc + ['\U{C}']) else if e == 'u' && pos + 6 <= |s| && Hex4(s, pos + 2) >= 0 then var code: int := Hex4(s, pos + 2); if 55296 <= code <= 56319 && pos + 12 <= |s| && s[pos + 6] == '\\' && s[pos + 7] == 'u' && 56320 <= Hex4(s, pos + 8) <= 57343 then var lo: int := Hex4(s, pos + 8); ParseStringTail(s, pos + 12, acc + [ScalarToChar(65536 + (code - 55296) * 1024 + lo - 56320)]) else ParseStringTail(s, pos + 6, acc + [ScalarToChar(code)]) else StringCursor(acc, pos, false)
  }

  function ParseStringModel(s: string, pos: nat): StringCursor
    requires pos <= |s|
    ensures pos <= ParseStringModel(s, pos).pos <= |s|
    decreases s, pos
  {
    if pos < |s| && s[pos] == '""' then
      ParseStringTail(s, pos + 1, """")
    else
      StringCursor("""", pos, false)
  }

  function ParseNumberModel(s: string, pos0: nat): JsonCursor
    requires pos0 <= |s|
    ensures pos0 <= ParseNumberModel(s, pos0).pos <= |s|
    decreases s, pos0
  {
    var neg: bool := pos0 < |s| && s[pos0] == '-';
    var first: int := if neg then pos0 + 1 else pos0;
    var whole: DigitCursor := ScanDigits(s, first, 0, 0);
    if whole.count == 0 || (whole.count > 1 && s[first] == '0') then
      JsonCursor(JNull, whole.pos, false)
    else
      var frac: DigitCursor := if whole.pos < |s| && s[whole.pos] == '.' then ScanDigits(s, whole.pos + 1, whole.value, 0) else DigitCursor(whole.value, whole.pos, 0); var hadDot: bool := whole.pos < |s| && s[whole.pos] == '.'; if hadDot && frac.count == 0 then JsonCursor(JNull, frac.pos, false) else var expMark: bool := frac.pos < |s| && (s[frac.pos] == 'e' || s[frac.pos] == 'E'); var expSignPos: int := if expMark then frac.pos + 1 else frac.pos; var expNeg: bool := expSignPos < |s| && s[expSignPos] == '-'; var expPlus: bool := expSignPos < |s| && s[expSignPos] == '+'; var expFirst: int := if expNeg || expPlus then expSignPos + 1 else expSignPos; var expDigits: DigitCursor := if expMark then ScanDigits(s, expFirst, 0, 0) else DigitCursor(0, frac.pos, 0); if expMark && expDigits.count == 0 then JsonCursor(JNull, expDigits.pos, false) else var mantissa: int := if neg then -frac.value else frac.value; var exponent: int := -(frac.count as int) + if expNeg then -expDigits.value else expDigits.value; var value: Json := if !hadDot && !expMark then JNum(mantissa) else JDec(mantissa, exponent); JsonCursor(value, expDigits.pos, true)
  }

  function ParseValueModel(s: string, pos0: nat, budget: nat): JsonCursor
    requires pos0 <= |s|
    ensures pos0 <= ParseValueModel(s, pos0, budget).pos <= |s|
    decreases budget, 4, |s| - pos0
  {
    var pos: nat := SkipWs(s, pos0);
    if budget == 0 || pos >= |s| then
      JsonCursor(JNull, pos, false)
    else
      var c: char := s[pos]; if c == '""' then var r: StringCursor := ParseStringModel(s, pos); JsonCursor(JStr(r.value), r.pos, r.ok) else if c == '{' then ParseObjectModel(s, pos, budget) else if c == '[' then ParseArrayModel(s, pos, budget) else if c == 't' && pos + 4 <= |s| && s[pos .. pos + 4] == ""true"" then JsonCursor(JBool(true), pos + 4, true) else if c == 'f' && pos + 5 <= |s| && s[pos .. pos + 5] == ""false"" then JsonCursor(JBool(false), pos + 5, true) else if c == 'n' && pos + 4 <= |s| && s[pos .. pos + 4] == ""null"" then JsonCursor(JNull, pos + 4, true) else if c == '-' || IsDigit(c) then ParseNumberModel(s, pos) else JsonCursor(JNull, pos + 1, false)
  }

  function ParseArrayModel(s: string, pos: nat, budget: nat): JsonCursor
    requires pos < |s| && s[pos] == '['
    requires budget > 0
    ensures pos <= ParseArrayModel(s, pos, budget).pos <= |s|
    decreases budget, 3, |s| - pos
  {
    var next: nat := SkipWs(s, pos + 1);
    if next < |s| && s[next] == ']' then
      JsonCursor(JArr([]), next + 1, true)
    else
      ParseArrayTailModel(s, next, budget, [])
  }

  function ParseArrayTailModel(s: string, pos: nat, budget: nat, acc: seq<Json>): JsonCursor
    requires pos <= |s|
    requires budget > 0
    ensures pos <= ParseArrayTailModel(s, pos, budget, acc).pos <= |s|
    decreases budget, 2, |s| - pos
  {
    var item: JsonCursor := ParseValueModel(s, pos, budget - 1);
    if !item.ok then
      JsonCursor(JArr(acc), item.pos, false)
    else
      var next: nat := SkipWs(s, item.pos); if next < |s| && s[next] == ']' then JsonCursor(JArr(acc + [item.value]), next + 1, true) else if next < |s| && s[next] == ',' && next + 1 > pos then ParseArrayTailModel(s, next + 1, budget, acc + [item.value]) else JsonCursor(JArr(acc + [item.value]), next, false)
  }

  function ParseObjectModel(s: string, pos: nat, budget: nat): JsonCursor
    requires pos < |s| && s[pos] == '{'
    requires budget > 0
    ensures pos <= ParseObjectModel(s, pos, budget).pos <= |s|
    decreases budget, 1, |s| - pos
  {
    var next: nat := SkipWs(s, pos + 1);
    if next < |s| && s[next] == '}' then
      JsonCursor(JObj(map[]), next + 1, true)
    else
      ParseObjectTailModel(s, next, budget, map[])
  }

  function ParseObjectTailModel(s: string, pos: nat, budget: nat, acc: map<string, Json>): JsonCursor
    requires pos <= |s|
    requires budget > 0
    ensures pos <= ParseObjectTailModel(s, pos, budget, acc).pos <= |s|
    decreases budget, 0, |s| - pos
  {
    var next: nat := SkipWs(s, pos);
    if next >= |s| || s[next] != '""' then
      JsonCursor(JObj(acc), next, false)
    else
      var key: StringCursor := ParseStringModel(s, next); var colon: nat := SkipWs(s, key.pos); if !key.ok || colon >= |s| || s[colon] != ':' then JsonCursor(JObj(acc), colon, false) else var value: JsonCursor := ParseValueModel(s, colon + 1, budget - 1); if !value.ok then JsonCursor(JObj(acc), value.pos, false) else var after: nat := SkipWs(s, value.pos); var fields: map<string, Json> := acc[key.value := value.value]; if after < |s| && s[after] == '}' then JsonCursor(JObj(fields), after + 1, true) else if after < |s| && s[after] == ',' && after + 1 > pos then ParseObjectTailModel(s, after + 1, budget, fields) else JsonCursor(JObj(fields), after, false)
  }

  method ParseString(s: string, pos0: nat)
      returns (val: string, pos: nat, ok: bool)
    requires pos0 <= |s|
    ensures pos0 <= pos <= |s|
    decreases s, pos0
  {
    val := """";
    ok := false;
    pos := pos0;
    if pos >= |s| || s[pos] != '""' {
      return;
    }
    pos := pos + 1;
    var runStart := pos;
    while pos < |s| && s[pos] != '""'
      invariant pos0 <= runStart <= pos <= |s|
      decreases |s| - pos
    {
      if s[pos] == '\\' && pos + 1 < |s| {
        val := val + s[runStart .. pos];
        var e := s[pos + 1];
        if e == '""' || e == '\\' || e == '/' {
          val := val + [e];
          pos := pos + 2;
        } else if e == 'n' {
          val := val + ['\n'];
          pos := pos + 2;
        } else if e == 't' {
          val := val + ['\t'];
          pos := pos + 2;
        } else if e == 'r' {
          val := val + ['\r'];
          pos := pos + 2;
        } else if e == 'b' {
          val := val + ['\U{8}'];
          pos := pos + 2;
        } else if e == 'f' {
          val := val + ['\U{C}'];
          pos := pos + 2;
        } else if e == 'u' && pos + 6 <= |s| && Hex4(s, pos + 2) >= 0 {
          var code := Hex4(s, pos + 2);
          if 55296 <= code <= 56319 && pos + 12 <= |s| && s[pos + 6] == '\\' && s[pos + 7] == 'u' && Hex4(s, pos + 8) >= 56320 && Hex4(s, pos + 8) <= 57343 {
            var lo := Hex4(s, pos + 8);
            val := val + [ScalarToChar(65536 + (code - 55296) * 1024 + lo - 56320)];
            pos := pos + 12;
          } else {
            val := val + [ScalarToChar(code)];
            pos := pos + 6;
          }
        } else {
          return;
        }
        runStart := pos;
      } else {
        if s[pos] as int < 32 {
          return;
        }
        pos := pos + 1;
      }
    }
    val := val + s[runStart .. pos];
    if pos < |s| && s[pos] == '""' {
      pos := pos + 1;
      ok := true;
    }
  }

  function AdvanceOver(s: string, pos: nat, n: nat): nat
    requires pos <= |s|
    decreases s, pos, n
  {
    if pos + n <= |s| then
      pos + n
    else
      |s|
  }

  method ParseNumber(s: string, pos0: nat)
      returns (j: Json, pos: nat, ok: bool)
    requires pos0 <= |s|
    ensures pos0 <= pos <= |s|
    decreases s, pos0
  {
    pos := pos0;
    ok := false;
    var neg := false;
    if pos < |s| && s[pos] == '-' {
      neg := true;
      pos := pos + 1;
    }
    var whole := 0;
    var sawDigit := false;
    var firstDigit := pos;
    while pos < |s| && IsDigit(s[pos])
      invariant pos0 <= pos <= |s|
      decreases |s| - pos
    {
      whole := whole * 10 + s[pos] as int - '0' as int;
      sawDigit := true;
      pos := pos + 1;
    }
    var mantissa := whole;
    var exp := 0;
    var decimalDigits := 0;
    if !sawDigit || (pos - firstDigit > 1 && s[firstDigit] == '0') {
      j := JNull;
      return;
    }
    if pos < |s| && s[pos] == '.' {
      pos := pos + 1;
      var fractionStart := pos;
      while pos < |s| && IsDigit(s[pos])
        invariant pos0 <= pos <= |s|
        decreases |s| - pos
      {
        mantissa := mantissa * 10 + s[pos] as int - '0' as int;
        decimalDigits := decimalDigits + 1;
        sawDigit := true;
        pos := pos + 1;
      }
      if pos == fractionStart {
        j := JNull;
        return;
      }
      exp := -decimalDigits;
    }
    var explicitExp := false;
    if pos < |s| && (s[pos] == 'e' || s[pos] == 'E') {
      explicitExp := true;
      pos := pos + 1;
      var expNeg := false;
      if pos < |s| && (s[pos] == '+' || s[pos] == '-') {
        expNeg := s[pos] == '-';
        pos := pos + 1;
      }
      var e := 0;
      var exponentStart := pos;
      while pos < |s| && IsDigit(s[pos])
        invariant pos0 <= pos <= |s|
        decreases |s| - pos
      {
        e := e * 10 + s[pos] as int - '0' as int;
        pos := pos + 1;
      }
      if pos == exponentStart {
        j := JNull;
        return;
      }
      exp := exp + if expNeg then -e else e;
    }
    var signed := if neg then -mantissa else mantissa;
    j := if !sawDigit then JNull else if decimalDigits == 0 && !explicitExp then JNum(signed) else JDec(signed, exp);
    ok := true;
  }

  method ParseValue(s: string, pos0: nat, budget: nat)
      returns (j: Json, pos: nat, ok: bool)
    requires pos0 <= |s|
    ensures pos0 <= pos <= |s|
    decreases budget, 1
  {
    pos := SkipWs(s, pos0);
    ok := false;
    if budget == 0 || pos >= |s| {
      j := JNull;
      return;
    }
    var c := s[pos];
    if c == '""' {
      var v, p, good := ParseString(s, pos);
      j := JStr(v);
      pos := p;
      ok := good;
    } else if c == '{' {
      var m, p, good := ParseObject(s, pos, budget);
      j := JObj(m);
      pos := p;
      ok := good;
    } else if c == '[' {
      var a, p, good := ParseArray(s, pos, budget);
      j := JArr(a);
      pos := p;
      ok := good;
    } else if c == 't' && pos + 4 <= |s| && s[pos .. pos + 4] == ""true"" {
      j := JBool(true);
      pos := pos + 4;
      ok := true;
    } else if c == 'f' && pos + 5 <= |s| && s[pos .. pos + 5] == ""false"" {
      j := JBool(false);
      pos := pos + 5;
      ok := true;
    } else if c == 'n' && pos + 4 <= |s| && s[pos .. pos + 4] == ""null"" {
      j := JNull;
      pos := pos + 4;
      ok := true;
    } else if c == '-' || IsDigit(c) {
      var n, p, good := ParseNumber(s, pos);
      j := n;
      pos := p;
      ok := good;
    } else {
      j := JNull;
      pos := pos + 1;
    }
  }

  method ParseObject(s: string, pos0: nat, budget: nat)
      returns (m: map<string, Json>, pos: nat, ok: bool)
    requires pos0 <= |s|
    ensures pos0 <= pos <= |s|
    decreases budget, 0
  {
    m := map[];
    pos := pos0;
    ok := false;
    if budget == 0 {
      return;
    }
    if pos < |s| && s[pos] == '{' {
      pos := pos + 1;
    }
    pos := SkipWs(s, pos);
    if pos < |s| && s[pos] == '}' {
      pos := pos + 1;
      ok := true;
      return;
    }
    while pos < |s|
      invariant pos0 <= pos <= |s|
      decreases |s| - pos
    {
      var before := pos;
      pos := SkipWs(s, pos);
      if pos >= |s| || s[pos] != '""' {
        break;
      }
      var key, p1, keyOk := ParseString(s, pos);
      pos := p1;
      if !keyOk {
        return;
      }
      pos := SkipWs(s, pos);
      if pos < |s| && s[pos] == ':' {
        pos := pos + 1;
      } else {
        break;
      }
      var v, p2, valueOk := ParseValue(s, pos, budget - 1);
      pos := p2;
      if !valueOk {
        return;
      }
      m := m[key := v];
      pos := SkipWs(s, pos);
      if pos < |s| && s[pos] == ',' {
        pos := pos + 1;
      } else if pos < |s| && s[pos] == '}' {
        pos := pos + 1;
        ok := true;
        break;
      } else {
        break;
      }
      if pos <= before {
        break;
      }
    }
  }

  method ParseArray(s: string, pos0: nat, budget: nat)
      returns (a: seq<Json>, pos: nat, ok: bool)
    requires pos0 <= |s|
    ensures pos0 <= pos <= |s|
    decreases budget, 0
  {
    a := [];
    pos := pos0;
    ok := false;
    if budget == 0 {
      return;
    }
    if pos < |s| && s[pos] == '[' {
      pos := pos + 1;
    }
    pos := SkipWs(s, pos);
    if pos < |s| && s[pos] == ']' {
      pos := pos + 1;
      ok := true;
      return;
    }
    while pos < |s|
      invariant pos0 <= pos <= |s|
      decreases |s| - pos
    {
      var before := pos;
      var v, p, valueOk := ParseValue(s, pos, budget - 1);
      pos := p;
      if !valueOk {
        return;
      }
      a := a + [v];
      pos := SkipWs(s, pos);
      if pos < |s| && s[pos] == ',' {
        pos := pos + 1;
      } else if pos < |s| && s[pos] == ']' {
        pos := pos + 1;
        ok := true;
        break;
      } else {
        break;
      }
      if pos <= before {
        break;
      }
    }
  }

  const PARSE_BUDGET: nat := 4000

  function ParseJsonModel(s: string): ParseResult
    decreases s
  {
    var parsed: JsonCursor := ParseValueModel(s, 0, PARSE_BUDGET);
    var end: nat := SkipWs(s, parsed.pos);
    if parsed.ok && end == |s| then
      Parsed(parsed.value)
    else
      Invalid
  }

  method ParseJsonChecked(s: string) returns (result: ParseResult)
    ensures result == ParseJsonModel(s)
    decreases s
  {
    result := ParseJsonModel(s);
  }

  method ParseJson(s: string) returns (j: Json)
    decreases s
  {
    var result := ParseJsonChecked(s);
    j := if result.Parsed? then result.value else JNull;
  }

  function CharLt(a: char, b: char): bool
    decreases a, b
  {
    a as int < b as int
  }

  function StrLt(a: string, b: string): bool
    decreases |a| + |b|
  {
    if |a| == 0 then
      |b| > 0
    else if |b| == 0 then
      false
    else if a[0] == b[0] then
      StrLt(a[1..], b[1..])
    else
      CharLt(a[0], b[0])
  }

  predicate Sorted(xs: seq<string>)
    decreases xs
  {
    forall i: int, _t#0: int {:trigger xs[_t#0], xs[i]} | _t#0 == i + 1 :: 
      0 <= i &&
      _t#0 < |xs| ==>
        StrLt(xs[i], xs[_t#0])
  }

  function Elems(xs: seq<string>): set<string>
    decreases |xs|
  {
    if |xs| == 0 then
      {}
    else
      {xs[0]} + Elems(xs[1..])
  }

  lemma /*{:_inductionTrigger x in xs}*/ /*{:_inductionTrigger Elems(xs)}*/ /*{:_induction xs}*/ ElemsMembership(xs: seq<string>, x: string)
    ensures x in Elems(xs) <==> x in xs
    decreases |xs|
  {
    if |xs| > 0 {
      ElemsMembership(xs[1..], x);
    }
  }

  lemma /*{:_inductionTrigger StrLt(b, a)}*/ /*{:_inductionTrigger StrLt(a, b)}*/ /*{:_induction a, b}*/ StrLtTrichotomy(a: string, b: string)
    ensures a == b || StrLt(a, b) || StrLt(b, a)
    decreases |a| + |b|
  {
    if |a| == 0 || |b| == 0 {
    } else if a[0] == b[0] {
      StrLtTrichotomy(a[1..], b[1..]);
    }
  }

  lemma /*{:_inductionTrigger StrLt(a, a)}*/ /*{:_induction a}*/ StrLtIrreflexive(a: string)
    ensures !StrLt(a, a)
    decreases |a|
  {
    if |a| > 0 {
      StrLtIrreflexive(a[1..]);
    }
  }

  lemma /*{:_inductionTrigger StrLt(a, c), StrLt(b, c)}*/ /*{:_inductionTrigger StrLt(b, c), StrLt(a, b)}*/ /*{:_induction a, b, c}*/ StrLtTransitive(a: string, b: string, c: string)
    requires StrLt(a, b) && StrLt(b, c)
    ensures StrLt(a, c)
    decreases |a| + |b| + |c|
  {
    if |a| > 0 && |b| > 0 && |c| > 0 && a[0] == b[0] && b[0] == c[0] {
      StrLtTransitive(a[1..], b[1..], c[1..]);
    }
  }

  ghost function PickKey(s: set<string>): string
    requires s != {}
    ensures PickKey(s) in s
    decreases s
  {
    ghost var x: string /*{:_delayTriggerWarning}*/ {:trigger x in s} :| x in s;
    x
  }

  ghost function LexMin(s: set<string>): string
    requires s != {}
    ensures LexMin(s) in s
    decreases |s|
  {
    ghost var x: string := PickKey(s);
    if |s| == 1 then
      x
    else
      assert |s - {x}| == |s| - 1; assert s - {x} != {}; ghost var w: seq<char> /*{:_delayTriggerWarning}*/ {:trigger w in s} :| w in s && w != x; assert w in s - {x}; ghost var y: string := LexMin(s - {x}); if StrLt(x, y) then x else y
  }

  lemma /*{:_inductionTrigger LexMin(s)}*/ /*{:_induction s}*/ LexMinIsLeast(s: set<string>)
    requires s != {}
    ensures forall y: string {:trigger StrLt(y, LexMin(s))} {:trigger y in s} :: y in s ==> !StrLt(y, LexMin(s))
    decreases |s|
  {
    ghost var x := PickKey(s);
    if |s| > 1 {
      assert |s - {x}| == |s| - 1;
      assert s - {x} != {};
      ghost var w :| w in s && w != x;
      assert w in s - {x};
      LexMinIsLeast(s - {x});
      ghost var tailMin := LexMin(s - {x});
      if StrLt(x, tailMin) {
        forall y: string | y in s
          ensures !StrLt(y, x)
        {
          if y != x {
            assert y in s - {x};
            if StrLt(y, x) {
              StrLtTransitive(y, x, tailMin);
            }
          } else {
            StrLtIrreflexive(x);
          }
        }
      } else {
        StrLtTrichotomy(x, tailMin);
        forall y: string | y in s
          ensures !StrLt(y, tailMin)
        {
          if y == x {
            StrLtTrichotomy(x, tailMin);
          } else {
            assert y in s - {x};
          }
        }
      }
    } else {
      assert |s - {x}| == |s| - 1;
      assert s - {x} == {};
      assert forall y: seq<char> {:trigger y in s} :: y in s ==> y == x;
      assert forall y: seq<char> {:trigger y in s} :: y in s <==> y == x;
      assert s == {x};
      StrLtIrreflexive(x);
    }
  }

  ghost function SortedKeySet(s: set<string>): seq<string>
    decreases |s|
  {
    if s == {} then
      []
    else
      ghost var k: string := LexMin(s); [k] + SortedKeySet(s - {k})
  }

  lemma /*{:_inductionTrigger b in s, a in s}*/ /*{:_induction a, b}*/ LeastKeyUnique(s: set<string>, a: string, b: string)
    requires a in s && b in s
    requires forall y: string {:trigger StrLt(y, a)} {:trigger y in s} :: y in s ==> !StrLt(y, a)
    requires forall y: string {:trigger StrLt(y, b)} {:trigger y in s} :: y in s ==> !StrLt(y, b)
    ensures a == b
    decreases s, a, b
  {
    StrLtTrichotomy(a, b);
  }

  method SortedKeySetRuntime(s: set<string>) returns (keys: seq<string>)
    ensures keys == SortedKeySet(s)
    decreases |s|
  {
    if s == {} {
      keys := [];
    } else {
      LexMinIsLeast(s);
      var k :| k in s && forall y: string {:trigger StrLt(y, k)} {:trigger y in s} :: y in s ==> !StrLt(y, k);
      LeastKeyUnique(s, k, LexMin(s));
      var tail := SortedKeySetRuntime(s - {k});
      keys := [k] + tail;
    }
  }

  lemma /*{:_inductionTrigger SortedKeySet(s)}*/ /*{:_induction s}*/ SortedKeySetProperties(s: set<string>)
    ensures Sorted(SortedKeySet(s))
    ensures Elems(SortedKeySet(s)) == s
    decreases |s|
  {
    if s != {} {
      ghost var k := LexMin(s);
      LexMinIsLeast(s);
      SortedKeySetProperties(s - {k});
      if |SortedKeySet(s - {k})| > 0 {
        ghost var next := SortedKeySet(s - {k})[0];
        assert next in Elems(SortedKeySet(s - {k}));
        assert next in s - {k};
        StrLtTrichotomy(k, next);
        assert k != next;
        assert !StrLt(next, k);
      }
    }
  }

  method InsertKey(k: string, xs: seq<string>) returns (ys: seq<string>)
    requires Sorted(xs)
    requires k !in xs
    ensures Sorted(ys)
    ensures |ys| == |xs| + 1
    ensures Elems(ys) == {k} + Elems(xs)
    ensures |ys| > 0 && (ys[0] == k || (|xs| > 0 && ys[0] == xs[0]))
    decreases |xs|
  {
    if |xs| == 0 {
      ys := [k];
    } else if StrLt(k, xs[0]) {
      ys := [k] + xs;
    } else {
      StrLtTrichotomy(k, xs[0]);
      assert k != xs[0];
      assert StrLt(xs[0], k);
      var tail := InsertKey(k, xs[1..]);
      ys := [xs[0]] + tail;
    }
  }

  method SortedKeys(m: map<string, Json>) returns (keys: seq<string>)
    ensures Sorted(keys)
    ensures Elems(keys) == m.Keys
    ensures keys == SortedKeySet(m.Keys)
    decreases m
  {
    keys := SortedKeySetRuntime(m.Keys);
    SortedKeySetProperties(m.Keys);
  }

  function IntText(n: int): string
    decreases n
  {
    if n < 0 then
      ""-"" + NatText(-n)
    else
      NatText(n)
  }

  function EscapeChar(c: char): string
    decreases c
  {
    if c == '""' then
      ""\\\""""
    else if c == '\\' then
      ""\\\\""
    else if c == '\n' then
      ""\\n""
    else if c == '\r' then
      ""\\r""
    else if c == '\t' then
      ""\\t""
    else if c == '\U{8}' then
      ""\\b""
    else if c == '\U{C}' then
      ""\\f""
    else if c as int < 32 then
      ""\\u00"" + [HexDigit(c as int / 16), HexDigit(c as int % 16)]
    else
      [c]
  }

  lemma RemainingC0EscapeRoundTrip(c: char)
    requires c as int < 32
    requires c != '\n' && c != '\r' && c != '\t' && c != '\U{8}' && c != '\U{C}'
    ensures |EscapeChar(c)| == 6
    ensures Hex4(EscapeChar(c), 2) == c as int
    ensures ScalarToChar(Hex4(EscapeChar(c), 2)) == c
    decreases c
  {
    HexByteRoundTrip(c as int);
  }

  lemma C0Examples()
    ensures EscapeChar('\U{0}') == ""\\u0000""
    ensures EscapeChar('\U{1}') == ""\\u0001""
    ensures EscapeChar('\U{1F}') == ""\\u001F""
  {
  }

  function Escape(s: string): string
    decreases |s|
  {
    if |s| == 0 then
      """"
    else
      EscapeChar(s[0]) + Escape(s[1..])
  } by method {
    if |s| == 0 {
      return """";
    }
    var n := |s|;
    var arr := new char[6 * n];
    var off: nat := 0;
    var i := 0;
    while i < n
      invariant 0 <= i <= n
      invariant arr.Length == 6 * n
      invariant off <= 6 * i
      invariant off <= arr.Length
      invariant arr[..off] == Escape(s[..i])
      decreases n - i
    {
      var e := EscapeChar(s[i]);
      EscapeCharLenBound(s[i]);
      EscapeSnoc(s, i);
      ghost var pre := arr[..off];
      assert pre == Escape(s[..i]);
      assert off + |e| <= 6 * n;
      var j := 0;
      while j < |e|
        invariant 0 <= j <= |e|
        invariant off + |e| <= arr.Length
        invariant off <= arr.Length
        invariant arr[..off] == pre
        invariant forall k: int {:trigger e[k]} :: 0 <= k < j ==> arr[off + k] == e[k]
        decreases |e| - j
      {
        arr[off + j] := e[j];
        j := j + 1;
      }
      assert arr[..off + |e|] == pre + e by {
        assert |arr[..off + |e|]| == |pre + e|;
        forall k: int | 0 <= k < off + |e|
          ensures arr[..off + |e|][k] == (pre + e)[k]
        {
          if k < off {
            assert arr[k] == pre[k];
          } else {
            assert arr[k] == e[k - off];
          }
        }
      }
      assert pre + e == Escape(s[..i + 1]);
      off := off + |e|;
      i := i + 1;
    }
    assert s[..n] == s;
    var result := seq(off, (k: int) requires 0 <= k < off reads arr => arr[k]);
    assert result == arr[..off] by {
      assert |result| == |arr[..off]|;
      forall k: int | 0 <= k < |result|
        ensures result[k] == arr[..off][k]
      {
        assert result[k] == arr[k];
      }
    }
    return result;
  }

  lemma EscapeCharLenBound(c: char)
    ensures 1 <= |EscapeChar(c)| <= 6
    decreases c
  {
  }

  lemma /*{:_inductionTrigger Escape(a) + Escape(b)}*/ /*{:_inductionTrigger Escape(a + b)}*/ /*{:_induction a, b}*/ EscapeAppend(a: string, b: string)
    ensures Escape(a + b) == Escape(a) + Escape(b)
    decreases |a|
  {
    if |a| == 0 {
      assert a == [];
      assert a + b == b;
    } else {
      assert (a + b)[0] == a[0];
      assert (a + b)[1..] == a[1..] + b;
      EscapeAppend(a[1..], b);
    }
  }

  lemma EscapeSnoc(s: string, i: nat)
    requires i < |s|
    ensures Escape(s[..i + 1]) == Escape(s[..i]) + EscapeChar(s[i])
    decreases s, i
  {
    assert s[..i + 1] == s[..i] + [s[i]];
    EscapeAppend(s[..i], [s[i]]);
    assert [s[i]][1..] == [];
    assert Escape([s[i]]) == EscapeChar(s[i]);
  }

  ghost function StringifyModel(j: Json, budget: nat): string
    decreases budget, 0
  {
    if budget == 0 || j.JNull? then
      ""null""
    else if j.JBool? then
      if j.b then
        ""true""
      else
        ""false""
    else if j.JNum? then
      IntText(j.n)
    else if j.JDec? then
      IntText(j.mantissa) + ""e"" + IntText(j.exp)
    else if j.JStr? then
      ""\"""" + Escape(j.s) + ""\""""
    else if j.JArr? then
      ""["" + StringifySeqModel(j.elems, budget - 1) + ""]""
    else
      ""{"" + StringifyFieldsModel(j.fields, SortedKeySet(j.fields.Keys), budget - 1) + ""}""
  }

  ghost function StringifySeqModel(xs: seq<Json>, budget: nat): string
    decreases budget, 1, |xs|
