      """"
    else
      StringifyModel(xs[0], budget) + if |xs| == 1 then """" else "","" + StringifySeqModel(xs[1..], budget)
  }

  ghost function StringifyFieldsModel(fields: map<string, Json>, keys: seq<string>, budget: nat): string
    decreases budget, 1, |keys|
  {
    if |keys| == 0 then
      """"
    else
      ghost var value: Json := if keys[0] in fields then fields[keys[0]] else JNull; ""\"""" + Escape(keys[0]) + ""\"":"" + StringifyModel(value, budget) + if |keys| == 1 then """" else "","" + StringifyFieldsModel(fields, keys[1..], budget)
  }

