  predicate AllDigits(ds: string)
    decreases ds
  {
    forall i: int {:trigger ds[i]} :: 
      0 <= i < |ds| ==>
        IsDigit(ds[i])
  }

  function FoldDigits(ds: string, acc: int): int
    decreases |ds|
  {
    if |ds| == 0 then
      acc
    else
      FoldDigits(ds[1..], acc * 10 + ds[0] as int - '0' as int)
  }

  function DigitStep(acc: int, d: char): int
    decreases acc, d
