  lemma /*{:_inductionTrigger ScanDigits(prefix + ds + suffix, |prefix|, acc, count)}*/ /*{:_induction prefix, ds, suffix, acc, count}*/ ScanDigitSegment(prefix: string, ds: string, suffix: string, acc: int, count: nat)
