  lemma /*{:_inductionTrigger NatText(n)}*/ /*{:_induction n}*/ NatTextFacts(n: nat)
    ensures |NatText(n)| > 0
    ensures AllDigits(NatText(n))
    ensures FoldDigits(NatText(n), 0) == n
    ensures |NatText(n)| > 1 ==> NatText(n)[0] != '0'
    decreases n
  {
    if n < 10 {
    } else {
      NatTextFacts(n / 10);
      FoldDigitsAppend(NatText(n / 10), Digit(n % 10), 0);
      assert FoldDigits([Digit(n % 10)], n / 10) == n;
      assert NatText(n)[0] == NatText(n / 10)[0];
    }
  }

  lemma ParseStringifyInt(n: int)
    ensures ParseNumberModel(IntText(n), 0) == JsonCursor(JNum(n), |IntText(n)|, true)
    decreases n
  {
    if n < 0 {
      NatTextFacts(-n);
      ScanDigitSegment(""-"", NatText(-n), """", 0, 0);
      assert IntText(n) == ""-"" + NatText(-n);
      assert ScanDigits(""-"" + NatText(-n) + """", 1, 0, 0) == DigitCursor(FoldDigits(NatText(-n), 0), 1 + |NatText(-n)|, |NatText(-n)|);
      assert |IntText(n)| == 1 + |NatText(-n)|;
      assert IntText(n) == ""-"" + NatText(-n) + """";
      assert FoldDigits(NatText(-n), 0) == -n;
      assert ScanDigits(IntText(n), 1, 0, 0) == DigitCursor(-n, |IntText(n)|, |NatText(-n)|);
    } else {
      NatTextFacts(n);
      ScanDigitSegment("""", NatText(n), """", 0, 0);
      assert IntText(n) == NatText(n);
      assert ScanDigits("""" + NatText(n) + """", 0, 0, 0) == DigitCursor(FoldDigits(NatText(n), 0), |NatText(n)|, |NatText(n)|);
      assert IntText(n) == """" + NatText(n) + """";
      assert FoldDigits(NatText(n), 0) == n;
      assert ScanDigits(IntText(n), 0, 0, 0) == DigitCursor(n, |IntText(n)|, |NatText(n)|);
    }
  }

