    ensures PutFields(acc, fields, keys).Keys == acc.Keys + Elems(keys)
    ensures forall k: seq<char> {:trigger fields[k]} {:trigger PutFields(acc, fields, keys)[k]} {:trigger k in Elems(keys)} :: k in Elems(keys) ==> PutFields(acc, fields, keys)[k] == fields[k]
