      assert keys[0] in Elems(keys);
      assert keys[0] in fields;
      assert Elems(keys[1..]) <= fields.Keys;
      PutFieldsFacts(acc[keys[0] := fields[keys[0]]], fields, keys[1..]);
      ElemsMembership(keys[1..], keys[0]);
      forall k: seq<char> | k in Elems(keys)
        ensures PutFields(acc, fields, keys)[k] == fields[k]
