  lemma {:isolate_assertions} /*{:_inductionTrigger ParseValueModel(prefix + IntText(mantissa) + ""e"" + IntText(exp) + suffix, |prefix|, budget)}*/ /*{:_induction prefix, suffix, budget}*/ ParseDecimalWireValueAt(prefix: string, mantissa: int, exp: int, suffix: string, budget: nat)
