  lemma {:isolate_assertions} /*{:_inductionTrigger |StringifyModel(Json.JArr(xs), budget)|, |prefix|, ValueStop(suffix)}*/ /*{:_inductionTrigger prefix + StringifyModel(Json.JArr(xs), budget), ValueStop(suffix)}*/ /*{:_induction prefix, suffix, budget}*/ ParseStringifiedArrayValueAt(prefix: string, xs: seq<Json>, suffix: string, budget: nat)
    requires budget > 0 && ValueStop(suffix)
    requires forall i: int {:trigger xs[i]} :: 0 <= i < |xs| ==> CanonicalDomain(xs[i], budget - 1)
    ensures ParseValueModel(prefix + StringifyModel(JArr(xs), budget) + suffix, |prefix|, budget) == JsonCursor(JArr(xs), |prefix| + |StringifyModel(JArr(xs), budget)|, true)
    decreases budget, 3, 0
  {
    ghost var text := prefix + StringifyModel(JArr(xs), budget) + suffix;
    assert StringifyModel(JArr(xs), budget) == ""["" + StringifySeqModel(xs, budget - 1) + ""]"";
    assert text[|prefix|] == '[';
    assert SkipWs(text, |prefix|) == |prefix|;
    if |xs| == 0 {
      assert text[|prefix| + 1] == ']';
      ParseArrayEmptyOpenStep(text, |prefix|, budget);
    } else {
      StringifyStartsNonWs(xs[0], budget - 1);
      assert text[|prefix| + 1] == StringifyModel(xs[0], budget - 1)[0];
      assert !IsWs(text[|prefix| + 1]);
      assert SkipWs(text, |prefix| + 1) == |prefix| + 1;
      ParseStringifiedSeqTail(prefix + ""["", xs, suffix, budget, []);
      ghost var out := JsonCursor(JArr(xs), |prefix| + |StringifyModel(JArr(xs), budget)|, true);
      assert text == prefix + ""["" + StringifySeqModel(xs, budget - 1) + ""]"" + suffix;
      assert ParseArrayTailModel(text, |prefix| + 1, budget, []) == out;
      ParseArrayOpenStep(text, |prefix|, budget, out);
    }
  }

  lemma {:isolate_assertions} /*{:_inductionTrigger |StringifyModel(Json.JObj(fields), budget)|, |prefix|, ValueStop(suffix)}*/ /*{:_inductionTrigger prefix + StringifyModel(Json.JObj(fields), budget), ValueStop(suffix)}*/ /*{:_induction prefix, suffix, budget}*/ ParseStringifiedObjectValueAt(prefix: string, fields: map<string, Json>, suffix: string, budget: nat)
    requires budget > 0 && ValueStop(suffix)
    requires forall k: seq<char> {:trigger fields[k]} {:trigger k in fields} :: k in fields ==> CanonicalDomain(fields[k], budget - 1)
    ensures ParseValueModel(prefix + StringifyModel(JObj(fields), budget) + suffix, |prefix|, budget) == JsonCursor(JObj(fields), |prefix| + |StringifyModel(JObj(fields), budget)|, true)
    decreases budget, 1, 0
  {
    ghost var text := prefix + StringifyModel(JObj(fields), budget) + suffix;
    assert StringifyModel(JObj(fields), budget) == ""{"" + StringifyFieldsModel(fields, SortedKeySet(fields.Keys), budget - 1) + ""}"";
    assert text[|prefix|] == '{';
    assert SkipWs(text, |prefix|) == |prefix|;
    ghost var keys := SortedKeySet(fields.Keys);
    SortedKeySetProperties(fields.Keys);
    if |keys| == 0 {
      assert fields.Keys == {};
      assert fields == map[];
      assert text[|prefix| + 1] == '}';
      ParseObjectEmptyOpenStep(text, |prefix|, budget);
    } else {
      assert text[|prefix| + 1] == '""';
      assert SkipWs(text, |prefix| + 1) == |prefix| + 1;
      forall i: int | 0 <= i < |keys|
        ensures keys[i] in fields && CanonicalDomain(fields[keys[i]], budget - 1)
      {
        ElemsMembership(keys, keys[i]);
      }
      ParseStringifiedFieldsTail(prefix + ""{"", fields, keys, suffix, budget, map[]);
      PutAllFields(fields);
      ghost var out := JsonCursor(JObj(fields), |prefix| + |StringifyModel(JObj(fields), budget)|, true);
      assert text == prefix + ""{"" + StringifyFieldsModel(fields, keys, budget - 1) + ""}"" + suffix;
      assert ParseObjectTailModel(text, |prefix| + 1, budget, map[]) == out;
      ParseObjectOpenStep(text, |prefix|, budget, out);
    }
  }

  lemma {:isolate_assertions} /*{:_inductionTrigger |StringifyModel(j, budget)|, |prefix|, ValueStop(suffix)}*/ /*{:_inductionTrigger prefix + StringifyModel(j, budget), ValueStop(suffix)}*/ /*{:_induction prefix, j, suffix, budget}*/ ParseStringifiedValueAt(prefix: string, j: Json, suffix: string, budget: nat)
    requires ValueStop(suffix)
    requires CanonicalDomain(j, budget)
    ensures ParseValueModel(prefix + StringifyModel(j, budget) + suffix, |prefix|, budget) == JsonCursor(j, |prefix| + |StringifyModel(j, budget)|, true)
    decreases budget, 4, 0
  {
    assert budget > 0;
    if j.JNull? {
    } else if j.JBool? {
    } else if j.JNum? {
      ParseStringifyIntAt(prefix, j.n, suffix);
    } else if j.JDec? {
      ParseStringifiedDecimalValueAt(prefix, j.mantissa, j.exp, suffix, budget);
    } else if j.JStr? {
      ghost var text := prefix + StringifyModel(j, budget) + suffix;
      assert StringifyModel(j, budget) == ""\"""" + Escape(j.s) + ""\"""";
      assert text[|prefix|] == '""';
      assert !IsWs(text[|prefix|]);
      assert SkipWs(text, |prefix|) == |prefix|;
      ParseStringifyStringAt(prefix, j.s, suffix);
      assert text == prefix + ""\"""" + Escape(j.s) + ""\"""" + suffix;
      assert ParseStringModel(text, |prefix|) == StringCursor(j.s, |prefix| + |Escape(j.s)| + 2, true);
      assert |StringifyModel(j, budget)| == |Escape(j.s)| + 2;
    } else if j.JArr? {
      ParseStringifiedArrayValueAt(prefix, j.elems, suffix, budget);
    } else {
      ParseStringifiedObjectValueAt(prefix, j.fields, suffix, budget);
    }
  }

  lemma {:isolate_assertions} {:fuel ParseValueModel, 0, 0} {:fuel ParseArrayTailModel, 0, 0} {:fuel SkipWs, 0, 0} ParseStringifiedSeqTail(prefix: string, xs: seq<Json>, suffix: string, budget: nat, acc: seq<Json>)
    requires budget > 0 && |xs| > 0
    requires ValueStop(suffix)
    requires forall i: int {:trigger xs[i]} :: 0 <= i < |xs| ==> CanonicalDomain(xs[i], budget - 1)
    ensures ParseArrayTailModel(prefix + StringifySeqModel(xs, budget - 1) + ""]"" + suffix, |prefix|, budget, acc) == JsonCursor(JArr(acc + xs), |prefix| + |StringifySeqModel(xs, budget - 1)| + 1, true)
    decreases budget, 2, |xs|
  {
    ghost var head := xs[0];
    if |xs| == 1 {
      ParseStringifiedValueAt(prefix, head, ""]"" + suffix, budget - 1);
      assert xs == [head];
      assert StringifySeqModel(xs, budget - 1) == StringifyModel(head, budget - 1);
      ghost var text := prefix + StringifyModel(head, budget - 1) + ""]"" + suffix;
      ghost var end := |prefix| + |StringifyModel(head, budget - 1)|;
      assert text == prefix + StringifyModel(head, budget - 1) + (""]"" + suffix);
      assert prefix + StringifySeqModel(xs, budget - 1) + ""]"" + suffix == text;
      assert ParseValueModel(text, |prefix|, budget - 1) == JsonCursor(head, end, true);
      assert text[end] == ']';
      SkipWsAtNonWs(text, end);
      assert acc + xs == acc + [head];
      ParseArrayCloseStep(text, |prefix|, budget, acc, head, end);
      assert JsonCursor(JArr(acc + [head]), end + 1, true) == JsonCursor(JArr(acc + xs), |prefix| + |StringifySeqModel(xs, budget - 1)| + 1, true);
    } else {
      ghost var rest := xs[1..];
      ghost var restText := StringifySeqModel(rest, budget - 1);
      ParseStringifiedValueAt(prefix, head, "","" + restText + ""]"" + suffix, budget - 1);
      ghost var nextPrefix := prefix + StringifyModel(head, budget - 1) + "","";
      ParseStringifiedSeqTail(nextPrefix, rest, suffix, budget, acc + [head]);
      SeqConcatAssoc(acc, [head], rest);
      assert xs == [head] + rest;
      assert StringifySeqModel(xs, budget - 1) == StringifyModel(head, budget - 1) + "","" + restText;
      assert prefix + StringifySeqModel(xs, budget - 1) + ""]"" + suffix == nextPrefix + restText + ""]"" + suffix;
      ghost var text := prefix + StringifySeqModel(xs, budget - 1) + ""]"" + suffix;
      ghost var comma := |prefix| + |StringifyModel(head, budget - 1)|;
      assert text == prefix + StringifyModel(head, budget - 1) + ("","" + restText + ""]"" + suffix);
      assert ParseValueModel(text, |prefix|, budget - 1) == JsonCursor(head, comma, true);
      assert text[comma] == ',';
      SkipWsAtNonWs(text, comma);
      assert nextPrefix + restText + ""]"" + suffix == text;
      assert |nextPrefix| + |restText| + 1 == |prefix| + |StringifySeqModel(xs, budget - 1)| + 1;
      assert comma + 1 == |nextPrefix|;
      ghost var out := JsonCursor(JArr(acc + [head] + rest), |nextPrefix| + |restText| + 1, true);
      assert ParseArrayTailModel(text, comma + 1, budget, acc + [head]) == out;
      ComposeArrayComma(text, |prefix|, budget, acc, head, comma, out);
      assert out == JsonCursor(JArr(acc + xs), |prefix| + |StringifySeqModel(xs, budget - 1)| + 1, true);
    }
  }

  lemma {:isolate_assertions} {:fuel ParseStringModel, 0, 0} {:fuel ParseValueModel, 0, 0} {:fuel ParseObjectTailModel, 0, 0} {:fuel SkipWs, 0, 0} ParseStringifiedFieldsTail(prefix: string, fields: map<string, Json>, keys: seq<string>, suffix: string, budget: nat, acc: map<string, Json>)
    requires budget > 0 && |keys| > 0
    requires ValueStop(suffix)
    requires forall i: int {:trigger keys[i]} :: (0 <= i < |keys| ==> keys[i] in fields) && (0 <= i < |keys| ==> CanonicalDomain(fields[keys[i]], budget - 1))
    ensures ParseObjectTailModel(prefix + StringifyFieldsModel(fields, keys, budget - 1) + ""}"" + suffix, |prefix|, budget, acc) == JsonCursor(JObj(PutFields(acc, fields, keys)), |prefix| + |StringifyFieldsModel(fields, keys, budget - 1)| + 1, true)
    decreases budget, 0, |keys|
  {
    ghost var key := keys[0];
    ghost var valuePrefix := prefix + ""\"""" + Escape(key) + ""\"":"";
    ghost var value := fields[key];
    if |keys| == 1 {
      ParseStringifyStringAt(prefix, key, "":"" + StringifyModel(value, budget - 1) + ""}"" + suffix);
      ParseStringifiedValueAt(valuePrefix, value, ""}"" + suffix, budget - 1);
      assert keys == [key];
      ghost var text := prefix + StringifyFieldsModel(fields, keys, budget - 1) + ""}"" + suffix;
      assert text == prefix + ""\"""" + Escape(key) + ""\"""" + ("":"" + StringifyModel(value, budget - 1) + ""}"" + suffix);
      assert text == valuePrefix + StringifyModel(value, budget - 1) + (""}"" + suffix);
      ghost var colon := |prefix| + |Escape(key)| + 2;
      ghost var close := |valuePrefix| + |StringifyModel(value, budget - 1)|;
      assert text[|prefix|] == '""';
      SkipWsAtNonWs(text, |prefix|);
      assert ParseStringModel(text, |prefix|) == StringCursor(key, colon, true);
      assert text[colon] == ':';
      SkipWsAtNonWs(text, colon);
      assert ParseValueModel(text, |valuePrefix|, budget - 1) == JsonCursor(value, close, true);
      assert text[close] == '}';
      SkipWsAtNonWs(text, close);
      assert PutFields(acc, fields, keys) == acc[key := value];
      ParseObjectCloseStep(text, |prefix|, budget, acc, key, colon, value, close);
      calc {
        ParseObjectTailModel(text, |prefix|, budget, acc);
      ==
        JsonCursor(JObj(acc[key := value]), close + 1, true);
      ==
        JsonCursor(JObj(PutFields(acc, fields, keys)), |prefix| + |StringifyFieldsModel(fields, keys, budget - 1)| + 1, true);
      }
    } else {
      ghost var rest := keys[1..];
      ghost var restText := StringifyFieldsModel(fields, rest, budget - 1);
      ParseStringifyStringAt(prefix, key, "":"" + StringifyModel(value, budget - 1) + "","" + restText + ""}"" + suffix);
      ParseStringifiedValueAt(valuePrefix, value, "","" + restText + ""}"" + suffix, budget - 1);
      ghost var nextPrefix := valuePrefix + StringifyModel(value, budget - 1) + "","";
      ParseStringifiedFieldsTail(nextPrefix, fields, rest, suffix, budget, acc[key := value]);
      assert StringifyFieldsModel(fields, keys, budget - 1) == ""\"""" + Escape(key) + ""\"":"" + StringifyModel(value, budget - 1) + "","" + restText;
      assert PutFields(acc, fields, keys) == PutFields(acc[key := value], fields, rest);
      assert prefix + StringifyFieldsModel(fields, keys, budget - 1) + ""}"" + suffix == nextPrefix + restText + ""}"" + suffix;
      ghost var text := prefix + StringifyFieldsModel(fields, keys, budget - 1) + ""}"" + suffix;
      assert text == prefix + ""\"""" + Escape(key) + ""\"":"" + StringifyModel(value, budget - 1) + "","" + restText + ""}"" + suffix;
      assert text == prefix + ""\"""" + Escape(key) + ""\"""" + ("":"" + StringifyModel(value, budget - 1) + "","" + restText + ""}"" + suffix);
      assert text == valuePrefix + StringifyModel(value, budget - 1) + ("","" + restText + ""}"" + suffix);
      ghost var colon := |prefix| + |Escape(key)| + 2;
      assert text[|prefix|] == '""';
      SkipWsAtNonWs(text, |prefix|);
      assert ParseStringModel(text, |prefix|) == StringCursor(key, colon, true);
      assert text[colon] == ':';
      SkipWsAtNonWs(text, colon);
      ghost var comma := |valuePrefix| + |StringifyModel(value, budget - 1)|;
      assert ParseValueModel(text, |valuePrefix|, budget - 1) == JsonCursor(value, comma, true);
      assert text[comma] == ',';
      SkipWsAtNonWs(text, comma);
      assert nextPrefix + restText + ""}"" + suffix == text;
      assert comma + 1 == |nextPrefix|;
      assert |nextPrefix| + |restText| + 1 == |prefix| + |StringifyFieldsModel(fields, keys, budget - 1)| + 1;
      ghost var out := JsonCursor(JObj(PutFields(acc[key := value], fields, rest)), |nextPrefix| + |restText| + 1, true);
      assert ParseObjectTailModel(text, comma + 1, budget, acc[key := value]) == out;
      assert budget > 0 && |prefix| < |text| && text[|prefix|] == '""';
      assert colon < |text| && SkipWs(text, colon) == colon && text[colon] == ':';
      assert comma < |text| && SkipWs(text, comma) == comma && text[comma] == ',';
      assert comma + 1 > |prefix|;
      ComposeObjectComma(text, |prefix|, budget, acc, key, colon, value, comma, out);
      assert out == JsonCursor(JObj(PutFields(acc, fields, keys)), |prefix| + |StringifyFieldsModel(fields, keys, budget - 1)| + 1, true);
    }
  }

  lemma {:isolate_assertions} /*{:_inductionTrigger ParseResult.Parsed(j)}*/ /*{:_inductionTrigger StringifyModel(j, STRINGIFY_BUDGET)}*/ /*{:_inductionTrigger CanonicalDomain(j, STRINGIFY_BUDGET)}*/ /*{:_induction j}*/ ParseStringifyRoundTrip(j: Json)
    requires CanonicalDomain(j, STRINGIFY_BUDGET)
    ensures ParseJsonModel(StringifyModel(j, STRINGIFY_BUDGET)) == Parsed(j)
    decreases j
  {
    assert PARSE_BUDGET == STRINGIFY_BUDGET;
    ParseStringifiedValueAt("""", j, """", STRINGIFY_BUDGET);
    ghost var text := StringifyModel(j, STRINGIFY_BUDGET);
    assert """" + text + """" == text;
    assert ParseValueModel(text, 0, STRINGIFY_BUDGET) == JsonCursor(j, |text|, true);
    assert ParseValueModel(text, 0, PARSE_BUDGET) == JsonCursor(j, |text|, true);
    assert SkipWs(text, |text|) == |text|;
  }

  lemma /*{:_inductionTrigger StringifySeqModel(xs[split..], budget)}*/ /*{:_inductionTrigger StringifySeqModel(xs[..split], budget)}*/ /*{:_induction xs, budget}*/ StringifySeqModelSplit(xs: seq<Json>, budget: nat, split: nat)
    requires 0 < split < |xs|
    ensures StringifySeqModel(xs, budget) == StringifySeqModel(xs[..split], budget) + "","" + StringifySeqModel(xs[split..], budget)
    decreases split
  {
    if split == 1 {
      assert xs[..split] == [xs[0]];
      assert xs[split..] == xs[1..];
    } else {
      StringifySeqModelSplit(xs[1..], budget, split - 1);
      assert xs[..split][0] == xs[0];
      assert xs[..split][1..] == xs[1 .. split];
      assert xs[1..][..split - 1] == xs[1 .. split];
      assert xs[1..][split - 1..] == xs[split..];
    }
  }

  method StringifySeqRuntime(xs: seq<Json>, budget: nat) returns (s: string)
    ensures s == StringifySeqModel(xs, budget)
    decreases budget, 1, |xs|
  {
    if |xs| == 0 {
      s := """";
    } else if |xs| == 1 {
      s := StringifyValue(xs[0], budget);
    } else {
      var split := |xs| / 2;
      assert 0 < split < |xs|;
      var left := StringifySeqRuntime(xs[..split], budget);
      var right := StringifySeqRuntime(xs[split..], budget);
      StringifySeqModelSplit(xs, budget, split);
      s := left + "","" + right;
    }
  }

  method StringifyFieldsRuntime(fields: map<string, Json>, keys: seq<string>, budget: nat)
      returns (s: string)
    requires forall i: int {:trigger keys[i]} :: 0 <= i < |keys| ==> keys[i] in fields
    ensures s == StringifyFieldsModel(fields, keys, budget)
    decreases budget, 1, |keys|
  {
    if |keys| == 0 {
      s := """";
    } else {
      var value := StringifyValue(fields[keys[0]], budget);
      var head := ""\"""" + Escape(keys[0]) + ""\"":"" + value;
      if |keys| == 1 {
        s := head;
      } else {
        var tail := StringifyFieldsRuntime(fields, keys[1..], budget);
        s := head + "","" + tail;
      }
    }
  }

  method StringifyValue(j: Json, budget: nat) returns (s: string)
    ensures s == StringifyModel(j, budget)
    decreases budget, 0
  {
    if budget == 0 {
      s := ""null"";
      return;
    }
    if j.JNull? {
      s := ""null"";
      return;
    }
    if j.JBool? {
      s := if j.b then ""true"" else ""false"";
      return;
    }
    if j.JNum? {
      s := IntText(j.n);
      return;
    }
    if j.JDec? {
      s := IntText(j.mantissa) + ""e"" + IntText(j.exp);
      return;
    }
    if j.JStr? {
      s := ""\"""" + Escape(j.s) + ""\"""";
      return;
    }
    if j.JArr? {
      var body := StringifySeqRuntime(j.elems, budget - 1);
      s := ""["" + body + ""]"";
      return;
    }
    var keys := SortedKeys(j.fields);
    forall i: int | 0 <= i < |keys|
      ensures keys[i] in j.fields
    {
      ElemsMembership(keys, keys[i]);
    }
    var body := StringifyFieldsRuntime(j.fields, keys, budget - 1);
    s := ""{"" + body + ""}"";
  }

  const STRINGIFY_BUDGET: nat := 4000

  method Stringify(j: Json) returns (s: string)
    ensures s == StringifyModel(j, STRINGIFY_BUDGET)
    decreases j
  {
    s := StringifyValue(j, STRINGIFY_BUDGET);
  }

  import opened ConfluxCodec

  import opened DT = ConfluxDecimalText

  import CC = ConfluxContract

  datatype StringCursor = StringCursor(value: string, pos: nat, ok: bool)

  datatype JsonCursor = JsonCursor(value: Json, pos: nat, ok: bool)

  datatype DigitCursor = DigitCursor(value: int, pos: nat, count: nat)

  datatype ParseResult = Invalid | Parsed(value: Json)
}

module ConfluxCodec {
  function Field(j: Json, key: string): Json
    decreases j, key
  {
    if j.JObj? && key in j.fields then
      j.fields[key]
    else
      JNull
  }

  function AsInt(j: Json): int
    decreases j
  {
    if j.JNum? then
      j.n
    else
      0
  }

  function AsStr(j: Json): string
    decreases j
  {
    if j.JStr? then
      j.s
    else
      """"
  }

  function AsNat(j: Json): nat
    decreases j
  {
    var x: int := AsInt(j);
    if x >= 0 then
      x
    else
      0
  }

  lemma NonNegRoundTrips(n: nat)
    ensures AsNat(JNum(n)) == n
    decreases n
  {
  }

  ghost predicate RoundTrips<T(!new)>(c: Codec<T>)
    decreases c
  {
    forall t: T {:trigger Some(t)} {:trigger c.encode(t)} :: 
      c.decode(c.encode(t)) == Some(t)
  }

  function JsonCodec(): Codec<Json>
  {
    Codec((j: Json) => j, (j: Json) => Some(j))
  }

  lemma JsonCodecRoundTrips()
    ensures RoundTrips(JsonCodec())
  {
  }

  datatype Option<T> = None | Some(value: T)

  datatype Json = JNull | JBool(b: bool) | JNum(n: int) | JDec(mantissa: int, exp: int) | JStr(s: string) | JArr(elems: seq<Json>) | JObj(fields: map<string, Json>)

  datatype Codec<!T> = Codec(encode: T -> Json, decode: Json -> Option<T>)
}

module ConfluxDurableHistory {
  function Append<E>(history: History<E>, entry: E): History<E>
    decreases history
  {
    History(history.entries + [entry])
  }

  function Replay<S, E>(reducer: Reducer<S, E>, initial: S, history: History<E>): S
    decreases history
  {
    Fold(reducer, initial, history.entries)
  }

  lemma AppendExtendsHistory<E>(history: History<E>, entry: E)
    ensures Append(history, entry).entries == history.entries + [entry]
    ensures |Append(history, entry).entries| == |history.entries| + 1
    decreases history
  {
  }

  lemma ReplayAppend<S, E>(reducer: Reducer<S, E>, initial: S, history: History<E>, entry: E)
    ensures Replay(reducer, initial, Append(history, entry)) == reducer(Replay(reducer, initial, history), entry)
    decreases history
  {
    FoldConcat(reducer, initial, history.entries, [entry]);
  }

  ghost predicate StateCodecRoundTrips<S(!new)>(codec: StateCodec<S>)
    decreases codec
  {
    forall state: S {:trigger Some(state)} {:trigger codec.encode(state)} :: 
      codec.decode(codec.encode(state)) == Some(state)
  }

  function MakeCheckpoint<S>(historyId: string, reducerSchemaVersion: string, coordinateOf: S -> nat, hashBytes: seq<bv8> -> string, codec: StateCodec<S>, state: S): ReplayCheckpoint<S>
    decreases historyId, reducerSchemaVersion, codec
  {
    var bytes: seq<bv8> := codec.encode(state);
    ReplayCheckpoint(1, historyId, coordinateOf(state), reducerSchemaVersion, hashBytes(bytes), bytes)
  }

  function RestoreCheckpoint<S>(expectedHistoryId: string, expectedReducerSchemaVersion: string, coordinateOf: S -> nat, hashBytes: seq<bv8> -> string, codec: StateCodec<S>, checkpoint: ReplayCheckpoint<S>): Option<S>
    decreases expectedHistoryId, expectedReducerSchemaVersion, codec, checkpoint
  {
    if checkpoint.schemaVersion != 1 || checkpoint.historyId != expectedHistoryId || checkpoint.reducerSchemaVersion != expectedReducerSchemaVersion || checkpoint.stateHash != hashBytes(checkpoint.stateBytes) then
      None
    else
      match codec.decode(checkpoint.stateBytes) case None() => None case Some(state) => if coordinateOf(state) == checkpoint.nextCoordinate then Some(state) else None
  }

  lemma RestoreRoundTrips<S(!new)>(historyId: string, reducerSchemaVersion: string, coordinateOf: S -> nat, hashBytes: seq<bv8> -> string, codec: StateCodec<S>, state: S)
    requires StateCodecRoundTrips(codec)
    ensures RestoreCheckpoint(historyId, reducerSchemaVersion, coordinateOf, hashBytes, codec, MakeCheckpoint(historyId, reducerSchemaVersion, coordinateOf, hashBytes, codec, state)) == Some(state)
    decreases historyId, reducerSchemaVersion, codec
  {
  }

  import opened ConfluxContract

  datatype History<!E> = History(entries: seq<E>)

  datatype StateCodec<!S> = StateCodec(encode: S -> seq<bv8>, decode: seq<bv8> -> Option<S>)

  datatype ReplayCheckpoint<!S> = ReplayCheckpoint(schemaVersion: nat, historyId: string, nextCoordinate: nat, reducerSchemaVersion: string, stateHash: string, stateBytes: seq<bv8>)
}

module ConfluxContentAddress {
  ghost predicate ContentCodecsRoundTrip<W(!new)>(c: ContentCodecs<W>)
    decreases c
  {
    (forall a: ContentAddress {:trigger Some(a)} {:trigger c.encodeAddress(a)} :: 
      c.decodeAddress(c.encodeAddress(a)) == Some(a)) &&
    (forall l: ContentLocator {:trigger Some(l)} {:trigger c.encodeLocator(l)} :: 
      c.decodeLocator(c.encodeLocator(l)) == Some(l)) &&
    forall r: VerifiedContentRef {:trigger Some(r)} {:trigger c.encodeRef(r)} :: 
      c.decodeRef(c.encodeRef(r)) == Some(r)
  }

  function SameContent(left: VerifiedContentRef, right: VerifiedContentRef): bool
    decreases left, right
  {
    left.address == right.address
  }

  function SizeMatches(address: ContentAddress, bytes: seq<bv8>): bool
    decreases address, bytes
  {
    match address.exactSize
    case None() =>
      true
    case Some(n) =>
      |bytes| == n
  }

  function VerifyMaterialization(reference: VerifiedContentRef, bytes: seq<bv8>, digestBytes: (DigestAlgorithm, seq<bv8>) -> string): bool
    decreases reference, bytes
  {
    SizeMatches(reference.address, bytes) &&
    digestBytes(reference.address.digestAlgorithm, bytes) == reference.address.digest
  }

  lemma LocatorDoesNotChangeIdentity(address: ContentAddress, first: Option<ContentLocator>, second: Option<ContentLocator>)
    ensures SameContent(VerifiedContentRef(address, first), VerifiedContentRef(address, second))
    decreases address, first, second
  {
  }

  lemma VerifiedMaterializationHasAddressDigest(reference: VerifiedContentRef, bytes: seq<bv8>, digestBytes: (DigestAlgorithm, seq<bv8>) -> string)
    requires VerifyMaterialization(reference, bytes, digestBytes)
    ensures digestBytes(reference.address.digestAlgorithm, bytes) == reference.address.digest
    ensures match reference.address.exactSize case None() => true case Some(n) => |bytes| == n
    decreases reference, bytes
  {
  }

  lemma MaterializationDecisionIsDeterministic(reference: VerifiedContentRef, bytes: seq<bv8>, digestBytes: (DigestAlgorithm, seq<bv8>) -> string)
    ensures forall a: ContentAddress, l1: Option<ContentLocator>, l2: Option<ContentLocator> {:trigger VerifiedContentRef(a, l2), VerifiedContentRef(a, l1)} :: VerifyMaterialization(VerifiedContentRef(a, l1), bytes, digestBytes) == VerifyMaterialization(VerifiedContentRef(a, l2), bytes, digestBytes)
    decreases reference, bytes
  {
  }

  lemma ContentAddressWitness()
    ensures exists r: VerifiedContentRef, b: seq<bv8>, d: (DigestAlgorithm, seq<bv8>) -> string {:trigger VerifyMaterialization(r, b, d)} :: VerifyMaterialization(r, b, d)
    ensures exists r: VerifiedContentRef, b: seq<bv8>, d: (DigestAlgorithm, seq<bv8>) -> string {:trigger VerifyMaterialization(r, b, d)} :: !VerifyMaterialization(r, b, d)
  {
    ghost var address := ContentAddress(Sha256, ""abc"", Some(3));
    ghost var local := ContentLocator(""file:fixture"", None, None);
    ghost var remote := ContentLocator(""https://fixture.invalid/blob"", Some(""application/octet-stream""), Some(""n1""));
    ghost var digest := (algorithm: DigestAlgorithm, bytes: seq<bv8>) => if algorithm == Sha256 && bytes == [1, 2, 3] then ""abc"" else ""other"";
    LocatorDoesNotChangeIdentity(address, Some(local), Some(remote));
    assert VerifyMaterialization(VerifiedContentRef(address, Some(local)), [1, 2, 3], digest);
    assert !VerifyMaterialization(VerifiedContentRef(address, Some(remote)), [1, 2], digest);
  }

  import opened ConfluxContract

  datatype DigestAlgorithm = Sha256

  datatype ContentAddress = ContentAddress(digestAlgorithm: DigestAlgorithm, digest: string, exactSize: Option<nat>)

  datatype ContentLocator = ContentLocator(uri: string, contentType: Option<string>, nonce: Option<string>)

  datatype VerifiedContentRef = VerifiedContentRef(address: ContentAddress, locator: Option<ContentLocator>)

  datatype ContentCodecs<!W> = ContentCodecs(encodeAddress: ContentAddress -> W, decodeAddress: W -> Option<ContentAddress>, encodeLocator: ContentLocator -> W, decodeLocator: W -> Option<ContentLocator>, encodeRef: VerifiedContentRef -> W, decodeRef: W -> Option<VerifiedContentRef>)
}

module Chat {
  const IDLE: bv32 := 1
  const ERR: bv32 := 2
  const GEN: bv32 := 8
  const INP: bv32 := 24
  const READ: bv32 := 32
  const ACT: bv32 := 31

  function setBit(s: bv32, b: bv32): bv32
    decreases s, b
  {
    s | b
  }

  function clearBit(s: bv32, b: bv32): bv32
    decreases s, b
  {
    s & !b
  }

  const qKey: QMsg -> string := (x: QMsg) => x.id

  function jNoNull(j: Wire.Json): Option<Wire.Json>
    decreases j
  {
    if j.JNull? then
      None
    else
      Some(j)
  }

  function upsertQ(qs: seq<QMsg>, m: QMsg): seq<QMsg>
    decreases qs, m
  {
    SR.SeqUpsertById(qKey, qs, m)
  }

  function removeQ(qs: seq<QMsg>, id: string): seq<QMsg>
    decreases qs, id
  {
    SR.SeqRemoveById(qKey, qs, id)
  }

  function containsQ(qs: seq<QMsg>, id: string): bool
    decreases |qs|
  {
    if |qs| == 0 then
      false
    else if qs[0].id == id then
      true
    else
      containsQ(qs[1..], id)
  }

  function findQ(qs: seq<QMsg>, id: string): seq<QMsg>
    decreases qs, id
  {
    var found: seq<QMsg> := Ops.Filter((q: QMsg) => q.id == id, qs);
    if |found| == 0 then
      []
    else
      [found[0]]
  }

  function reorderQ(qs: seq<QMsg>, order: seq<string>): seq<QMsg>
    decreases qs, order
  {
    OL.SeqReorderByKeys(qKey, order, qs)
  }

  function keepUpTo(ts: seq<Turn>, id: string): seq<Turn>
    decreases ts, id
  {
    OL.SeqKeepThrough((t: Turn) => t.turnId, id, ts)
  }

  predicate hasTurn(ts: seq<Turn>, id: string)
    decreases ts, id
  {
    exists i: int {:trigger ts[i]} :: 
      0 <= i < |ts| &&
      ts[i].turnId == id
  }

  function dedupPrepend(loaded: seq<Turn>, existing: seq<Turn>): seq<Turn>
    decreases loaded, existing
  {
    Ops.Filter((t: Turn) => !hasTurn(existing, t.turnId), loaded) + existing
  }

  predicate isOpenInput(p: Part)
    decreases p
  {
    p.PInputRequest? &&
    p.response.None?
  }

  function hasOpenReq(ps: seq<Part>, id: string): bool
    decreases |ps|
  {
    if |ps| == 0 then
      false
    else
      (ps[0].PInputRequest? && ps[0].response.None? && ps[0].req.id == id) || hasOpenReq(ps[1..], id)
  }

  function mergeInputReq(existing: InputReq, req: InputReq): InputReq
    decreases existing, req
  {
    if |req.answers| > 0 then
      req
    else
      req.(answers := existing.answers)
  }

  function mergeInputPart(req: InputReq): Part -> Part
    decreases req
  {
    (p: Part) => match p case PInputRequest(existing, _ /* _v0 */) => PInputRequest(mergeInputReq(existing, req), None) case _ /* _v1 */ => p
  }

  function upsertInputPart(ps: seq<Part>, req: InputReq): seq<Part>
    decreases ps, req
  {
    if hasOpenReq(ps, req.id) then
      SR.SeqUpdateByIdWhere(partKey, isOpenInput, ps, req.id, mergeInputPart(req))
    else
      ps + [PInputRequest(req, None)]
  }

  function answerInputPart(qId: string, ans: Option<Wire.Json>): Part -> Part
    decreases qId, ans
  {
    (p: Part) => match p case PInputRequest(r, resp) => PInputRequest(r.(answers := if ans.Some? then r.answers[qId := ans.value] else r.answers - {qId}), resp) case _ /* _v2 */ => p
  }

  function changeAnswerPart(ps: seq<Part>, reqId: string, qId: string, ans: Option<Wire.Json>): seq<Part>
    decreases ps, reqId, qId, ans
  {
    SR.SeqUpdateByIdWhere(partKey, isOpenInput, ps, reqId, answerInputPart(qId, ans))
  }

  function mergeAnswers(drafts: map<string, Wire.Json>, completed: map<string, Wire.Json>): map<string, Wire.Json>
    decreases drafts, completed
  {
    map k: string {:trigger drafts[k]} {:trigger completed[k]} {:trigger k in completed} {:trigger k in drafts.Keys + completed.Keys} | k in drafts.Keys + completed.Keys :: if k in completed then completed[k] else drafts[k]
  }

  function completeInputPart(resp: string, answers: map<string, Wire.Json>): Part -> Part
    decreases resp, answers
  {
    (p: Part) => match p case PInputRequest(r, _ /* _v3 */) => PInputRequest(r.(answers := mergeAnswers(r.answers, answers)), Some(resp)) case _ /* _v4 */ => p
  }

  function completeAnswerPart(ps: seq<Part>, reqId: string, resp: string, answers: map<string, Wire.Json>): seq<Part>
    decreases ps, reqId, resp, answers
  {
    SR.SeqUpdateByIdWhere(partKey, isOpenInput, ps, reqId, completeInputPart(resp, answers))
  }

  predicate turnMatches(s: ChatState, id: string)
    decreases s, id
  {
    s.activeTurn.Some? &&
    s.activeTurn.value.turnId == id
  }

  function optOr(o: Option<string>, d: string): string
    decreases o, d
  {
    if o.Some? then
      o.value
    else
      d
  }

  function anyPendingTC(ps: seq<Part>): bool
    decreases |ps|
  {
    if |ps| == 0 then
      false
    else
      (ps[0].PToolCall? && (ps[0].tc.status == ""pending-confirmation"" || ps[0].tc.status == ""pending-result-confirmation"" || ps[0].tc.status == ""auth-required"")) || anyPendingTC(ps[1..])
  }

  function hasPendingTCState(s: ChatState): bool
    decreases s
  {
    s.activeTurn.Some? &&
    anyPendingTC(s.activeTurn.value.parts)
  }

  function anyOpenInput(ps: seq<Part>): bool
    decreases |ps|
  {
    if |ps| == 0 then
      false
    else
      (ps[0].PInputRequest? && ps[0].response.None?) || anyOpenInput(ps[1..])
  }

  function hasOpenInputState(s: ChatState): bool
    decreases s
  {
    s.activeTurn.Some? &&
    anyOpenInput(s.activeTurn.value.parts)
  }

  function activityBits(s: ChatState, isError: bool): bv32
    decreases s, isError
  {
    if isError then
      ERR
    else if hasOpenInputState(s) || hasPendingTCState(s) then
      INP
    else if s.activeTurn.Some? then
      GEN
    else
      IDLE
  }

  function summaryStatus(s: ChatState, isError: bool): bv32
    decreases s, isError
  {
    (s.status & !ACT) | activityBits(s, isError)
  }

  function appendPart(t: Turn, p: Part): Turn
    decreases t, p
  {
    t.(parts := t.parts + [p])
  }

  function partKey(p: Part): string
    decreases p
  {
    match p
    case PMarkdown(pid, _ /* _v5 */) =>
      pid
    case PReasoning(pid, _ /* _v6 */) =>
      pid
    case PToolCall(tc) =>
      tc.toolCallId
    case PInputRequest(req, _ /* _v7 */) =>
      req.id
  }

  function deltaMarkdown(ps: seq<Part>, id: string, content: string): seq<Part>
    decreases ps, id, content
  {
    SR.SeqUpdateAllWhere(partKey, (p: Part) => p.PMarkdown?, ps, id, (p: Part) => match p case PMarkdown(pid, c) => PMarkdown(pid, c + content) case _ /* _v8 */ => p)
  }

  function deltaReasoning(ps: seq<Part>, id: string, content: string): seq<Part>
    decreases ps, id, content
  {
    SR.SeqUpdateAllWhere(partKey, (p: Part) => p.PReasoning?, ps, id, (p: Part) => match p case PReasoning(pid, c) => PReasoning(pid, c + content) case _ /* _v9 */ => p)
  }

  function mapTC(ps: seq<Part>, id: string, f: ToolCall -> ToolCall): seq<Part>
    decreases ps, id
  {
    SR.SeqUpdateAllWhere(partKey, (p: Part) => p.PToolCall?, ps, id, (p: Part) => match p case PToolCall(tc) => PToolCall(f(tc)) case _ /* _v10 */ => p)
  }

  function metaOr(meta: Option<Wire.Json>, prior: Option<Wire.Json>): Option<Wire.Json>
    decreases meta, prior
  {
    if meta.Some? then
      meta
    else
      prior
  }

  function optionId(j: Wire.Json): string
    decreases j
  {
    if j.JObj? && ""id"" in j.fields && j.fields[""id""].JStr? then
      j.fields[""id""].s
    else
      """"
  }

  function selectOption(options: Option<seq<Wire.Json>>, id: Option<string>): Option<Wire.Json>
    decreases if options.Some? then |options.value| else 0
  {
    if options.None? || id.None? || |options.value| == 0 then
      None
    else if optionId(options.value[0]) == id.value then
      jNoNull(options.value[0])
    else
      selectOption(Some(options.value[1..]), id)
  }

  function deltaOne(tc: ToolCall, content: string, inv: Option<string>, meta: Option<Wire.Json>): ToolCall
    decreases tc, content, inv, meta
  {
    if tc.status != ""streaming"" then
      tc
    else
      tc.(meta := metaOr(meta, tc.meta), partialInput := Some(optOr(tc.partialInput, """") + content), invocationMessage := optOr(inv, tc.invocationMessage))
  }

  function readyOne(tc: ToolCall, inv: Option<string>, input: Option<string>, title: Option<Wire.Json>, risk: Option<Wire.Json>, edits: Option<Wire.Json>, editable: Option<bool>, options: Option<seq<Wire.Json>>, confirmed: Option<string>, meta: Option<Wire.Json>): ToolCall
    decreases tc, inv, input, title, risk, edits, editable, options, confirmed, meta
  {
    if tc.status != ""streaming"" && tc.status != ""running"" && tc.status != ""pending-confirmation"" then
      tc
    else if confirmed.Some? then
      tc.(status := ""running"", meta := metaOr(meta, tc.meta), invocationMessage := optOr(inv, """"), toolInput := input, confirmationTitle := None, riskAssessment := None, edits := None, editable := None, options := None, confirmed := confirmed, success := None, pastTenseMessage := None, reason := None, reasonMessage := None, userSuggestion := None, selectedOption := None, content := None, structuredContent := None, error := None, auth := None, partialInput := None)
