  }

  function endTurn(s: ChatState, id: string, turnState: string, isError: bool, err: Option<Wire.Json>): (ChatState, ReduceOutcome)
    decreases s, id, turnState, isError, err
  {
    if !turnMatches(s, id) then
      (s, NoOp)
    else
      var t: Turn := s.activeTurn.value; var finalized: Turn := t.(state := turnState, parts := forceCancel(t.parts), error := err); var next: ChatState := s.(turns := s.turns + [finalized], activeTurn := None); (next.(status := summaryStatus(next, isError)), Applied)
  }

  function ApplyToChat(s: ChatState, a: ChatAction, now: int): (ChatState, ReduceOutcome)
    decreases s, a, now
  {
    match a
    case CDraftChanged(d) =>
      (s.(draft := d), Applied)
    case CActivityChanged(ac) =>
      (s.(activity := ac), Applied)
    case CTurnStarted(id, m, qid) =>
      var withTurn: ChatState := s.(activeTurn := Some(Turn(id, m, [], ""in-progress"", None, None)));
      var s2: ChatState := withTurn.(status := clearBit(summaryStatus(withTurn, false), READ));
      var s3: ChatState := if qid.Some? && s2.steeringMessage.Some? && s2.steeringMessage.value.id == qid.value then s2.(steeringMessage := None) else s2;
      var s4: ChatState := if qid.Some? then s3.(queuedMessages := removeQ(s3.queuedMessages, qid.value)) else s3;
      (s4, Applied)
    case CTurnComplete(id) =>
      endTurn(s, id, ""complete"", false, None)
    case CTurnCancelled(id) =>
      endTurn(s, id, ""cancelled"", false, None)
    case CError(id, e) =>
      endTurn(s, id, ""error"", true, jNoNull(e))
    case CUsage(id, u) =>
      if turnMatches(s, id) then
        (s.(activeTurn := Some(s.activeTurn.value.(usage := jNoNull(u)))), Applied)
      else
        (s, NoOp)
    case CResponsePart(id, p) =>
      if turnMatches(s, id) then
        (s.(activeTurn := Some(appendPart(s.activeTurn.value, p))), Applied)
      else
        (s, NoOp)
    case CDelta(id, pid, c) =>
      if turnMatches(s, id) then
        (s.(activeTurn := Some(s.activeTurn.value.(parts := deltaMarkdown(s.activeTurn.value.parts, pid, c)))), Applied)
      else
        (s, NoOp)
    case CReasoning(id, pid, c) =>
      if turnMatches(s, id) then
        (s.(activeTurn := Some(s.activeTurn.value.(parts := deltaReasoning(s.activeTurn.value.parts, pid, c)))), Applied)
      else
        (s, NoOp)
    case CToolCallStart(id, tcId, tn, dn, intent, contributor, meta) =>
      if turnMatches(s, id) then
        var tc: ToolCall := ToolCall(tcId, tn, dn, ""streaming"", intent, contributor, meta, """", None, None, None, None, None, None, None, None, None, None, None, None, None, None, None, None, None, None);
        (s.(activeTurn := Some(s.activeTurn.value.(parts := s.activeTurn.value.parts + [PToolCall(tc)]))), Applied)
      else
        (s, NoOp)
    case CToolCallDelta(id, tcId, c, inv, meta) =>
      if turnMatches(s, id) then
        (s.(activeTurn := Some(s.activeTurn.value.(parts := mapTC(s.activeTurn.value.parts, tcId, (x: ToolCall) => deltaOne(x, c, inv, meta))))), Applied)
      else
        (s, NoOp)
    case CToolCallReady(id, tcId, inv, input, title, risk, edits, editable, options, confirmed, meta) =>
      if turnMatches(s, id) then
        var s1: ChatState := s.(activeTurn := Some(s.activeTurn.value.(parts := mapTC(s.activeTurn.value.parts, tcId, (x: ToolCall) => readyOne(x, inv, input, title, risk, edits, editable, options, confirmed, meta)))));
        (s1.(status := summaryStatus(s1, false)), Applied)
      else
        (s, NoOp)
    case CToolCallConfirmed(id, tcId, approved, cv, rsn, reasonMessage, userSuggestion, edited, selectedOptionId, meta) =>
      if turnMatches(s, id) then
        var s1: ChatState := s.(activeTurn := Some(s.activeTurn.value.(parts := mapTC(s.activeTurn.value.parts, tcId, (x: ToolCall) => confirmOne(x, approved, cv, rsn, reasonMessage, userSuggestion, edited, selectedOptionId, meta)))));
        (s1.(status := summaryStatus(s1, false)), Applied)
      else
        (s, NoOp)
    case CToolCallAuthRequired(id, tcId, auth, meta) =>
      if turnMatches(s, id) then
        var s1: ChatState := s.(activeTurn := Some(s.activeTurn.value.(parts := mapTC(s.activeTurn.value.parts, tcId, (x: ToolCall) => authRequiredOne(x, auth, meta)))));
        (s1.(status := summaryStatus(s1, false)), Applied)
      else
        (s, NoOp)
    case CToolCallAuthResolved(id, tcId, meta) =>
      if turnMatches(s, id) then
        var s1: ChatState := s.(activeTurn := Some(s.activeTurn.value.(parts := mapTC(s.activeTurn.value.parts, tcId, (x: ToolCall) => authResolvedOne(x, meta)))));
        (s1.(status := summaryStatus(s1, false)), Applied)
      else
        (s, NoOp)
    case CToolCallComplete(id, tcId, ok, past, resultContent, structured, err, rrc, meta) =>
      if turnMatches(s, id) then
        var s1: ChatState := s.(activeTurn := Some(s.activeTurn.value.(parts := mapTC(s.activeTurn.value.parts, tcId, (x: ToolCall) => completeOne(x, ok, past, resultContent, structured, err, rrc, meta)))));
        (s1.(status := summaryStatus(s1, false)), Applied)
      else
        (s, NoOp)
    case CToolCallResultConfirmed(id, tcId, approved, meta) =>
      if turnMatches(s, id) then
        var s1: ChatState := s.(activeTurn := Some(s.activeTurn.value.(parts := mapTC(s.activeTurn.value.parts, tcId, (x: ToolCall) => resultConfirmOne(x, approved, meta)))));
        (s1.(status := summaryStatus(s1, false)), Applied)
      else
        (s, NoOp)
    case CToolCallContentChanged(id, tcId, c, meta) =>
      if turnMatches(s, id) then
        (s.(activeTurn := Some(s.activeTurn.value.(parts := mapTC(s.activeTurn.value.parts, tcId, (x: ToolCall) => contentChangedOne(x, c, meta))))), Applied)
      else
        (s, NoOp)
    case CTruncated(idOpt) =>
      if idOpt.Some? && !hasTurn(s.turns, idOpt.value) then
        (s, NoOp)
      else
        (var kept: seq<Turn> := if idOpt.Some? then keepUpTo(s.turns, idOpt.value) else []; var next: ChatState := s.(turns := kept, activeTurn := None, nextCursor := if idOpt.Some? then s.nextCursor else None); (next.(status := summaryStatus(next, false)), Applied))
    case CQueuedReordered(order) =>
      (s.(queuedMessages := reorderQ(s.queuedMessages, order)), Applied)
    case CTurnsLoaded(loaded, cursor) =>
      (s.(turns := dedupPrepend(loaded, s.turns), nextCursor := cursor), Applied)
    case CInputRequested(req) =>
      if s.activeTurn.Some? then
        var at: Turn := s.activeTurn.value;
        var next: ChatState := s.(activeTurn := Some(at.(parts := upsertInputPart(at.parts, req))));
        (next.(status := clearBit(summaryStatus(next, false), READ)), Applied)
      else
        (s, NoOp)
    case CInputAnswerChanged(reqId, qId, ans) =>
      if s.activeTurn.Some? && hasOpenReq(s.activeTurn.value.parts, reqId) then
        var at: Turn := s.activeTurn.value;
        (s.(activeTurn := Some(at.(parts := changeAnswerPart(at.parts, reqId, qId, ans)))), Applied)
      else
        (s, NoOp)
    case CInputCompleted(reqId, resp, answers) =>
      if s.activeTurn.Some? && hasOpenReq(s.activeTurn.value.parts, reqId) then
        var at: Turn := s.activeTurn.value;
        var next: ChatState := s.(activeTurn := Some(at.(parts := completeAnswerPart(at.parts, reqId, resp, answers))));
        (next.(status := summaryStatus(next, false)), Applied)
      else
        (s, NoOp)
    case CPendingMessageSet(kind, id, msg) =>
      if kind == ""steering"" then
        (s.(steeringMessage := Some(QMsg(id, msg))), Applied)
      else
        (s.(queuedMessages := upsertQ(s.queuedMessages, QMsg(id, msg))), Applied)
    case CPendingMessageRemoved(kind, id) =>
      if kind == ""steering"" then
        if s.steeringMessage.Some? && s.steeringMessage.value.id == id then
          (s.(steeringMessage := None), Applied)
        else
          (s, NoOp)
      else
        (s.(queuedMessages := removeQ(s.queuedMessages, id)), Applied)
    case CUnknown(_ /* _v12 */) =>
      (s, NoOp)
  }

