  lemma WfChatStatePreserved(s: ChatState, a: ChatAction, now: int)
    requires WfChatState(s) && WfChatAction(a)
    ensures WfChatState(ApplyToChat(s, a, now).0)
    decreases s, a, now
  {
    match a
    case {:split false} CTurnStarted(id, m, qid) =>
      if qid.Some? {
        SR.RemovePreservesUnique(qKey, s.queuedMessages, qid.value);
      }
    case {:split false} CQueuedReordered(order) =>
      OL.ReorderPreservesUnique(qKey, order, s.queuedMessages);
    case {:split false} CPendingMessageSet(kind, id, msg) =>
      if kind != ""steering"" {
        SR.UpsertPreservesUnique(qKey, s.queuedMessages, QMsg(id, msg));
      }
    case {:split false} CPendingMessageRemoved(kind, id) =>
      if kind != ""steering"" {
        SR.RemovePreservesUnique(qKey, s.queuedMessages, id);
      }
    case {:split false} CTurnComplete(id) =>
    case {:split false} CTurnCancelled(id) =>
    case {:split false} CError(id, e) =>
    case {:split false} CTruncated(idOpt) =>
    case {:split false} CInputRequested(req) =>
    case {:split false} CInputAnswerChanged(reqId, qId, ans) =>
    case {:split false} CInputCompleted(reqId, resp, answers) =>
    case {:split false} CDraftChanged(_ /* _v13 */) =>
    case {:split false} CActivityChanged(_ /* _v14 */) =>
    case {:split false} CUsage(_ /* _v15 */, _ /* _v16 */) =>
    case {:split false} CResponsePart(_ /* _v17 */, _ /* _v18 */) =>
    case {:split false} CDelta(_ /* _v19 */, _ /* _v20 */, _ /* _v21 */) =>
    case {:split false} CReasoning(_ /* _v22 */, _ /* _v23 */, _ /* _v24 */) =>
    case {:split false} CToolCallStart(_ /* _v25 */, _ /* _v26 */, _ /* _v27 */, _ /* _v28 */, _ /* _v29 */, _ /* _v30 */, _ /* _v31 */) =>
    case {:split false} CToolCallDelta(_ /* _v32 */, _ /* _v33 */, _ /* _v34 */, _ /* _v35 */, _ /* _v36 */) =>
    case {:split false} CToolCallReady(_ /* _v37 */, _ /* _v38 */, _ /* _v39 */, _ /* _v40 */, _ /* _v41 */, _ /* _v42 */, _ /* _v43 */, _ /* _v44 */, _ /* _v45 */, _ /* _v46 */, _ /* _v47 */) =>
    case {:split false} CToolCallConfirmed(_ /* _v48 */, _ /* _v49 */, _ /* _v50 */, _ /* _v51 */, _ /* _v52 */, _ /* _v53 */, _ /* _v54 */, _ /* _v55 */, _ /* _v56 */, _ /* _v57 */) =>
    case {:split false} CToolCallAuthRequired(_ /* _v58 */, _ /* _v59 */, _ /* _v60 */, _ /* _v61 */) =>
