  lemma ConfirmOnePreservesNoNull(tc: ToolCall, approved: bool, confirmedVal: Option<string>, reason: Option<string>, reasonMessage: Option<Wire.Json>, userSuggestion: Option<Wire.Json>, editedInput: Option<string>, selectedOptionId: Option<string>, meta: Option<Wire.Json>)
