  lemma ConfirmOnePreservesNoNull_NonVacuous()
    ensures exists tc: ToolCall {:trigger confirmOne(tc, true, Some(""user-action""), None, None, None, None, Some(""approve""), None)} {:trigger tc.options} :: WfToolCallNoNull(tc) && tc.options.Some? && |tc.options.value| > 0 && WfToolCallNoNull(confirmOne(tc, true, Some(""user-action""), None, None, None, None, Some(""approve""), None))
