  function activeParts(s: ChatState): seq<Part>
    decreases s
  {
    if s.activeTurn.Some? then
      s.activeTurn.value.parts
    else
      []
  }

  function firstActiveToolCall(s: ChatState): Option<ToolCall>
    decreases s
  {
    var ps: seq<Part> := activeParts(s);
    if |ps| > 0 && ps[0].PToolCall? then
      Some(ps[0].tc)
    else
      None
  }

  function firstStoredToolCall(s: ChatState): Option<ToolCall>
    decreases s
  {
    if |s.turns| == 0 then
      None
    else
      var ps: seq<Part> := s.turns[0].parts; if |ps| > 0 && ps[0].PToolCall? then Some(ps[0].tc) else None
  }

  method runScalarTurns() returns (pass: nat)
