  datatype ChatAction = CDraftChanged(draft: Option<string>) | CActivityChanged(activity: Option<string>) | CTurnStarted(turnId: string, message: Wire.Json, queuedMessageId: Option<string>) | CTurnComplete(turnId: string) | CTurnCancelled(turnId: string) | CUsage(turnId: string, usage: Wire.Json) | CError(turnId: string, err: Wire.Json) | CResponsePart(turnId: string, part: Part) | CDelta(turnId: string, partId: string, content: string) | CToolCallStart(turnId: string, toolCallId: string, toolName: string, displayName: string, intention: Option<string>, contributor: Option<ToolCallContributor>, meta: Option<Wire.Json>) | CToolCallDelta(turnId: string, toolCallId: string, content: string, invocationMessage: Option<string>, meta: Option<Wire.Json>) | CToolCallReady(turnId: string, toolCallId: string, invocationMessage: Option<string>, toolInput: Option<string>, confirmationTitle: Option<Wire.Json>, riskAssessment: Option<Wire.Json>, edits: Option<Wire.Json>, editable: Option<bool>, options: Option<seq<Wire.Json>>, confirmed: Option<string>, meta: Option<Wire.Json>) | CToolCallConfirmed(turnId: string, toolCallId: string, approved: bool, confirmedVal: Option<string>, reason: Option<string>, reasonMessage: Option<Wire.Json>, userSuggestion: Option<Wire.Json>, editedToolInput: Option<string>, selectedOptionId: Option<string>, meta: Option<Wire.Json>) | CToolCallAuthRequired(turnId: string, toolCallId: string, auth: Wire.Json, meta: Option<Wire.Json>) | CToolCallAuthResolved(turnId: string, toolCallId: string, meta: Option<Wire.Json>) | CToolCallComplete(turnId: string, toolCallId: string, success: bool, pastTenseMessage: Option<string>, resultContent: Option<Wire.Json>, structuredContent: Option<Wire.Json>, error: Option<Wire.Json>, requiresResultConfirmation: bool, meta: Option<Wire.Json>) | CToolCallResultConfirmed(turnId: string, toolCallId: string, approved: bool, meta: Option<Wire.Json>) | CToolCallContentChanged(turnId: string, toolCallId: string, newContent: Wire.Json, meta: Option<Wire.Json>) | CReasoning(turnId: string, partId: string, content: string) | CTruncated(upToTurnId: Option<string>) | CQueuedReordered(order: seq<string>) | CTurnsLoaded(loaded: seq<Turn>, cursor: Option<string>) | CInputRequested(req: InputReq) | CInputAnswerChanged(requestId: string, questionId: string, answer: Option<Wire.Json>) | CInputCompleted(requestId: string, response: string, answers: map<string, Wire.Json>) | CPendingMessageSet(kind: string, id: string, message: Wire.Json) | CPendingMessageRemoved(kind: string, id: string) | CUnknown(raw: Wire.Json)
}

module AhpSkeleton {
  function Pow10(k: nat): int
    ensures Pow10(k) >= 1
    decreases k
  {
    if k == 0 then
      1
    else
      10 * Pow10(k - 1)
  }

  opaque function decInt(m: int, e: int): Option<int>
    decreases m, e
  {
    if e >= 0 then
      Some(m * Pow10(e))
    else if m % Pow10(-e) == 0 then
      Some(m / Pow10(-e))
    else
      None
  }

  function jsonInt(j: Wire.Json): Option<int>
    decreases j
  {
    if j.JNum? then
      Some(j.n)
    else if j.JDec? then
      decInt(j.mantissa, j.exp)
    else
      None
  }

  function asInt(o: Option<Wire.Json>): int
    decreases o
  {
    if o.None? then
      0
    else
      var r: Option<int> := jsonInt(o.value); if r.Some? then r.value else 0
  }

  function optInt(o: Option<Wire.Json>): Option<int>
    decreases o
  {
    if o.Some? then
      jsonInt(o.value)
    else
      None
  }

  lemma JsonIntWitness()
    ensures jsonInt(Wire.JNum(7)) == Some(7)
    ensures jsonInt(Wire.JDec(1, 3)) == Some(1000)
    ensures jsonInt(Wire.JDec(50, -1)) == Some(5)
    ensures jsonInt(Wire.JDec(15, -1)) == None
  {
    reveal decInt();
    assert Pow10(3) == 1000 && Pow10(1) == 10;
  }

  ghost predicate DenotesInt(mantissa: int, exp: int, n: int)
    decreases mantissa, exp, n
  {
    (exp >= 0 && n == mantissa * Pow10(exp)) || (exp < 0 && mantissa % Pow10(-exp) == 0 && n == mantissa / Pow10(-exp))
  }

  lemma AsIntCanonicalizes(mantissa: int, exp: int, n: int)
    requires DenotesInt(mantissa, exp, n)
    ensures jsonInt(Wire.JDec(mantissa, exp)) == Some(n)
    ensures jsonInt(Wire.JNum(n)) == Some(n)
    decreases mantissa, exp, n
  {
    reveal decInt();
  }

  lemma IntWireFormsAgree(mantissa: int, exp: int, n: int)
    requires DenotesInt(mantissa, exp, n)
    ensures jsonInt(Wire.JDec(mantissa, exp)) == jsonInt(Wire.JNum(n))
    decreases mantissa, exp, n
  {
    AsIntCanonicalizes(mantissa, exp, n);
  }

  function EncodeStatus(s: SessionStatus): int
    decreases s
  {
    s as int
  }

  lemma StatusRoundTrip(s: SessionStatus)
    ensures EncodeStatus(s) as bv32 == s
    decreases s
  {
  }

  function ApplyToRoot(s: RootState, a: RootAction, now: int): (RootState, ReduceOutcome)
    decreases s, a, now
  {
    match a
    case RootAgentsChanged(ag) =>
      (s.(agents := ag), Applied)
    case RootActiveSessionsChanged(n) =>
      (s.(activeSessions := Some(n)), Applied)
    case RootTerminalsChanged(t) =>
      (s.(terminals := Some(t)), Applied)
    case RootConfigChanged(cfg, repl) =>
      (match s.config
      case None() =>
        (s, NoOp)
      case Some(c) =>
        var newValues: map<string, Wire.Json> := if repl then cfg else c.values + cfg;
        (s.(config := Some(RootConfig(c.schema, newValues))), Applied))
    case RootUnknown(_ /* _v0 */) =>
      (s, NoOp)
  }

  predicate IsUnknownRoot(a: RootAction)
    decreases a
  {
    a.RootUnknown?
  }

  predicate ConfigPreconditionFails(s: RootState, a: RootAction)
    decreases s, a
  {
    a.RootConfigChanged? &&
    s.config.None?
  }

  lemma Root_UnknownIsNoOp(s: RootState, a: RootAction, now: int)
    requires IsUnknownRoot(a)
    ensures ApplyToRoot(s, a, now).0 == s && ApplyToRoot(s, a, now).1 == NoOp
    decreases s, a, now
  {
  }

  lemma Root_UnknownIsNoOp_NonVacuous()
    ensures exists a: RootAction {:trigger IsUnknownRoot(a)} :: IsUnknownRoot(a)
  {
    assert IsUnknownRoot(RootUnknown(Wire.JNull));
  }

  lemma Root_ConfigPreconditionFailsIsNoOp(s: RootState, a: RootAction, now: int)
    requires ConfigPreconditionFails(s, a)
    ensures ApplyToRoot(s, a, now).0 == s && ApplyToRoot(s, a, now).1 == NoOp
    decreases s, a, now
  {
  }

  lemma Root_ConfigPreconditionFails_NonVacuous()
    ensures exists s: RootState, a: RootAction {:trigger ConfigPreconditionFails(s, a)} :: ConfigPreconditionFails(s, a)
  {
    assert ConfigPreconditionFails(RootState([], None, None, None), RootConfigChanged(map[], false));
  }

  lemma Root_Deterministic(s: RootState, a: RootAction, now: int)
    ensures ApplyToRoot(s, a, now) == ApplyToRoot(s, a, now)
    decreases s, a, now
  {
  }

  function FoldRoot(s: RootState, actions: seq<RootAction>, now: int): RootState
    decreases s, actions, now
  {
    CC.Fold((s': RootState, a: RootAction) => ApplyToRoot(s', a, now).0, s, actions)
  }

  lemma FoldConverges(s: RootState, actions: seq<RootAction>, now: int)
    ensures FoldRoot(s, actions, now) == FoldRoot(s, actions, now)
    decreases s, actions, now
  {
  }

  function apply1(s: RootState, a: RootAction): RootState
    decreases s, a
  {
    ApplyToRoot(s, a, 9999).0
  }

  method RunCorpus() returns (pass: nat, total: nat)
  {
    total := 7;
    pass := 0;
    var empty := RootState([], None, None, None);
    var ag := [AgentInfo(""copilot"", ""Copilot"", ""AI"", [])];
    if apply1(empty, RootAgentsChanged(ag)) == RootState(ag, None, None, None) {
      pass := pass + 1;
    }
    if apply1(empty, RootActiveSessionsChanged(5)) == RootState([], Some(5), None, None) {
      pass := pass + 1;
    }
    var terms := [Wire.JObj(map[""resource"" := Wire.JStr(""agenthost:/terminal/1"")]), Wire.JObj(map[""resource"" := Wire.JStr(""agenthost:/terminal/2"")])];
    if apply1(empty, RootTerminalsChanged(terms)) == RootState([], None, Some(terms), None) {
      pass := pass + 1;
    }
    if apply1(empty, RootUnknown(Wire.JObj(map[""type"" := Wire.JStr(""root/nonExistentAction"")]))) == empty {
      pass := pass + 1;
    }
    var sch := Wire.JObj(map[""type"" := Wire.JStr(""object"")]);
    var cfg127 := RootState([], None, None, Some(RootConfig(sch, map[""theme"" := Wire.JStr(""light"")])));
    var exp127 := RootState([], None, None, Some(RootConfig(sch, map[""theme"" := Wire.JStr(""dark"")])));
    if apply1(cfg127, RootConfigChanged(map[""theme"" := Wire.JStr(""dark"")], false)) == exp127 {
      pass := pass + 1;
    }
    if apply1(empty, RootConfigChanged(map[""theme"" := Wire.JStr(""dark"")], false)) == empty {
      pass := pass + 1;
    }
    var cfg130 := RootState([], None, None, Some(RootConfig(sch, map[""theme"" := Wire.JStr(""light""), ""locale"" := Wire.JStr(""en"")])));
    var exp130 := RootState([], None, None, Some(RootConfig(sch, map[""theme"" := Wire.JStr(""dark"")])));
    if apply1(cfg130, RootConfigChanged(map[""theme"" := Wire.JStr(""dark"")], true)) == exp130 {
      pass := pass + 1;
    }
  }

  import Wire = ConfluxCodec

  import CC = ConfluxContract

  export
    provides ApplyToRoot, StatusRoundTrip, RunCorpus, Wire, CC
    reveals Option, ReduceOutcome, SessionStatus, EncodeStatus, ActionOrigin, Envelope, AgentInfo, RootConfig, RootState, RootAction, apply1, FoldRoot, jsonInt, asInt, optInt
    provides decInt


  datatype Option<T> = None | Some(value: T)

  datatype ReduceOutcome = Applied | NoOp | OutOfScope

  type SessionStatus = bv32

  datatype ActionOrigin = ActionOrigin(clientId: string, clientSeq: nat)

  datatype Envelope<A> = Envelope(channel: string, action: A, serverSeq: nat, origin: Option<ActionOrigin>, rejectionReason: Option<string>)

  datatype AgentInfo = AgentInfo(provider: string, displayName: string, description: string, models: seq<string>)

  datatype RootConfig = RootConfig(schema: Wire.Json, values: map<string, Wire.Json>)

  datatype RootState = RootState(agents: seq<AgentInfo>, activeSessions: Option<int>, terminals: Option<seq<Wire.Json>>, config: Option<RootConfig>)

  datatype RootAction = RootAgentsChanged(agents: seq<AgentInfo>) | RootActiveSessionsChanged(activeSessions: int) | RootTerminalsChanged(terminals: seq<Wire.Json>) | RootConfigChanged(config: map<string, Wire.Json>, replace: bool) | RootUnknown(raw: Wire.Json)
}

module Session {
  const B_INPUT: bv32 := 16
  const B_READ: bv32 := 32
  const B_ARCH: bv32 := 64

  function setBit(s: bv32, b: bv32): bv32
    decreases s, b
  {
    s | b
  }

  function clearBit(s: bv32, b: bv32): bv32
    decreases s, b
  {
    s & !b
  }

  const custKey: Cust -> string := (x: Cust) => x.id
  const chatKey: Chat -> string := (x: Chat) => x.resource
  const clientKey: Client -> string := (x: Client) => x.clientId
  const inputKey: InputReq -> string := (x: InputReq) => x.id

  function toggleEnabled(en: bool): Cust -> Cust
    decreases en
  {
    (e: Cust) => e.(enabled := Some(en))
  }

  function chatPatch(st: Option<int>, ac: Option<string>, md: Option<string>): Chat -> Chat
    decreases st, ac, md
  {
    (c: Chat) => c.(status := if st.Some? then st.value else c.status, activity := if ac.Some? then ac else c.activity, modifiedAt := if md.Some? then md.value else c.modifiedAt)
  }

  const mcpPred: Cust -> bool := (c: Cust) => c.kind == ""mcpServer""

  function mcpPatch(st: Option<Wire.Json>, ch: Option<Wire.Json>): Cust -> Cust
    decreases st, ch
  {
    (e: Cust) => e.(state := st, channel := ch)
  }

  function upsertCust(cs: seq<Cust>, id: string, en: bool): seq<Cust>
    decreases cs, id, en
  {
    SR.SeqUpdateById(custKey, cs, id, toggleEnabled(en))
  }

  function removeCust(cs: seq<Cust>, id: string): seq<Cust>
    decreases cs, id
  {
    SR.SeqRemoveById(custKey, cs, id)
  }

  function removeChat(chs: seq<Chat>, r: string): seq<Chat>
    decreases chs, r
  {
    SR.SeqRemoveById(chatKey, chs, r)
  }

  function upsertChat(chs: seq<Chat>, c: Chat): seq<Chat>
    decreases chs, c
  {
    SR.SeqUpsertById(chatKey, chs, c)
  }

  function updChat(chs: seq<Chat>, r: string, st: Option<int>, ac: Option<string>, md: Option<string>): seq<Chat>
    decreases chs, r, st, ac, md
  {
    SR.SeqUpdateById(chatKey, chs, r, chatPatch(st, ac, md))
  }

  function upsertClient(cl: seq<Client>, c: Client): seq<Client>
    decreases cl, c
  {
    SR.SeqUpsertById(clientKey, cl, c)
  }

  function removeClient(cl: seq<Client>, id: string): seq<Client>
    decreases cl, id
  {
    SR.SeqRemoveById(clientKey, cl, id)
  }

  function upsertInput(ins: seq<InputReq>, r: InputReq): seq<InputReq>
    decreases ins, r
  {
    SR.SeqUpsertById(inputKey, ins, r)
  }

  function removeInput(ins: seq<InputReq>, id: string): seq<InputReq>
    decreases ins, id
  {
    SR.SeqRemoveById(inputKey, ins, id)
  }

  function upsertCustFull(cs: seq<Cust>, c: Cust): seq<Cust>
    decreases cs, c
  {
    SR.SeqUpsertById(custKey, cs, c)
  }

  function setMcp(cs: seq<Cust>, id: string, st: Option<Wire.Json>, ch: Option<Wire.Json>): seq<Cust>
    decreases cs, id, st, ch
  {
    SR.SeqUpdateByIdWhere(custKey, mcpPred, cs, id, mcpPatch(st, ch))
  }

  predicate isMcp(cs: seq<Cust>, id: string)
    decreases cs, id
  {
    exists i: int {:trigger cs[i]} :: 
      0 <= i < |cs| &&
      cs[i].id == id &&
      cs[i].kind == ""mcpServer""
  }

  function ApplyToSession(s: SessionState, a: SessionAction, now: int): (SessionState, ReduceOutcome)
    decreases s, a, now
  {
    match a
    case Ready() =>
      (s.(lifecycle := ""ready""), Applied)
    case CreationFailed(e) =>
      (s.(lifecycle := ""creationFailed"", creationError := if e == Wire.JNull then None else Some(e)), Applied)
    case TitleChanged(t) =>
      (s.(title := t), Applied)
    case ServerToolsChanged(t) =>
      (s.(serverTools := if t == Wire.JNull then None else Some(t)), Applied)
    case MetaChanged(m) =>
      (s.(meta := if m == Wire.JNull then None else Some(m)), Applied)
    case IsReadChanged(v) =>
      (s.(status := if v then setBit(s.status, B_READ) else clearBit(s.status, B_READ)), Applied)
    case IsArchivedChanged(v) =>
      (s.(status := if v then setBit(s.status, B_ARCH) else clearBit(s.status, B_ARCH)), Applied)
    case ActivityChanged(ac) =>
      (s.(activity := ac), Applied)
    case ConfigChanged(cfg, repl) =>
      (match s.config
      case None() =>
        (s, NoOp)
      case Some(c) =>
        (s.(config := Some(SConfig(c.schema, if repl then cfg else c.values + cfg))), Applied))
    case CustomizationsChanged(cs) =>
      (s.(customizations := cs), Applied)
    case CustomizationToggled(id, en) =>
      (s.(customizations := upsertCust(s.customizations, id, en)), Applied)
    case CustomizationRemoved(id) =>
      (s.(customizations := removeCust(s.customizations, id)), Applied)
    case DefaultChatChanged(c) =>
      (s.(defaultChat := c), Applied)
    case ChatAdded(c) =>
      (s.(chats := upsertChat(s.chats, c)), Applied)
    case ChatRemoved(r) =>
      (s.(chats := removeChat(s.chats, r), defaultChat := if s.defaultChat == Some(r) then None else s.defaultChat), Applied)
    case ChatUpdated(r, st, ac, md) =>
      (s.(chats := updChat(s.chats, r, st, ac, md)), Applied)
    case ChangesetsChanged(cs) =>
      (s.(changesets := cs), Applied)
    case CanvasesChanged(cs) =>
      (s.(canvases := if cs == Wire.JNull then None else Some(cs)), Applied)
    case OpenCanvasesChanged(cs) =>
      (s.(openCanvases := if cs == Wire.JNull then None else Some(cs)), Applied)
    case ActiveClientSet(c) =>
      (s.(activeClients := upsertClient(s.activeClients, c)), Applied)
    case ActiveClientRemoved(id) =>
      (s.(activeClients := removeClient(s.activeClients, id)), Applied)
    case InputNeededSet(r) =>
      (s.(inputNeeded := upsertInput(s.inputNeeded, r), status := setBit(s.status, B_INPUT)), Applied)
    case InputNeededRemoved(id) =>
      var rem: seq<InputReq> := removeInput(s.inputNeeded, id);
      (s.(inputNeeded := rem, status := if |rem| == 0 then clearBit(s.status, B_INPUT) else s.status), Applied)
    case CustomizationUpdated(c) =>
      (s.(customizations := upsertCustFull(s.customizations, c)), Applied)
    case McpServerStateChanged(id, st, ch) =>
      if isMcp(s.customizations, id) then
        (s.(customizations := setMcp(s.customizations, id, if st == Wire.JNull then None else Some(st), ch)), Applied)
      else
        (s, NoOp)
    case McpServerStartRequested(id) =>
      if isMcp(s.customizations, id) then
        (s.(customizations := setMcp(s.customizations, id, Some(Wire.JObj(map[""kind"" := Wire.JStr(""starting"")])), None)), Applied)
      else
        (s, NoOp)
    case McpServerStopRequested(id) =>
      if isMcp(s.customizations, id) then
        (s.(customizations := setMcp(s.customizations, id, Some(Wire.JObj(map[""kind"" := Wire.JStr(""stopped"")])), None)), Applied)
      else
        (s, NoOp)
    case SUnknown(_ /* _v0 */) =>
      (s, NoOp)
  }

  predicate WfCust(c: Cust)
    decreases c
  {
    (c.state.Some? ==>
      c.state.value != Wire.JNull) &&
    (c.channel.Some? ==>
      c.channel.value != Wire.JNull)
  }

  predicate WfCusts(cs: seq<Cust>)
    decreases cs
  {
    forall i: int {:trigger cs[i]} :: 
      0 <= i < |cs| ==>
        WfCust(cs[i])
  }

  predicate SessionWf(s: SessionState)
    decreases s
  {
    (s.meta.Some? ==>
      s.meta.value != Wire.JNull) &&
    (s.creationError.Some? ==>
      s.creationError.value != Wire.JNull) &&
    (s.serverTools.Some? ==>
      s.serverTools.value != Wire.JNull) &&
    (s.changesets.Some? ==>
      s.changesets.value != Wire.JNull) &&
    (s.canvases.Some? ==>
      s.canvases.value != Wire.JNull) &&
    (s.openCanvases.Some? ==>
      s.openCanvases.value != Wire.JNull) &&
    WfCusts(s.customizations) &&
    SR.UniqueKeys(custKey, s.customizations) &&
    SR.UniqueKeys(chatKey, s.chats) &&
    SR.UniqueKeys(clientKey, s.activeClients) &&
    SR.UniqueKeys(inputKey, s.inputNeeded)
  }

  predicate WfSessionActionInv(a: SessionAction)
    decreases a
  {
    match a
    case CustomizationsChanged(cs) =>
      WfCusts(cs) &&
      SR.UniqueKeys(custKey, cs)
    case CustomizationUpdated(c) =>
      WfCust(c)
    case ChangesetsChanged(cs) =>
      cs.Some? ==>
        cs.value != Wire.JNull
    case McpServerStateChanged(_ /* _v1 */, _ /* _v2 */, ch) =>
      ch.Some? ==>
        ch.value != Wire.JNull
    case _ /* _v3 */ =>
      true
  }

  lemma /*{:_inductionTrigger _default.SeqUpsertById(custKey, cs, c)}*/ /*{:_induction cs, c}*/ UpsertWfCusts(cs: seq<Cust>, c: Cust)
    requires WfCusts(cs) && WfCust(c)
    ensures WfCusts(SR.SeqUpsertById(custKey, cs, c))
    decreases |cs|
  {
    if |cs| == 0 {
    } else if custKey(cs[0]) == custKey(c) {
    } else {
      UpsertWfCusts(cs[1..], c);
    }
  }

  lemma /*{:_inductionTrigger _default.SeqRemoveById(custKey, cs, id)}*/ /*{:_induction cs, id}*/ RemoveWfCusts(cs: seq<Cust>, id: string)
    requires WfCusts(cs)
    ensures WfCusts(SR.SeqRemoveById(custKey, cs, id))
    decreases |cs|
  {
    if |cs| == 0 {
    } else {
      RemoveWfCusts(cs[1..], id);
    }
  }

  lemma /*{:_inductionTrigger _default.SeqUpdateById(custKey, cs, id, f)}*/ /*{:_induction cs, id}*/ UpdateWfCusts(cs: seq<Cust>, id: string, f: Cust -> Cust)
    requires WfCusts(cs) && forall x: Cust {:trigger f(x)} :: WfCust(x) ==> WfCust(f(x))
    ensures WfCusts(SR.SeqUpdateById(custKey, cs, id, f))
    decreases |cs|
  {
    if |cs| == 0 {
    } else if custKey(cs[0]) == id {
    } else {
      UpdateWfCusts(cs[1..], id, f);
    }
  }

  lemma /*{:_inductionTrigger _default.SeqUpdateByIdWhere(custKey, mcpPred, cs, id, f)}*/ /*{:_induction cs, id}*/ UpdateWhereWfCusts(cs: seq<Cust>, id: string, f: Cust -> Cust)
    requires WfCusts(cs) && forall x: Cust {:trigger f(x)} :: WfCust(x) ==> WfCust(f(x))
    ensures WfCusts(SR.SeqUpdateByIdWhere(custKey, mcpPred, cs, id, f))
    decreases |cs|
  {
    if |cs| == 0 {
    } else if custKey(cs[0]) == id && mcpPred(cs[0]) {
    } else {
      UpdateWhereWfCusts(cs[1..], id, f);
    }
  }

  lemma SessionWfPreserved(s: SessionState, a: SessionAction, now: int)
    requires SessionWf(s) && WfSessionActionInv(a)
    ensures SessionWf(ApplyToSession(s, a, now).0)
    decreases s, a, now
  {
    match a
    case {:split false} Ready() =>
    case {:split false} CreationFailed(e) =>
    case {:split false} TitleChanged(t) =>
    case {:split false} ServerToolsChanged(t) =>
    case {:split false} MetaChanged(m) =>
    case {:split false} IsReadChanged(v) =>
    case {:split false} IsArchivedChanged(v) =>
    case {:split false} ActivityChanged(ac) =>
    case {:split false} ConfigChanged(cfg, repl) =>
    case {:split false} CustomizationsChanged(cs) =>
    case {:split false} CustomizationToggled(id, en) =>
      assert forall x: Cust {:trigger toggleEnabled(en)(x)} :: WfCust(x) ==> WfCust(toggleEnabled(en)(x));
      SR.UpdatePreservesUnique(custKey, s.customizations, id, toggleEnabled(en));
      UpdateWfCusts(s.customizations, id, toggleEnabled(en));
    case {:split false} CustomizationRemoved(id) =>
      SR.RemovePreservesUnique(custKey, s.customizations, id);
      RemoveWfCusts(s.customizations, id);
    case {:split false} DefaultChatChanged(c) =>
    case {:split false} ChatAdded(c) =>
      SR.UpsertPreservesUnique(chatKey, s.chats, c);
    case {:split false} ChatRemoved(r) =>
      SR.RemovePreservesUnique(chatKey, s.chats, r);
    case {:split false} ChatUpdated(r, st, ac, md) =>
