module Terminal {
  function appendData(content: seq<Part>, d: string): seq<Part>
    decreases content, d
  {
    if |content| == 0 then
      [Unclassified(d)]
    else
      var last: Part := content[|content| - 1]; var init: seq<Part> := content[..|content| - 1]; match last case Command(cid, cl, out, ts, comp, ec, dm) => (if !comp then init + [Command(cid, cl, out + d, ts, comp, ec, dm)] else content + [Unclassified(d)]) case Unclassified(v) => init + [Unclassified(v + d)]
  }

  function finishCommand(content: seq<Part>, id: string, code: int, dur: int): seq<Part>
    decreases content, id, code, dur
  {
    Ops.Map((p: Part) => match p case Command(cid, cl, out, ts, comp, ec, dm) => (if cid == id then Command(cid, cl, out, ts, true, Some(code), Some(dur)) else p) case Unclassified(_ /* _v0 */) => p, content)
  }

  function ApplyToTerminal(s: TerminalState, a: TerminalAction, now: int): (TerminalState, ReduceOutcome)
    decreases s, a, now
  {
    match a
    case TCwdChanged(c) =>
      (s.(cwd := Some(c)), Applied)
    case TTitleChanged(t) =>
      (s.(title := t), Applied)
    case TResized(co, ro) =>
      (s.(cols := Some(co), rows := Some(ro)), Applied)
    case TExited(code) =>
      (s.(exitCode := Some(code)), Applied)
    case TData(d) =>
      (s.(content := appendData(s.content, d)), Applied)
    case TCleared() =>
      (s.(content := []), Applied)
    case TClaimed(c) =>
      (s.(claim := Some(c)), Applied)
    case TCommandDetectionAvailable() =>
      (s.(supportsCommandDetection := Some(true)), Applied)
    case TCommandExecuted(id, cl, ts) =>
      (s.(content := s.content + [Command(id, cl, """", ts, false, None, None)], supportsCommandDetection := Some(true)), Applied)
    case TCommandFinished(id, code, dur) =>
      (s.(content := finishCommand(s.content, id, code, dur)), Applied)
    case TInput() =>
      (s, NoOp)
    case TUnknown(_ /* _v1 */) =>
      (s, NoOp)
  }

  lemma T_UnknownIsNoOp(s: TerminalState, a: TerminalAction, now: int)
    requires a.TUnknown? || a.TInput?
    ensures ApplyToTerminal(s, a, now).0 == s && ApplyToTerminal(s, a, now).1 == NoOp
    decreases s, a, now
  {
  }

  lemma T_UnknownIsNoOp_NonVacuous()
    ensures exists a: TerminalAction {:trigger a.TInput?} {:trigger a.TUnknown?} :: a.TUnknown? || a.TInput?
  {
    assert TUnknown(Wire.JNull).TUnknown?;
  }

  function apply1(s: TerminalState, a: TerminalAction): TerminalState
    decreases s, a
  {
    ApplyToTerminal(s, a, 9999).0
  }

  function fold(s: TerminalState, acts: seq<TerminalAction>): TerminalState
    decreases s, acts
  {
    CC.Fold(apply1, s, acts)
  }

