    var expLc := [Unclassified(""$ ""), Command(""cmd-1"", ""echo hello"", ""hello\r\n"", 1700000000000, true, Some(0), Some(10)), Unclassified(""$ ""), Command(""cmd-2"", ""exit 1"", """", 1700000001000, true, Some(1), Some(5))];
    if lc.content == expLc && lc.supportsCommandDetection == Some(true) {
      pass := pass + 1;
    }
