  datatype Part = Unclassified(value: string) | Command(commandId: string, commandLine: string, output: string, timestamp: int, isComplete: bool, exitCode: Option<int>, durationMs: Option<int>)

  datatype TerminalState = TerminalState(title: string, cwd: Option<string>, cols: Option<int>, rows: Option<int>, content: seq<Part>, claim: Option<Wire.Json>, exitCode: Option<int>, supportsCommandDetection: Option<bool>)

  datatype TerminalAction = TCwdChanged(cwd: string) | TTitleChanged(title: string) | TResized(cols: int, rows: int) | TExited(code: int) | TData(data: string) | TCleared | TClaimed(claim: Wire.Json) | TCommandDetectionAvailable | TCommandExecuted(commandId: string, commandLine: string, timestamp: int) | TCommandFinished(commandId: string, code: int, durationMs: int) | TInput | TUnknown(raw: Wire.Json)
}

