  }

  function upsertAnn(anns: seq<Annotation>, a: Annotation): seq<Annotation>
    decreases anns, a
  {
    SR.SeqUpsertById(AnnId, anns, a)
  }

  function removeAnn(anns: seq<Annotation>, id: string): seq<Annotation>
    decreases anns, id
  {
    SR.SeqRemoveById(AnnId, anns, id)
  }

  predicate hasAnn(anns: seq<Annotation>, id: string)
    decreases anns, id
  {
    exists i: int {:trigger anns[i]} :: 
      0 <= i < |anns| &&
      anns[i].id == id
  }

  function upsertEntry(entries: seq<Entry>, e: Entry): seq<Entry>
    decreases entries, e
  {
    SR.SeqUpsertById(EntryId, entries, e)
  }

  function removeEntry(entries: seq<Entry>, id: string): seq<Entry>
    decreases entries, id
  {
    SR.SeqRemoveById(EntryId, entries, id)
  }

  function updateAnn(anns: seq<Annotation>, id: string, f: Annotation -> Annotation): seq<Annotation>
    decreases anns, id
  {
    SR.SeqUpdateById(AnnId, anns, id, f)
  }

  function setEntry(e: Entry): Annotation -> Annotation
    decreases e
  {
    (an: Annotation) => an.(entries := upsertEntry(an.entries, e))
  }

  function dropEntry(eid: string): Annotation -> Annotation
    decreases eid
  {
    (an: Annotation) => an.(entries := removeEntry(an.entries, eid))
  }

  function reanchor(tid: Option<string>, res: Option<string>, rng: Option<Wire.Json>, rslv: Option<bool>): Annotation -> Annotation
    decreases tid, res, rng, rslv
  {
    (an: Annotation) => applyUpdate(an, tid, res, rng, rslv)
  }

  function applyUpdate(ann: Annotation, tid: Option<string>, res: Option<string>, rng: Option<Wire.Json>, rslv: Option<bool>): Annotation
    decreases ann, tid, res, rng, rslv
  {
    ann.(turnId := if tid.Some? then tid.value else ann.turnId, resource := if res.Some? then res.value else ann.resource, range := if rng.Some? then Some(rng.value) else ann.range, resolved := if rslv.Some? then rslv.value else ann.resolved)
  }

  function ApplyToAnnotations(s: AnnotationsState, a: AnnotationsAction, now: int): (AnnotationsState, ReduceOutcome)
    decreases s, a, now
  {
    match a
    case Set(ann) =>
      (s.(annotations := upsertAnn(s.annotations, ann)), Applied)
    case Removed(id) =>
      (s.(annotations := removeAnn(s.annotations, id)), Applied)
    case EntrySet(aid, e) =>
      if hasAnn(s.annotations, aid) then
        (s.(annotations := updateAnn(s.annotations, aid, setEntry(e))), Applied)
      else
        (s, NoOp)
    case EntryRemoved(aid, eid) =>
      if hasAnn(s.annotations, aid) then
        (s.(annotations := updateAnn(s.annotations, aid, dropEntry(eid))), Applied)
      else
        (s, NoOp)
    case Updated(aid, tid, res, rng, rslv) =>
      if hasAnn(s.annotations, aid) then
        (s.(annotations := updateAnn(s.annotations, aid, reanchor(tid, res, rng, rslv))), Applied)
      else
        (s, NoOp)
    case AnUnknown(_ /* _v0 */) =>
      (s, NoOp)
  }

  ghost predicate WfAnnotationsState(s: AnnotationsState)
    decreases s
  {
    SR.UniqueKeys(AnnId, s.annotations) &&
    forall x: Annotation {:trigger x.entries} {:trigger x in s.annotations} :: 
      x in s.annotations ==>
        _default.UniqueKeys(EntryId, x.entries)
  }

  ghost predicate WfAnnotationsAction(a: AnnotationsAction)
    decreases a
  {
    a.Set? ==>
      SR.UniqueKeys(EntryId, a.annotation.entries)
  }

  lemma /*{:_inductionTrigger _default.SeqUpsertById(keyOf, xs, v)}*/ /*{:_induction xs}*/ UpsertMemberOf<K, V>(keyOf: V -> K, xs: seq<V>, v: V, x: V)
    requires x in SR.SeqUpsertById(keyOf, xs, v)
    ensures x == v || x in xs
    decreases |xs|
  {
    if |xs| == 0 {
    } else if keyOf(xs[0]) == keyOf(v) {
      assert SR.SeqUpsertById(keyOf, xs, v) == [v] + xs[1..];
    } else {
      assert SR.SeqUpsertById(keyOf, xs, v) == [xs[0]] + SR.SeqUpsertById(keyOf, xs[1..], v);
      if x != xs[0] {
        UpsertMemberOf(keyOf, xs[1..], v, x);
      }
    }
  }

  lemma /*{:_inductionTrigger _default.SeqUpdateById(keyOf, xs, k, f)}*/ /*{:_induction xs}*/ UpdateMemberOf<K, V>(keyOf: V -> K, xs: seq<V>, k: K, f: V -> V, x: V)
    requires x in SR.SeqUpdateById(keyOf, xs, k, f)
    ensures x in xs || exists y: V {:trigger f(y)} {:trigger y in xs} :: y in xs && x == f(y)
    decreases |xs|
  {
    if |xs| == 0 {
    } else if keyOf(xs[0]) == k {
      assert SR.SeqUpdateById(keyOf, xs, k, f) == [f(xs[0])] + xs[1..];
      if x != f(xs[0]) && x !in xs[1..] {
        assert false;
      }
      if x == f(xs[0]) {
        assert xs[0] in xs && x == f(xs[0]);
      }
    } else {
      assert SR.SeqUpdateById(keyOf, xs, k, f) == [xs[0]] + SR.SeqUpdateById(keyOf, xs[1..], k, f);
      if x != xs[0] {
        UpdateMemberOf(keyOf, xs[1..], k, f, x);
        if x !in xs[1..] {
          ghost var y :| y in xs[1..] && x == f(y);
          assert y in xs;
        }
      }
    }
  }

  lemma WfAnnotationsStatePreserved(s: AnnotationsState, a: AnnotationsAction, now: int)
    requires WfAnnotationsState(s) && WfAnnotationsAction(a)
    ensures WfAnnotationsState(ApplyToAnnotations(s, a, now).0)
    decreases s, a, now
  {
    match a
    case {:split false} Set(ann) =>
      SR.UpsertPreservesUnique(AnnId, s.annotations, ann);
      ghost var outAnns := upsertAnn(s.annotations, ann);
      forall x: Annotation | x in outAnns
        ensures SR.UniqueKeys(EntryId, x.entries)
      {
        UpsertMemberOf(AnnId, s.annotations, ann, x);
      }
    case {:split false} Removed(id) =>
      SR.RemovePreservesUnique(AnnId, s.annotations, id);
      SR.RemoveKeysSubset(AnnId, s.annotations, id);
    case {:split false} EntrySet(aid, e) =>
      if hasAnn(s.annotations, aid) {
        assert SR.KeyPreserving(AnnId, setEntry(e));
        SR.UpdatePreservesUnique(AnnId, s.annotations, aid, setEntry(e));
        ghost var outAnns := updateAnn(s.annotations, aid, setEntry(e));
        forall x: Annotation | x in outAnns
          ensures SR.UniqueKeys(EntryId, x.entries)
        {
          UpdateMemberOf(AnnId, s.annotations, aid, setEntry(e), x);
          if x !in s.annotations {
            ghost var y :| y in s.annotations && x == setEntry(e)(y);
            SR.UpsertPreservesUnique(EntryId, y.entries, e);
          }
        }
      }
    case {:split false} EntryRemoved(aid, eid) =>
      if hasAnn(s.annotations, aid) {
        assert SR.KeyPreserving(AnnId, dropEntry(eid));
        SR.UpdatePreservesUnique(AnnId, s.annotations, aid, dropEntry(eid));
        ghost var outAnns := updateAnn(s.annotations, aid, dropEntry(eid));
        forall x: Annotation | x in outAnns
          ensures SR.UniqueKeys(EntryId, x.entries)
        {
          UpdateMemberOf(AnnId, s.annotations, aid, dropEntry(eid), x);
          if x !in s.annotations {
            ghost var y :| y in s.annotations && x == dropEntry(eid)(y);
            SR.RemovePreservesUnique(EntryId, y.entries, eid);
          }
        }
      }
    case {:split false} Updated(aid, tid, res, rng, rslv) =>
      if hasAnn(s.annotations, aid) {
        assert SR.KeyPreserving(AnnId, reanchor(tid, res, rng, rslv));
        SR.UpdatePreservesUnique(AnnId, s.annotations, aid, reanchor(tid, res, rng, rslv));
        ghost var outAnns := updateAnn(s.annotations, aid, reanchor(tid, res, rng, rslv));
        forall x: Annotation | x in outAnns
          ensures SR.UniqueKeys(EntryId, x.entries)
        {
          UpdateMemberOf(AnnId, s.annotations, aid, reanchor(tid, res, rng, rslv), x);
          if x !in s.annotations {
            ghost var y :| y in s.annotations && x == reanchor(tid, res, rng, rslv)(y);
            assert x.entries == y.entries;
          }
        }
      }
    case {:split false} AnUnknown(_ /* _v1 */) =>
  }

  lemma An_UnknownIsNoOp(s: AnnotationsState, a: AnnotationsAction, now: int)
    requires a.AnUnknown?
    ensures ApplyToAnnotations(s, a, now).0 == s && ApplyToAnnotations(s, a, now).1 == NoOp
    decreases s, a, now
  {
  }

  lemma An_UnknownIsNoOp_NonVacuous()
    ensures exists a: AnnotationsAction {:trigger a.AnUnknown?} :: a.AnUnknown?
  {
    assert AnUnknown(Wire.JNull).AnUnknown?;
  }

  lemma An_UnknownAnnIsNoOp(s: AnnotationsState, aid: string, e: Entry, now: int)
    requires !hasAnn(s.annotations, aid)
    ensures ApplyToAnnotations(s, EntrySet(aid, e), now).0 == s
    decreases s, aid, e, now
  {
  }

  function apply1(s: AnnotationsState, a: AnnotationsAction): AnnotationsState
    decreases s, a
  {
    ApplyToAnnotations(s, a, 9999).0
  }

  lemma Apply1PreservesWfAnnotations(s: AnnotationsState, a: AnnotationsAction)
    requires WfAnnotationsState(s) && WfAnnotationsAction(a)
    ensures WfAnnotationsState(apply1(s, a))
    decreases s, a
  {
    WfAnnotationsStatePreserved(s, a, 9999);
  }

  lemma AnnotationsWfWitness() returns (s: AnnotationsState)
    ensures WfAnnotationsState(s)
  {
    s := AnnotationsState([]);
    assert SR.UniqueKeys(AnnId, s.annotations);
  }

  function fold(s: AnnotationsState, acts: seq<AnnotationsAction>): AnnotationsState
    decreases s, acts
  {
    CC.Fold(apply1, s, acts)
  }

  function R(): Wire.Json
  {
    Wire.JObj(map[""start"" := Wire.JNull])
  }

  method RunCorpus() returns (pass: nat, total: nat)
  {
    total := 10;
    pass := 0;
    var e1 := Entry(""c-1"", ""original"", None);
    var a1 := Annotation(""t-1"", ""turn-1"", ""file:///src/a.ts"", Some(R()), false, [e1], None);
    var st1 := AnnotationsState([a1]);
    var a2 := Annotation(""t-2"", ""turn-2"", ""file:///src/b.ts"", None, false, [Entry(""c-2"", ""x"", None)], None);
    if apply1(st1, Set(a2)) == AnnotationsState([a1, a2]) {
      pass := pass + 1;
    }
    var a1r := Annotation(""t-1"", ""turn-1"", ""file:///src/a.ts"", None, true, [e1], None);
    if apply1(st1, Set(a1r)) == AnnotationsState([a1r]) {
      pass := pass + 1;
    }
    if apply1(st1, Removed(""t-1"")) == AnnotationsState([]) {
      pass := pass + 1;
    }
    if apply1(st1, Removed(""nope"")) == st1 {
      pass := pass + 1;
    }
    var e2 := Entry(""c-2"", ""reply"", None);
    if apply1(st1, EntrySet(""t-1"", e2)) == AnnotationsState([a1.(entries := [e1, e2])]) {
      pass := pass + 1;
    }
    if apply1(st1, EntrySet(""nope"", e2)) == st1 {
      pass := pass + 1;
    }
    var a1two := a1.(entries := [e1, e2]);
    if apply1(AnnotationsState([a1two]), EntryRemoved(""t-1"", ""c-2"")) == AnnotationsState([a1]) {
      pass := pass + 1;
    }
    if apply1(st1, Updated(""t-1"", None, None, None, Some(true))) == AnnotationsState([a1.(resolved := true)]) {
      pass := pass + 1;
    }
    var newR := Wire.JObj(map[""start"" := Wire.JBool(true)]);
    var a1re := a1.(turnId := ""turn-2"", resource := ""file:///src/b.ts"", range := Some(newR));
    if apply1(st1, Updated(""t-1"", Some(""turn-2""), Some(""file:///src/b.ts""), Some(newR), None)) == AnnotationsState([a1re]) {
      pass := pass + 1;
    }
    if apply1(st1, Updated(""nope"", None, None, None, Some(true))) == st1 {
      pass := pass + 1;
    }
  }

  export
    provides ApplyToAnnotations, apply1, RunCorpus
    reveals fold
    provides AhpSkeleton, Wire, CC, WfAnnotationsState, WfAnnotationsAction, Apply1PreservesWfAnnotations, AnnotationsWfWitness
    reveals AnnotationsState, AnnotationsAction, Annotation, Entry


  import opened AhpSkeleton

  import Wire = ConfluxCodec

  import CC = ConfluxContract

  import SR = ConfluxSeqRoute

  datatype Entry = Entry(id: string, text: string, meta: Option<Wire.Json>)

  datatype Annotation = Annotation(id: string, turnId: string, resource: string, range: Option<Wire.Json>, resolved: bool, entries: seq<Entry>, meta: Option<Wire.Json>)

  datatype AnnotationsState = AnnotationsState(annotations: seq<Annotation>)

  datatype AnnotationsAction = Set(annotation: Annotation) | Removed(annotationId: string) | EntrySet(annotationId: string, entry: Entry) | EntryRemoved(annotationId: string, entryId: string) | Updated(annotationId: string, turnId: Option<string>, resource: Option<string>, range: Option<Wire.Json>, resolved: Option<bool>) | AnUnknown(raw: Wire.Json)
}

module Changeset {
  const fileKey: ChangesetFile -> string := (x: ChangesetFile) => x.id
  const opKey: ChangesetOperation -> string := (x: ChangesetOperation) => x.id

  function opSet(st: string, err: Option<Wire.Json>): ChangesetOperation -> ChangesetOperation
    decreases st, err
  {
    (e: ChangesetOperation) => e.(status := st, error := err)
  }

  function upsertFile(files: seq<ChangesetFile>, f: ChangesetFile): seq<ChangesetFile>
    decreases files, f
  {
    SR.SeqUpsertById(fileKey, files, f)
  }

  function removeFile(files: seq<ChangesetFile>, id: string): seq<ChangesetFile>
    decreases files, id
  {
    SR.SeqRemoveById(fileKey, files, id)
  }

  function setReviewed(files: seq<ChangesetFile>, ids: seq<string>, rev: bool): seq<ChangesetFile>
    decreases files, ids, rev
  {
    Ops.Map((f: ChangesetFile) => if f.id in ids then f.(reviewed := Some(rev)) else f, files)
  }

  function updateOp(ops: seq<ChangesetOperation>, id: string, status: string, error: Option<Wire.Json>): seq<ChangesetOperation>
    decreases ops, id, status, error
  {
    SR.SeqUpdateById(opKey, ops, id, opSet(status, error))
  }

  predicate hasOp(ops: seq<ChangesetOperation>, id: string)
    decreases ops, id
  {
    exists i: int {:trigger ops[i]} :: 
      0 <= i < |ops| &&
      ops[i].id == id
  }

  predicate anyNeedsReviewed(files: seq<ChangesetFile>, ids: seq<string>, rev: bool)
    decreases files, ids, rev
  {
    exists i: int {:trigger files[i]} :: 
      0 <= i < |files| &&
      files[i].id in ids &&
      files[i].reviewed != Some(rev)
  }

  ghost predicate WfChangesetState(s: ChangesetState)
    decreases s
  {
    SR.UniqueKeys(fileKey, s.files) &&
    (s.operations.Some? ==>
      SR.UniqueKeys(opKey, s.operations.value))
  }

  ghost predicate WfChangesetAction(a: ChangesetAction)
    decreases a
  {
    match a
    case OperationsChanged(ops) =>
      ops.Some? ==>
        SR.UniqueKeys(opKey, ops.value)
    case ContentChanged(fs, ops, err) =>
      (fs.Some? ==>
        SR.UniqueKeys(fileKey, fs.value)) &&
      (ops.Some? ==>
        SR.UniqueKeys(opKey, ops.value))
    case _ /* _v0 */ =>
      true
  }

  function ApplyToChangeset(s: ChangesetState, a: ChangesetAction, now: int): (ChangesetState, ReduceOutcome)
    decreases s, a, now
  {
    match a
    case StatusChanged(st, err) =>
      (s.(status := st, error := err), Applied)
    case FileSet(f) =>
      (s.(files := upsertFile(s.files, f)), Applied)
    case FileRemoved(id) =>
      (s.(files := removeFile(s.files, id)), Applied)
    case OperationsChanged(ops) =>
      (s.(operations := ops), Applied)
    case Cleared() =>
      (s.(files := []), if |s.files| == 0 then NoOp else Applied)
    case OperationStatusChanged(id, st, err) =>
      (match s.operations
      case None() =>
        (s, NoOp)
      case Some(ops) =>
        if hasOp(ops, id) then
          (s.(operations := Some(updateOp(ops, id, st, err))), Applied)
        else
          (s, NoOp))
    case ContentChanged(fs, ops, err) =>
      var s1: ChangesetState := if fs.Some? then s.(files := fs.value) else s;
      var s2: ChangesetState := if ops.Some? then s1.(operations := ops) else s1;
      var s3: ChangesetState := if err.Some? then s2.(error := err) else s2;
      (s3, Applied)
    case FilesReviewedChanged(ids, rev) =>
      if anyNeedsReviewed(s.files, ids, rev) then
        (s.(files := setReviewed(s.files, ids, rev)), Applied)
      else
        (s, NoOp)
    case CsUnknown(_ /* _v1 */) =>
      (s, NoOp)
  }

  lemma WfChangesetStatePreserved(s: ChangesetState, a: ChangesetAction, now: int)
    requires WfChangesetState(s) && WfChangesetAction(a)
    ensures WfChangesetState(ApplyToChangeset(s, a, now).0)
    decreases s, a, now
  {
    match a
    case {:split false} StatusChanged(st, err) =>
    case {:split false} FileSet(f) =>
      SR.UpsertPreservesUnique(fileKey, s.files, f);
    case {:split false} FileRemoved(id) =>
      SR.RemovePreservesUnique(fileKey, s.files, id);
    case {:split false} OperationsChanged(ops) =>
    case {:split false} Cleared() =>
    case {:split false} OperationStatusChanged(id, st, err) =>
      if s.operations.Some? && hasOp(s.operations.value, id) {
        SR.UpdatePreservesUnique(opKey, s.operations.value, id, opSet(st, err));
      }
    case {:split false} ContentChanged(fs, ops, err) =>
    case {:split false} FilesReviewedChanged(ids, rev) =>
      if anyNeedsReviewed(s.files, ids, rev) {
        ghost var mapped := setReviewed(s.files, ids, rev);
        assert |mapped| == |s.files|;
        forall i: int, j: int | 0 <= i < |mapped| && 0 <= j < |mapped| && fileKey(mapped[i]) == fileKey(mapped[j])
          ensures i == j
        {
          assert fileKey(mapped[i]) == fileKey(s.files[i]);
          assert fileKey(mapped[j]) == fileKey(s.files[j]);
        }
        assert SR.UniqueKeys(fileKey, mapped);
      }
    case {:split false} CsUnknown(raw) =>
  }

  lemma Cs_UnknownIsNoOp(s: ChangesetState, a: ChangesetAction, now: int)
    requires a.CsUnknown?
    ensures ApplyToChangeset(s, a, now).0 == s && ApplyToChangeset(s, a, now).1 == NoOp
    decreases s, a, now
  {
  }

  lemma Cs_UnknownIsNoOp_NonVacuous()
    ensures exists a: ChangesetAction {:trigger a.CsUnknown?} :: a.CsUnknown?
  {
    assert CsUnknown(Wire.JNull).CsUnknown?;
  }

  lemma Cs_UnknownOpIsNoOp(s: ChangesetState, id: string, st: string, err: Option<Wire.Json>, now: int)
    requires s.operations.Some? && !hasOp(s.operations.value, id)
    ensures ApplyToChangeset(s, OperationStatusChanged(id, st, err), now).0 == s
    decreases s, id, st, err, now
  {
  }

  function apply1(s: ChangesetState, a: ChangesetAction): ChangesetState
    decreases s, a
  {
    ApplyToChangeset(s, a, 9999).0
  }

  lemma Apply1PreservesWfChangeset(s: ChangesetState, a: ChangesetAction)
    requires WfChangesetState(s) && WfChangesetAction(a)
    ensures WfChangesetState(apply1(s, a))
    decreases s, a
  {
    WfChangesetStatePreserved(s, a, 9999);
  }

  lemma ChangesetWfWitness() returns (s: ChangesetState)
    ensures WfChangesetState(s)
  {
    s := ChangesetState(""idle"", [], None, None);
    assert SR.UniqueKeys(fileKey, s.files);
  }

  function fold(s: ChangesetState, acts: seq<ChangesetAction>): ChangesetState
    decreases s, acts
  {
    CC.Fold(apply1, s, acts)
  }

  function E(): Wire.Json
  {
    Wire.JObj(map[""diff"" := Wire.JNull])
  }

  method RunCorpus() returns (pass: nat, total: nat)
  {
    total := 15;
    pass := 0;
    var fa := ChangesetFile(""file:///src/a.ts"", None, E());
    var fb := ChangesetFile(""file:///src/b.ts"", None, E());
    if apply1(ChangesetState(""computing"", [], None, Some(Wire.JStr(""boom""))), StatusChanged(""ready"", None)) == ChangesetState(""ready"", [], None, None) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [], None, None), StatusChanged(""error"", Some(Wire.JStr(""x"")))) == ChangesetState(""error"", [], None, Some(Wire.JStr(""x""))) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [fa], None, None), FileSet(fb)) == ChangesetState(""ready"", [fa, fb], None, None) {
      pass := pass + 1;
    }
    var fbv2 := ChangesetFile(""file:///src/b.ts"", Some(true), E());
    if apply1(ChangesetState(""ready"", [fa, fb], None, None), FileSet(fbv2)) == ChangesetState(""ready"", [fa, fbv2], None, None) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [fa, fb], None, None), FileRemoved(""file:///src/a.ts"")) == ChangesetState(""ready"", [fb], None, None) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [fa], None, None), FileRemoved(""nope"")) == ChangesetState(""ready"", [fa], None, None) {
      pass := pass + 1;
    }
    var op := ChangesetOperation(""create-pr"", ""Create Pull Request"", [""changeset""], ""idle"", None);
    if apply1(ChangesetState(""ready"", [], None, None), OperationsChanged(Some([op]))) == ChangesetState(""ready"", [], Some([op]), None) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [], Some([op]), None), OperationsChanged(None)) == ChangesetState(""ready"", [], None, None) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [fa], None, None), Cleared).files == [] {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [], None, None), CsUnknown(Wire.JObj(map[""type"" := Wire.JStr(""changeset/nope"")]))) == ChangesetState(""ready"", [], None, None) {
      pass := pass + 1;
    }
    var opR := op.(status := ""running"");
    if apply1(ChangesetState(""ready"", [], Some([op]), None), OperationStatusChanged(""create-pr"", ""running"", None)) == ChangesetState(""ready"", [], Some([opR]), None) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [], Some([op]), None), OperationStatusChanged(""nope"", ""running"", None)) == ChangesetState(""ready"", [], Some([op]), None) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [fa], None, None), ContentChanged(Some([fb]), Some([op]), None)) == ChangesetState(""ready"", [fb], Some([op]), None) {
      pass := pass + 1;
    }
    var fc := ChangesetFile(""file:///src/c.ts"", Some(false), E());
    var fbT := ChangesetFile(""file:///src/b.ts"", Some(true), E());
    var faT := ChangesetFile(""file:///src/a.ts"", Some(true), E());
    var r160 := apply1(ChangesetState(""ready"", [fa, fbT, fc], None, None), FilesReviewedChanged([""file:///src/a.ts"", ""file:///src/b.ts"", ""file:///src/missing.ts""], true));
    if r160 == ChangesetState(""ready"", [faT, fbT, fc], None, None) {
      pass := pass + 1;
    }
    if apply1(ChangesetState(""ready"", [fbT], None, None), FilesReviewedChanged([""file:///src/b.ts""], true)) == ChangesetState(""ready"", [fbT], None, None) {
      pass := pass + 1;
    }
  }

