      (s.(title := if t.Some? then t else s.title, activity := if ac.Some? then ac else s.activity, contentUri := if uri.Some? then uri else s.contentUri, availability := if av.Some? then av.value else s.availability), Applied)
    case CloseRequested() =>
      (s, NoOp)
    case CanvasUnknown(_ /* _v0 */) =>
